INSERT INTO rooms VALUES(101,1,'Dimly Lit Path',replace('This path is made of crushed granite with curious blue streaks in it.\nThe path continues north to a village, or south to the west gate.\n','\n',char(10)));
INSERT INTO rooms VALUES(102,1,'Dimly Lit Path',replace('This section of the road is badly worn and frequently traversed.  There is\nfaint singing to the north.  The road back to the forest lies to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(103,1,'Dimly Lit Path',replace('This section of the road is badly worn and frequently traversed.  Singing is\ngetting stronger to the north.  The road back to the forest lies to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(104,1,'Entrance to Smurf Village',replace('You stand at the entrance to a tiny village.  You can see across the whole\nvillage easily.  Little blue creatures with white hats and boots and little \nfluffy tails scamper about.  They sing continuously.  The singing is getting\non your nerves and you have the urge to squash them.\n','\n',char(10)));
INSERT INTO rooms VALUES(105,1,'Smurfy Road',replace('You are way too big to be using this road.  But who cares.  Who''s gonna stop\nyou?  These little blue smurfs?  The singing is growing intense.  Your ears\nare starting to ring.  Smurfy Road continues to the north, west, and east.\nThere is still time to turn back and go south.\n','\n',char(10)));
INSERT INTO rooms VALUES(106,1,'Smurfy Road',replace('You continue to travel down Smurfy Road.  Isn''t it just smurfy?  Smurfy road\ncontinues its smurfy path to the smurfy north, smurfy west, and smurfy south.\nA smurfy home lies to the smurfy east.\n','\n',char(10)));
INSERT INTO rooms VALUES(107,1,'Smurfy Road',replace('Oh boy, another smurfy road!  Smurfy Road goes north and south here.  There\nis a smurfy, mushroom home to the west.  A beautiful smurfberry patch is to\nthe east.\n','\n',char(10)));
INSERT INTO rooms VALUES(108,1,'Smurfy Road',replace('Smurfy Road continues to smurf here.  It smurfs to the south and smurfs to\nan end to the north.  A smurfberry patch is to the east.  A stone path lies\nto the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(109,1,'Smurfy Road',replace('A smurfy well lies here in the middle of Smurfy Road.  A fence separates\nthe smurfs from harm to the north.  A berry patch is to the east.  Smurfy\nRoad continues to to the south and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(110,1,'Smurfy Road',replace('A corner of smurfy road is where you stand.  A smurfy fence blocks passage\nto the east or south.  A smurfy home is to the north.  Smurfy Road goes back\nto the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(111,1,'Smurfy Road',replace('Western corner of Smurfy Road.  You can continue to smurf down the road\nto the east and north.  You can also smurf into a smurfy home to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(112,1,'Smurfy Road',replace('There''s no place like smurf.  There''s no place like smurf.  Sorry wrong\nmovie.  A smurfy home is to the west.  Papa Smurf''s backyard is to the\nnorth but you can''t go there.  Smurfy Road continues to the south and\neast.\n','\n',char(10)));
INSERT INTO rooms VALUES(113,1,'Stone Path',replace('You are walking along a cute little stone path.  To the south lies Papa\nSmurf''s house.  A Smurfy house is to the west.  Smurfy road is to the east.\nEverything is so peaceful here.  You could stay forever.\n','\n',char(10)));
INSERT INTO rooms VALUES(114,1,'Smurfy Road',replace('Yet another part of Smurfy Road.  Hey if you go west its the last\nsection of Smurfy Road.  You can go back to the smurfy well to the east.\n','\n',char(10)));
INSERT INTO rooms VALUES(115,1,'Smurfy Road',replace('The last piece of Smurfy Road.  You can go back to Smurfy Road to the east.\nA nice, beautiful, smurfy, mushroom home is to the south.  In the distance to\nthe north you can see Gargamel''s Castle.\n','\n',char(10)));
INSERT INTO rooms VALUES(116,1,'Smurfberry Patch',replace('Delicious smurfberries grow here.  You could probably eat a year''s worth of\nsmurfberries in one sitting.  Smurfy Road is back to the west.  Another\nsmurfberry patch is to the north.\n','\n',char(10)));
INSERT INTO rooms VALUES(117,1,'Smurfberry Patch',replace('Another patch of smurfberries is growing here.  The smell is driving your\nnostrils crazy.  It almost, ALMOST, makes you forget all the singing going\non.  Smurfy Road is to the west, while smurfberry patches are to the north\nand south.\n','\n',char(10)));
INSERT INTO rooms VALUES(118,1,'Smurfberry Patch',replace('The northernmost of the smurfberry patches grows here.  It looks just\nas scrumptious as all the rest.  Just take a few; they''ll never know.  Smurfy\nRoad is to the west.  A smurfberry patch is to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(119,1,'Brainy Smurf''s Home',replace('You rip the roof of the home to get a good look inside.  You see\nmany smurfy books.  The print is so small you couldn''t even read it\nwith a magnifying glass.  I wonder if Brainy Smurf minds if you\ndestroy his home?  Smurfy Road is back to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(120,1,'Handy Smurf''s Home',replace('This home was well built.  Of course, until you rip it apart you big meany\nyou.  Tools are all over the place.  Too small for you to use.  Smurfy Road is\nback to the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(121,1,'Hefty Smurf''s Home',replace('Hefty is anything but wimpy.  So is his house.  It actually took you a \ncouple of minutes to destroy his house.  Better watch out -- he might be\na little mad at you.  Smurfy Road is back to the north.\n','\n',char(10)));
INSERT INTO rooms VALUES(122,1,'Sleepy Smurf''s Home',replace('Be vewy vewy quiet.  Sleepy Smurf is probably sleeping.  You see so many\nbeds you can''t even tell if he is here.  Maybe you should quietly go back to\nSmurfy Road to the east.\n','\n',char(10)));
INSERT INTO rooms VALUES(123,1,'Grumpy Smurf''s Home',replace('This is Grumpy Smurf''s home.  He is pissed at you.  Of course, he is pissed\nat everyone.  So don''t take it bad.  Maybe you''d better leave before he really\ngets mad.  Smurfy Road to the east is your only salvation.\n','\n',char(10)));
INSERT INTO rooms VALUES(124,1,'Jokey Smurf''s Home',replace('You pull the top of his house and it explodes in your face.  That Jokey\nSmurf, what a kidder.  You can hear his laughter as you wipe the ashes off\nyour face.  You better get even.  Smurfy Road is to the north.\n','\n',char(10)));
INSERT INTO rooms VALUES(125,1,'Papa Smurf''s Home',replace('It''s the home of the leader of the smurfs.  Papa Smurf has a nicely decorated\nhome.  He takes pride in his work.  You could get to know him or just squash\nhim.  If Papa Smurf is not here he is probably at Smurfette''s putting the\nmoves on her.  A stone path lies to the north.\n','\n',char(10)));
INSERT INTO rooms VALUES(126,1,'Path to Gargamel''s Castle',replace('You are walking along a path to Gargamel''s Castle to the North.\nSmurfy Road lies to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(127,1,'Outside Gargamel''s Castle',replace('You are standing outside Gargamel''s Castle.  You can hear him screaming at\nAzreal from inside.  You can also him cursing out those wretched smurfs.\nHis Castle is to the north while Smurfy Road is to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(128,1,'Gargamel''s Castle',replace('This is Gargamel''s Castle.  His big black kettle is in the middle of the room.\nWhere else would he put it?  The place has only one room.\n','\n',char(10)));
INSERT INTO rooms VALUES(129,1,'Smurfette''s House',replace('This house is conveniently next to Papa Smurfs.  Makes it easier for Papa\nSmurf to sneak over at night.  I hope he uses protection.  I would hate to\nhave little smurfs running around.  The only exit is to the east.\n','\n',char(10)));
INSERT INTO rooms VALUES(300,3,'Path in the plains',replace('You are walking on a path situated in the rough plains.\nYou feel the strong winds blow through your hair as you study\nthe beautiful landscaping here. The path continues east, north\nand west leads to plains and you see the path around Midgaard\nto the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(301,3,'Path in the plains',replace('You are walking on a path situated in the rough plains.\nYou feel the strong winds blow through your hair as you study\nthe beautiful landscaping here. The path continues east and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(302,3,'Path in the plains',replace('You are walking on a path situated in the rough plains.\nYou feel the strong winds blow through your hair as you study\nthe beautiful landscaping here. The path continues north and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(303,3,'Path in the plains',replace('You are walking on a path situated in the rough plains.\nYou feel the strong winds blow through your hair as you study\nthe beautiful landscaping here. The path leads north and south.\nTo the east and the west you have the grassy plains.\n','\n',char(10)));
INSERT INTO rooms VALUES(304,3,'Path in the plains',replace('You are walking on a path situated in the rough plains.\nYou feel the strong winds blow through your hair as you study\nthe beautiful landscaping here. The Path leads north and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(305,3,'Path in the plains',replace('You are walking on a path situated in the rough plains.\nYou feel the strong winds blow through your hair as you watch the\nbeautiful landscaping here. To the east and west you see the grassy plains.\nThe path extends into small foothills to the north and also continues south.\n','\n',char(10)));
INSERT INTO rooms VALUES(306,3,'Path in the foothills',replace('You are on the path leading through the small foothills.\nThe wind blow through your hair as you study the beautiful\nlandscaping here. From the north you sense a certain freshness.\nThe path continues east and south. You smell freshness from north.\n','\n',char(10)));
INSERT INTO rooms VALUES(307,3,'Path in the foothills',replace('You are walking on a path situated in the small foothills.\nThe winds are more than average here but it feels nice. You can follow\nthe path east or west.\n','\n',char(10)));
INSERT INTO rooms VALUES(308,3,'Path in the foothills',replace('You are walking on a narrow path in the foothills.\nYou feel the strong winds blow through your hair as you study\nthe beautiful landscaping here. The path goes north and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(309,3,'Path in the foothills',replace('You are walking on a path situated in foothills.\nTo the west you sense a certain freshness and the path continues\nsouth and east.\n','\n',char(10)));
INSERT INTO rooms VALUES(310,3,'Path in the foothills',replace('You are walking on a long path in the east-west direction.\nThe surroundings are green, vegetated foothills.\nYou are able to force your way through some dense plants to the north.\n','\n',char(10)));
INSERT INTO rooms VALUES(311,3,'Path in the foothills',replace('You are walking on the long, narrow path through the foothills.\nTo your east you see a T-intersection and to the west the path\ncontinues far.\n','\n',char(10)));
INSERT INTO rooms VALUES(312,3,'The path intersection',replace('You are standing on an intersection between 3 paths.\nTo the west you can follow a long, narrow path through the foothills.\nTo the north a wide path leads to the Village of Ofcol and an\nancient path leads towards the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(313,3,'Road to Ofcol',replace('You are walking on a wide road with trail marks on it.  To the north\nyou see the village of Ofcol and to the south there is the T intersection.\nYou can enter the foothills west.  The foothills to your east are too\nsteep to climb.\n','\n',char(10)));
INSERT INTO rooms VALUES(314,3,'Outside Ofcol',replace('You are standing outside the village of Ofcol.\nThe village looks very small, but still a nice and safe place to stay.\nYou may enter the city to the north or journey towards the\nT-intersection in the southern direction.\n','\n',char(10)));
INSERT INTO rooms VALUES(315,3,'Gallow hill',replace('You walk in the grassy plains. On this little hill you can see\ntwo gallows, with rotting human tissue hanging from the robe.\nThere is a sign here.\n','\n',char(10)));
INSERT INTO rooms VALUES(316,3,'Grassy plains',replace('You walk in the grassy plains among the herbs which grow here. The wind is\nstrong and rough. Far to the north you can see the foothills and further on\nmountain peaks are visible.\n','\n',char(10)));
INSERT INTO rooms VALUES(317,3,'Grassy plains',replace('You walk in the grassy plains among the herbs which grow here. The wind is\nstrong and rough. Far to the north you can see the foothills and further on\nmountain peaks are visible. City of Midgaard is to the south but so are some\nVERY steep slopes.\n','\n',char(10)));
INSERT INTO rooms VALUES(318,3,'Grassy plains',replace('You walk in the beautiful grassy plains. The wind is strong and rough.\nFar to the north you can see the foothills and further on mountain peaks\nare visible.\n','\n',char(10)));
INSERT INTO rooms VALUES(319,3,'Grassy plains',replace('You walk in the grassy plains among the herbs which grow here. The wind is\nstrong and rough. To the north you can see the foothills and just behind\nmountain peaks are visible.\n','\n',char(10)));
INSERT INTO rooms VALUES(320,3,'Grassy plains',replace('You walk in some grassy plains. The wind is strong and rough. To the\nnorth you can see the foothills and further on mountain peaks are visible.\n','\n',char(10)));
INSERT INTO rooms VALUES(321,3,'Grassy plains',replace('You walk in the grassy plains. The wind is fairly strong.\n','\n',char(10)));
INSERT INTO rooms VALUES(322,3,'Grassy foothills',replace('You walk in the grassy foothills north of the plains. The wind is rough.\nTo the north you can see foothills and just behind them mountain peaks\nare visible.\n','\n',char(10)));
INSERT INTO rooms VALUES(323,3,'The steep foothills',replace('You walk in the steep foothills. It is rather hard to move here.\nTo the north you can see a grassy valley with wildflowers.\n','\n',char(10)));
INSERT INTO rooms VALUES(324,3,'The steep foothills',replace('You are walking in the steep foothills. It is rather hard to move here.\nTo the north you can see the mountains towering over you.  Pine trees\ngrow here.\n','\n',char(10)));
INSERT INTO rooms VALUES(325,3,'The steep foothills',replace('You are walking in the steep foothills. It is rather hard to move here.\nFurther to the north you can see the mountains towering over you.\nSeveral pinetrees grow here.\n','\n',char(10)));
INSERT INTO rooms VALUES(326,3,'The pool in the foothills',replace('You are standing by a pool in the small foothills. It is clear and cold.\nA steep slope rises up into the foothills to the north. Behind them ...\nthe mountains.\n','\n',char(10)));
INSERT INTO rooms VALUES(327,3,'The foothills',replace('You are walking in some foothills. It is rather hard to move here.\nFurther to the north you can see the mountains towering over you.\nSeveral pinetrees grow here.\n','\n',char(10)));
INSERT INTO rooms VALUES(330,3,'In front of hut in foothills',replace('You are standing in the foothills. To the west, well hidden among the small\nfoothills and pines, you see a small hut. To the north you can see\nthe foothills, and some pineforrest. Further on mountain peaks are visible.\n','\n',char(10)));
INSERT INTO rooms VALUES(331,3,'Hermit''s hut',replace('You are inside the hermit''s hut. It is rather old, but serves it purpose.\nIt keeps its habitant from the rough winds and dangerous beasts of the\nplains and foothills. There is a small fireplace here.\n','\n',char(10)));
INSERT INTO rooms VALUES(332,3,'The ancient path',replace('You are moving on an ancient path. The path is slightly covered with\nleaves and twitches.\nTo the north you can see the T-crossing and the path continues south.\n','\n',char(10)));
INSERT INTO rooms VALUES(333,3,'The ancient path',replace('You are standing on the ancient path which runs north and south.\nThe path is hardly visible here.\n','\n',char(10)));
INSERT INTO rooms VALUES(334,3,'The ancient path',replace('You are standing on the ancient path which runs north and south.\nThe path is hardly visible here.\n','\n',char(10)));
INSERT INTO rooms VALUES(335,3,'The ancient path',replace('The path runs north and east from here.  You notice some markers placed\nalong the side of the path.\n','\n',char(10)));
INSERT INTO rooms VALUES(336,3,'The wooden bridge',replace('You have stepped upon a wooden bridge. It looks old but safe to cross.\nIt is made of a wood you haven''t seen before.\n','\n',char(10)));
INSERT INTO rooms VALUES(337,3,'The ancient path',replace('You find yourself located between the bridge and the rock formations.\nAs you approach the formations you begin to realize the true size of\nthem, about 15 feet tall and almost perfect rectangular shape.\nYou feel impressed with the awesome sight.\n','\n',char(10)));
INSERT INTO rooms VALUES(338,3,'Grassy plains',replace('You walk in the grassy plains among the herbs which grow here. The wind is\nstrong and rough. Far to the north you can see the foothills and further on\nmountain peaks are visible.\n','\n',char(10)));
INSERT INTO rooms VALUES(339,3,'The Stones of G''harne',replace('You are in the center of 7, 15 ft tall monolith like black stones.\nIn the center of the ring formed by the monolith you can''t help\nnoticing a big sacrifice altar. The ground is covered with dirt, but the\naltar shows no sign of such. West of here is the ancient path.\n','\n',char(10)));
INSERT INTO rooms VALUES(340,3,'Dark smelly tunnels',replace('You are standing in a gloomy tunnel leading south and west, right under\nthe altar of G''harne.  The walls are covered with a smelly slime and small\nrotting pieces of a meat like substance, fills the air with an unbearable\nstench.  You might be able to force your way up into fresh air from here.\n','\n',char(10)));
INSERT INTO rooms VALUES(341,3,'Dead end of tunnel',replace('The tunnel comes to an abrupt end here. It simply looks like it\nhasn''t been excavated further.  North of here the tunnel makes a turn east.\n','\n',char(10)));
INSERT INTO rooms VALUES(342,3,'Dark smelly tunnels',replace('You are standing in a gloomy tunnel leading east and west.\nThe walls are covered with a smelly slime and small rotting pieces of a\nmeat like substance, fills the air with an unbearable stench.\n','\n',char(10)));
INSERT INTO rooms VALUES(343,3,'Dark smelly tunnels',replace('You are standing in a small smelly tunnel under the plains.\nThe smell is growing stronger to the west, so is the density of the\nslime and other undeterminable substances ...\n','\n',char(10)));
INSERT INTO rooms VALUES(344,3,'The Hall of G''harne',replace('You stand in the hall of G''harne. The walls are dressed with strange\ncarving, symbolizing human sacrifice and people worshipping giant worms.\nDisgusting slime and gore are also very dominant in your view of this room.\n','\n',char(10)));
INSERT INTO rooms VALUES(345,3,'Steep slope',replace('You try to climb down the slope.\n>\nYou slip!\nYou fall and tumble.\nYou hit your head HARD.\nYou die.\n\nYou''ve fallen, and you can''t get up!\n','\n',char(10)));
INSERT INTO rooms VALUES(600,6,'Granny''s Still Room',replace('You are in Granny Jenkins'' still room.  The smell of whiskey is heady, and\nthe bottles of it on the floor make your mouth water and your mind swirl.  You\nalso see a very large still.  So THIS is why there are so many grain fields!\nThe exit is to the east.\n','\n',char(10)));
INSERT INTO rooms VALUES(601,6,'The Big Intersection',replace('You are in the big intersection between Raff Way and Impy Way.  Crowds \nof people walk past you as they go on their daily tasks.  Raff Way continues\neast and west, and Impy Way runs north and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(602,6,'Impy Way',replace('You are on Impy Way.  You can see a leather shop east and a blacksmith\nwest.  To the north you see a big intersection, and Impy Way continues south.\n','\n',char(10)));
INSERT INTO rooms VALUES(603,6,'The Blacksmith',replace('You are in a black and smelly room.  Pieces of metal are strewn all over\nthe floor, and a wave of heat from a big furnace hits you.  An anvil sits on \none side of the room, and on the other side is a workbench.  The exit is east.\n','\n',char(10)));
INSERT INTO rooms VALUES(604,6,'The Leather Shop',replace('You are in a brown and smelly room.  Pieces of leather are strewn all over\nthe floor.  The smell of burnt hide assaults your nose.  You can tell by the\nlooks that the tanning is done VERY CLOSE to here!   A table is near the\nentrance.  The exit is west.\n','\n',char(10)));
INSERT INTO rooms VALUES(605,6,'Impy Way',replace('You are on Impy Way.  To the east is a meat store, and to the west is a\npawn shop.  Impy Way continues north and south.  People are rushing around you\nto go to these stores.\n','\n',char(10)));
INSERT INTO rooms VALUES(606,6,'The Pawn Shop.',replace('You are in a little shop filled with a lot of knick knacks and semi-\nvaluable goods.  There is a display case full of little treasures that you are\nsure that you or any other little kid would like to touch!  The exit is east.\n','\n',char(10)));
INSERT INTO rooms VALUES(607,6,'The Meat Store',replace('You are in a meat store.  Hanging on hooks are meats of many kinds of\nanimals.  In the background, you can hear the sound of blade against flesh.\nIt smells like meat here (which is not a good smell).  The exit is west.\n','\n',char(10)));
INSERT INTO rooms VALUES(608,6,'Impy Way',replace('You are on Impy Way.  To the east is Farmer''s Market, and to the west is\nNyles'' House of Ale.  Impy Way runs north and ends south of here.  You can hear\nthe sound of housewives gossiping at the market.\n','\n',char(10)));
INSERT INTO rooms VALUES(609,6,'Nyles'' House of Ale',replace('This is a very busy bar, with everyone holding homemade bottles of\nale.  You see even the more gentile persons here, laughing along with\nNyles, who offers you a quart of ale too.\n','\n',char(10)));
INSERT INTO rooms VALUES(610,6,'Farmer''s Market',replace('You see many carts filled with fruits and vegetables.  Many farmers are\nall trying to sell you their produce, each saying their''s is better.  The exit\nis west.\n','\n',char(10)));
INSERT INTO rooms VALUES(611,6,'The End of Impy Way',replace('You are at the end of Impy and of the city part of Ofcol.  To the east is\na dirt road leading toward the farm animals.  West from here are fields.  Impy\nWay continues north.\n','\n',char(10)));
INSERT INTO rooms VALUES(612,6,'Fields',replace('You are in a corn field.  You can''t see far, since the corn stalks are\ntaller than you are.  You remember that the end of Impy Way is east of here, \nand you think you see a building to the north.  The field continues south and \nwest.\n','\n',char(10)));
INSERT INTO rooms VALUES(613,6,'Fields',replace('You are among fruit trees in a field.  You see many apple and orange \ntrees.  You can make out the corn fields north and some vegetable patches west.\nThe sight of the fruit makes your mouth water.\n','\n',char(10)));
INSERT INTO rooms VALUES(614,6,'Fields',replace('You are among the vegetable fields.  You see many cabbage and lettuce\npatches, along with tomato bushes and potato plants.  To the east are some\nfruit trees, and north are some wheat fields.\n','\n',char(10)));
INSERT INTO rooms VALUES(615,6,'Fields',replace('You are among the wheat fields.  The gentle caress of the wheat and the\ncool shadow from the tall stalks and scarecrow lulls you to sleep and dream\nof a little girl and little dog from a faraway place.  To the east are the corn\nstalks, and south of you are the vegetable patches.\n','\n',char(10)));
INSERT INTO rooms VALUES(616,6,'The Shed',replace('You are in the storage shed.  Bales of wheat, corn and hay are piled\nagainst the wall, and some vegetables are in carts.  You see a small door\non the west door.  The main exit is south.\n','\n',char(10)));
INSERT INTO rooms VALUES(617,6,'Slaughterhouse',replace('You are in the slaughterhouse, where all the animals are slaughtered so\nthat they can be sold or their skins be tanned.  The scream of dying animals\nmakes your stomach churn.  The exit is to the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(618,6,'Dirt Road',replace('You are on a dirt road.  To the east is a barn, and you see a big chicken\ncoop south of you.  The dirt road continues north and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(619,6,'Chicken Coop',replace('You are in the chicken coop.  The smell of chickens and chicken droppings\nmakes you gasp.  The exit is north.\n','\n',char(10)));
INSERT INTO rooms VALUES(620,6,'Barn',replace('You are in a barn.  There are some cows here, munching on mounds of hay.\nMilk is milked and bottled here.  You see the exit west.\n','\n',char(10)));
INSERT INTO rooms VALUES(621,6,'Dirt Road',replace('You are on a dirt road.  To the north and south, you see some grass \nfields.  There is a pigsty west, and the dirt road continues east.\n','\n',char(10)));
INSERT INTO rooms VALUES(622,6,'Grass Field',replace('You are in a grass field.  Fences block the way north, east, and west.\nThe dirt road is to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(623,6,'Grass Field',replace('You are in a grass field.  Fences block the way south, east, and west.\nThe dirt road is to the north.\n','\n',char(10)));
INSERT INTO rooms VALUES(624,6,'Pig Sty',replace('For some reason, you are in a pig sty.  You wonder why you are standing in\nmuck.  To realize your senses and notice the dirt road is to the east.\n','\n',char(10)));
INSERT INTO rooms VALUES(625,6,'Impy Way',replace('You are on Impy Way.  East and west of you are big houses.  Impy Way\ncontinues north and reaches a big intersection south.  Children are running to\nfrom home to home.\n','\n',char(10)));
INSERT INTO rooms VALUES(626,6,'Big House',replace('You are in a big house.  Evidently, the owners of this house are richer\nthan the average citizen, since there is more than one room to this house.  A\ndoor leads to the kitchen east, and a bedroom is upstairs.  The exit is to the\nwest.\n','\n',char(10)));
INSERT INTO rooms VALUES(627,6,'Bedroom',replace('You are in the bedroom.  There isn''t much of interest except for a bed and\na closet.  The stairs lead back down.\n','\n',char(10)));
INSERT INTO rooms VALUES(628,6,'Kitchen',replace('You are in a kitchen.  There isn''t much of interest here.  The main room\nis west of here.\n','\n',char(10)));
INSERT INTO rooms VALUES(629,6,'Big House',replace('You are in a big house.  Evidently, the owners of this house are richer\nthan the average citizen, since there is more than one room to this house.  A\ndoor leads to the kitchen west, and a bedroom is upstairs.  The exit is to the\neast.\n','\n',char(10)));
INSERT INTO rooms VALUES(630,6,'Bedroom',replace('You are in the bedroom.  There isn''t much of interest except for a bed and\na closet.  The stairs lead back down.\n','\n',char(10)));
INSERT INTO rooms VALUES(631,6,'Kitchen',replace('You are in a kitchen.  There isn''t much of interest here.  The main room\nis east of here.\n','\n',char(10)));
INSERT INTO rooms VALUES(632,6,'Impy Way',replace('You are on Impy Way.  Houses are to the east and west of here.  Impy Way\ncontinues north and south.  There are many people walking along the streets.\n','\n',char(10)));
INSERT INTO rooms VALUES(633,6,'House',replace('You are in a house.  The living room and kitchen are all bundled into\nthis room.  There is a bedroom south of here.  The exit is west.\n','\n',char(10)));
INSERT INTO rooms VALUES(634,6,'Bedroom',replace('You are in a bedroom.  There isn''t much of interest here except for a bed\nand a dresser.  The main room of the house is north of here.\n','\n',char(10)));
INSERT INTO rooms VALUES(635,6,'House',replace('You are in a house.  The living room and kitchen are all bundled into\nthis room.  There is a bedroom south of here.  The exit is east.\n','\n',char(10)));
INSERT INTO rooms VALUES(636,6,'Bedroom',replace('You are in a bedroom.  There isn''t much of interest here except for a bed\nand a dresser.  The main room of the house is north of here.\n','\n',char(10)));
INSERT INTO rooms VALUES(637,6,'Impy Way',replace('You are on Impy Way.  Houses are to the east and west of here.  Impy Way\ncontinues south.  To the north is a big intersection.  There are many people\nwalking along the streets.\n','\n',char(10)));
INSERT INTO rooms VALUES(638,6,'House',replace('You are in a house.  The living room and kitchen are all bundled into\nthis room.  There is a bedroom south of here.  The exit is west.\n','\n',char(10)));
INSERT INTO rooms VALUES(639,6,'Bedroom',replace('You are in a bedroom.  There isn''t much of interest here except for a bed\nand a dresser.  The main room of the house is north of here.\n','\n',char(10)));
INSERT INTO rooms VALUES(640,6,'House',replace('You are in a house.  The living room and kitchen are all bundled into\nthis room.  There is a bedroom south of here.  The exit is east.\n','\n',char(10)));
INSERT INTO rooms VALUES(641,6,'Bedroom',replace('You are in a bedroom.  There isn''t much of interest here except for a bed\nand a dresser.  The main room of the house is north of here.\n','\n',char(10)));
INSERT INTO rooms VALUES(642,6,'The Big Intersection',replace('You are on the intersection of Impy Way and Swiftest Way.  To the north of\nyou is a big house.  Swiftest Way runs east and west, and Impy way continues\nsouth.  There are quite a few people on this intersection.\n','\n',char(10)));
INSERT INTO rooms VALUES(643,6,'Big House',replace('You are in a big house.  Evidently, the owners of this house are richer\nthan the average citizen, since there is more than one room to this house.  A\ndoor leads to the kitchen north, and a bedroom is upstairs.  The exit is to \nthe south.\n','\n',char(10)));
INSERT INTO rooms VALUES(644,6,'Bedroom',replace('You are in the bedroom.  There isn''t much of interest except for a bed \nand a closet.  The stairs lead back down.\n','\n',char(10)));
INSERT INTO rooms VALUES(645,6,'Kitchen',replace('You are in a kitchen.  There isn''t much of interest here.  The main room\nis east of here.\n','\n',char(10)));
INSERT INTO rooms VALUES(646,6,'Swiftest Way',replace('You are on Swiftest Way, the commoner''s residential area.  Small houses\nare north and south of you.  Swiftest Way continues east, and west is a big\nintersection.\n','\n',char(10)));
INSERT INTO rooms VALUES(647,6,'Swiftest Way',replace('You are on Swiftest Way, the commoner''s residential area.  Small houses\nare north and south of you.  Swiftest Way continues east and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(648,6,'End of Swiftest Way',replace('You are on Swiftest Way, the commoner''s residential area.  Small houses\nare north, south, and east of you.  Swiftest Way continues west.\n','\n',char(10)));
INSERT INTO rooms VALUES(649,6,'Swiftest Way',replace('You are on Swiftest Way, the commoner''s residential area.  Small houses\nare north and south of you.  Swiftest Way continues west, and to the east you\nsee a big intersection.\n','\n',char(10)));
INSERT INTO rooms VALUES(650,6,'Swiftest Way',replace('You are on Swiftest Way, the commoner''s residential area.  Small houses\nare north and south of you.  Swiftest Way continues east and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(651,6,'The end of Swiftest Way',replace('You are on Swiftest Way, the commoner''s residential area.  Small houses\nare north, south, and west of you.  Swiftest Way continues east.\n','\n',char(10)));
INSERT INTO rooms VALUES(652,6,'Small House',replace('You are in a small house, owned by a commoner of Ofcol.  There isn''t much\nof value here to you, but you''d bet that the owner really cherishes the pile\nof stuff here.  The exit is to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(653,6,'Small House',replace('You are in a small house, owned by a commoner of Ofcol.  There isn''t much\nof value here to you, but you''d bet that the owner really cherishes the pile\nof stuff here.  The exit is to the north.\n','\n',char(10)));
