INSERT INTO rooms VALUES(665,6,'Small House',replace('You are in a small house, owned by a commoner of Ofcol.  There isn''t much\nof value here to you, but you''d bet that the owner really cherishes the pile\nof stuff here.  The exit is to the east.\n','\n',char(10)));
INSERT INTO rooms VALUES(666,6,'Raff Way',replace('You are on Raff Way.  To the west, you can see a big intersection.  To \nthe east, you see Raff Way continue toward the Golden Citadel.  There are \nbeautiful flowers growing along the rode here, making this more of a garden\nthan a rode.\n','\n',char(10)));
INSERT INTO rooms VALUES(667,6,'Raff Way',replace('You are on Raff Way.  Raff Way continues west to the city of Ofcol.  To \nthe east, you see Raff Way continue toward the Golden Citadel.  There are \nbeautiful flowers growing along the rode here, making this more of a garden\nthan a rode.\n','\n',char(10)));
INSERT INTO rooms VALUES(668,6,'Dirt Road',replace('You are on a dirt road.  To the east is a large building with a bad smell\nemanating from it.  To the west is the end of Impy Way, and this road continues\nsouth.\n','\n',char(10)));
INSERT INTO rooms VALUES(669,6,'The Temple of Ofcol',replace('You are in the Temple of Ofcol.  Golden tiles cover the floor, and solid\ngold columns reach the twelve foot ceiling of this vast chamber.  Servants in\ngolden livery wander this place, making even the raggiest messenger boy look\nricher than you are.  Exits lead to the anterooms in the cardinal directions.\n','\n',char(10)));
INSERT INTO rooms VALUES(670,6,'The Anteroom to the Temple of Ofcol',replace('You are in an anteroom to the Temple of Ofcol.  Gold tiles cover the\nfloor, and servants in golden livery pass you by peaceably.  The temple is to\nthe south, and to the north is a hallway.  A stairways leads up.\n','\n',char(10)));
INSERT INTO rooms VALUES(671,6,'The Anteroom to the Temple of Ofcol',replace('You are in an anteroom to the Temple of Ofcol.  Gold tiles cover the\nfloor, and servants in golden livery pass you by peaceably.  The temple is to\nthe east, and to the west is a hallway.  A stairways leads up.\n','\n',char(10)));
INSERT INTO rooms VALUES(672,6,'The Anteroom to the Temple of Ofcol',replace('You are in an anteroom to the Temple of Ofcol.  Gold tiles cover the\nfloor, and servants in golden livery pass you by peaceably.  The temple is to\nthe west, and to the east is a hallway.  A stairways leads up.\n','\n',char(10)));
INSERT INTO rooms VALUES(673,6,'The Anteroom to the Temple of Ofcol',replace('You are in an anteroom to the Temple of Ofcol.  Gold tiles cover the\nfloor, and servants in golden livery pass you by peaceably.  The temple is to\nthe north, and to the south is a hallway.  A stairways leads up.\n','\n',char(10)));
INSERT INTO rooms VALUES(674,6,'A Hallway of the Golden Citadel',replace('You are in a hallway of the Golden Citadel.  Gold tiles cover the floors,\nand rich golden tapestries drape the walls.  Servants in golden livery pass you\nby peaceably.  Exits lead east and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(675,6,'A Hallway of the Golden Citadel',replace('You are in a hallway of the Golden Citadel.  Gold tiles cover the floors,\nand rich golden tapestries drape the walls.  Servants in golden livery pass you\nby peaceably.  Exits lead east, west, and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(676,6,'A Hallway of the Golden Citadel',replace('You are in a hallway of the Golden Citadel.  Gold tiles cover the floors,\nand rich golden tapestries drape the walls.  Servants in golden livery pass you\nby peaceably.  Exits lead west and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(677,6,'A Hallway of the Golden Citadel',replace('You are in a hallway of the Golden Citadel.  Gold tiles cover the floors,\nand rich golden tapestries drape the walls.  Servants in golden livery pass you\nby peaceably.  Exits lead north and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(678,6,'A Hallway of the Golden Citadel',replace('You are in a hallway of the Golden Citadel.  Gold tiles cover the floors,\nand rich golden tapestries drape the walls.  Servants in golden livery pass you\nby peaceably.  Exits lead north and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(679,6,'A Hallway of the Golden Citadel',replace('You are in a hallway of the Golden Citadel.  Gold tiles cover the floors,\nand rich golden tapestries drape the walls.  Servants in golden livery pass you\nby peaceably.  Exits lead to the cardinal directions, with the east leading\ntoward the Temple of Ofcol, and west leading toward the City of Ofcol.\n','\n',char(10)));
INSERT INTO rooms VALUES(680,6,'A Hallway of the Golden Citadel',replace('You are in a hallway of the Golden Citadel.  Gold tiles cover the floors,\nand rich golden tapestries drape the walls.  Servants in golden livery pass you\nby peaceably.  Exits lead west, north and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(681,6,'A Hallway of the Golden Citadel',replace('You are in a hallway of the Golden Citadel.  Gold tiles cover the floors,\nand rich golden tapestries drape the walls.  Servants in golden livery pass you\nby peaceably.  Exits lead north and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(682,6,'A Hallway of the Golden Citadel',replace('You are in a hallway of the Golden Citadel.  Gold tiles cover the floors,\nand rich golden tapestries drape the walls.  Servants in golden livery pass you\nby peaceably.  Exits lead north and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(683,6,'A Hallway of the Golden Citadel',replace('You are in a hallway of the Golden Citadel.  Gold tiles cover the floors,\nand rich golden tapestries drape the walls.  Servants in golden livery pass you\nby peaceably.  Exits lead north and east.\n','\n',char(10)));
INSERT INTO rooms VALUES(684,6,'A Hallway of the Golden Citadel',replace('You are in a hallway of the Golden Citadel.  Gold tiles cover the floors,\nand rich golden tapestries drape the walls.  Servants in golden livery pass you\nby peaceably.  Exits lead east, west, and north.\n','\n',char(10)));
INSERT INTO rooms VALUES(685,6,'A Hallway of the Golden Citadel',replace('You are in a hallway of the Golden Citadel.  Gold tiles cover the floors,\nand rich golden tapestries drape the walls.  Servants in golden livery pass you\nby peaceably.  Exits lead west and north.\n','\n',char(10)));
INSERT INTO rooms VALUES(686,6,'An Upper Chamber of the Golden Citadel',replace('You are in one of the upper chambers of the Golden Citadel.  The decora-\ntions of this place surpass even those of the first floor.  Gold tiles etched\nwith platinum cover the floor, walls and the ceiling.  The lights from numerous\ntorches reflect from these shimmering planes, giving the illusion that you are\nstanding in a gem.  Stairways lead up and down, and the hall leads south. \n','\n',char(10)));
INSERT INTO rooms VALUES(687,6,'An Upper Chamber of the Golden Citadel',replace('You are in one of the upper chambers of the Golden Citadel.  The decora-\ntions of this place surpass even those of the first floor.  Gold tiles etched\nwith platinum cover the floor, walls and the ceiling.  The lights from numerous\ntorches reflect from these shimmering planes, giving the illusion that you are\nstanding in a gem.  Stairways lead up and down, and the hall leads east. \n','\n',char(10)));
INSERT INTO rooms VALUES(688,6,'The Hall of the DragonLords',replace('You are in a vast hall, filled with the commanders of the Golden Citadel.\nGolden tiles etched with platinum cover the floors, and weapons of all types\nare mounted on the walls of this meeting hall.  Surrounding a solid gold table\nare four sons of the Keeper of the Golden Citadel.  They smile at you and ask \nyou to join them in lunch.  Exits lead to the cardinal directions. \n','\n',char(10)));
INSERT INTO rooms VALUES(689,6,'An Upper Chamber of the Golden Citadel',replace('You are in one of the upper chambers of the Golden Citadel.  The decora-\ntions of this place surpass even those of the first floor.  Gold tiles etched\nwith platinum cover the floor, walls and the ceiling.  The lights from numerous\ntorches reflect from these shimmering planes, giving the illusion that you are\nstanding in a gem.  Stairways lead up and down, and the hall leads west. \n','\n',char(10)));
INSERT INTO rooms VALUES(690,6,'An Upper Chamber of the Golden Citadel',replace('You are in one of the upper chambers of the Golden Citadel.  The decora-\ntions of this place surpass even those of the first floor.  Gold tiles etched\nwith platinum cover the floor, walls and the ceiling.  The lights from numerous\ntorches reflect from these shimmering planes, giving the illusion that you are\nstanding in a gem.  Stairways lead up and down, and the hall leads north. \n','\n',char(10)));
INSERT INTO rooms VALUES(691,6,'A Top Chamber of the Golden Citadel',replace('You are in one of the top chambers of the Golden Citadel.  The decorations\nof this room looks like a dragon''s hoard.  The whole room is carved out of pure\ngold, and gems of all types glitter from the walls, ceiling, even the floor.\nIt is obvious that this room was not meant for you to intrude upon.  A stair-\ncase leads back down, and a doorway leads south.\n','\n',char(10)));
INSERT INTO rooms VALUES(692,6,'A Top Chamber of the Golden Citadel',replace('You are in one of the top chambers of the Golden Citadel.  The decorations\nof this room looks like a dragon''s hoard.  The whole room is carved out of pure\ngold, and gems of all types glitter from the walls, ceiling, even the floor.\nIt is obvious that this room was not meant for you to intrude upon.  A stair-\ncase leads back down, and a doorway leads east.\n','\n',char(10)));
INSERT INTO rooms VALUES(693,6,'The Dragon Chamber',replace('You are in a vast chamber carved from gold and platinum.  Gems the size of\na man''s fist protrude from the walls, ceiling, and the floor, making your step\npainful.  A vast open sky-light lets fresh air come in from the top.  In the\ncenter of this chamber, you see a great wealth of coins, and on top of that\npile of coins, you see a golden dragon squinting at you.  Exits lead to the\ncardinal directions to the anterooms.\n','\n',char(10)));
INSERT INTO rooms VALUES(694,6,'A Top Chamber of the Golden Citadel',replace('You are in one of the top chambers of the Golden Citadel.  The decorations\nof this room looks like a dragon''s hoard.  The whole room is carved out of pure\ngold, and gems of all types glitter from the walls, ceiling, even the floor.\nIt is obvious that this room was not meant for you to intrude upon.  A stair-\ncase leads back down, and a doorway leads west.\n','\n',char(10)));
INSERT INTO rooms VALUES(695,6,'A Top Chamber of the Golden Citadel',replace('You are in one of the top chambers of the Golden Citadel.  The decorations\nof this room looks like a dragon''s hoard.  The whole room is carved out of pure\ngold, and gems of all types glitter from the walls, ceiling, even the floor.\nIt is obvious that this room was not meant for you to intrude upon.  A stair-\ncase leads back down, and a doorway leads north.\n','\n',char(10)));
INSERT INTO rooms VALUES(696,6,'Above the Dragon Chamber',replace('You are above the Dragon Chamber.  You curiously note that this shaft that\nconnects the chamber to the sky is wide enough that even a dragon can fit\nthrough.  This shaft leads up and down.\n','\n',char(10)));
INSERT INTO rooms VALUES(697,6,'In the Shaft from the Dragon Chamber',replace('You are in the shaft leading from the Dragon Chamber.  Below you lies the\nDragon Chamber of the Golden Citadel.  Above you, you see the sky, but \ncurrently, the way out is sealed by a layer of diamond that looks impenetrable.\n','\n',char(10)));
INSERT INTO rooms VALUES(698,6,'Inside the Entrance to the Golden Citadel',replace('You are inside the entrance to the Golden Citadel.  Rich golden tapestries\nline the walls, and golden tiles cover the floors.  The exit to this citadel is\nto the west, while the citadel itself is to the east.\n','\n',char(10)));
INSERT INTO rooms VALUES(699,6,'Outside the Entrance to the Golden Citadel',replace('You are outside the entrance to the Golden Citadel.  A great gate is to\nto the east, marking the entranceway into the citadel.  The road also leads\nback west to Raff Way.\n','\n',char(10)));
INSERT INTO rooms VALUES(901,9,'Mountain',replace('You are climbing a large mountain which towers over Ofcol.  The path\ncontinues up the mountain, but part of it is gone.  There is no way to\ncontinue by land.\n','\n',char(10)));
INSERT INTO rooms VALUES(902,9,'Mountain',replace('You are making your way up the mountain.  The rigorous climb has left you\ntired, and you are ready to take a break.\n','\n',char(10)));
INSERT INTO rooms VALUES(903,9,'Mountain',replace('You have finally reached the top of the mountain.  The air here is so thin\nthat you must gasp for breath.  To the north, you see what seems to be the\nentrance to a city.\n','\n',char(10)));
INSERT INTO rooms VALUES(904,9,'Entrance',replace('You are at the entrance to a huge city.  As you look around, you realize\nthat the inhabitants of this city must be very wealthy indeed - you have never\nseen a city with such beautiful buildings.\n','\n',char(10)));
INSERT INTO rooms VALUES(905,9,'Zeus Street',replace('You are walking down a huge street.  You notice that there are not many\npeople in this town.  On a corner, you see a sign marked ''Zeus Street''.\nTo the west, you see a small store.\n','\n',char(10)));
INSERT INTO rooms VALUES(906,9,'Zeus Street',replace('You are walking down what appears to be the main street of this city.\nYou see large residences to the east and west, while the street continues\nto the north and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(907,9,'Zeus Street',replace('You are on the main street of this town, called Zeus street.\n','\n',char(10)));
INSERT INTO rooms VALUES(908,9,'Zeus Street',replace('You are still on the main thoroughfare of this town.  To the north, you see\na large castle.  To the east there is a smaller road, while there is some sort\nof store to the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(909,9,'Castle Entryway',replace('You are in the entryway of a large castle.  It is very beautiful, with\nlarge paintings and a lovely carpet.  You hear jovial laughter to the north,\nwhile smaller corridors branch off to the east and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(910,9,'Throne Room',replace('You stop dead in your tracks as you enter this room.  Before you is Zeus,\nin all his glory, sitting on a huge golden throne.  You had thought him to be \njust a myth, but here he is ... you wonder who else lives in this castle.\n','\n',char(10)));
INSERT INTO rooms VALUES(911,9,'Western Wing',replace('You are in the western wing of the castle.  You see the entrance to the\neast, while this hallway continues to the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(912,9,'Western Wing',replace('You are in the western wing of the castle.  The hallway continues to the\nnorth, while there are private rooms to the west and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(913,9,'Western Wing',replace('You are in the western wing of the castle.  This hallway continues to the\nsouth, and you hear pots and pans rattling to the north.\n','\n',char(10)));
INSERT INTO rooms VALUES(914,9,'Kitchen',replace('You have entered the kitchen of this castle, and it is a hotbed of\nactivity.  Servants are bustling about, preparing food for the Gods themselves.\n','\n',char(10)));
INSERT INTO rooms VALUES(915,9,'Eastern Wing',replace('You are in the eastern wing of the castle.  The hall continues to the\neast, while the entrance is back to the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(916,9,'Eastern Wing',replace('You are in the eastern wing of the castle.  The hall turns to the north\nhere, while there are private rooms to the east and the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(917,9,'Eastern Wing',replace('You are in the eastern wing of the castle.  You hear animals to the north,\nwhile the hallway continues to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(918,9,'Dungeon',replace('You are in Zeus''s Dungeon.  You wonder what creatures are so terrible that\neven mighty Zeus fears them enough to imprison them.\n','\n',char(10)));
INSERT INTO rooms VALUES(919,9,'Dungeon',replace('You are in Zeus''s Dungeon.  There are cells to the north, west, and east. \nFrom the east and west, you hear guttural noises.  From the north, nothing ...\n','\n',char(10)));
INSERT INTO rooms VALUES(920,9,'Cell',replace('You are in a small, cramped, dirty cell.  It is a horrid place.\n','\n',char(10)));
INSERT INTO rooms VALUES(921,9,'Cell',replace('You are in a small, cramped, dirty cell.  It is a horrid place.\n','\n',char(10)));
INSERT INTO rooms VALUES(922,9,'Cell',replace('You are in a small, cramped, dirty cell.  It is a horrid place.\n','\n',char(10)));
INSERT INTO rooms VALUES(923,9,'Stairway',replace('You have come to a large stairway leading up.  To the south, you see the\nthrone room of Zeus.\n','\n',char(10)));
INSERT INTO rooms VALUES(924,9,'Bakery',replace('You are in the small store which supplies the residents of this town with\ntheir food.  It smells wonderful in here!\n','\n',char(10)));
INSERT INTO rooms VALUES(925,9,'Residence',replace('You are in the residence of one of the inhabitants of this town.  She\nlooks vaguely familiar, but you can''t place her name ...\n','\n',char(10)));
INSERT INTO rooms VALUES(926,9,'Residence',replace('You are in the residence of one of the inhabitants of this town.  He looks\nvaguely familiar, but you can''t place his name ...\n','\n',char(10)));
INSERT INTO rooms VALUES(927,9,'Mystic Shop',replace('You are in the store which provides the citizens here with whichever\narcane objects they may need.\n','\n',char(10)));
INSERT INTO rooms VALUES(928,9,'Ares Street',replace('You are on a smaller road which branches off from the main street.  On a\nsign, you notice that the name of this road is Ares Street.\n','\n',char(10)));
INSERT INTO rooms VALUES(929,9,'Guest Quarters',replace('You have entered private quarters which are reserved for visitors to the\ncastle.  You nearly faint as you recognize the occupant of this chamber as Odin\nhimself, patron God of Midgaard.  He must be visiting Zeus.\n','\n',char(10)));
INSERT INTO rooms VALUES(930,9,'Storage Room',replace('You are in a storage room of the castle.  There isn''t much here, just a\nfew boxes filled with old junk.\n','\n',char(10)));
INSERT INTO rooms VALUES(931,9,'Guest Quarters',replace('You have entered a room reserved for visitors to this castle.  You are\namazed as you recognize the occupant - Ra, the Egyptian Sun God.  He must be\nvisiting Zeus.\n','\n',char(10)));
INSERT INTO rooms VALUES(932,9,'Storage Room',replace('You are in a storage room of the castle.  There isn''t much here, just a lot\nof dust.\n','\n',char(10)));
INSERT INTO rooms VALUES(933,9,'Stable',replace('You are in the stable of the castle.  Rather than the horses which you\nexpected to find, it is filled with a wide variety of creatures which you\nthought were mythical.  Obviously, you were wrong.\n','\n',char(10)));
INSERT INTO rooms VALUES(934,9,'Ares Street',replace('You have reached the end of Ares Street.  To the south you see an armoury,\nwhile there is a weapons shop to the east.  To the north, you hear the sounds\nof a blacksmith.\n','\n',char(10)));
INSERT INTO rooms VALUES(935,9,'Armoury',replace('This small store is almost empty.  It seems as if there is not much here,\nbut the shopkeeper doesn''t want to do business with you anyways.\n','\n',char(10)));
INSERT INTO rooms VALUES(936,9,'Weapon Shop',replace('You have entered a small store with a modest selection of weapons.  You\nget the feeling that there is not a very wide selection here, but the\nshopkeeper doesn''t want to do business with you anyways.\n','\n',char(10)));
INSERT INTO rooms VALUES(937,9,'Smithy',replace('This large room is so noisy, you can barely hear yourself think.  All the\noccupants are hard at work, crafting high quality weapons and armor.  Something\nis strange about the west wall, although you can''t quite tell what it is.\n','\n',char(10)));
INSERT INTO rooms VALUES(938,9,'The Planning Room',replace('You have entered a large room dominated by a huge table with a large map\non it.  Several men are gathered around the table, studying the map carefully.\nYou hear the barking of dogs to the north.\n','\n',char(10)));
INSERT INTO rooms VALUES(939,9,'Second Floor',replace('You are on the second floor of this castle.  You are numb from your\ndiscoveries on the first floor, and wonder what secrets the upper floor of this\ncastle holds.  Hallways extend in all directions, and you see a small, closed \nhatch above you.\n','\n',char(10)));
INSERT INTO rooms VALUES(940,9,'Northern Hall',replace('You are in the northern hallway.  There is a private room to the north,\nand the stairs leading down are to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(941,9,'Southern Hall',replace('You are in the southern hallway.  There is a private room to the south,\nand the stairs leading down are to the north.\n','\n',char(10)));
INSERT INTO rooms VALUES(942,9,'Western Hall',replace('You are in the western hallway.  There is a private room to the west, and\nthe stairs leading down are to the east.\n','\n',char(10)));
INSERT INTO rooms VALUES(943,9,'Eastern Hall',replace('You are in the eastern hallway.  There is a private room to the east, and\nthe stairs leading down are to the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(944,9,'Bed Room',replace('You are in the bed room of a God!  This one seems to be empty.\n','\n',char(10)));
INSERT INTO rooms VALUES(945,9,'Bed Room',replace('You are in the bed room of a God!\n','\n',char(10)));
INSERT INTO rooms VALUES(946,9,'Bed Room',replace('You are in the bed room of a God!\n','\n',char(10)));
INSERT INTO rooms VALUES(947,9,'Bed Room',replace('You are in the bed room of a God!\n','\n',char(10)));
INSERT INTO rooms VALUES(948,9,'Hall of Gods',replace('You have entered the most sacred of places, the hall of true Gods.  If you\nare a mortal, it would probably be a good idea to leave NOW!  Exits leave in\nall directions.\n','\n',char(10)));
INSERT INTO rooms VALUES(951,9,'The Portal',replace('A sign reads: Beware of the unexpected and don''t expect too much.\n','\n',char(10)));
INSERT INTO rooms VALUES(954,9,'The Believer',replace('A voice whispers, ''before the time has passed, enjoy your life.''\n','\n',char(10)));
INSERT INTO rooms VALUES(1001,10,'In the air ...',replace('You are flying!\nCurrently you are about 40 meters above the ground north of the city.\nIt seems like you can see forever!\n','\n',char(10)));
INSERT INTO rooms VALUES(1002,10,'In the air ...',replace('You are flying!\nCurrently you are about 20 meters above the inside wall of West Midgaard.\nIt seems like you can see forever!\n','\n',char(10)));
INSERT INTO rooms VALUES(1003,10,'In the air ...',replace('You are flying!\nCurrently you are about 20 meters above the west gate of Midgaard.\nIt seems like you can see forever!\n','\n',char(10)));
INSERT INTO rooms VALUES(1004,10,'In the air ...',replace('You are flying!\nCurrently you are about 40 meters above Wall Road.\nIt seems like you can see forever!\n','\n',char(10)));
INSERT INTO rooms VALUES(1005,10,'In the air ...',replace('You are flying!\nCurrently you are about 40 meters above Wall Road.\nIt seems like you can see forever!\n','\n',char(10)));
INSERT INTO rooms VALUES(1006,10,'In the air ...',replace('You are flying!\nCurrently you are about 40 meters above the ground north of Midgaard.\nIt seems like you can see forever!\n','\n',char(10)));
INSERT INTO rooms VALUES(1007,10,'In the air ...',replace('You are flying!\nCurrently you are about 20 meters above the magic shop.\nIt seems like you can see forever!\n','\n',char(10)));
INSERT INTO rooms VALUES(1008,10,'In the air ...',replace('You are flying!\nCurrently you are about 40 meters above Main Street.\nIt seems like you can see forever!\n','\n',char(10)));
INSERT INTO rooms VALUES(1009,10,'In the air ...',replace('You are flying!\nCurrently you are about 20 meters above the Mage Guild Hall.\nIt seems like you can see forever!\n','\n',char(10)));
INSERT INTO rooms VALUES(1010,10,'In the air ...',replace('You are flying!\nCurrently you are about 40 meters above Poor Alley.\nIt seems like you can see forever!\n','\n',char(10)));
INSERT INTO rooms VALUES(1011,10,'In the air ...',replace('You are flying!\nCurrently you are about 40 meters above the ground north of Midgaard.\nIt seems like you can see forever!\n','\n',char(10)));
INSERT INTO rooms VALUES(1012,10,'In the air ...',replace('You are flying!\nCurrently you are about 20 meters above the bakery.\nIt seems like you can see forever!\n','\n',char(10)));
INSERT INTO rooms VALUES(1013,10,'In the air ...',replace('You are flying!\nCurrently you are about 40 meters above Main Street.\nIt seems like you can see forever!\n','\n',char(10)));
INSERT INTO rooms VALUES(1014,10,'In the air ...',replace('You are flying!\nCurrently you are about 20 meters above Armoury.\nIt seems like you can see forever!\n','\n',char(10)));
INSERT INTO rooms VALUES(1015,10,'In the air ...',replace('You are flying!\nCurrently you are about 40 meters above Poor Alley.\nIt seems like you can see forever!\n','\n',char(10)));
INSERT INTO rooms VALUES(1016,10,'In the air ...',replace('You are flying!\nCurrently you are about 10 meters above the temple spire of Midgaard\nIt seems like you can see forever!\n','\n',char(10)));
INSERT INTO rooms VALUES(1017,10,'In the air ...',replace('You are flying!\nCurrently you are about 40 meters above the Temple Square.\nIt seems like you can see forever!\n','\n',char(10)));
INSERT INTO rooms VALUES(1018,10,'In the air ...',replace('You are flying!\nCurrently you are about 40 meters above Market Square.\nIt seems like you can see forever!\n','\n',char(10)));
INSERT INTO rooms VALUES(1019,10,'In the air ...',replace('You are flying!\nCurrently you are about 40 meters above Market and Commons.\nIt seems like you can see forever!\n','\n',char(10)));
INSERT INTO rooms VALUES(1020,10,'In the air ...',replace('You are flying!\nCurrently you are about 40 meters above ground, overlooking the Common Square.\nIt seems like you can see forever!\n','\n',char(10)));
INSERT INTO rooms VALUES(1021,10,'In the air ...',replace('You are flying!\nCurrently you are about 60 meters above the ground just north of Midgaard.\nIt seems like you can see forever!\n','\n',char(10)));
INSERT INTO rooms VALUES(1022,10,'In the air ...',replace('You are flying!\nCurrently you are about 40 meters above the west gate of Midgaard.\nIt seems like you can see forever!\n','\n',char(10)));
INSERT INTO rooms VALUES(1023,10,'In the air ...',replace('You are flying!\nCurrently you are about 60 meters above west gate of Midgaard.\nIt seems like you can see forever!\n','\n',char(10)));
INSERT INTO rooms VALUES(1024,10,'In the air ...',replace('You are flying!\nCurrently you are about 60 meters above wall road.\nIt seems like you can see forever!\n','\n',char(10)));
INSERT INTO rooms VALUES(1025,10,'In the air ...',replace('You are flying!\nCurrently you are about 60 meters above wall road.\nIt seems like you can see forever!\n','\n',char(10)));
INSERT INTO rooms VALUES(1026,10,'In the air ...',replace('You are flying!\nCurrently you are about 60 meters above the ground north of Midgaard.\nIt seems like you can see forever!\n','\n',char(10)));
INSERT INTO rooms VALUES(1027,10,'In the air ...',replace('You are flying!\nCurrently you are about 40 meters above the magic shop.\nIt seems like you can see forever!\n','\n',char(10)));
INSERT INTO rooms VALUES(1028,10,'In the air ...',replace('You are flying!\nCurrently you are about 60 meters above main street.\nIt seems like you can see forever!\n','\n',char(10)));
INSERT INTO rooms VALUES(1029,10,'In the air ...',replace('You are flying!\nCurrently you are about 40 meters above the mage guild.\nIt seems like you can see forever!\n','\n',char(10)));
INSERT INTO rooms VALUES(1030,10,'In the air ...',replace('You are flying!\nCurrently you are about 60 meters above poor alley.\nIt seems like you can see forever!\n','\n',char(10)));
INSERT INTO rooms VALUES(1031,10,'In the air ...',replace('You are flying!\nCurrently you are about 60 meters above the ground north of Midgaard.\nIt seems like you can see forever!\n','\n',char(10)));
INSERT INTO rooms VALUES(1032,10,'In the air ...',replace('You are flying!\nCurrently you are about 40 meters above bakery and cleric guild.\nIt seems like you can see forever!\n','\n',char(10)));
INSERT INTO rooms VALUES(1033,10,'In the air ...',replace('You are flying!\nCurrently you are about 60 meters above main street.\nIt seems like you can see forever!\n','\n',char(10)));
INSERT INTO rooms VALUES(1034,10,'In the air ...',replace('You are flying!\nCurrently you are about 40 meters above the armoury.\nIt seems like you can see forever!\n','\n',char(10)));
INSERT INTO rooms VALUES(1035,10,'In the air ...',replace('You are flying!\nCurrently you are about 60 meters above poor alley.\nIt seems like you can see forever!\n','\n',char(10)));
INSERT INTO rooms VALUES(1036,10,'In the air ...',replace('You are flying!\nCurrently you are about 30 meters above the temple spire.\nIt seems like you can see forever!\n','\n',char(10)));
INSERT INTO rooms VALUES(1037,10,'In the air ...',replace('You are flying!\nCurrently you are about 60 meters above the temple square.\nIt seems like you can see forever!\n','\n',char(10)));
INSERT INTO rooms VALUES(1038,10,'In the air ...',replace('You are flying!\nCurrently you are about 60 meters above market square.\nIt seems like you can see forever!\n','\n',char(10)));
INSERT INTO rooms VALUES(1039,10,'In the air ...',replace('You are flying!\nCurrently you are about 60 meters above market square and commons square.\nIt seems like you can see forever!\n','\n',char(10)));
INSERT INTO rooms VALUES(1040,10,'In the air ...',replace('You are flying!\nCurrently you are about 60 meters above commoners square and the dump.\nIt seems like you can see forever!\n','\n',char(10)));
INSERT INTO rooms VALUES(1100,11,'A dimly lit path',replace('You tread through the deep, dark forest on a dimly lit path.  Up ahead you\ncan hear the faint sounds of a village.\n','\n',char(10)));
INSERT INTO rooms VALUES(1101,11,'A dimly lit path',replace('You tread through the deep, dark forest on a dimly lit path.  Up ahead you\ncan hear the faint sounds of a village.\n','\n',char(10)));
INSERT INTO rooms VALUES(1102,11,'A dimly lit path',replace('You tread through the deep, dark forest on a dimly lit path.  The forest\nhere seems less dense than to the south.  Northward you see the faint outline\nof a village.\n','\n',char(10)));
INSERT INTO rooms VALUES(1103,11,'Entrance to the Shire',replace('You stand at the entrance to the Shire.  You see halflings, no more than\nwee tall, every which way you look. Bywater Road leads east and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(1104,11,'Bywater Road',replace('You stand on Bywater Road, the busiest street in all of Shiredom.  The road\ncontinues to the east and west while to the north lies the general store.\n','\n',char(10)));
INSERT INTO rooms VALUES(1105,11,'The General Store',replace('You are inside the general store.  All sorts of goodies are stacked on the\nmany shelves.  Your local friendly shopkeeper is smiling patiently, waiting to \nserve you to the best of his abilities.  The only exit is to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(1106,11,'Bywater Road',replace('You stand on Bywater Road, the busiest street in all of Shiredom.  The road\ncontinues to the east and west.  To the north, steps lead to a friendly looking\nweaponry/armory while a nursery lies to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(1107,11,'The House of Arms',replace('You are inside the finest weapons and armour shop in all of Shiredom.  The\nshopkeeper proudly displays his fine wares and humbly offers the best daggers\nthat you have ever laid eyes on.\n','\n',char(10)));
INSERT INTO rooms VALUES(1108,11,'Kid''n Keep',replace('You are inside Kid''n Keep, the convenient one-stop nursery that maintains\nthe youth of the Shire.  Toddlers run every which way while their nursemaids\nsigh in exasperation.  The only exit lies to the north.\n','\n',char(10)));
INSERT INTO rooms VALUES(1109,11,'A bend in the road',replace('Bywater Road continues west and south.  A large, imposing building lies\nto the east.  Farther to the south, you can see an Inn of some sort.\n','\n',char(10)));
INSERT INTO rooms VALUES(1110,11,'Shiriff Post of the Eastern Shire',replace('You are in the Shiriff Post which acts as the nucleus for the three shiriffs\nof the Eastern Shire.  As you examine the shiriffs on duty, you come to realize\nthat the halflings of the Shire are not to be reckoned with.  You cower with \nawe.  A door offers passage to the east.\n','\n',char(10)));
INSERT INTO rooms VALUES(1111,11,'Thain''s Office',replace('You stand inside the office of the Thain, the police protectorate of the\ngreat Shire.  The Thain has sworn to protect the Shire from all thieves and\nmurderers with his life, and so eyes you suspiciously.  A door to the west\nleads to the Shiriff Post.\n','\n',char(10)));
INSERT INTO rooms VALUES(1112,11,'Bywater Road',replace('You stand on Bywater Road, the busiest street in all of Shiredom.  The road\ncontinues to the north and south.  To the east you spy the training grounds for\nshiriffs in training.\n','\n',char(10)));
INSERT INTO rooms VALUES(1113,11,'Bywater Road',replace('You stand on Bywater Road, the busiest street in all of Shiredom.  The road\ncontinues to the north.  The private residences of Shire inhabitants are to\nthe east and west while to the south lies the Ivy Bush, second only to the\nGreen Dragon for its hospitality and service.\n','\n',char(10)));
INSERT INTO rooms VALUES(1114,11,'A smial',replace('You are inside a smial, a hole in the ground which serves as the proper\ndwelling place for halflings.  As you look around this private abode, you feel\nas if you were intruding and so quickly cover your eyes.  The only exit lies\nto the east.\n','\n',char(10)));
INSERT INTO rooms VALUES(1115,11,'A smial',replace('You are inside a smial, a hole in the ground which serves as the proper\ndwelling place for halflings.  As you look around this private abode, you feel\nas if you were intruding and so quickly cover your eyes.  The only exit lies\nto the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(1116,11,'The Ivy Bush',replace('You are in the Ivy Bush, one of the most famous inns in all of Shiredom.\nChique Shire urbanites and seasoned travelers fill the confines of the room\nwith gay and lively talk.  A jovial innkeeper stops all that he is doing to\nawait your command.  The only exit lies to the north.\n','\n',char(10)));
INSERT INTO rooms VALUES(1117,11,'Shiriff Training Grounds',replace('The sounds of mock battle and feigned death cries fill your ears.  Every\nwhich way you turn you see halfling trainees at the prime of their youth.  A\nwizened old battle instructor meets your gaze and asks if he may be of \nservice.  The only exit lies to the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(1118,11,'Bywater Road',replace('You stand on Bywater Road, the busiest street in all of Shiredom.  The road\ncontinues to the east and west.  A large, imposing building lies to the south.\nYou catch a glimpse of the Brandywine River to the north.\n','\n',char(10)));
INSERT INTO rooms VALUES(1119,11,'Shiriff Post of the Bridge',replace('You are in the Shiriff Post which acts as the nucleus for the three shiriffs\nof the Bridge.  As you examine the shiriffs on duty, you come to realize that\nthe halflings of the Shire are not to be reckoned with.  You cower with awe.\nThe only exit is to the north.\n','\n',char(10)));
INSERT INTO rooms VALUES(1120,11,'Bywater Road',replace('You stand on Bywater Road, the busiest street in all of Shiredom.  The road\ncontinues to the east and west.  To the south you spy the Grocer''s Delight,\nthe premium grocer''s shop in all the realm while to the north lies Brandywine\nBridge.\n','\n',char(10)));
INSERT INTO rooms VALUES(1121,11,'The Grocer''s Delight',replace('You tremble with ecstasy as the tempting odors of freshly made pipeweed\nbread fill your lungs.  Rumor has it that the pipeweed bread sold here can\nrestore vitality.  You look around but find no one to take your order.  \nYou then peep over the counter and discover a friendly grocer who is too \nshort to be seen over the counter.  The only exit is to the north.\n','\n',char(10)));
INSERT INTO rooms VALUES(1122,11,'Bywater Road',replace('You stand on Bywater Road, the busiest street in all of Shiredom.  The road\ncontinues to the east.  A small hill lies to the west while you can see a\nwatermill to the far south.  You catch a glimpse of the Brandywine River to\nthe north.\n','\n',char(10)));
INSERT INTO rooms VALUES(1123,11,'Entrance to Watermill',replace('You stand at the entrance to a watermill.  You hear the bustle of busy\nworkers and the sound of a creaking mill.  Bywater Road is to the north while\nthe watermill continues to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(1124,11,'The Watermill',replace('Halfling workers are scattered everywhere, busy at work.  You see the river\nto the west and get a compelling urge to grab the nearest worker and to toss\nhim into the river.  The entrance stands to the north while a door offers\npassage to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(1125,11,'Rear of watermill',replace('You stand in a damp, dimly lit room.  Mildew clings to the walls and it\nappears as if you were the first person to enter the room in ages.  A barely\nvisible portal in the ground catches your eye.\n','\n',char(10)));
INSERT INTO rooms VALUES(1126,11,'Took Hill',replace('You stand on top of Took Hill, named after the legendary Bandobras Took.\nYou feel honored to be standing on a hill named after your hero.  From this\nvantage point you can see all of shiredom.  You get the feeling that with\none stomp you could eliminate their great city.  You can see the outline of\nMidgaard to the far east.  Sounds of joyful celebration are heard from the\nfields west of here.  The Brandywine flows by lazily nearby.\n','\n',char(10)));
INSERT INTO rooms VALUES(1127,11,'Northern end of grassy field',replace('You stand in a grassy field--nothing to get too excited about.  The field\nextends toward the south and the west.  To the east you see Took Hill.\n','\n',char(10)));
INSERT INTO rooms VALUES(1128,11,'A grassy field',replace('You stand in the center of a grassy field.  A great birthday party appears\nto be taking place.  Great tables of food are spread out and a young halfling\nbeauty offers you welcome.  You are enticed by her generosity and suggestive\nwinks.\n','\n',char(10)));
INSERT INTO rooms VALUES(1129,11,'Southern end of grassy field',replace('You stand in a grassy field--nothing to get too excited about.  The field\nextends toward the north and the west.  To the east you see Took Hill.\n','\n',char(10)));
INSERT INTO rooms VALUES(1130,11,'Western end of grassy field',replace('You stand in a grassy field--nothing to get too excited about.  The field\nextends every which way but west.\n','\n',char(10)));
INSERT INTO rooms VALUES(1131,11,'Brandywine Bridge',replace('You stand on a solidly built bridge.  As you look down you spy gaily\ncolored fish swimming with the current of Brandywine River.  The cool water\nlooks invitingly refreshing and you get a sudden urge to strip and bathe in\nthe river, but you hear the laughter of women nearby and so resist the urge.\nDelving Lane extends to the north while Bywater Road can be seen to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(1132,11,'Delving Lane',replace('Delving Lane runs north and south in this small borough of the Shire.  To \nthe south stands Brandywine Bridge.  The Green Dragon, the undisputed leader\nin the art of innkeeping, offers rest and comfort to the east.  You hear the\nbray of horses from the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(1133,11,'Delving Lane',replace('Delving Lane runs north and south in this small borough of the Shire.  A \nlarge, imposing building lies to the east.  You hear the bray of horses from\nthe west.\n','\n',char(10)));
INSERT INTO rooms VALUES(1134,11,'Delving Lane',replace('Delving Lane runs north and south in this small borough of the Shire. There\nis a small house to the west, nothing to the east, and up ahead you see a round\ndoor which leads to a rather impressive abode.\n','\n',char(10)));
INSERT INTO rooms VALUES(1135,11,'Bag End',replace('You stand in a comfortably well-equipped house, a palace by humble halfling\nstandards.  On the wall you see a banner which reads "Home Sweet Home".\nA solid oak door to the east leads to a pantry while you see a cozy bedroom\nto the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(1136,11,'Bedroom',replace('You stand in the private bedroom of Bag End.  There are two beds to the\nside, neither of which are made.  Portraits of halflings hang on the wall,\nand as you gaze upon them you come to the conclusion that the owner of\nBag End comes from a long line of distinguished halflings.  A cozy fire\nin the fireplace keeps the room warm and comfortable.\n','\n',char(10)));
INSERT INTO rooms VALUES(1137,11,'Pantry',replace('You are inside the pantry.  Shelves filled with food and drink surround\nyou on all sides.  You wonder why a halfling would need so much to eat.\nThe presence of something unseen chills you to your bones.  On the floor\nyou spy a trapdoor.\n','\n',char(10)));
INSERT INTO rooms VALUES(1138,11,'A grassy field',replace('You stand upon a grassy field.  A bull stands grazing not far away and\nout of the corner of your eye you can see him considering you.  The sound\nof animals fill the air from the north.  To the south you see a pig pen.\n','\n',char(10)));
INSERT INTO rooms VALUES(1139,11,'Pig pen',replace('You feel your boots sinking into the mud.  Numerous pigs roam about,\noblivious to your company.  A grassy field is to the north while you see\na small path winding to the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(1140,11,'A stony path',replace('You walk on a stony path which leads to a small residence to the north.\nFrom the east you hear the noisy din of pigs.\n','\n',char(10)));
INSERT INTO rooms VALUES(1141,11,'Gamgee Residence',replace('You stand inside a modest home.  You deduce that this is indeed the home\nof whomever owns the surrounding lands.  The air is somewhat musty and \nthe smell reminds you of a stable.  As you look around disdainfully, you\nthink to yourself that this is more of a shack than a proper residence and\nyou long for the urban riches of the Shire proper.\n','\n',char(10)));
INSERT INTO rooms VALUES(1142,11,'A barn',replace('Animals of every sort fill the small barn.  You feel the hot breath of\nhorses and cows on your neck and you feel the sudden need for fresh air.\nOther than that, you feel cozy and protected and don''t mind staying for a\nbit longer.  All the warmth and good vibes remind you of the days when your\nmother would hold you in her arms and sing you to sleep.  You find yourself\nwanting to cradle all the animals.\n','\n',char(10)));
INSERT INTO rooms VALUES(1143,11,'A chicken coop',replace('You stand inside a rather crowded chicken coop.  The cackle of hens fill\nthe air.  The only exit is to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(1144,11,'The Green Dragon',replace('Welcome to the Green Dragon, the undisputed leader in the art of\ninnkeeping.  A rather charming and friendly hostess stands to the side,\nready to offer you food and drink.  While most of the patrons are halfling\nlocals, you spy an occasional human or two.  As you listen more closely\nto the conversations that fill the inn, you hear the tales of great and\nseasoned adventurers as well as the usual gossip.  You feel as if you''ve\nfound your second home in the Green Dragon.  You see a stairway leading\nupwards.\n','\n',char(10)));
INSERT INTO rooms VALUES(1145,11,'Shiriff Post of Delving Lane',replace('You are in the Shiriff Post which acts as the nucleus for the three shiriffs\nof Delving Lane.  As you examine the shiriffs on duty, you come to realize\nthat the halflings of the Shire are not to be reckoned with.  You cower with\nawe.  The only exit is to the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(1146,11,'A dark tunnel',replace('You stand inside a small underground tunnel.  The ceiling is so low that\nyou must crouch to avoid hitting your head.  You see light from a small\nhole in the ceiling while to the east you see nothing but darkness.\n','\n',char(10)));
INSERT INTO rooms VALUES(1147,11,'A dark tunnel',replace('You stand inside a small underground tunnel.  The ceiling is so low that\nyou must crouch to avoid hitting your head.  The tunnel continues east and\nwest.  All you can see is darkness.\n','\n',char(10)));
INSERT INTO rooms VALUES(1148,11,'A dark tunnel',replace('You stand inside a small underground tunnel.  The ceiling is so low that\nyou must crouch to avoid hitting your head.  The tunnel continues east and\nwest.  All you can see is darkness.\n','\n',char(10)));
INSERT INTO rooms VALUES(1149,11,'A three way intersection',replace('You stand at an intersection.  The tunnel continues east and west while\nto the north you can barely make out a smaller trail.\n','\n',char(10)));
INSERT INTO rooms VALUES(1150,11,'End of a dark tunnel',replace('You stand at the end of a dark tunnel.  The underground tunnel continues\nto the west.  From a trapdoor in the ceiling you can hear the din of\nadventurers.\n','\n',char(10)));
INSERT INTO rooms VALUES(1151,11,'A dark tunnel',replace('You stand inside a small underground tunnel.  The ceiling is so low that\nyou must crouch to avoid hitting your head.  The tunnel continues north and\nsouth.  To the west you see a Shirriff Post while to the east lies a small\nhome.  All you can see is darkness.\n','\n',char(10)));
INSERT INTO rooms VALUES(1152,11,'A dark tunnel',replace('You stand inside a small underground tunnel.  The ceiling is so low that \nyou must crouch to avoid hitting your head.  The tunnel continues north and\nsouth.  To the west lies a small home.  All you can see is darkness.\n','\n',char(10)));
INSERT INTO rooms VALUES(1153,11,'Shiriff Post of the Lower Shire',replace('You are in the shiriff Post which acts as the nucleus for the three shiriffs \nof the Lower Shire.  As you examine the shiriffs on duty, you come to realize\nthat the halflings of the Shire are not to be reckoned with.  You cower with\nawe.  The only exit is to the east.\n','\n',char(10)));
INSERT INTO rooms VALUES(1154,11,'A halfling hole',replace('You stand inside a rather crudely built halfling hole.  The many passageways\nand winding paths remind you of a rodent''s lair.  The air is musty and damp\nand you feel the need for fresh air.\n','\n',char(10)));
INSERT INTO rooms VALUES(1155,11,'A halfling hole',replace('You stand inside a rather crudely built halfling hole.  The many passageways\nand winding paths remind you of a rodent''s lair.  The air is musty and damp\nand you feel the need for fresh air.\n','\n',char(10)));
INSERT INTO rooms VALUES(1156,11,'End of a dark tunnel',replace('You are at one end of a dark tunnel.  The tunnel continues to the south\nwhile on the ceiling you can make out a trapdoor.\n','\n',char(10)));
INSERT INTO rooms VALUES(1157,11,'The Inn of the Green Dragon',replace('You are standing in the Inn of the Green dragon.  Large paintings of \nhalflings at work, and halflings at play adorn the walls.  Comfortable \nbenches and seats line the walls.  A stairway leads down.\n','\n',char(10)));
INSERT INTO rooms VALUES(1200,12,'The Chat Room',replace('You are lounging in a quiet cosy parlour, warmed by a gentle magical fire\nwhich twinkles happily in a warm fireplace.  There are no doors out.  Clearly\nthe owner of this room needs none.\n','\n',char(10)));
INSERT INTO rooms VALUES(1300,12,'Entrance to the Shadow Grove',replace('Before you, the grove of shadows lies. Giant grey trees are all that\ncan be seen through the thick shadows. A great sense of both power and\nmenace permeates the surrounding area. You have a strange urge to turn\nback and go back the way you''ve come.\n  A small path leads north into the shadows and back south to the road.\n','\n',char(10)));
INSERT INTO rooms VALUES(1301,12,'The Shadow Grove',replace('You are inside the shadow grove. Giant trees seem to glare at you\nfrom all sides. The shadowy mist obscures most of your vision. Strange\nsounds of moaning and growling come from all directions.\n  All exits lead into shadows, you are very confused.\n','\n',char(10)));
INSERT INTO rooms VALUES(1302,12,'The Shadow Grove',replace('You are inside the shadow grove. Giant trees seem to glare at you\nfrom all sides. The shadowy mist obscures most of your vision. Strange\nsounds moaning and growling come from all directions.\n  All exits lead into shadows, you are very confused.\n','\n',char(10)));
INSERT INTO rooms VALUES(1303,12,'The Shadow Grove',replace('You are inside the shadow grove. Giant trees seem the glare at you\nfrom all sides. The shadowy mist obscures most of your vision. Strange\nsounds of moaning and growling come from all directions.\n  All exits lead into shadows, you are very confused.\n','\n',char(10)));
INSERT INTO rooms VALUES(1304,12,'The Shadow Grove',replace('You are inside the shadow grove. Giant trees seem to glare at you\nfrom all sides. The shadowy mist obscures most of your vision. Strange\nsounds of moaning and growling come from all directions.\n  All exits lead into shadows, you are very confused.\n','\n',char(10)));
INSERT INTO rooms VALUES(1305,12,'The Shadow Grove',replace('You are inside the shadow grove. Giant trees seem to glare at you\nfrom all sides. The shadowy mist obscures most of your vision. Strange\nsounds of moaning and growling come from all directions.\n  All exits lead into shadows, you are very confused.\n','\n',char(10)));
INSERT INTO rooms VALUES(1306,12,'The Shadow Grove',replace('You are inside the shadow grove. Giant trees seem to glare at you\nfrom all sides. The shadowy mist obscures most of your vision. Strange\nsounds of moaning and growling come from all directions.\n  All exits lead into shadows, you are very confused.\n','\n',char(10)));
INSERT INTO rooms VALUES(1307,12,'The Shadow Grove',replace('You are inside the shadow grove. Giant trees seem to glare at you\nfrom all sides. The shadowy mist obscures most of your vision. Strange\nsounds of moaning and growling come from all directions.\n  All exits lead into shadows, you are very confused.\n','\n',char(10)));
INSERT INTO rooms VALUES(1308,12,'The Shadow Grove',replace('You are inside the shadow grove. Giant trees seem to glare at you\nfrom all sides. The shadowy mist obscures most of your vision. Strange\nsounds of moaning and growling come from all directions.\n  All exits lead into shadows, you are very confused.\n','\n',char(10)));
INSERT INTO rooms VALUES(1309,12,'The Shadow Grove',replace('You are inside the shadow grove. Giant trees seem to glare at you\nfrom all sides. The shadowy mist obscures most of your vision. Strange\nsounds of moaning and growling come from all directions.\n  All directions lead into shadows, you are very confused.\n','\n',char(10)));
INSERT INTO rooms VALUES(1311,12,'A small clearing',replace('You are in a small clearing in the shadow grove. There is charred grass\nunderfoot, and the signs of fire here and there. It is almost as if the\nplant life shuns this spot. The shadowy mist hovers all around, obscuring\nyour view into the grove.\n  A small path leads north to some shadowy structure. All other exits are\nshrouded in shadowy mist.\n','\n',char(10)));
INSERT INTO rooms VALUES(1312,12,'Entrance to the High Tower',replace('You have reached the entrance to the high tower of sorcerery. The\ntower looms above you at an incredible height. It seems to disappear\ninto the storm clouds above.\n  A diamond gate is to the north, guarded by a huge golem. The trail\nback south has disappeared behind you.\n','\n',char(10)));
INSERT INTO rooms VALUES(1313,12,'Inside the High Tower of Sorcerery',replace('You are inside the high tower of sorcery. The sight is truly amazing.\nFrom here, it is obvious that somehow, the tower is much larger on the\ninside than it is on the outside. Young mages walk about, completely\noblivious to your presence.\n  Exits lead north to the common room, west to the dinning room, east to\na plain hallway and back south through the gate.\n','\n',char(10)));
INSERT INTO rooms VALUES(1314,12,'Common Room',replace('You are in the common room. There are many apprentice warlocks here\ntalking and resting, playing games, comparing notes. Obviously they\nare taking a break from their rigorous studies. There are benches,\ntables and a small water fountain here, otherwise the room is quite\nunremarkable.\n  Exits lead off in all directions.\n','\n',char(10)));
INSERT INTO rooms VALUES(1315,12,'The Hallway',replace('You are in a long hallway, it seems rather unremarkable.\n  The hallway continues east and back west.\n','\n',char(10)));
INSERT INTO rooms VALUES(1316,12,'Dining Room',replace('You are in the dining area of the student mages. From the number of\ntables and chairs here, you can see that this room could easily seat\nseveral hundred people. It is oddly deserted here, obviously not meal time.\n  Exits lead west to the kitchen, and back east.\n','\n',char(10)));
INSERT INTO rooms VALUES(1317,12,'Dark Hallway',replace('You are in a dark hallway. It is apparent that this area is seldom\nused by the regular occupants of the tower. Dust covers the floors\nhere.\n  The faint outline of a trapdoor can be seen in the dust.\n','\n',char(10)));
INSERT INTO rooms VALUES(1318,12,'Mages Tavern',replace('You are in mages tavern. The air is smokey and filled with the smells\nof foreign food and drink. The other patrons pay you little heed, as\nthey obviously have more interesting things to contemplate. Strick the\nbartender is here waiting to take your order.\n  The only exit leads back west.\n','\n',char(10)));
INSERT INTO rooms VALUES(1319,12,'The Magic Shop',replace('You are in the High Tower''s store of magic. Tatorious stands behind\nthe counter, selling all sorts of herbs, parchment and other reagents\nused in magical studies.\n  The only exit leads back east to the common room.\n','\n',char(10)));
INSERT INTO rooms VALUES(1320,12,'the kitchen',replace('You are in a small kitchen. All the usual kitchen type utensils and\nequipment is here, including some not so usual ones. Among the later,\na huge black oven against one wall, it must be at least 12 feet high.\nOpposite the oven is an equally enormous meat locker, large enough to\ncomfortably store several hapless adventurers no doubt. In the middle of\nthe room, hanging in mid-air is a spice rack.\n','\n',char(10)));
INSERT INTO rooms VALUES(1321,12,'Below the trapdoor',replace('You are below the trapdoor. It is very dark and dusty here, very little\nlight filters through from above. A faint sound of dripping water can be\nheard in the distance below.\n  A rope ladder leads down.\n','\n',char(10)));
INSERT INTO rooms VALUES(1322,12,'A damp intersection',replace('You are in a damp intersection of what seems to be the basement of the\ntower. The sound of running water can be heard coming from the south,\nother than that, an almost tangible stillness fills the air.\n  Passages lead off in all directions, and a ladder leads up.\n','\n',char(10)));
INSERT INTO rooms VALUES(1323,12,'A dark passage',replace('You are at the end of a dark passage which ends in a stout wooden door.\nOther then through the door, the only apparent exit is back the way you\ncame.\n','\n',char(10)));
INSERT INTO rooms VALUES(1324,12,'A dark passage',replace('You are at the end of a dark passage. A half opened door is to the east,\nshedding soft light around the edges. Faint snoring sounds can be heard\nbehind the door.\n  Exits lead east through the door, or back west.\n','\n',char(10)));
INSERT INTO rooms VALUES(1325,12,'The stagnant pool',replace('You are at the edge of a stagnant pool of water. The smell here is quite\nnauseating. This is apparently where the denizens of the tower dispose of\ntheir garbage. Faint gurgling can be heard from beneath the surface of the\npool.\n  Exits lead back north, or perhaps for the very adventurous, down into the\npool.\n','\n',char(10)));
INSERT INTO rooms VALUES(1326,12,'A dark passage',replace('You are in a dark passage, which comes to an abrupt stop at what appears\nto be a cave-in to the west. It is certainly unpassable, and perhaps quite\ndangerous just being this close.\n  The only exit leads back east.\n','\n',char(10)));
INSERT INTO rooms VALUES(1327,12,'A dark cell',replace('You are in a dark cell. Straw and dirt cover the floors here, it is\nvery dark. Someone, or something seems to be chained to the far wall.\n  The only exit is back south.\n','\n',char(10)));
INSERT INTO rooms VALUES(1328,12,'The Jailor''s office',replace('You are in the Jailor''s office. It is rather messy here. Judging by the\nsleeping form of the Jailor on duty, you can surmise that very few, if any\nprisoners survive long enough to spend much time in these dank dungeons.\n  The only exit leads back west.\n','\n',char(10)));
INSERT INTO rooms VALUES(1329,12,'Below the stagnant pool',replace('As you dive beneath the putrid waters, you feel a strong tug and a whirlpool\ndrags you under.  You are sucked into blackness.  You feel your lungs burst\nfrom lack of oxygen.  Just as you feel your life fading, you notice a change in\ndirection ... and are sucked under by a rip tide.\n','\n',char(10)));
INSERT INTO rooms VALUES(1330,12,'The hallway',replace('You are in a long hallway leading east and west. The walls emit a faint\nmagical glow which provides enough light to see by.\n','\n',char(10)));
INSERT INTO rooms VALUES(1331,12,'A bend in the hallway',replace('You are at a bend in the hallway. The walls emit a faint magical glow\nwhich provides enough light to see by.\n','\n',char(10)));
INSERT INTO rooms VALUES(1332,12,'A store room',replace('You are in a small store room. Assorted junk is piled on shelves or\nleaning against walls.\n  The only apparent exit it back south.\n','\n',char(10)));
INSERT INTO rooms VALUES(1333,12,'A broom closet',replace('You are in a dark broom closet. Many straw brooms and other cleaning\ninstruments have been left here, apparently unused (perhaps the maid quit?).\n  The only exit leads back north to the hallway.\n','\n',char(10)));
INSERT INTO rooms VALUES(1334,12,'A hallway',replace('You are in a long hallway leading north and south. The walls emit a\nfaint magical glow which provides enough light to see by.\n','\n',char(10)));
INSERT INTO rooms VALUES(1335,12,'Guardians chamber',replace('You are in the chamber of the tower guardians. It is rather sparsely\nfurnished, but then again the odd occupants don''t look to need furniture.\nHere and there a disembodied pair of hands or eyes flits about.\n','\n',char(10)));
INSERT INTO rooms VALUES(1336,12,'A guest bedroom',replace('You are in a small guest bedroom. A small cot is in one corner, and a\ndusty mirror on one wall, other than that the room looks quite bare, and\nunused.\n  The only apparent exit leads back west to the hallway.\n','\n',char(10)));
INSERT INTO rooms VALUES(1337,12,'A guest bedroom',replace('You are in a comfortable looking bedroom. A small globe of magical energy\nfloats overhead, providing light. A small cot is in one corner looking\never so comfortable, so comfortable in fact ...someone is sleeping in it.\n  The only apparent exit leads back west to the hallway.\n','\n',char(10)));
INSERT INTO rooms VALUES(1338,12,'A hallway',replace('You are in a long hallway leading from the south. The walls emit a faint\nmagical glow which provides enough light to see by.\n  Stairs lead up to the next level and the hallway leads back south.\n','\n',char(10)));
INSERT INTO rooms VALUES(1339,12,'The burnt room',replace('You are in what looks to have once been a guest bed room. The walls are\nblackened and burnt by what you could only imagine to be magical fire.\nThere is no sign of the previous occupant, undoubtedly he left in a hurry.\n  The only exit leads back west to the hallway.\n','\n',char(10)));
INSERT INTO rooms VALUES(1340,12,'A hallway',replace('You are in a long hallway leading west from here. The walls emit a faint\nmagical glow which provides enough light to see by. Some faint moonlight\ncan be seen in the culdesac to the east.\n  The hallway continues west and stairs lead down to the level below.\n','\n',char(10)));
INSERT INTO rooms VALUES(1341,12,'A culdesac',replace('You are in a small culdesac. A window to the east is letting in moonlight\nand a pleasant breeze. Through it, the surrounding country side can be seen.\n  The only apparent exit leads back west to the hallway.\n','\n',char(10)));
INSERT INTO rooms VALUES(1342,12,'The Apprentice''s Barracks',replace('You are in the barracks of the apprentice magic users. Here and there, a\nyoung apprentice sits engrossed in magical study, or practicing a feeble\ncantrip. Cots line the walls, and the room continues west.\n','\n',char(10)));
INSERT INTO rooms VALUES(1343,12,'A hallway',replace('You are in a long hallway leading east and west. The walls emit a faint\nmagical glow which provides enough light to see by.\n  There is a door to the north, and the hallway continues west or back east.\n','\n',char(10)));
INSERT INTO rooms VALUES(1344,12,'The Apprentice''s barracks',replace('You are in the barracks of the apprentice magic users. Here and there, a\nyoung apprentice sits engrossed in magical study, or practicing a feeble\ncantrip. Cots line the walls, and the room continues east.\n','\n',char(10)));
INSERT INTO rooms VALUES(1345,12,'A hallway',replace('You are in a long hallway leading east and west. The walls emit a faint\nmagical glow which provides enough light to see by. Flashes of light can\nbe seen under the doorway to the north.\n','\n',char(10)));
INSERT INTO rooms VALUES(1346,12,'The apprentice''s workshop',replace('You are in a small workshop. Writing implements and parchment are strewn\nabout on a few worktables. In the far corner several young mages have a\nsmall kitten cornered and seem to be testing spells upon it.\n  The only apparent exit leads back south to the hallway.\n','\n',char(10)));
INSERT INTO rooms VALUES(1347,12,'A bend in the hallway',replace('You are at a bend in the hallway. The walls emit a faint magical glow\nwhich provides enough light to see by.\n  The hallway continues south and back east.\n','\n',char(10)));
INSERT INTO rooms VALUES(1348,12,'The hallway',replace('You are in a long hallway leading north and south. The walls emit a faint\nmagical glow which provides enough light to see by.\n  There is a closed metal door to the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(1349,12,'A classroom',replace('You are in a large classroom filled with bored looking students of the\nart. The instructor stops in his lecture on the fine uses of magic missile\nat your entry and lunges to attack you.\n  The only apparent exit is back east to the hallway.\n','\n',char(10)));
INSERT INTO rooms VALUES(1350,12,'A hallway',replace('You are in a long hallway leading north and south. The walls emit a faint\nmagical glow which provides enough light to see by.\n','\n',char(10)));
INSERT INTO rooms VALUES(1351,12,'A hallway',replace('You are in a long hallway leading north and south. The walls emit a faint\nmagical glow which provides enough light to see by.\n','\n',char(10)));
INSERT INTO rooms VALUES(1352,12,'An empty classroom',replace('You are in an empty classroom. Some strange sigils are written on a\nblackboard which is floating in the air here. Other than a few desks,\nit is bare of furnishings.\n  The only apparent exit leads back east to the hallway.\n','\n',char(10)));
INSERT INTO rooms VALUES(1353,12,'A bend in the hallway',replace('You are at a bend in the hallway. The walls emit a faint magical glow\nwhich provides enough light to see by.\n  The hallway continues east and north.\n','\n',char(10)));
INSERT INTO rooms VALUES(1354,12,'An empty classroom',replace('You are in an apparently empty classroom. A strange feeling of being\nwatched comes over you, and you hear the faint rustle of robes.\n  The only apparent exit is back east to the hallway.\n','\n',char(10)));
INSERT INTO rooms VALUES(1355,12,'A hallway',replace('You are in a long hallway leading east and west. The walls emit a faint\nmagical glow which provides enough light to see by.\n  A sturdy iron door can be seen to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(1356,12,'A hallway',replace('You are in a long hallway leading east and west. The walls emit a faint\nmagical glow which provides enough light to see by.\n  There is a large oaken door to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(1357,12,'The Amphitheater',replace('You are in a small amphitheater. Rows of comfortable looking chairs circle\na large podium. The echos of your footsteps seem very loud here.\n  The only apparent exit leads north to the hallway.\n','\n',char(10)));
INSERT INTO rooms VALUES(1358,12,'A hallway',replace('You are in a long hallway leading east and west. The walls emit a faint\nmagical glow providing enough light to see by.\n  A small door can be seen to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(1359,12,'The training room',replace('You are in a large training room. It is filled with battle scared manikins\n, and many other devices used in the practice of fighting.\n','\n',char(10)));
INSERT INTO rooms VALUES(1360,12,'A bend in the hallway',replace('You are at a bend in the hallway. The walls emit a faint magical glow\nwhich provides enough light to see by.\n  The hallway continues north and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(1361,12,'A dueling room',replace('You are in a large room used for duals arcane. The walls, ceiling and\nfloor all bare the scars of many fiery spells, but still look quite strong\nand hold fast.\n  The only exit leads north to the hallway.\n','\n',char(10)));
INSERT INTO rooms VALUES(1362,12,'A hallway',replace('You are in a long hallway leading north and south. The walls emit a faint\nmagical glow which provides enough light to see by.\n  A doorway can be seen to the east.\n','\n',char(10)));
INSERT INTO rooms VALUES(1363,12,'A hallway',replace('You are in a long hallway leading north and south. The walls emit a faint\nmagical glow which provides enough light to see by.\n  A wooden door can been seen to the east.\n','\n',char(10)));
INSERT INTO rooms VALUES(1364,12,'The spellmaster''s lounge',replace('You are in a large comfortable looking lounge. Off duty spell teachers\nare here relaxing in their idle time. A large coffee machine is against\nthe far wall.\n  The only apparent exit leads back west to the hallway.\n','\n',char(10)));
INSERT INTO rooms VALUES(1365,12,'A bedroom',replace('You are in a large, plush bedroom. The owner is obviously someone of high\nstanding in the magical community here. An ice mirror is on one wall, and\na scrying globe sit on a stand in the middle of the room. An enormous bed\ncan be seen floating about a meter above the floor.\n  The only exit leads back west to the hallway.\n','\n',char(10)));
INSERT INTO rooms VALUES(1366,12,'A hallway',replace('You are in a long hallway leading north and south. The walls emit a faint\nmagical glow providing enough light to see by.\n  A glass door can be seen to the east.\n','\n',char(10)));
INSERT INTO rooms VALUES(1367,12,'The study',replace('You are in a small, well kept study. Ancient tomes are on shelves on the\nwalls, A huge table sits in the middle of the room, with maps weighted\ndown upon it. The only light source here comes from an interestingly non-\nmagical oil lamp.\n  The only apparent exit leads back west to the hallway.\n','\n',char(10)));
INSERT INTO rooms VALUES(1368,12,'Below the stairs',replace('You are at the end of a long hallway. The walls emit a faint magical glow\nwhich provides enough light to see by. A lesser guardian is here keeping\nsilent watch on the entrance to the levels above.\n  Stairs lead up and the hallway continues back south.\n','\n',char(10)));
INSERT INTO rooms VALUES(1369,12,'Atop the stairway',replace('You are atop a stairway. The halls here look quite a bit less used than\nthose below. Obviously access to these magic filled corridors is limited\nto those of the upper echelon of mages. The walls here emit a faint blue\nmagical aura which provides some light.\n  The hallway leads west from here and the stairs go down.\n','\n',char(10)));
INSERT INTO rooms VALUES(1370,12,'A hallway',replace('You are in a long hallway stretching east and west. The walls here emit\na faint magical energy providing enough light to see by.\n  There is a thick looking wooden door to the north.\n','\n',char(10)));
INSERT INTO rooms VALUES(1371,12,'A small office',replace('You are in a small office. It looks like a calligrapher''s study, there\nare quills, inkpots and parchments all about on desks and worktables.\nA section to the west seems to be curtained off, but the flicker of a\ncandle can be seen through the curtain.\n','\n',char(10)));
INSERT INTO rooms VALUES(1372,12,'A hallway',replace('You are in a long hallway leading east and west. The walls emit a faint\nmagical glow which provides enough light to see by.\n','\n',char(10)));
INSERT INTO rooms VALUES(1373,12,'The master scribe''s workshop',replace('You are in the workshop of the tower''s master scribe. Many half finished\nscrolls lay on the writing table in the center of the room. A giant candle\nflickering with soft blue flames provides the only light here.\n  The only apparent exit is the way you came in.\n','\n',char(10)));
INSERT INTO rooms VALUES(1374,12,'A hallway',replace('You are in a long hallway leading east and west. The walls emit a faint\nmagical glow which provides enough light to see by.\n  A half closed door can be seen to the north.\n','\n',char(10)));
INSERT INTO rooms VALUES(1375,12,'A store room',replace('You are in a small dark store room. A few common items are stacked upon\nthe shelves here, but very little looks interesting.\n','\n',char(10)));
INSERT INTO rooms VALUES(1376,12,'A bend in the hallway',replace('You are at a bend in the long hallway. The walls emit a faint magical\nglow which provides enough light to see by.\n  The hallway continues south and east from here.\n','\n',char(10)));
INSERT INTO rooms VALUES(1377,12,'A hallway',replace('You are in a long hallway leading north and south. The walls emit a faint\nmagical glow which provides enough light to see by.\n  An iron bound door can be seen to the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(1378,12,'A hallway',replace('You are in a long hallway leading north and south. The walls emit a faint\nmagical glow which provides enough light to see by.\n  The sharp sound of metal on metal can be heard to the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(1379,12,'A store room',replace('You are in a large store room. Bins of ores, minerals and other rare\nmaterials are here along with many neatly stacked piles of precious metals.\nA large cabinet with sigils of warding is bolted to one wall.\n  The ring of metal on metal can be heard to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(1380,12,'A hallway',replace('You are in a long hallway leading north and south. The walls emit a faint\nmagical glow which provides enough light to see by.\n','\n',char(10)));
INSERT INTO rooms VALUES(1381,12,'A very hot room',replace('You are in a very hot room. Against one wall is a large forge, magical\nfires crackle within and heavy blue smoke pours into a vent in the ceiling.\nA rune-encrusted mithril anvil is in the center of the room, looking well\nused. Other tools of metallurgy hang on a rack which floats about three\nmeters in the air of its own force.\n','\n',char(10)));
INSERT INTO rooms VALUES(1382,12,'The master Enchanter''s chamber',replace('You have entered the master enchanter''s chamber. Upon all the walls here\nare racks of finely crafted weapons. A huge chest with a glowing lock is\nset to one side. Several unfinished looking blades rest atop a small work\ntable.\n','\n',char(10)));
INSERT INTO rooms VALUES(1383,12,'A bend in the hallway',replace('You are at a bend in a long hallway. The walls emit a faint magical glow\nwhich provides enough light to see by.\n  The hallway continues north and east.\n','\n',char(10)));
INSERT INTO rooms VALUES(1384,12,'A hallway',replace('You are in a long hallway leading east and west. The walls emit a faint\nmagical glow which provides enough light to see by.\n  A steel door can be seen to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(1385,12,'A hallway',replace('You are in a long hallway leading east and west. The walls emit a faint\nmagical glow which provides enough light to see by.\n','\n',char(10)));
INSERT INTO rooms VALUES(1386,12,'A laboratory',replace('You are in a small laboratory. Many strange instruments, vials, bottles\nand some scrawled notes are piled about a workbench. This room is very\nuntidy, looking almost abandoned, or used by a madman.\n  The only apparent exits are east and north.\n','\n',char(10)));
INSERT INTO rooms VALUES(1387,12,'A hallway',replace('You are in a long hallway leading east and west. The walls emit a faint\nmagical glow which provides enough light to see by.\n  You can see a steel door to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(1388,12,'The Mad Alchemist''s workroom',replace('You are in the workroom of The Mad Alchemist. Bubbling braziers, long\nglass tubes and scores of oddly shaped vials and bottles are everywhere.\nIt is incredibly messy here, crushed glass and other trash litter the floor.\n  The only apparent exit is the one you entered by.\n','\n',char(10)));
INSERT INTO rooms VALUES(1389,12,'A bend in the hallway',replace('You are at a bend in a long hallway. The walls emit a faint magical glow\nwhich provides enough light to see by.\n  The hallway continues north and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(1390,12,'The pentagram chamber',replace('You are in a large room with a five pointed star etched into the floor.\nA crackling energy field can be seen to the south, it looks quite dangerous.\n','\n',char(10)));
INSERT INTO rooms VALUES(1391,12,'A hallway',replace('You are in a long hallway leading north and south. The walls emit a faint\nmagical glow which provides enough light to see by.\n  A bronze door can be seen to the east.\n','\n',char(10)));
INSERT INTO rooms VALUES(1392,12,'Inside the Energy Field',replace('You feel a stomach twisting sensation as you enter the energy field.\nNice going!  You might as well wait here until the wizard who built this\ntrap comes back to imprison your soul as well as your body.\n','\n',char(10)));
INSERT INTO rooms VALUES(1393,12,'A hallway',replace('You are in a long hallway leading north and south. The walls emit a faint\nmagical glow which provides enough light to see by.\n  A bronze door can be seen to the east.\n','\n',char(10)));
INSERT INTO rooms VALUES(1394,12,'An empty room',replace('You are in an empty room. It is both quiet and comfortable here, it looks\nlike a safe place to rest.\n','\n',char(10)));
INSERT INTO rooms VALUES(1395,12,'The charm master''s chamber',replace('You are in the chambers of the tower''s master of charm. Some straw and\ndirt litters the floor here, it looks to have been recently used by wild\nanimals.\n  Strange sounds can be heard through the bars to the north.\n','\n',char(10)));
INSERT INTO rooms VALUES(1396,12,'A hallway',replace('You are in a long hallway leading north and south. The walls emit a faint\nmagical glow which provides enough light to see by.\n','\n',char(10)));
INSERT INTO rooms VALUES(1397,12,'The animal pens',replace('You are in the animal pens. Many caged animals are here looking unhappy.\nObviously they are destined to be enslaved, or used in some cruel magical\nexperimentation.\n','\n',char(10)));
INSERT INTO rooms VALUES(1398,12,'The end of the hallway',replace('You are at the end of a long north-south hallway. The walls emit a faint\nmagical glow which provides enough light to see by.\n  Stairs here lead up to the next level, and the hallway continues south.\n','\n',char(10)));
INSERT INTO rooms VALUES(1399,12,'Atop the stairway',replace('You are atop the stairway to the upper levels of the high tower. The walls\nemit a faint magical glow which provides enough light to see by.\n  A hallway leads west from here, and the stairs lead down.\n','\n',char(10)));
INSERT INTO rooms VALUES(1400,12,'A hallway',replace('You are in a long hallway leading east and west. The walls emit a faint\nmagical glow which provides enough light to see by.\n  A silver door can be seen to the north.\n','\n',char(10)));
INSERT INTO rooms VALUES(1401,12,'A store room',replace('You are in a large store room. Raw materials are neatly bundled and piled\nhere and here. Many freshly cut staves rods and wands of different sizes\nare here.\n  You can see a silver door to the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(1402,12,'The master spellbinder''s chamber',replace('You are in the chambers of the master spell binder. Unlike other work\nshops of similar nature, this one is without furnishings or tools. The\nspell binder obviously needs none for the working of his art.\n  A silver door can be seen to the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(1403,12,'The spellbinder''s cache',replace('You have discovered the cache of the master spell binder. There are three\nvery large silver chased cabinets here, other than that, the room is bare.\n  A silver door can be seen to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(1404,12,'A hallway',replace('You are in a long hallway leading east and west. The walls emit a faint\nmagical glow which provides enough light to see by.\n','\n',char(10)));
INSERT INTO rooms VALUES(1405,12,'A hallway',replace('You are in a long hallway leading east and west. The walls emit a faint\nmagical glow which provides enough light to see by.\n  A silver door can be seen to the north.\n','\n',char(10)));
INSERT INTO rooms VALUES(1406,12,'A bend in the hallway',replace('You are at a bend in the long hallway. The walls emit a faint magical\nglow which provides enough light to see by.\n  The hallway continues east and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(1407,12,'A hallway',replace('You are in a long hallway leading north and south. The walls emit a faint\nmagical glow which provides enough light to see by.\n','\n',char(10)));
INSERT INTO rooms VALUES(1408,12,'A hallway',replace('You are in a long hallway leading north and south. The walls emit a faint\nmagical glow which provides enough light to see by.\n  A rusty old door can be seen to the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(1409,12,'The golem master''s workshop',replace('You are in the golem master''s workshop. A few unfinished looking humanoid\nforms of different make are here, some moving, some not. The animated forms\nlunge to attack you.\n','\n',char(10)));
INSERT INTO rooms VALUES(1410,12,'A store room',replace('You are in a small store room. Large chunks of clay, stone, wood and many\nother raw materials are here.\n','\n',char(10)));
INSERT INTO rooms VALUES(1411,12,'The golem chamber',replace('You are in the golem chamber. Golems made of every imaginable material\nare here, ranging in size from a hand-span to nearly the ceiling. They all\nseem to be sleeping.\n','\n',char(10)));
INSERT INTO rooms VALUES(1412,12,'It is very dark here...',replace('It is very dark here...\n','\n',char(10)));
INSERT INTO rooms VALUES(1413,12,'A hallway',replace('You are in a long hallway leading north and south. The walls emit a faint\nmagical glow which provides enough light to see by.\n','\n',char(10)));
INSERT INTO rooms VALUES(1414,12,'A bend in the hallway',replace('You are at a bend in the long hallway. The walls emit a faint magical\nglow which provides enough light to see by.\n  The hallway continues north and east from here.\n','\n',char(10)));
INSERT INTO rooms VALUES(1415,12,'A hallway',replace('You are in a long hallway leading east and west. The walls emit a faint\nmagical glow which provides enough light to see by.\n','\n',char(10)));
INSERT INTO rooms VALUES(1416,12,'A hallway',replace('You are in a long hallway leading east and west. The walls emit a faint\nmagical glow which provides enough light to see by.\n  An emerald door can be seen to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(1417,12,'The master of illusion''s chamber',replace('You are in the chamber of the master of illusions. The walls here are\nevery changing in color and texture, as if they were reforming before your\nvery eyes. Many splendorous treasures lie all around in heaps and piles, or\nat least they seem to be treasures...\n','\n',char(10)));
INSERT INTO rooms VALUES(1418,12,'A bedroom',replace('You are in the bedroom of the master of illusions. Strange looking items\nand artifacts float here and there in the air. The ripples of strong magic\ncan be felt everywhere.\n  The room seems much larger than it looks...\n','\n',char(10)));
INSERT INTO rooms VALUES(1419,12,'A hallway',replace('You are in a long hallway leading east and west. The walls emit a faint\nmagical glow which provides enough light to see by.\n  A glass door can be seen to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(1420,12,'The meditation chamber',replace('You are in a meditation chamber. It is very silent here, in fact you\ncan not even hear your own footsteps.\n  You feel very peaceful.\n','\n',char(10)));
INSERT INTO rooms VALUES(1421,12,'A bend in the hallway',replace('You are at a bend in the long hallway. The walls emit a faint magical\nglow which provides enough light to see by.\n  The hallway continues north and west from here.\n','\n',char(10)));
INSERT INTO rooms VALUES(1422,12,'A hallway',replace('You are in a long hallway leading north and south. The walls emit a faint\nmagical glow which provides enough light to see by.\n  A blackened door can be seen to the east.\n','\n',char(10)));
INSERT INTO rooms VALUES(1423,12,'A dark room',replace('You are in a large dark room. The air here seems quite stale, and a sense\nof extreme dread comes over you. The stench of rotten flesh seems to be\nwafting in from the open doorway to the north.\n','\n',char(10)));
INSERT INTO rooms VALUES(1424,12,'A dark room',replace('You are in a large dark room. The stench here makes you gag and wretch.\nThere are body parts and half rotted corpses strewn about with complete\nabandon. Several operating tables with still forms that resemble nothing\nyou''ve ever seen alive are here.\n  Tortured screams can be heard from the north.\n','\n',char(10)));
INSERT INTO rooms VALUES(1425,12,'The Necromancer''s Lair',replace('You are in the lair of the evil Necromancer. Undead minions of all types,\nhuman and otherwise stand here waiting to do their master''s bidding. Some\nglowing arcane sigils have been etched into walls and floor, no doubt to\nprotect the evil master from his own ungodly creations.\n','\n',char(10)));
INSERT INTO rooms VALUES(1426,12,'A hallway',replace('You are in a long hallway leading north and south. The walls emit a faint\nmagical glow which provides enough light to see by.\n','\n',char(10)));
INSERT INTO rooms VALUES(1427,12,'A hallway',replace('You are in a long hallway leading north and south. The walls emit a faint\nmagical glow which provides enough light to see by.\n','\n',char(10)));
INSERT INTO rooms VALUES(1428,12,'The end of the hallway',replace('You are at the end of a long hallway. The walls here glow with a faint\nmagical energy which provides plenty of light.\n  Stairs lead up to the next level here and the hallway continues south.\n','\n',char(10)));
INSERT INTO rooms VALUES(1429,12,'A corridor',replace('You are at the east end of a long corridor. Obsidian walls engraved with\nancient runes of power stretch out before you. Magical energies seem to\ncrackle with power all around and whisper in tongues long forgotten, almost\nas if the corridor it self were alive.\n','\n',char(10)));
INSERT INTO rooms VALUES(1430,12,'A corridor',replace('You are in a long corridor. Obsidian walls engraved with ancient runes\nof power stretch out before you. Magical energies seem to crackle with\npower all around and whisper in tongues long forgotten, almost as if the\ncorridor itself were alive.\n','\n',char(10)));
INSERT INTO rooms VALUES(1431,12,'A bend in the corridor',replace('You are at a bend in the long corridor. Obsidian walls engraved with\nancient runes of power stretch out before you. Magical energies seem to\ncrackle with power all around and whisper in tongues long forgotten, almost\nas if the corridor itself were alive.\n','\n',char(10)));
INSERT INTO rooms VALUES(1432,12,'A corridor',replace('You are in a long corridor leading north and south. Obsidian walls\nengraved with ancient runes of power stretch out before you. Magical\nenergies seem to crackle with power all around and whisper in tongues\nlong forgotten, almost as if the corridor itself were alive.\n','\n',char(10)));
INSERT INTO rooms VALUES(1433,12,'An intersection',replace('You are at an intersection in the corridor. The obsidian walled halls\nlead off in every direction from here, pulsing with the power of their\nancient runes.\n','\n',char(10)));
INSERT INTO rooms VALUES(1434,12,'A corridor',replace('You are at the end of a long corridor. Obsidian walls engraved with\nancient runes of power stretch out before you. A darkened door is to the\neast. Tendrils of mist cling to the floor here, they seem to be seeping\nfrom under the door.\n','\n',char(10)));
INSERT INTO rooms VALUES(1435,12,'The scrying chamber',replace('You are in the scrying chamber of the high tower of sorcerery. It is here\nthat arcane rituals are performed to enable those of the art to look in\nupon denizens throughout the world and spy out their darkest secrets.\n  A huge black cauldron is in the center of the room, bubbling and gurgling,\nit pours forth a constant stream of smokey fog into the air about you. Here\nand there on stands of different sizes are crystal balls and oddly shaped\nmirrors.\n','\n',char(10)));
INSERT INTO rooms VALUES(1436,12,'A corridor',replace('You have reached an end in the long corridor. Obsidian walls engraved\nwith ancient runes of power stretch out before you. The sound of snoring\ncan barely be heard through the door to the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(1437,12,'The entrance to the library',replace('You are in the entrance to the great library of magic. A giant desk is\nhere, covered with books parchments and scrolls. Long shelves loaded with\nrow upon row of books stretch out in every direction as far as the eye can\nsee.\n','\n',char(10)));
INSERT INTO rooms VALUES(1438,12,'In the library',replace('You are in the great library of magic. A strong musty smell permeates the\nentire area. Upon shelves which float just out of reach are hundreds of\nbooks, tomes and scrolls of every possible shape size and color. The elusive\nbooks seem to wink in and out of existence before your untrained eyes.\n  It is very quiet here.\n','\n',char(10)));
INSERT INTO rooms VALUES(1439,12,'In the library',replace('You are in the great library of magic. A strong musty smell permeates the\nentire area. Upon shelves which float just out of reach are hundreds of\nbooks, tomes and scrolls of every possible shape size and color. The elusive\nbooks seem to wink in and out of existence before your untrained eyes.\n  It is very quiet here.\n','\n',char(10)));
INSERT INTO rooms VALUES(1440,12,'In the library',replace('You are in the great library of magic. A strong musty smell permeates the\nentire area. Upon shelves which float just out of reach are hundreds of\nbooks, tomes and scrolls of every possible shape size and color. The elusive\nbooks seem to wink in and out of existence before your untrained eyes.\n  It is very quiet here.\n','\n',char(10)));
INSERT INTO rooms VALUES(1441,12,'In the library',replace('You are in the great library of magic. A strong musty smell permeates the\nentire area. Upon shelves which float just out of reach are hundreds of\nbooks, tomes and scrolls of every possible shape size and color. The elusive\nbooks seem to wink in and out of existence before your untrained eyes.\n  It is very quiet here.\n','\n',char(10)));
INSERT INTO rooms VALUES(1442,12,'In the library',replace('You are in the great library of magic. A strong musty smell permeates the\nentire area. Upon shelves which float just out of reach are hundreds of\nbooks, tomes and scrolls of every possible shape size and color. The elusive\nbooks seem to wink in and out of existence before your untrained eyes.\n  It is very quiet here.\n','\n',char(10)));
INSERT INTO rooms VALUES(1443,12,'In the library',replace('You are in the great library of magic. A strong musty smell permeates the\nentire area. Upon shelves which float just out of reach are hundreds of\nbooks, tomes and scrolls of every possible shape size and color. The elusive\nbooks seem to wink in and out of existence before your untrained eyes.\n  It is very quiet here.\n','\n',char(10)));
INSERT INTO rooms VALUES(1444,12,'Between the shelves',replace('You are in the great library of magic. The shelves seem uncomfortably\nclose here, you can barely maneuver between them. The musty smell is still\nstrong, and the elusive books still hover just out of reach.\n  A faint flicker of light can barely be made out to the north.\n','\n',char(10)));
INSERT INTO rooms VALUES(1445,12,'The reading room',replace('You are in a small room completely devoid of furnishings. The only thing\nhere is an enormous tome, lying face open on the floor. The great book looks\nboth heavy and ancient. Its jewel encrusted bindings are well worn as the\nbark of a tree. Spidery writings seem to crawls across the pages, totally\nincomprehensible to your mortal eye. Something seems to be wedged between\nthe pages.\n','\n',char(10)));
INSERT INTO rooms VALUES(1446,12,'A corridor',replace('You are in a long corridor leading north and south. Obsidian walls\nengraved with ancient runes of power stretch out before you. Magical\nenergies seem to crackle with power all around and whisper in tongues\nlong forgotten, almost as if the corridor itself were alive.\n','\n',char(10)));
INSERT INTO rooms VALUES(1447,12,'The end of the corridor',replace('You are at the end of a long corridor. The obsidian walls come to an\nabrupt halt at the edge of a golden archway here. The hum of power is so\nstrong it nearly numbs your body.\n  The archway lies before you, glowing and pulsing with energy.\n','\n',char(10)));
INSERT INTO rooms VALUES(1448,12,'The arched entrance',replace('You feel a slight tingle as you pass through the archway, as if the living\nmagical energies here had infused your body, found it wanting and left. The\nintense glow from the arch above you is almost blinding. Through the light\nyou can barely make out a stairway leading up.\n','\n',char(10)));
INSERT INTO rooms VALUES(1449,12,'The landing',replace('You are on a small landing in the middle of a long stairway leading up.\nYour senses seem dulled here, no sound or smell can be detected at all, and\nthe only thing you can see in any direction is endless stairway.\n','\n',char(10)));
INSERT INTO rooms VALUES(1450,12,'An intersection',replace('You are at an intersection of several hallways. You feel as if strange\nmystical forces are pushing and pulling at each other from all around you.\nThe sensation of being trapped, in the middle is almost tangible in the air\nhere.\n  A grey tiled hallway leads south, black tiled east, white tiled west, and\na multi-colored hallway swirling with patterns that remain just barely\nunrecognizable is to the north.\n','\n',char(10)));
INSERT INTO rooms VALUES(1451,12,'A grey tiled hallway',replace('You are in a grey tiled hallway leading north and south. Dim balls of\nenergy float here and there shedding a warm light, and showing the way.\nA feeling of peace and balance comes over you.\n','\n',char(10)));
INSERT INTO rooms VALUES(1452,12,'A grey tiled hallway',replace('You are in a grey tiled hallway leading north and south. Dim balls of\nenergy float here and there shedding a warm light, and showing the way.\nA feeling of peace and balance comes over you.\n  Large grey metal double doors can be seen to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(1453,12,'The antechamber',replace('You are in the antechamber of the master magician of the grey light. A\nfeeling of strong magic floats in the air about you, almost as if you could\ntaste the power held within these walls.\n  Once your eyes adjust to the semi-light, you can make out a larger room\nto the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(1454,12,'The main chamber',replace('A feeling of tranquility comes over you as you enter the main chamber of\nneutrality. Some artifacts are hung on the walls here, or set on stands.\nThe room in general looks both comfortable and official. Probably where the\nmaster of neutrality holds audience.\n','\n',char(10)));
INSERT INTO rooms VALUES(1455,12,'The study',replace('You are in a large study. Shelves filled with many books or arcane\nknowledge are on every wall. A large oaken desk is in the center, with\nmany parchments and scrolls on it. The most notable thing in the room is\na small set of scales, which floats about eye level. In perfect balance,\nthe scales are no doubt a sign of the master''s neutrality.\n','\n',char(10)));
INSERT INTO rooms VALUES(1456,12,'A closet',replace('You are in a small closet. It is filled with many cloaks, and some other\napparel.\n','\n',char(10)));
INSERT INTO rooms VALUES(1457,12,'A bedroom',replace('You are in the bedroom of the master magician of neutrality. Curtained\nwindows can be seen on the south wall. A large comfortable looking bed\ntakes up most of the room.\n','\n',char(10)));
INSERT INTO rooms VALUES(1458,12,'A dark hallway',replace('You are in a long dark hallway leading east and west. Not much can be\nseen in the unnatural darkness here, but you get a deep sense of dread\nthe further you go.\n','\n',char(10)));
INSERT INTO rooms VALUES(1459,12,'A dark hallway',replace('You are in a long dark hallway leading east and west. Not much can be\nseen in the unnatural darkness here, but you get a deep sense of dread\nthe further you go.\n','\n',char(10)));
INSERT INTO rooms VALUES(1460,12,'The end of the hallway',replace('You are at the end of a long dark hallway. The darkness here is almost\ntangible in its thickness. A deep sense of fear and loathing comes over\nyou.\n  A pair of obsidian doors can be seen to the east.\n','\n',char(10)));
INSERT INTO rooms VALUES(1461,12,'The chamber of darkness',replace('You are in a vast chamber. The walls fade into darkness, leaving you\nwith a very vague idea of the actual size of the room. Swirling here and\nthere in the dark, are patches of pure black which seem to suck in your\nlight and leave it that much darker here.\n','\n',char(10)));
INSERT INTO rooms VALUES(1462,12,'It is very dark here...',replace('It is very dark here...\n','\n',char(10)));
INSERT INTO rooms VALUES(1463,12,'Torture chamber',replace('You are in an ill lit chamber. Instruments of torture hang from a rack\non the wall, they seem to quiver with anticipation of a victim as if they\nhad a mind of their own. An operating table is here, though it is bare.\n  An extreme feeling of evil permeates the entire area.\n','\n',char(10)));
INSERT INTO rooms VALUES(1464,12,'The inner chamber',replace('You are in a small dark chamber. Upon the walls are glowing sigils of\ndark power, scrawled and traced in an evil language no longer known to most\nof this plane of existence. There is an obsidian altar here which seems to\nglow, but does not shed any light, in fact it seems to be taking light in.\n','\n',char(10)));
INSERT INTO rooms VALUES(1465,12,'A bright hallway',replace('You are in a long well lit hallway leading east and west. The walls here\nare a milky white color, and glow with a warm luminescence, as does the\nfloor. A feeling of goodness permeates the area, and you feel unworthy to\ntread upon these sacred floors.\n','\n',char(10)));
INSERT INTO rooms VALUES(1466,12,'A bright hallway',replace('You are in a long well lit hallway leading east and west. The walls here\nare a milky white color, and glow with a warm luminescence, as does the\nfloor. A feeling of goodness permeates the area, and you feel unworthy to\ntread upon these sacred floors.\n  A huge set of double doors in finely worked ivory can be seen to the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(1467,12,'An antechamber',replace('You are in a small antechamber. It is well lit here, though the source\nof light cannot be seen. It is almost as if the room itself exudes a warm\nglow of goodness. A larger chamber can be seen to the west, but you do not\nfeel worthy to pass into it.\n','\n',char(10)));
INSERT INTO rooms VALUES(1469,12,'The chamber of the white light',replace('You are in a vast chamber, its walls floor and ceiling are of an unknown\nmetallic material, the brightest white, almost blindingly stark. A flickering\nflame is in the center of the room, seeming to feed off of darkness and\ncleansing the room of any evil. You feel a slight tug at your being as the\nflame flickers towards you.\n','\n',char(10)));
INSERT INTO rooms VALUES(1470,12,'The meditation chamber',replace('You are in a small meditation chamber. White silk cushions are everywhere,\nlooking very comfortable. You get an easy peaceful feeling of relaxation\nhere, almost making you want to lie down and fall asleep.\n','\n',char(10)));
INSERT INTO rooms VALUES(1471,12,'A study',replace('You are in a spacious study. It is extremely tidy here, to an almost\nantiseptic nature. One would wonder how anyone could study without a\nmess all around them, the master of this chamber obviously can.\n','\n',char(10)));
INSERT INTO rooms VALUES(1472,12,'A closet',replace('You are in a small closet. Cloaks and vests hang from hooks in the wall,\nand a few old boots are all that can be seen here. Rather featureless.\n','\n',char(10)));
INSERT INTO rooms VALUES(1473,12,'A wide hallway',replace('You are in a large hallway, wide enough to accommodate several people\nstanding abreast. The floor here is a swirl of multicolored patterns, in\nconstant motion.\n  A huge grey metal door blocks the way north, it looks quite sturdy.\n','\n',char(10)));
INSERT INTO rooms VALUES(1474,12,'A wide hallway',replace('You are in a large hallway, wide enough to accommodate several people\nstanding abreast. The floor here is a swirl of multicolored patterns, in\nconstant motion.\n  A huge black obsidian door blocks the way north, it looks quite sturdy.\n','\n',char(10)));
INSERT INTO rooms VALUES(1475,12,'A wide hallway',replace('You are in a large hallway, wide enough to accommodate several people\nstanding abreast. The floor here is a swirl of multicolored patterns, in\nconstant motion.\n  A huge white ivory door blocks the way north, it looks quite sturdy.\n','\n',char(10)));
INSERT INTO rooms VALUES(1476,12,'The entranceway',replace('You are at the entrance to the audience chamber of the grand master of\nmagic. Beautiful tapestries displaying the ancient masters of lore are on\nthe walls, and the floor is covered with a plush multicolored carpet, which\nseems to rustle and move at the touch of your boots.\n','\n',char(10)));
INSERT INTO rooms VALUES(1477,12,'The audience chamber',replace('You are in a large chamber. Small bolts of energy leap from wall to wall,\ncrackling with power. The floor is a swirl of indeterminable colors and\npatterns ever changing. Bright bursts of color seem to explode into the air\nand fade again at random times. All this splendor plays about and draws\nattention to a large throne in the center of the room, it seems to be cut\nfrom a single enormous emerald.\n','\n',char(10)));
INSERT INTO rooms VALUES(1478,12,'A dressing room',replace('You are in a plush dressing room. Fine garments of many styles and some\noutlandish colors hang from a rack suspended in mid air at eye level. The\nonly other interesting feature in the room is a large silver mirror on a\nfinely crafted gold stand.\n','\n',char(10)));
INSERT INTO rooms VALUES(1479,12,'The library',replace('You are in a small cozy looking library. A few well made books sit atop\nshelves which span every wall. A large oaken writing table is in the center\nof the room with odd papers and parchments on it. The illumination here,\nto your surprise is a quite un-magical oil lamp.\n','\n',char(10)));
INSERT INTO rooms VALUES(1480,12,'The altar',replace('You are in a small chapel designed around a beautifully crafted golden\naltar. Many icons to lesser deities line the room, but it is obvious by one\nglance at the symbols on the altar, that this room was designed for the\nworship of Mystra, the goddess of magic.\n','\n',char(10)));
INSERT INTO rooms VALUES(1481,12,'The treasury',replace('You are in a small chamber, the stale air here is testament to the fact\nthat it has gone undisturbed for many years.\n','\n',char(10)));
INSERT INTO rooms VALUES(1482,12,'A passage',replace('You are in a small dark passage, which would be unremarkable if not for\nthe fact that it ends in a blinding blue light to the west. On hooks set\ninto the wall here there hang several travel worthy cloaks, and a small\nleather backpack.  It looks as if someone has prepared this room to be used\nin the event speedy of a evacuation.\n','\n',char(10)));
INSERT INTO rooms VALUES(1483,12,'In the light',replace('You seem to be floating in a magical energy field, though you cannot see\nthe source of the energy, you can feel its power pushing at you from all\nsides, completely negating the effects of gravity.\n  An imperfection in the uniform blue can be seen overhead, it might be an\nexit.\n','\n',char(10)));
INSERT INTO rooms VALUES(1499,12,'Skylar''s Hideout',replace('You are in a small, very messy room. An unmade bed is against one wall, and\nbooks and papers cover every available flat surface. Empty beer cans lie here\nand there, discarded with total abandon. A few over full ashtrays can be seen\non a desk.\n','\n',char(10)));
INSERT INTO rooms VALUES(1501,15,'Entrance to Gnome Village',replace('You stand on a dusty path that leads north and east.  To the east you hear\nthe sounds of a small village.\n','\n',char(10)));
INSERT INTO rooms VALUES(1502,15,'A Dusty Path',replace('This is a path leading into the village.  It continues east and west and\nthere is a small house to the north.\n','\n',char(10)));
INSERT INTO rooms VALUES(1503,15,'A Road in the Village',replace('This road runs north and south through the center of the village.  There\nare a few people moving around, but not many.\n','\n',char(10)));
INSERT INTO rooms VALUES(1504,15,'A Dusty Path',replace('You are on a dusty path on the far side of the village.  Houses are to the\nnorth and south, while the path continues east.  There is a sign here.\n','\n',char(10)));
INSERT INTO rooms VALUES(1505,15,'A Road in the Village',replace('This road runs north and south through the center of the village.  There\nare a few people moving around, but not many.\n','\n',char(10)));
INSERT INTO rooms VALUES(1506,15,'A Road in the Village',replace('This road runs north and south through the center of the village.  There\nare a few people moving around, but not many.\n','\n',char(10)));
INSERT INTO rooms VALUES(1507,15,'A Road in the Village',replace('This road runs north and south through the center of the village.  There\nare a few people moving around, but not many.\n','\n',char(10)));
INSERT INTO rooms VALUES(1508,15,'A Road in the Village',replace('This road runs north and south through the center of the village.  There\nare a few people moving around, but not many.\n','\n',char(10)));
INSERT INTO rooms VALUES(1509,15,'A Small Gnome House',replace('This is a small suburban house made from quality wood.  You can see the\nexpert workmanship that went into making it, but it lacks creativity.\n','\n',char(10)));
INSERT INTO rooms VALUES(1510,15,'A Small Gnome House',replace('This is a small suburban house made from quality wood.  You can see the\nexpert workmanship that went into making it, but it lacks creativity.\n','\n',char(10)));
INSERT INTO rooms VALUES(1511,15,'A Small Gnome House',replace('This is a small suburban house made from quality wood.  You can see the\nexpert workmanship that went into making it, but it lacks creativity.\n','\n',char(10)));
INSERT INTO rooms VALUES(1512,15,'A Small Gnome House',replace('This is a small suburban house made from quality wood.  You can see the\nexpert workmanship that went into making it, but it lacks creativity.\n','\n',char(10)));
INSERT INTO rooms VALUES(1513,15,'A Small Gnome House',replace('This is a small suburban house made from quality wood.  You can see the\nexpert workmanship that went into making it, but it lacks creativity.\n','\n',char(10)));
INSERT INTO rooms VALUES(1514,15,'A Gnome Shop',replace('You are in one of the several shops of this fine town.  The wares look fine,\nbut unfortunately the gnomes don''t do business with outsiders.\n','\n',char(10)));
INSERT INTO rooms VALUES(1515,15,'A Gnome Shop',replace('You are in one of the several shops of this fine town.  The wares look fine,\nbut unfortunately the gnomes don''t do business with outsiders.\n','\n',char(10)));
INSERT INTO rooms VALUES(1516,15,'A Gnome Shop',replace('You are in one of the several shops of this fine town.  The wares look fine,\nbut unfortunately the gnomes don''t do business with outsiders.\n','\n',char(10)));
INSERT INTO rooms VALUES(1517,15,'Path by a Stream',replace('You are on a small path leading north and west, that is surrounded on the\nother two sides by a small stream.  The water looks mighty cold.\n','\n',char(10)));
INSERT INTO rooms VALUES(1518,15,'Path by a Stream',replace('You are on a small east-west path.  The path shows new grass, as if it\nhas stopped being used sometime in the recent past.  A river is to the south,\nand a small hut is to the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(1519,15,'A Small Hut',replace('The hut is a mess!  Blood has stained the grass walls into a dark rich\ncrimson color.  Torn clothes and trash lie all around, and you think you\nsee a skeleton in the corner.\n','\n',char(10)));
INSERT INTO rooms VALUES(1520,15,'On the Stream',replace('The stream is cold and frigid, yet it supports plenty of life beneath its\nsurface.  The current trickles west and there is a field to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(1521,15,'On the Stream',replace('The current here flows from the east, but a logjam blocks you from \ncontinuing onward.\n','\n',char(10)));
INSERT INTO rooms VALUES(1522,15,'The Field of Mice''s Dreams',replace('This is a large green field of waist high grass.  You feel something\nscurry over your feet.  There is a cave to the east.\n','\n',char(10)));
INSERT INTO rooms VALUES(1523,15,'The Dark Cave',replace('The cave gleams as your light reflects off of it.  As you squint your eyes\nand try to look ahead, you think you see something move.\n','\n',char(10)));
INSERT INTO rooms VALUES(1524,15,'Darker Cave',replace('The cave gets even darker as your terror grows stronger.  You fear for your\nlife as something emerges out of the shadows.\n','\n',char(10)));
INSERT INTO rooms VALUES(1526,15,'A Dusty Path',replace('You are on a well traveled path that leads in many directions.  To the north\nis a large house, and to the west is a fortress.\n','\n',char(10)));
INSERT INTO rooms VALUES(1527,15,'The Iron Gateway',replace('You stand at the entrance to the gnome fortress.  The place seems to be\nwell fortified.\n','\n',char(10)));
INSERT INTO rooms VALUES(1528,15,'A Long Hallway',replace('You are now inside of the fortress; you must be lucky that the guards \nhaven''t killed you.  As you glance around, you notice that the walls and\nfloors are spotlessly cleaned.  The barracks are to the north and a\nstorage room is to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(1529,15,'A Long Hallway',replace('You are now inside of the fortress; you must be lucky that the guards \nhaven''t killed you.  As you glance around, you notice that the walls and\nfloors are spotlessly cleaned.  A mess hall is to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(1530,15,'The Barracks',replace('You now stand in the sleeping quarters of the gnome guards.  Every bed is\nmade perfectly, and not single article of clothing is on the floor.  There\nis a small storage room to the east.\n','\n',char(10)));
INSERT INTO rooms VALUES(1531,15,'A Small Storage Room',replace('This is where the gnomes store all their spare clothing and armor.\nThere is not much here, but you might come up with something.\n','\n',char(10)));
INSERT INTO rooms VALUES(1532,15,'A Small Storage Room',replace('This is where the gnomes store all their spare weapons.  A door leads off\nto the east.\n','\n',char(10)));
INSERT INTO rooms VALUES(1533,15,'A Small Storage Room',replace('This is yet another room for storing gnome stuff.  Maps and battle plans\nare stored in neat stacks on the shelves.\n','\n',char(10)));
INSERT INTO rooms VALUES(1534,15,'The Mess Hall',replace('You are in the room where the guards come to get their grub.  The benches \nand tables are neatly cleaned and straightened, while shiny plates line\nthe walls.\n','\n',char(10)));
INSERT INTO rooms VALUES(1535,15,'A Small Room',replace('This is a small plain room.  Its only interesting feature is a ladder down.\n','\n',char(10)));
INSERT INTO rooms VALUES(1536,15,'A Small Unused Room',replace('You stand in a small room in an unused section of the fortress.  The whole\nroom is coated with dust and cobwebs.  The ladder leads back up, and\na rusty door is to the east.\n','\n',char(10)));
INSERT INTO rooms VALUES(1537,15,'Dark Hallway',replace('You find yourself in a very old section of the fortress.  You must be the\nfirst person to pass through here in years.  The hallway continues south\nand a door leads off to the east.\n','\n',char(10)));
INSERT INTO rooms VALUES(1538,15,'Torture Chamber',replace('This is a room that was once used to extract lies out of helpless victims.\nThe machines look unused, but could still work.\n','\n',char(10)));
INSERT INTO rooms VALUES(1539,15,'Dark Hallway',replace('The hall continues in a north-south direction.  The floor is coated with\nsome kind of molded slime.  Doors lead east and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(1540,15,'Dark Hallway',replace('The hall continues in a north-south direction.  The floor is coated with\nsome kind of molded slime.  Doors lead east and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(1541,15,'Prison Cell',replace('You are in a dark and nasty prison cell.  Bodies lying on the floor give off\nan unbearable stench.\n','\n',char(10)));
INSERT INTO rooms VALUES(1542,15,'Prison Cell',replace('You are in a dark and nasty prison cell.  Bodies lying on the floor give off\nan unbearable stench.\n','\n',char(10)));
INSERT INTO rooms VALUES(1543,15,'Prison Cell',replace('You are in a dark and nasty prison cell.  Bodies lying on the floor give off\nan unbearable stench.\n','\n',char(10)));
INSERT INTO rooms VALUES(1544,15,'Prison Cell',replace('You are in a dark and nasty prison cell.  Bodies lying on the floor give off\nan unbearable stench.\n','\n',char(10)));
INSERT INTO rooms VALUES(1545,15,'End of the Dark Hallway',replace('You have reached the end of the dark hallway and maybe the end of your puny\nlife.  Something lumbers its way out of the shadows.\n','\n',char(10)));
INSERT INTO rooms VALUES(1546,15,'A Ladder',replace('You have come into a vertical tunnel with a ladder.\n','\n',char(10)));
INSERT INTO rooms VALUES(1547,15,'Lair',replace('You have entered a new lair in the fortress.  Anything could be lurking\naround the corner.\n','\n',char(10)));
INSERT INTO rooms VALUES(1548,15,'A Damp Hallway',replace('You are wandering in a dark, damp, twisting hallway.  The temperature\nseems to be greater here, as well as your fear.\n','\n',char(10)));
INSERT INTO rooms VALUES(1549,15,'A Damp Hallway',replace('You are wandering in a dark, damp, twisting hallway.  The temperature\nseems to be greater here, as well as your fear.\n','\n',char(10)));
INSERT INTO rooms VALUES(1550,15,'A Damp Hallway',replace('You are wandering in a dark, damp, twisting hallway.  The temperature\nseems to be greater here, as well as your fear.\n','\n',char(10)));
INSERT INTO rooms VALUES(1551,15,'A Damp Hallway',replace('You are wandering in a dark, damp, twisting hallway.  The temperature\nseems to be greater here, as well as your fear.\n','\n',char(10)));
INSERT INTO rooms VALUES(1552,15,'A Damp Hallway',replace('You are wandering in a dark, damp, twisting hallway.  The temperature\nseems to be greater here, as well as your fear.\n','\n',char(10)));
INSERT INTO rooms VALUES(1553,15,'A Damp Hallway',replace('You are wandering in a dark, damp, twisting hallway.  The temperature\nseems to be greater here, as well as your fear.\n','\n',char(10)));
INSERT INTO rooms VALUES(1554,15,'A Damp Hallway',replace('You are wandering in a dark, damp, twisting hallway.  The temperature\nseems to be greater here, as well as your fear.\n','\n',char(10)));
INSERT INTO rooms VALUES(1555,15,'A Damp Hallway',replace('You are wandering in a dark, damp, twisting hallway.  The temperature\nseems to be greater here, as well as your fear.\n','\n',char(10)));
INSERT INTO rooms VALUES(1556,15,'The End of the Hallway',replace('You make your way out of the hallway, just to find yourself in greater\ndanger.  Before you looms the source of the great heat.\n','\n',char(10)));
INSERT INTO rooms VALUES(1557,15,'The Altar',replace('You finally reach the end of the maze.  There is a great altar here in the\nshape of a bat.  A passageway leads off to the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(1558,15,'The Chief''s House',replace('You enter into a large and luxurious house.  The floor is coated with carpets\nand the walls are covered in paintings.  You feel privileged just for stepping\ninside.\n','\n',char(10)));
INSERT INTO rooms VALUES(1559,15,'The Unused Path',replace('You are now on a fairly unused path that leads east out of the village.  \nYou wonder what could be out this way.\n','\n',char(10)));
INSERT INTO rooms VALUES(1560,15,'The Overgrown Path',replace('As the path continues on, the grass grows higher.  You can''t imagine\nwhat could possibly be out this way.\n','\n',char(10)));
INSERT INTO rooms VALUES(1561,15,'The Clearing',replace('Your progress is suddenly stopped by mountains on all sides.  The path leads\nback to the west, and there appears to be an old mine shaft to the north.\n','\n',char(10)));
INSERT INTO rooms VALUES(1562,15,'Entrance to the Mine Shaft',replace('As you enter the mine shaft, you get a sudden fear of the walls closing\nin on you.  You are surprised to notice that you don''t need a light.\n','\n',char(10)));
INSERT INTO rooms VALUES(1563,15,'Mine Shaft',replace('This mine shaft looks stable, at least in this area.  The wooden supports are\nthick and strong.  Torches line the walls.  Exits lead in all directions.\n','\n',char(10)));
INSERT INTO rooms VALUES(1564,15,'Mine Shaft',replace('This mine shaft looks stable, at least in this area.  The wooden supports are\nthick and strong.  Torches line the walls.  Exits lead in all directions.\n','\n',char(10)));
INSERT INTO rooms VALUES(1565,15,'Mine Shaft',replace('This mine shaft looks stable, at least in this area.  The wooden supports are\nthick and strong.  Torches line the walls.  Exits lead in all directions\nexcept north.\n','\n',char(10)));
INSERT INTO rooms VALUES(1566,15,'Walkway',replace('You are on a well built path in the middle of a mountain.  You sense something\ngreat up ahead, considering the hard work that must have gone into creating\nthis passage.\n','\n',char(10)));
INSERT INTO rooms VALUES(1567,15,'Walkway',replace('You are on a well built path in the middle of a mountain.  You sense something\ngreat up ahead, considering the hard work that must have gone into creating\nthis passage.\n','\n',char(10)));
INSERT INTO rooms VALUES(1568,15,'The Grand Hall',replace('You have stepped into the Grand Hall of the hobgoblin kingdom; your luck\nmust be running low by now.  Golden pillars span the hallway, and you\nnotice a red carpet beneath your feet.\n','\n',char(10)));
INSERT INTO rooms VALUES(1569,15,'The Throne Room',replace('This is large bright room filled with Hobgoblins.  To the south there is\na large golden throne against the wall.\n','\n',char(10)));
INSERT INTO rooms VALUES(1570,15,'The Treasury',replace('You are inside the hobgoblin''s treasury.  Your eyes are almost blinded by the\ngold, silver and copper coins.\n','\n',char(10)));
INSERT INTO rooms VALUES(1571,15,'Guarded Room',replace('You are inside a well guarded room.  The place is slightly better built than\nthe mine shafts, and is lit by lanterns.\n','\n',char(10)));
INSERT INTO rooms VALUES(1572,15,'Guarded Room',replace('You are inside a well guarded room.  The place is slightly better built than\nthe mine shafts, and is lit by lanterns.\n','\n',char(10)));
INSERT INTO rooms VALUES(1573,15,'Hobgoblin Armory',replace('The guards store their spare weapons and armor here.  There are rusty swords\non rotting shelves, and armor hanging from hooks or laying on the floor.\n','\n',char(10)));
INSERT INTO rooms VALUES(1574,15,'Mine Shaft',replace('You enter a part of the mine shaft where the torches have grown dim\nand are almost ready to go out.  From what you can see, there are plenty\nof cobwebs on the walls and rats at your feet.\n','\n',char(10)));
INSERT INTO rooms VALUES(1575,15,'Entrance to a Dungeon',replace('The floor dips slightly as you walk into this dark and nasty place.  Your\nskin crawls as you look at the filth on the walls and see it move.  Most\nof the exits lead into jail cells.\n','\n',char(10)));
INSERT INTO rooms VALUES(1576,15,'A Dungeon',replace('You are in the deepest and darkest part of the mine shafts.  The light from\nthe torches barely reaches to where you are.  Most directions from here\nlead to jail cells.\n','\n',char(10)));
INSERT INTO rooms VALUES(1577,15,'A Jail Cell',replace('You are in a musty, dark jail cell.  Wet and dirty straw covers the floor.\nThe walls glisten with slime.  You see something stir in the straw.\n','\n',char(10)));
INSERT INTO rooms VALUES(1578,15,'The Jail Cell',replace('You are in a musty, dark jail cell.  Wet and dirty straw covers the floor.\nThe walls glisten with slime.  You see something stir in the straw.\n','\n',char(10)));
INSERT INTO rooms VALUES(1579,15,'The Jail Cell',replace('You are in a musty, dark jail cell.  Wet and dirty straw covers the floor.\nThe walls glisten with slime.  You see something stir in the straw.\n','\n',char(10)));
INSERT INTO rooms VALUES(1580,15,'The Jail Cell',replace('You are in a musty, dark jail cell.  Wet and dirty straw covers the floor.\nThe walls glisten with slime.  You see something stir in the straw.\n','\n',char(10)));
INSERT INTO rooms VALUES(1581,15,'The Jail Cell',replace('You are in a musty, dark jail cell.  Wet and dirty straw covers the floor.\nThe walls glisten with slime.  You see something stir in the straw.\n','\n',char(10)));
INSERT INTO rooms VALUES(1582,15,'Small Mine Shaft',replace('You are in a small extension of the mine shaft.  The dust on the floor is\nundisturbed by footprints.\n','\n',char(10)));
INSERT INTO rooms VALUES(1583,15,'Hobgoblin Barracks',replace('You are suddenly surrounded by a small army of hobgoblin guards.  The room\nitself is a mess with clothes and armor everywhere.  The beds are unmade and\nstained.\n','\n',char(10)));
INSERT INTO rooms VALUES(1584,15,'Hobgoblin Barracks',replace('Yech!  As you continue forward, the smell just keeps getting worse.\nWhat are you DOING here?\n','\n',char(10)));
INSERT INTO rooms VALUES(1585,15,'Mess Hall',replace('You stand in the hobgoblin eating area.  There are a few rotting tables\nand many broken dishes scattered around the room.  You almost slip on a\nrotten piece of meat, but catch yourself just in time.\n','\n',char(10)));
INSERT INTO rooms VALUES(1586,15,'A Store Room',replace('You stand in a small room filled with flour, grain, fruit, and bat droppings.\n','\n',char(10)));
INSERT INTO rooms VALUES(1587,15,'The Kitchen',replace('This kitchen hasn''t been cleaned since the creation of humans.  The trash and\nspoiled food laying on the floor reach up to your knees.  Off to the side a\npot is boiling over.  A human hand floats in it.\n','\n',char(10)));
INSERT INTO rooms VALUES(1588,15,'A Small Mine Shaft',replace('You come to a place in the mine shaft where a tunnel leads down.  The\nsmall passage continues north and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(1589,15,'Hermit''s Lair',replace('You are in a small section where the mine wall has collapsed to reveal a\ntiny one-room cave.  The area is barely lit, but you can make out something\nmoving towards you.\n','\n',char(10)));
INSERT INTO rooms VALUES(1590,15,'A Hole',replace('You are in a hole.\n','\n',char(10)));
INSERT INTO rooms VALUES(1601,16,'Rough East-West Path',replace('You are on a very rough and overgrown path heading east-west over rugged\nterrain.  To the east the path passes between low hills.\n','\n',char(10)));
INSERT INTO rooms VALUES(1602,16,'Rough Path Between the Hills',replace('Here the path passes between low hills. The going is very rough, but\nto the east the ground is smoother. In that direction a pair of tower\nlooms above the hills.\n','\n',char(10)));
INSERT INTO rooms VALUES(1603,16,'Path through an Open Area',replace('You are on a path through an open area. East of here loom two tall towers,\njoined by a barbican and surrounded by a murky moat. West the path passes\nbetween low hills.\n','\n',char(10)));
INSERT INTO rooms VALUES(1604,16,'West Side of Moat',replace('You stand on the west side of a moat that encircles two towers, each\nover 50 feet high. You will need a boat to go east across the moat. A\nrugged path heads west, and another one heads north to a cluster of low \nbuildings.\n','\n',char(10)));
INSERT INTO rooms VALUES(1605,16,'Path North of Moat',replace('You walk on a faint path heading south toward the west side of the moat,\nand north to three small buildings.\n','\n',char(10)));
INSERT INTO rooms VALUES(1606,16,'Cluster of Buildings',replace('You are in the middle of a cluster of small buildings. There is a building\nto the north, east, and west.  A sign over the eastern building says\n''House of Pancakes''.\n','\n',char(10)));
INSERT INTO rooms VALUES(1607,16,'House of Pancakes',replace('The moment you enter this room, the ceiling descends and crushes you\ninto a pancake.  Don''t you hate it when that happens?\n','\n',char(10)));
INSERT INTO rooms VALUES(1608,16,'Old Store Room',replace('You have entered what appears to be an old storeroom. Most of the items\nthat were in here appear to have been ruined long ago.\n','\n',char(10)));
INSERT INTO rooms VALUES(1609,16,'Empty Room',replace('This room appears to be completely empty. The only exit seems to be the\nway you came.  There are some scratches around the floor.\n','\n',char(10)));
INSERT INTO rooms VALUES(1610,16,'Minotaur''s Room',replace('You have entered a secret chamber under the empty room. In this room is\nthe worn but cared-for gear and trappings of some large humanoid.\n','\n',char(10)));
INSERT INTO rooms VALUES(1620,16,'Western Moat',replace('You are in the middle of the moat, on the west side of the tower.  There is a\nlanding on both sides of the moat.  Deep throated ''ribbids'' come from the\nwater all around you.\n','\n',char(10)));
INSERT INTO rooms VALUES(1621,16,'Northern Moat',replace('You are in the middle of the moat, on the north side of the tower.  There is\nno place to land here.  Deep throated ''ribbids'' come from the water all\naround you.\n','\n',char(10)));
INSERT INTO rooms VALUES(1622,16,'Southern Moat',replace('You are in the middle of the moat, on the south side of the tower.  There is\nno place to land here.  Deep throated ''ribbids'' come from the water all\naround you.\n','\n',char(10)));
INSERT INTO rooms VALUES(1623,16,'Tower Foyer',replace('You are on a foyer on the west side of the structure. The moat is west of \nhere. There is also a large door eastward into the structure.  You notice that\nthe walls are ornately decorated with very life-like stone gargoyles.\n','\n',char(10)));
INSERT INTO rooms VALUES(1624,16,'The Grand Lobby',replace('You have entered a vast lobby. This lobby appears to have once been very\nornately furnished, but now everything is decayed and moldering.  A highly\nornate balcony surrounds the lobby. To the east, below the balcony, is an\nopening. The door leading out is west.  You notice that the balcony is\ncovered in highly ornate and life-like stone gargoyles.\n','\n',char(10)));
INSERT INTO rooms VALUES(1625,16,'Base of the Western Tower',replace('You stand in the center of the Western tower''s base. Torch brackets occupy\nthe four corners of this huge room. Above each torch is a lifelike ornate\nstone gargoyle.  There are doors north and south, and passages east and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(1626,16,'The Musty Corridor',replace('You are walking along a musty east-west corridor joining the two towers.\nThere are room on each side of the corridor, and openings at each end.\n','\n',char(10)));
INSERT INTO rooms VALUES(1627,16,'Kitchen',replace('You have entered what must once have been a kitchen. The rusting remains of\nvarious utensils lie on countertops. There is also an old wash basin and a\npot-belly stove.  There is a door south, and a serving hatch east.\n','\n',char(10)));
INSERT INTO rooms VALUES(1628,16,'Conservatory',replace('You are in the tower''s private conservatory. However, through years of neglect,\nthe plants have grown into a hideous jungle.  The only exit is north.\n','\n',char(10)));
INSERT INTO rooms VALUES(1629,16,'The Dining Hall',replace('You have entered a fabulous dining hall.  The wrecked remains of a long table\ndominate the room. A horrible odor pervades the room, like some foul-smelling\nbeast has been eating and shitting in here.  There is a serving hatch west and\na door south.\n','\n',char(10)));
INSERT INTO rooms VALUES(1630,16,'Art Gallery',replace('You are in the ruined remains of an art gallery. Everything appears to\nhave been stolen long ago, however.  The only exit is north.\n','\n',char(10)));
INSERT INTO rooms VALUES(1631,16,'Base of the Eastern Tower',replace('You stand in the center of the Eastern tower''s base. Torch brackets occupy the\nfour corners of this huge room.  Above each torch is a lifelike ornate stone\ngargoyle.  There are are open doors to the north and south, and passages east\nand west.  In addition, a spiral staircase leads up to the next level of this\ntower.\n','\n',char(10)));
INSERT INTO rooms VALUES(1632,16,'The Common Room',replace('You are in what must once have been a common room for all residents of the\ntower. There is a huge fire pit with a chimney in the center, and the smashed\nremains of a great many table and chairs.  The exit is south.\n','\n',char(10)));
INSERT INTO rooms VALUES(1633,16,'Servant''s Quarters',replace('You are in what once was the servant''s quarters, as evidenced by the shabby\nbelongings and decor. What little remains is rotting and of little value\nanyway.  The only exit is north.\n','\n',char(10)));
INSERT INTO rooms VALUES(1634,16,'A Large Murky Cellar',replace('You are in a large, murky cellar. An almost tangible air of horror pervades\nthe room.  A thin layer of nitre covers the walls and ceiling.  Rotting\nfurniture looms obliquely about the room.\n','\n',char(10)));
INSERT INTO rooms VALUES(1635,16,'On the First Staircase',replace('You are on a Spiral staircase connecting the first and second levels of\nthe eastern tower. You can go up or down.\n','\n',char(10)));
INSERT INTO rooms VALUES(1636,16,'Second Level of the Eastern Tower',replace('You are in the center of the second level of the Eastern tower. This large\nroom appears quite empty, except for the candle abras firmly fixed to the\nwalls.  An opening leads westward, and a spiral staircase leads down.\n','\n',char(10)));
INSERT INTO rooms VALUES(1637,16,'The Elegant Hall',replace('You are in what was once a elegant hall, although everything is moldering now.\nThe rotted remains of a plush carpet covers the floor, while several moldy\ntapestries adorn the each side of the hall.  There are door north and south,\nand openings east and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(1638,16,'The Shaman''s Room',replace('You have entered an elegantly furnished room that looks to be still in use!\nCostly paintings and pieces of furniture are tastefully situated.  On the\nnorth wall is an altar to Knar, the ghastly patron of Gargoyles.  The only\nexit is south.\n','\n',char(10)));
INSERT INTO rooms VALUES(1639,16,'The Library',replace('This room appears to have been a library.  Empty book shelves line each wall.\nThe only exit is north.\n','\n',char(10)));
INSERT INTO rooms VALUES(1640,16,'Second Level of the Western Tower',replace('You are in the center of the western tower''s second floor.  A large spiral \nstaircase of 29 steps connects this level with the third.  There are doors\nto the east and west.  Except for a torch bracket in each corner, the \nroom is barren.\n','\n',char(10)));
INSERT INTO rooms VALUES(1641,16,'On the Balcony',replace('You are on the balcony overlooking the Grand lobby.  You have a fabulous\nview of the entire room.  The only exit is the way you came in.\n','\n',char(10)));
INSERT INTO rooms VALUES(1642,16,'The Spiral Stairs',replace('You are on a large spiral staircase of 29 steps, leading between the \nsecond and third floors.  You can go up or down.\n','\n',char(10)));
INSERT INTO rooms VALUES(1643,16,'Third Level of Western Tower',replace('You stand in the center of the western tower''s third floor.  This large room\nglows mysteriously with a strange light all its own.  From a door to the east\ncomes a strange inky blackness.  A spiral staircase leads down.\n','\n',char(10)));
INSERT INTO rooms VALUES(1644,16,'It''s too dark to see anything!',replace('It''s too dark to see anything!\n','\n',char(10)));
INSERT INTO rooms VALUES(1645,16,'The Armory',replace('In this room, which has somehow evaded the ravages of time, are neatly stored\nracks of common weapons.  They appear to be quite ordinary; however, a chest\nin one corner catches your eye.  The only exit is the way you came in.\n','\n',char(10)));
INSERT INTO rooms VALUES(1646,16,'The Officer''s Quarters',replace('You have entered a lavish but functional room decked out in a military style.\nMurals on the wall show battle scenes in gargoyles, minotaurs, and huge,\nflying snake-like reptiles with poisonous tails fight humans and dwarves.\nVarious objects in the room give evidence that it is occupied by individuals\nof authority.  The only door is north.\n','\n',char(10)));
INSERT INTO rooms VALUES(1647,16,'Third Level of Eastern Tower',replace('You are in the center of the Eastern Tower''s third floor.  The room you are in\nglows with a mysterious light that has no source.  In the center of the room a\nladder climbs up to a hatchway in the ceiling.  The hatchway is a strange\nlooking keyhole.  There is also a door to the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(1648,16,'Turret of the Eastern Tower',replace('You stand in the turret of the eastern tower.  A huge hole has been\nmade in the roof by some enormous beast, letting the daylight (or moonlight)\nin.  There is a hatchway in the floor, and an opening to the west leading out\nonto a catwalk.\n','\n',char(10)));
INSERT INTO rooms VALUES(1649,16,'On the Catwalk',replace('You are outdoors on a catwalk between the turrets of the eastern and \nwestern towers.  There is a 40 foot drop to the north and south.  You have\na fabulous view of the surrounding countryside, which consists of a bleak\nwilderness.  At the east end of the catwalk is a small opening leading\ninside the eastern turret.  At the western end, a strange mirror-like portal\nleads into the western turret.\n','\n',char(10)));
INSERT INTO rooms VALUES(1650,16,'Turret of the Western Tower',replace('You are in the turret of the western tower.  You feel very strange here.\nScattered about this room are a great many coins and valuable articles.\nYet you can''t get rid of a feeling of dread!  A mirror-like portal is in the\nwestern wall.\n','\n',char(10)));
INSERT INTO rooms VALUES(1651,16,'On the Other Side',replace('You are outdoors on a catwalk between the turrets of the Eastern and Western\ntowers.  There is no opening into the western tower of any kind.  You have a\nfabulous view of your surroundings, a murky city partially obscured by strange\nsmoke that creeps along the ground instead of rising. The city stretches as far\nas the eye can see under the conditions.\n','\n',char(10)));
INSERT INTO rooms VALUES(1652,16,'The Chamber',replace('You are in a small carpeted chamber. The chamber is empty except for a single\nchair facing a mirror on the wall.\n','\n',char(10)));
INSERT INTO rooms VALUES(1701,16,'Main Eastern Road',replace('You are on the old Eastern Road.  The crossroads to the east joins ANOTHER\nnorthern route to this road, which continues east.  South of the crossroads is\nan old building.  The area around here is lightly timbered.\n','\n',char(10)));
INSERT INTO rooms VALUES(1702,16,'Crossroads to the Wilderness',replace('You are at a crossroads to the wilderness areas east and north of here,\nand the more civilized areas to the west. The main road is west, an\nolder road continues east, and a simple trail heads north.  To the south,\nan old ram-shackle building is being used as a trading post for the\nsurrounding wilderness. \n','\n',char(10)));
INSERT INTO rooms VALUES(1703,16,'Trading Post',replace('You are in a trading post just south of the crossroads, where rangers,\ntrappers and hunters from the surrounding area come to buy, sell, and\nbarter goods.\n','\n',char(10)));
INSERT INTO rooms VALUES(1704,16,'Trail north of crossroads',replace('You are on a primitive north-south trail. South of here is a major cross-\nroads and an old building. To the north the trail continues toward a\ndeep, dark forest.\n','\n',char(10)));
INSERT INTO rooms VALUES(1705,16,'Trail south of forest',replace('You are on a primitive north-south trail.  Just north of here looms the\nentrance to a deep, dark forest. To the south the trail continues.\n','\n',char(10)));
INSERT INTO rooms VALUES(1706,16,'Entrance to the forest',replace('You are at the entrance to dark forest comprised mostly of huge black oak\nand towering firs.  A trail from the south continues north on into the\nwoods at this point.\n','\n',char(10)));
INSERT INTO rooms VALUES(1707,16,'Trail in Dark Oak Forest',replace('The trail here passes through groves of closely knit Black Oak. Some of\nthese trees are of enormous size.  Rustling and other low noises come\nfrom the forest on either side of the trail.  The trail continues on north\nand south.\n','\n',char(10)));
INSERT INTO rooms VALUES(1708,16,'Junction in Dark Forest',replace('You are in the midst of a deep dark forest of huge oak trees.  There is a\njunction of trails here, with paths leading south, west and east.\n','\n',char(10)));
INSERT INTO rooms VALUES(1709,16,'Path to Centaur Village',replace('You are on an east-west path in the forest.  Here the forest is mostly\ntowering firs, not quite as dense as the oak groves that can be seen eastward.\nWestward, the trail heads toward a small clearing.\n','\n',char(10)));
INSERT INTO rooms VALUES(1710,16,'The East side of the Centaur Clearing',replace('You are on the east side of a clearing.  Small primitive huts are scattered\nabout the edges of this clearing.  Beyond these on all sides are towering\nfir trees.  A path leads east out of the clearing. The clearing continues to\nthe west.\n','\n',char(10)));
INSERT INTO rooms VALUES(1711,16,'West side of the Centaur Clearing',replace('You are on the west side of the clearing in the center of the Centaur village.\nHuts surround the clearing on all sides, and beyond are towering firs.  The\nclearing continues to the east.  To the west is a very large hut.\n','\n',char(10)));
INSERT INTO rooms VALUES(1712,16,'A Centaur''s Hut',replace('You are inside a smallish hut, the home of a family of Centaurs.  The hut\nis sparsely furnished, mostly the trappings of survival.\n','\n',char(10)));
INSERT INTO rooms VALUES(1713,16,'A Centaur''s Hut',replace('You are inside a smallish hut, the home of a family of Centaurs.  The hut\nis sparsely furnished, mostly the trappings of survival.\n','\n',char(10)));
INSERT INTO rooms VALUES(1714,16,'A Centaur''s Hut',replace('You are inside a smallish hut, the home of a family of Centaurs.  The hut\nis sparsely furnished, mostly the trappings of survival.\n','\n',char(10)));
INSERT INTO rooms VALUES(1715,16,'A Centaur''s Hut',replace('You are inside a smallish hut, the home of a family of Centaurs.  The hut\nis sparsely furnished, mostly the trappings of survival.\n','\n',char(10)));
INSERT INTO rooms VALUES(1716,16,'Entrance to a Large Hut',replace('You are in the entry foyer of a large hut.  A curtain separates this section\nof the hut from the next section to the west.  To the east is an opening out\nonto the clearing.\n','\n',char(10)));
INSERT INTO rooms VALUES(1717,16,'Back of a Large Hut',replace('You are in the back of a large hut.  A curtain separates this section from\nthe front of the hut to the east.  This room is finely decorated, if\nsomewhat primitive.  The decor suggests someone of authority lives here.\n','\n',char(10)));
INSERT INTO rooms VALUES(1720,16,'Eastern Path in Dark Forest',replace('You are on an east-west path through extremely old growths of oak.  The path\nis fairly faint here.  Undergrowth closes in so closely that little can\nbe seen in any direction.\n','\n',char(10)));
INSERT INTO rooms VALUES(2001,20,'North entrance to the catacombs',replace('You are almost surprised to see a tunnel leading off to the south\ninto utter darkness.  The floorboards above you haven''t been moved\nin a long time, yet there is life down here.  A beam of light from\nthe opening above you falls upon a message scrawled on the wall here.\n\nThe message reads:\n     Adventure for the strong yet calculating\n     Death for the weak and shallow\n     Treasure for the smart and lucky\n     Death for the stupid and accursed\n\nAn ancient Glyph above the entrance keeps monsters from wandering up\nfrom the catacombs.\n','\n',char(10)));
INSERT INTO rooms VALUES(2002,20,'North/south tunnel',replace('This part of the catacombs looked roughly hewn and man-made. There is\na large cross painted on the floor of the tunnel.To the south it seems\nmaybe a bit lighter for some odd reason.  To the north a ray of light\ncomes in from a hole in the ceiling.\n','\n',char(10)));
INSERT INTO rooms VALUES(2003,20,'Weapon training area',replace('This is a place to keep up on there weapon skills.  Much of the\nequipment looks old and worn but upon further inspection seems quite\nsturdy in fact.\n','\n',char(10)));
INSERT INTO rooms VALUES(2004,20,'Prayer training area',replace('The templar''s curious mix of religion and fighting is evident here.\nA central painting depicts a cross composed of swords.  The elders\nteach the ancient art of prayer to the young pages.\n','\n',char(10)));
INSERT INTO rooms VALUES(2005,20,'Junction of hallways',replace('Training facilities are evident to the west. To the south lies a hallway\nwhich has doors every couple of feet, looks like living quarters of some\nsort.  To the east the tunnel leads back into the natural catacombs.\n','\n',char(10)));
INSERT INTO rooms VALUES(2006,20,'Hallway',replace('The hallway takes on a more indoor look to the west.  To the east it\nlooks awfully dark.\n','\n',char(10)));
INSERT INTO rooms VALUES(2007,20,'Intersection',replace('The tunnel continues to the north and the south, becoming less hewn and\nmore natural to the south.  A passageway lined with paneling leads west.\n','\n',char(10)));
INSERT INTO rooms VALUES(2008,20,'Pages'' sleeping quarters',replace('Several bunk beds are lined up across the room.  It looks rather spartan\nand there is little evidence of toys or games.  Most of the desks are\nfilled with books and papers of little interest.\n','\n',char(10)));
INSERT INTO rooms VALUES(2009,20,'Templar Knights sleeping quarters',replace('This is a huge room which is filled wall to wall with beds. Apparently\nall the low level knights all sleep in this one room.  A door on the\nsouth wall is labelled "Elders only!".\n','\n',char(10)));
INSERT INTO rooms VALUES(2010,20,'N/S hallway',replace('The hallway leads north an south.  A door leads to a templar''s room to\nthe east.  The decoration looks rather sparse here.\n','\n',char(10)));
INSERT INTO rooms VALUES(2011,20,'A Middle-aged templar''s room',replace('This is a room furnished in a room becoming a low level templar scribe.\nNo real amenities but better than a communal sleeping quarters. As far\nas you can tell he would be a rank equivalent to a Sargeant.\n','\n',char(10)));
INSERT INTO rooms VALUES(2012,20,'Humid, damp tunnel',replace('As the tunnel leads south it gets more humid and damp.  Moss covers the\nwalls and ferns even grow in the cracks here and there.  To the north it\nseems much more sterile.\n','\n',char(10)));
INSERT INTO rooms VALUES(2013,20,'Administration room',replace('The elders gather here to discuss training strategies and count their\nloot.  You notice papers which look like important secret documents\nlying around. An escape passage leads west.\n','\n',char(10)));
INSERT INTO rooms VALUES(2014,20,'N/S hallway',replace('The hallway continues to become more important-looking as you wander\nsouth.  A room to the east looks rather more pleasant that some of the\nothers.\n','\n',char(10)));
INSERT INTO rooms VALUES(2015,20,'Mid-level leader''s room',replace('A rather nice looking room considering the drab conditions down here.\nThrough all the signs of decoration you can still see evidence of water\nleaks.\n','\n',char(10)));
INSERT INTO rooms VALUES(2016,20,'Mess hall',replace('The a huge table with an immaculate white table cloth stretches way off\nto the south.  The room is kept immaculately clean by the nights\nthemselves.  They truly belive that cleanliness is next to godliness.\n','\n',char(10)));
INSERT INTO rooms VALUES(2017,20,'N/S hallway',replace('The hallway continues north and south.  A peculiar kind of glow seems\nto come from somewhere further along the hallway to the south. The room\nto the east looks like the lap of luxury.\n','\n',char(10)));
INSERT INTO rooms VALUES(2018,20,'High officer''s room',replace('First thing you notice in this room is the pleasant aroma of cedar.  All\nthe paneling in the room is made of fine cedar.  A painting of an\nelegant knight hangs on the wall.\n','\n',char(10)));
INSERT INTO rooms VALUES(2019,20,'Mossy intersection',replace('There is a turn off to the passage here.  The main passage leads north\nand south. To the south it seems to get impossibly darker.  To the east\nyou hear... birds?  A small rivulet of water seeps in from the passage\neast.  The air is very humid and damp here.\n','\n',char(10)));
INSERT INTO rooms VALUES(2020,20,'The holy grove',replace('A small grove of birches grow seem to grow from solid rock.  You hear\nbirds singing but try as you might you cant see any.  A strange glow\nemanates from a place somewhere to the southeast in the grove.\n','\n',char(10)));
INSERT INTO rooms VALUES(2021,20,'The holy grove',replace('The trees seem real enough even though they take root in solid rock.\nYou hear other small animals scampering through the light undergrowth\nyet you see nothing. The grove continues south, east and west. An out of\nplace passage way for some reason heads north.\n','\n',char(10)));
INSERT INTO rooms VALUES(2022,20,'The holy grove',replace('The grove continues west and south.  The glow is roughly to the south\nsomewhere.\n','\n',char(10)));
INSERT INTO rooms VALUES(2023,20,'Mess hall',replace('"mess" isn''t exactly the best word to describe this room.  On the\ncontrary, it is immaculately clean.  A very long table stretches way off\nto the north. A hallway is to the east.\n','\n',char(10)));
INSERT INTO rooms VALUES(2024,20,'End of a hallway',replace('You hear voices coming from a room to the west.  the hallway goes north.\nTo the east lies a room which seems to glow with power and piety.\n','\n',char(10)));
INSERT INTO rooms VALUES(2025,20,'Grand Templar''s room',replace('All the items in this room look ancient yet strangely very powerful and\nrich.  There is an aura of great holiness about the room.\n','\n',char(10)));
INSERT INTO rooms VALUES(2026,20,'Very dark passage',replace('This room is so dark that even powerful magic lights seems to barely\nilluminate the ground in front of you.  If its possible it seems even\ndarker to the south.  The passage also leads back north.\n','\n',char(10)));
INSERT INTO rooms VALUES(2027,20,'The holy grove',replace('The grove continues north and east.  To the east a strange humming can\nbarely be heard.\n','\n',char(10)));
INSERT INTO rooms VALUES(2028,20,'The holy grove',replace('All of a sudden all the mysterious sounds of the grove stop. Or perhaps\nits just the strange humming and glowing from a clearing to the south\ndrowning out everything else. There is a sort of magical forcefield door\nto the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(2029,20,'Very dark caveway',replace('This room is so very dark that no one is quite sure whats in it, so\nthere''s nothing really to describe except maybe the powerful sense of\nevil coming from the east and the almost overcoming urge to run to the\nwest.\n','\n',char(10)));
INSERT INTO rooms VALUES(2030,20,'Deep within the catacombs',replace('It stinks like a lair in here.  A rotten smell of humanoid flesh\nlingers.  You stumble over what you think are corpses in the utter\ndarkness. You sense a evil growl from somewhere in the room. maybe\neverywhere in the room. . ..\n','\n',char(10)));
INSERT INTO rooms VALUES(2031,20,'Very dark cavern',replace('The cavern is hard to describe due to the extreme magical darkness.\nProbing with a light source seems to reveal nothing but more darkness.\n','\n',char(10)));
INSERT INTO rooms VALUES(2032,20,'The holy place',replace('A glowing stone lies in the center of the clearing.  You recognize it as\nthe stone of the Excalibur.  The strange humming glowing makes it\ndifficult to see if the Excalibur is there or not. Might want to take a\ncloser look if possible.\n','\n',char(10)));
INSERT INTO rooms VALUES(2033,20,'Misty passageway',replace('Warm mist swirl about you making you feel threatened as well as\nprotected at the same time.  The swirling mist makes it tough to tell\ndirections quite clearly, but you seem to be able to go north or south.\nThe mist gets denser to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(2034,20,'Intersection of caverns',replace('Caverns head north, south and east from this peculiar spot. Medium\nsized caverns from the east and the north join to form a huge cavern\nheading south.  The walls of the cavern are made of a bizarre mixture\nof many shiny crystals.\n','\n',char(10)));
INSERT INTO rooms VALUES(2035,20,'Entrance to the burial grounds',replace('You have entered what appears to be a burial ground of sorts. The\ntemplars buried their dead here.  Chills go down your spine as you feel\nsomething watching you.  You hear the random groan of a ghost, the howl\nof a wraith, and the dry clanking of bones.\n','\n',char(10)));
INSERT INTO rooms VALUES(2036,20,'The burial grounds',replace('Random tombs to unknown warriors were lain in rows as far as the eye\ncan see.  To your horror many of the graves are empty and desecrated.\nA gap in the rows of tombs leads south and there are more graves to the\neast and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(2037,20,'The burial grounds',replace('It seems as if many of the warriors could not stop fighting even in\ndeath.  They fight amongst each other and flail at any living being\nthat would wander near.\n','\n',char(10)));
INSERT INTO rooms VALUES(2038,20,'The burial grounds',replace('Legions of skeletal warriors wander by and battle the enemy even in\ndeath.  Old battlelines have been forgotten and new ones made. Its a\ngruesome scene.\n','\n',char(10)));
INSERT INTO rooms VALUES(2039,20,'New graves',replace('The tombs in this section seem somewhat more recent.  Rotting zombie\nwarriors groan and wail with blank stares.  You hear sounds of digging\noff a bit to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(2040,20,'Misty cavern',replace('A chilling icy mist swirl about you.  The dampness and warmth has become\nbitter cold.  The walls of the cavern are several feet thick with ice\nhere.  An icy wind blows from the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(2041,20,'Misty cavern',replace('The temperature is a pleasant and mild here.  This is due to a warm wind\nblowing in from the east and a chilly breeze blowing in from the west.\nThe updrafts create bizarre icy-steamy mists which dance along the\nwalls.\n','\n',char(10)));
INSERT INTO rooms VALUES(2042,20,'Mist cavern',replace('A warm wind blows in from the east.  The air is still stifling hot in\nhere despite the breeze.  The mist seems thick enough to be alive. . .\n','\n',char(10)));
INSERT INTO rooms VALUES(2043,20,'Waterfall of mist',replace('River of hot mist pour down in a cascade from a hole in the cavern.  It\nfalls like water down from the heights like a waterfall and creates\nbeautiful swirls.  It causes a hot wind to flow west.\n','\n',char(10)));
INSERT INTO rooms VALUES(2044,20,'Huge multicolored tunnel',replace('The tunnel leads north and south.  To the south there is an odd\ntwinkling phenomenon.\n','\n',char(10)));
INSERT INTO rooms VALUES(2045,20,'Desolate ruins',replace('Several mausoleums used to grace the way here but these have been\ndefiled. And most have been torn down and burned by looters. Some still\nseem to be intact to the south.  To the northwest is a seeming field of\ntombs of soldiers, now a battleground for the undead.\n','\n',char(10)));
INSERT INTO rooms VALUES(2046,20,'Curators place',replace('The undertaker, the historian and the curator used to be here. Now they\ntoo have joined the legions of the undead.  From the looks of the place\nthey seem to have starved to death.  Rickety stairs head down into a\nsort of basement.\n','\n',char(10)));
INSERT INTO rooms VALUES(2047,20,'Fresh graves',replace('Graves of recent casualties lie here.  Even the most recent don''t seem to\nhave been left undisturbed.  You hear sounds of digging in progress\nfurther to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(2048,20,'Twisty cavern',replace('The way twist this way and that and its all you can do to keep your head\nfrom spinning.  The air is very cold here and layers of ice on the wall.\nThe sounds of metal on ice echo through the cavern. A side passage leads\neast and the main passage goes north and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(2049,20,'Striped tunnel',replace('The walls of the tunnels have many brilliant colors in them from the\nvarious veins of crystals running in them.  An odd twinkling comes from\nthe east.\n','\n',char(10)));
INSERT INTO rooms VALUES(2050,20,'Prism cave',replace('The roof of this cave peaks over a hundred feet high making it one of\nthe biggest in the catacombs.  Crystals of every color cast prismatic\nsprays of light everywhere.  The light from your lamp causes almost a\nblinding flare of brilliance as more light is added to the multi-colored\ntwinkling phenomenon that exists here.  This is also the lair of the\nfabled and feared Prism Dragon.\n','\n',char(10)));
INSERT INTO rooms VALUES(2051,20,'Ruined monument',replace('A monument to a famous king once stood here. Not much is left to even\nsignify that is was here at all.  A building of some sort can be entered\nthrough a basement to the east.  The southern gate of the grounds is to\nthe south.\n','\n',char(10)));
INSERT INTO rooms VALUES(2052,20,'Basement',replace('Its dark and it smells like. ...BATS down here!  All you see is a swirl\nof the darkness and lots of scratching bats madly flailing around. A set\nof stairs go up into the building and a broken window leads west.\n','\n',char(10)));
INSERT INTO rooms VALUES(2053,20,'Fresh graves',replace('The graves here seem very recent.  You notice many signs of digging and\ndefilement.  There are piles of fresh bodies here awaiting burial.  A\nstrange sense of evil magic from the south makes the hairs on the back\nof your neck to stand on end!\n','\n',char(10)));
INSERT INTO rooms VALUES(2054,20,'Southern gate',replace('A rusty gate here no longer keeps anyone out or in.  You see a lonely\nE/W passage to the south.  A little used trail winds east through a\ncrack in the wall.\n','\n',char(10)));
INSERT INTO rooms VALUES(2055,20,'Scene of ghastly horror',replace('An army of undead creatures of all types are lined up patiently. Their\nleader is an evil demonoid necromancer.  His plans to use his army of\nundead to take over the world seem about ready to get underway.\n','\n',char(10)));
INSERT INTO rooms VALUES(2056,20,'Twisty passage',replace('The passage bends north and east here.  To the east your not certain\nwhat lies ahead due to all the twists and turns you''ve made.  To the\nnorth is seems cold.\n','\n',char(10)));
INSERT INTO rooms VALUES(2057,20,'Cross of caverns',replace('A little-used cavern enters from the south. A passage twists away to\nthe west.  An odd twinkling comes from the cave to the north.\n','\n',char(10)));
INSERT INTO rooms VALUES(2058,20,'Lonely tunnel',replace('Something indescribable makes you feel lonesome and sad here. Its just\na feeling you get from this tunnel.  The tunnel east and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(2059,20,'Lonely tunnel',replace('Something indescribable makes you feel lonesome and sad here. You see a\ngate to a burial ground to the north.  This lonesome tunnel sighs along\nwest and east.\n','\n',char(10)));
INSERT INTO rooms VALUES(2060,20,'Bend in the lonely tunnel',replace('Something indescribable makes you feel lonesome and sad here. The\ntunnel bends west and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(2061,20,'Lonely tunnel',replace('Something indescribable makes you feel lonesome and sad here. The very\nwalls of the tunnel seems to groan.  to the north the tunnel bends and\neast is an intersection.\n','\n',char(10)));
INSERT INTO rooms VALUES(2062,20,'Intersection',replace('To the north you enter the burial grounds.  a trail of blood leads that\ndirection.  Also you feel an ominous sense of evil magic from there.\nThe tunnel to the west creaks and sighs as if alive.  To the south you\nsmell a hint of fresh air.\n','\n',char(10)));
INSERT INTO rooms VALUES(2063,20,'Tunnel',replace('The tunnel heads north and south.  North you see an intersection and\nfar to the south you sense light and smell a fresh breeze.\n','\n',char(10)));
INSERT INTO rooms VALUES(2064,20,'Tunnel',replace('The tunnel slopes noticeably down to the north and you sense the surface\ncould be reached to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(2065,20,'Southern entrance to the catacombs',replace('Through a trapdoor above you streams light.  Through a doorway to\nthe south streams darkness.  A message has been scrawled upon the wall\nhere.  The message reads:\n     Adventure for the strong yet calculating\n     Death for the weak and shallow\n     Treasure for the smart and lucky\n     Death for the stupid and accursed\nAn ancient Glyph above the entrance keeps monsters from wandering up\nfrom the catacombs.\n','\n',char(10)));
INSERT INTO rooms VALUES(2066,20,'Unknown passage',replace('Oh dear you seem to have lost your way.  You look back from whence you\ncame but there''s no exit there anymore.  There are exits in other\ndirections but you have a feeling that you are hopelessly lost.\n','\n',char(10)));
INSERT INTO rooms VALUES(2067,20,'Unknown passage',replace('Oh dear you seem to have lost your way.  You look back from whence you\ncame but there''s no exit there anymore.  There are exits in other\ndirections but you have a feeling that you are hopelessly lost.\n','\n',char(10)));
INSERT INTO rooms VALUES(2068,20,'Unknown passage',replace('Oh dear you seem to have lost your way.  You look back from whence you\ncame but there''s no exit there anymore.  There are exits in other\ndirections but you have a feeling that you are hopelessly lost.\n','\n',char(10)));
INSERT INTO rooms VALUES(2069,20,'Unknown passage',replace('Oh dear you seem to have lost your way.  You look back from whence you\ncame but there''s no exit there anymore.  There are exits in other\ndirections but you have a feeling that you are hopelessly lost.\n','\n',char(10)));
INSERT INTO rooms VALUES(2101,21,'A Dark Alleyway',replace('The walls of the alleyway have been spray-painted over many times\nover the years.  One section of graffiti actually looks legible,\nit says:    This section has been designed for levels 5 through 10\n            If you are above level 15 please don''t expect much fun.\n            If you are below level 5 enter at your own risk.\nAnother section of graffiti says "Raff Rules!"\nThere is a boulevard to the east and Wall Road East is to the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(2102,21,'Beginning of White Dragon Boulevard',replace('This section of town has been overrun by the Troll gang.  Even the\npolice stay out of here for fear of being brutalized.  This was once\na nice lower-middleclass neighborhood, but know the gangs run the\nstreets.  All the shops and homes have been boarded up and abandoned.\nAn alleyway is to the west and the street continues east.  An over-\ngrown lot is to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(2103,21,'Along White Dragon Boulevard',replace('Everywhere you look you see signs of recent violence.  Patches of blood\nlie everywhere and broken sticks and abandoned knifes are strewn here\nand there.  An over-grown lot is to the south.  White Dragon Boulevard leads\neast and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(2104,21,'White Dragon Boulevard at Armory',replace('Only gang members dare wander the streets here.\nWhat used to be the armory lies to the south.  White Dragon Boulevard\nleads east and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(2105,21,'White Dragon Blvd.',replace('Black Dragon Avenue used to run south from here but the way has been\nblocked by the toppling of a building into the street.  White Dragon\nboulevard continues east and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(2106,21,'Corner of Ice and White Dragon',replace('Ice Dragon Way leads south from here.  It used to run the whole length\nof the neighborhood and way lined with beautiful crystal sculptures.\nWhite Dragon boulevard leads east and west from here.\n','\n',char(10)));
INSERT INTO rooms VALUES(2107,21,'White Dragon Boulevard',replace('A once majestic inn with a white marble facade lies to the south.\nUnfortunately, it has fallen into disrepair and decay.  You can continue\neast or west.\n','\n',char(10)));
INSERT INTO rooms VALUES(2108,21,'Corner of Bronze and White Dragon',replace('This is the north-east corner of the neighborhood. White Dragon\nboulevard heads west and Bronze Dragon street heads south.\n','\n',char(10)));
INSERT INTO rooms VALUES(2109,21,'An over-grown lot',replace('A huge building was going to be built here, but they gave the\nproject up when violence took over the town.  Now it is just a\nweed-strewn plot of land.  The lot continues east and there is a road north.\n','\n',char(10)));
INSERT INTO rooms VALUES(2110,21,'East end of an over-grown plot of land',replace('This was planned to be a park, but the developer was scared out\nof town by the gang.  Now it is just a dusty square of land. The\npark was started to the south.  The lot continues west and there\nis a street to the north.\n','\n',char(10)));
INSERT INTO rooms VALUES(2111,21,'Armory',replace('Well actually, this is what USED to be the armory.  The equipment has\nall been stolen or broken beyond repair. The back wall of the\nbuilding has been bashed down, allowing you to go south.  White\nDragon Boulevard is north.\n','\n',char(10)));
INSERT INTO rooms VALUES(2112,21,'A Bend in the Way',replace('Ice Dragon Way bends east and south from here.  You notice a lot of\nblood dried into the dirt here.\n','\n',char(10)));
INSERT INTO rooms VALUES(2113,21,'Ice Dragon Bend',replace('Ice Dragon Way bends to the north and west here.  There are footprints\nhere.  They seem to indicate a large struggle took place here\nrecently.  What used to be the town Magic shop is to the east.\n','\n',char(10)));
INSERT INTO rooms VALUES(2114,21,'The remains of the magic shop',replace('The wizard was tough but he couldn''t take on 50 of them at once.  So he\ndied and they took all his stuff and used it on their fellowmen.\nThe front door leads west back out to the street.  There is a back\ndoor leading to another street to the east.\n','\n',char(10)));
INSERT INTO rooms VALUES(2115,21,'Bronze Dragon Street at wizard''s back door',replace('Bronze Dragon street goes north and south.  The back door to what\nremains of the magic shop is west.\n','\n',char(10)));
INSERT INTO rooms VALUES(2116,21,'Dracolich Plaza',replace('They began construction of a pleasant plaza here.  You wouldn''t have\nknown it though if i hadn''t told you.  It has been renamed in honor\nof the Dragon gang''s idol, the Dracolich.  It has become sort of a\ntraining ground.  There is a short cut to the east and an overgrown\nlot of land to the north.\n','\n',char(10)));
INSERT INTO rooms VALUES(2117,21,'Shortcut',replace('This is a shortcut between Dracolich Plaza and the center of town.\nDracolich Plaza is to the west and the shortcut continues south.\n','\n',char(10)));
INSERT INTO rooms VALUES(2118,21,'Ice Dragon Way',replace('Several smashed crystal statues line the Way here.  You begin to wonder\nwho smashed them, and with what.  The Way bends out of sight to the north\nand continues south.  To the east is a courtyard.\n','\n',char(10)));
INSERT INTO rooms VALUES(2119,21,'Courtyard North',replace('Once it was the courtyard of a beautiful building complex.  But alas,\nsomeone forgot to water the plants and they all died.  Then again,\nyou wonder how many people have died here too.  The courtyard extends\nto the south and there is a road to the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(2120,21,'Bronze Dragon Street',replace('There used to be a gate out to the east here which led to distant lands.\nThe gate has rusted permanently shut.  The street goes north and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(2121,21,'Shortcut',replace('The shortcut extends north.  There is a street to the east.\n','\n',char(10)));
INSERT INTO rooms VALUES(2122,21,'Ice Dragon Way',replace('The Way continues north and intersects with Yellow Dragon Avenue\nto the south.  For some reason, you somehow realize that there is a\nshortcut to the west that leads to Dracolich Plaza.\n','\n',char(10)));
INSERT INTO rooms VALUES(2123,21,'Courtyard South',replace('Once full of lush green plants, it is now barren of growth.  A set of\nstairs used to extend up to a suite of rooms but the set is missing\nstairs 3-15.  The courtyard extends north and there is a street to\nthe south.\n','\n',char(10)));
INSERT INTO rooms VALUES(2124,21,'Old Abandoned Warehouse',replace('Once the center of a lucrative storage business, it has fallen to\ndisrepair like everything else.  It is now the hideout of the\nDragon gang.  The gang leader runs his reign of terror from here.\nThere is a wooden door barely on the hinges to the east.\n','\n',char(10)));
INSERT INTO rooms VALUES(2125,21,'Bronze Dragon Street at Warehouse',replace('The street runs north and south.  There is an old wooden door leading\nto a warehouse to the west.  The warehouse LOOKS abandoned. . .\n','\n',char(10)));
INSERT INTO rooms VALUES(2126,21,'Yellow Dragon Road',replace('Yellow Dragon Road is the southern boundary of Troll Territory.  The\nroad extends east.  You enter "no-man''s land" to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(2127,21,'Yellow Dragon Road',replace('The road runs east and west.  Ice Dragon Way leads north from here.\n','\n',char(10)));
INSERT INTO rooms VALUES(2128,21,'Yellow Dragon Road',replace('The roads continues east and west.  There is a courtyard to the north.\nYou enter "no man''s land" to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(2129,21,'Yellow Dragon Road',replace('There is a barred window to the north.  There appears to be a light\ncoming from the cracks around it.  The road extends east and west\nfrom here.  Or you can enter "no man''s land" south from here.\n','\n',char(10)));
INSERT INTO rooms VALUES(2130,21,'Yellow Dragon Road',replace('Bronze Dragon Street intersects here and runs north.  Yellow Dragon ends\nhere but continues to the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(2131,21,'NO MAN''S LAND',replace('This is the section of town between the two gang''s territories.  This\nis usually where the violence starts.  No Man''s land continues south\nand east; or there is a street to the north.\n','\n',char(10)));
INSERT INTO rooms VALUES(2132,21,'NO MAN''S LAND',replace('This is the section of town between the two gang''s territories.  This\nis usually where the violence starts.  No Man''s land continues south\neast and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(2133,21,'NO MAN''S LAND',replace('This is the section of town between the two gang''s territories.  This\nis usually where the violence starts.  No Man''s land continues south,\neast and west; or there is a street to the north.\n','\n',char(10)));
INSERT INTO rooms VALUES(2134,21,'NO MAN''S LAND',replace('This is the section of town between the two gang''s territories.  This\nis usually where the violence starts.  No Man''s land continues south,\neast, and west; or there is a street to the north.\n','\n',char(10)));
INSERT INTO rooms VALUES(2135,21,'NO MAN''S LAND',replace('This is the section of town between the two gang''s territories.  This\nis usually where the violence starts.  No Man''s land continues south\nand west.\n','\n',char(10)));
INSERT INTO rooms VALUES(2136,21,'NO MAN''S LAND',replace('This is the section of town between the two gang''s territories.  This\nis usually where the violence starts.  No Man''s land continues north\nand east; or there is a street to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(2137,21,'NO MAN''S LAND',replace('This is the section of town between the two gang''s territories.  This\nis usually where the violence starts.  No Man''s land continues north,\neast and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(2138,21,'NO MAN''S LAND',replace('This is the section of town between the two gang''s territories.  This\nis usually where the violence starts.  No Man''s land continues north,\neast, and west; or there is a street to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(2139,21,'NO MAN''S LAND',replace('This is the section of town between the two gang''s territories.  This\nis usually where the violence starts.  No Man''s land continues north,\neast, and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(2140,21,'NO MAN''S LAND',replace('This is the section of town between the two gang''s territories.  This\nis usually where the violence starts.  No Man''s land continues south\nand west; or there is a street to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(2141,21,'Bend in Hector Street',replace('Hector street bends to the east and the south here.  "No Man''s Land"\nentrance is to the north.\n','\n',char(10)));
INSERT INTO rooms VALUES(2142,21,'Hector Street at Bakery',replace('Hector street runs east and west.  The Bakery used to be to the south\nbut the entrance is sealed off.  Probably just a bunch of stale pies in\nthere anyways.\n','\n',char(10)));
INSERT INTO rooms VALUES(2143,21,'Another corner of Hector and Achilles streets',replace('Achilles street heads to the south and Hector runs east and west.\nThere is an entrance to "No Man''s Land" to the north.  On the\nsouthwest corner of this intersection, it looks like a building\nwas recently burned down.\n','\n',char(10)));
INSERT INTO rooms VALUES(2144,21,'Hector Street at Jeweler',replace('Once a bright spot in the town, it now looks like one of the\nhardest hit by the violence.  The building could collapse at any\nmoment.  The street continues east and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(2145,21,'Corner of Ajax and Hector',replace('There is a grand fountain to the east but the water doesn''t\nlook good to drink.  Ajax street heads south and Hector\ngoes back west.  "No Man''s Land" is to the north.\n','\n',char(10)));
INSERT INTO rooms VALUES(2146,21,'Hector Street',replace('The street is full of garbage here.  An odd building lies to the west,\nbut you don''t seem to be able to find a way into it.  The street\nruns north and south here.\n','\n',char(10)));
INSERT INTO rooms VALUES(2147,21,'Achilles Avenue',replace('The town bards sang of the victory parades that used to pass along this\nroute.  It was once a major way through the center of town.  The street\ngoes south to a bend and north to an intersection.\n','\n',char(10)));
INSERT INTO rooms VALUES(2148,21,'A small ruined chapel',replace('This was a small temple built to honor the minor gods and goddesses.\nIt is now desecrated by graffiti and vandalism.  Perhaps its worst\ndefilement is that it is the hangout of the Ogre gang.  There is a street to\nthe east through a rusty metal door.\n','\n',char(10)));
INSERT INTO rooms VALUES(2149,21,'Ajax Avenue at chapel',replace('The temple to honor the minor gods is through a rusty metal door\nto the west.  The street continues north and south.  You hear the\nmuffled sounds of screams coming from the chapel.\n','\n',char(10)));
INSERT INTO rooms VALUES(2150,21,'First intersection of Hector and Achilles',replace('There is a large statue here depicting a battle between two\ngreat warriors.  You think it''s odd that it has not been defiled,\nbut then you sense a aura protecting it.  Achilles runs east\nand south, while Hector heads out to the north.\n','\n',char(10)));
INSERT INTO rooms VALUES(2151,21,'Hector street',replace('A large open space, possibly a cemetery, lies to the south.\nThere is a large wrought-iron fence with spikes on top\nwhich prevents you from entering the area.  The street\ncontinues east and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(2152,21,'A bend in the road',replace('Achilles Avenue bends to the north and west here.  There\nis also a narrow alley to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(2153,21,'What is left of the weaponshop',replace('It doesn''t even look like those punks gave the weaponsmith a\nproper burial.  But what a going away present he seems to have\nreceived!  Blood is splattered and dried all over the walls here.\nIt looks like a great deal of carnage happened here.  The way\nout to the east leads out onto a street.\n','\n',char(10)));
INSERT INTO rooms VALUES(2154,21,'Ajax street at Weaponshop (or whats left of it)',replace('The street goes north and south.  The stables used to be to the\neast, but I bet all the horses are dead or gone.\n','\n',char(10)));
INSERT INTO rooms VALUES(2155,21,'Khan Park',replace('Not really a "park" as you and i would think of it but\nit seems queerly peaceful here in comparison to the rest of\nthe area.  There seems to be some kind of memorial to the\ngreat Mongol warrior Khan being crudely constructed here.\nThere is a street to the east and another to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(2156,21,'Achilles avenue at entrance to park',replace('A ... park?! lies to the west.  The street runs south to an\nintersection and curves to the north.\n','\n',char(10)));
INSERT INTO rooms VALUES(2157,21,'A bend in Ajax',replace('The roads bends south and east here.  You barely notice\na small alley leading north.  Some kind of tunnel entrance\nis to the west but it has been crushed under its own weight.\n','\n',char(10)));
INSERT INTO rooms VALUES(2158,21,'Ajax street',replace('A once prideful guildhouse was on the northeast corner of\nthis intersection.  Most of the walls and ceiling have long since\nbeen demolished.  An inn/pub is to the south.  The street bends\nto the east or west.\n','\n',char(10)));
INSERT INTO rooms VALUES(2159,21,'Curve in the road',replace('The street goes north or west from here.  A narrow street once\nheaded southeast from here.\n','\n',char(10)));
INSERT INTO rooms VALUES(2160,21,'A wide alleyway',replace('The sides of the alleyway have been vandalized many times.\nOne patch of graffiti actually looks readable:\n            This section has been designed for levels 5 through 10\n            If you are above level 10 please don''t expect much.\n            If you are below level 5 enter at your own risk.\nIn another spot it says "now entering Ogre territory..."\nA street lies to the west and a major road to the east.\n','\n',char(10)));
INSERT INTO rooms VALUES(2161,21,'Alexander Road',replace('You see many gang members walking around looking for\nfights to pick and things to break.  It seems as if all of the\nother citizens have been run out of town.  All the former\nhomes are boarded up and uninhabitable.  The road continues\neast and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(2162,21,'Alexander Street at park entrance',replace('A park-looking area lies to the north and a passage between\ntwo buildings leads to another street to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(2163,21,'Achilles Avenue',replace('The Avenue Runs north and south.  You sense you are deep within\nOgre gang territory, and a chill goes up your spine.\n','\n',char(10)));
INSERT INTO rooms VALUES(2164,21,'Ajax Street',replace('You can see a sinister black wrought-iron fence to the west.\nYou wonder if it''s keeping you out, or the ghouls in?\n','\n',char(10)));
INSERT INTO rooms VALUES(2165,21,'The inn/pub',replace('The inn actually looks fairly functional despite its lack\nof repair.  The boys come here to hoot it up and drink them selves\ninto oblivion sometimes.  It looks as if the beer is still on tap!!!\nA hallway leads south and you spy a street through the doorway\nto the north.\n','\n',char(10)));
INSERT INTO rooms VALUES(2166,21,'Solomon Street',replace('This street forms the southern boundary of Ogre territory.  The\nstreet extends far to the east.  There is also a pathway between\nbuildings which leads to another street to the north.\n','\n',char(10)));
INSERT INTO rooms VALUES(2167,21,'Intersection of Achilles and Solomon',replace('Solomon street is to the east and west.  The other part of the\nT is Achilles Avenue, starting here and winding to the north.\n','\n',char(10)));
INSERT INTO rooms VALUES(2168,21,'Solomon Street',replace('A wrought-iron fence blocks off what used to be an entrance to the\ncemetery here to the north.  The evil just seems too strong to\nto consider entering.  You feel you should stick with the "lesser"\nevils along the road to the east and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(2169,21,'Intersection of Ajax and Solomon',replace('The two roads meet at a corner here.  Ajax runs north and\nSolomon heads west.  An inn/pub is through a back doorway\nto the east.\n','\n',char(10)));
INSERT INTO rooms VALUES(2170,21,'Hallway',replace('The hallway heads back north to the main part of the inn/pub.\nThe stairs leading up to the guest rooms here do not seem\nadvisable to climb.  A doorway empties out into Solomon\nstreet to the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(2171,21,'Wall Road',replace('The road extends south along the inside of the wall surrounding\nthe city.  You spy a city gate to the north.\n','\n',char(10)));
INSERT INTO rooms VALUES(2172,21,'Wall Road',replace('Wall road extends north along the inside of the city wall.  A dark\nalley lies to the east.\n','\n',char(10)));
INSERT INTO rooms VALUES(2201,22,'The Tower Gates',replace('You are at the entrance to a tall tower.  Lightning flashes periodically and\nit is raining.  You think it might be a good idea to turn back into the grove.\n','\n',char(10)));
INSERT INTO rooms VALUES(2202,22,'The Foyer',replace('This is the entrance to the Tower.  The hallway continues to the north,\nleading towards a staircase.  You notice a grim painting on the wall,  and \nquickly look away.\n','\n',char(10)));
INSERT INTO rooms VALUES(2203,22,'Hallway',replace('This hallway seems to stretch on forever.  You notice a stairway in  \nthe distance. \n','\n',char(10)));
INSERT INTO rooms VALUES(2204,22,'Hallway',replace('You trudge down the hallway.  You notice doors to the east and west. \n','\n',char(10)));
INSERT INTO rooms VALUES(2205,22,'Nursery',replace('It looks like a tornado has been through here.  Toys are scattered everywhere,\nand a small group of dragon hatchlings are fighting over a bone. \n','\n',char(10)));
INSERT INTO rooms VALUES(2206,22,'Storage Room',replace('This room is covered with dust, it looks as if no one has been here in ages.\n','\n',char(10)));
INSERT INTO rooms VALUES(2207,22,'End of the Hallway',replace('You have finally reached the end of the hallway.  A huge staircase leads up.\nYou see a sign at the base of the staircase. \n','\n',char(10)));
INSERT INTO rooms VALUES(2208,22,'Guardian''s Room',replace('You climb down the rickety stairs and find yourself face to face with a \ngargantuan hydra.  How fast can you climb UP stairs? \n','\n',char(10)));
INSERT INTO rooms VALUES(2209,22,'The Treasure Room',replace('You have made it past the hydra into the vault.  You are astounded by \nthe treasure here.  Not only are you now rich, you can probably rest here\nsafely.  The west wall seems to have a large door made entirely of ruby.\n','\n',char(10)));
INSERT INTO rooms VALUES(2210,22,'The Second Floor',replace('You have made it up to the second floor.  You hear hissing and see several\ndragon men rushing you.  You wonder how long you will be staying here.\n','\n',char(10)));
INSERT INTO rooms VALUES(2211,22,'The Court',replace('You have entered what seems to be a large court.  The people guarding it\ndon''t seem happy to see you ...\n','\n',char(10)));
INSERT INTO rooms VALUES(2212,22,'Hall O'' Pleasure',replace('You stop dead in your tracks as you enter this ornately decorated room - it\nis populated with the king''s harem.  \n','\n',char(10)));
INSERT INTO rooms VALUES(2213,22,'The Court',replace('You are continuing down the hall.  To the east and west you see ornate doors.\n','\n',char(10)));
INSERT INTO rooms VALUES(2214,22,'The Library',replace('You have entered a huge room, filled with books.  A peaceful man is\nsitting at a table, studying.\n','\n',char(10)));
INSERT INTO rooms VALUES(2215,22,'The Sanctum',replace('This small room is modestly decorated with small dragon icons.  Its sole\noccupant is deep in thought.\n','\n',char(10)));
INSERT INTO rooms VALUES(2216,22,'The Court Ends',replace('You have reached the end of the court.  A huge Draconian is sitting in a\nchair here.  As you enter, he motions with his hand and you are rushed by three\nof his bodyguards.\n','\n',char(10)));
INSERT INTO rooms VALUES(2217,22,'bedroom',replace('This is the personal room of the draconian king.  It is not empty.\n','\n',char(10)));
INSERT INTO rooms VALUES(2218,22,'Entrance to the Crypt',replace('You have entered a large room which smells heavily of reptile.  You wonder\nwhat awaits you here.\n','\n',char(10)));
INSERT INTO rooms VALUES(2219,22,'Crypt',replace('You are in a large room which continues to the west.  You notice many\ncoffins here.  Open coffins reveal remains of something other than man.  \nThe smell of reptile is very strong here.\n','\n',char(10)));
INSERT INTO rooms VALUES(2220,22,'The Lair',replace('You have entered a large room dominated by a great white dragon.  It growls\nat you before it attacks.\n','\n',char(10)));
INSERT INTO rooms VALUES(2221,22,'A Lair',replace('You have entered a large room dominated by a great black dragon.  It looks\nas though it is amused by your presence.\n','\n',char(10)));
INSERT INTO rooms VALUES(2222,22,'The Crypt Ends',replace('You have come to the end of the Crypt.  It seems deserted.  There is a \nstrange coffin lying against the wall.\n','\n',char(10)));
INSERT INTO rooms VALUES(2223,22,'Entrance to the Great Hall',replace('You have entered a huge hall.  It has been carefully decorated with\nbeautiful tapestries depicting a great battle between dragons and men.  The\ndragons appear to be the victors.\n','\n',char(10)));
INSERT INTO rooms VALUES(2224,22,'The Great Hall',replace('You are working your way down the Hall.  To the north, you notice a smaller\npassageway, while the main hall continues to the east.\n','\n',char(10)));
INSERT INTO rooms VALUES(2225,22,'A Narrow Passageway',replace('This Passageway branches off from the main hall and leads somewhere ... where?\n','\n',char(10)));
INSERT INTO rooms VALUES(2226,22,'Lair',replace('You have entered a large lair with bones strewn about the ground.  You\nnotice the source of these as you come face to face with a rather large red\ndragon.  You notice a trap door in the floor.\n','\n',char(10)));
INSERT INTO rooms VALUES(2227,22,'Underground Tunnel',replace('You have entered an underground tunnel.  It is dark and dirty, and you find\nyourself wishing you were back in Midgaard.\n','\n',char(10)));
INSERT INTO rooms VALUES(2228,22,'Underground Tunnel',replace('This tunnel has come to a dead end.  You feel nervous about being trapped here.\n','\n',char(10)));
INSERT INTO rooms VALUES(2229,22,'The Great Hall Ends.',replace('You have come to the end of the great hall.  You see before you a huge\ngolden door, it must be at least twenty feet tall!  It has beautiful etchings\nof dragons.  You see a sign on the door.\n','\n',char(10)));
INSERT INTO rooms VALUES(2230,22,'THE Lair',replace('You have entered a huge lair.  You feel that something big lives here or at least did.  The golden door lies back to the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(2231,22,'The End...',replace('You have reached the final lair.  It is dominated by a huge five headed\ndragon.  You suddenly realize that you have SERIOUS problems...\n','\n',char(10)));
INSERT INTO rooms VALUES(2232,22,'Stairwell',replace('This is an old decrepit stairwell that leads to the wine cellar.  It looks\nlike it hasn''t been used for decades.  Well, at least not by anything living.\n','\n',char(10)));
INSERT INTO rooms VALUES(2233,22,'Wine cellar',replace('This is the old wine cellar of the Dragon Tower.  The shelves are empty.\nNothing living has been in here for a long time.  You see a tunnel leading\noff to the east and boy does it smell bad.  Kinda of like rotting flesh.\n','\n',char(10)));
INSERT INTO rooms VALUES(2234,22,'Tunnel',replace('This tunnel seems to stretch for miles.  You try to distinguish the end but\nyour eyes soon tire from the strain.  The smell here has increased two fold.\nThe tunnel continues to go to the east.  The wine cellar lies back to the \nwest.\n','\n',char(10)));
INSERT INTO rooms VALUES(2235,22,'A cave opening',replace('You stand at the opening of a giant cave.  There are many bones strewn across\nthe room.  Some human, some indistinguishable.  It smells very bad in here.\nYou can hear movement in the cave to the north.  The tunnel goes back to the\nsouth.\n','\n',char(10)));
INSERT INTO rooms VALUES(2236,22,'The End of the tunnel',replace('You have finally come to the end of the tunnel.  Back to the west lies\nthe miles of tunnels you have walked through.  You see the faint outline of\na trapdoor above you.  A bride over an underground river lies to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(2237,22,'The Bridge',replace('You are walking along an old wooden bridge.  Its not that secure.  You \nmight want to hurry along.  To the south, on the other side of the bridge,\nlies a small opening.\n','\n',char(10)));
INSERT INTO rooms VALUES(2238,22,'A small opening',replace('You are standing in a small opening.  To the north lies the old wooden\nbridge.  To your south the you can see a clearing.  You can see sunlight\nagain.  What a welcome relief!\n','\n',char(10)));
INSERT INTO rooms VALUES(2239,22,'Clearing',replace('You stand out in a clearing.  Mountains are all around you.  There is a \nwell in the middle of the clearing.  Lying against the well is a sign.  A\npath leads up the mountain.  The small opening is back to the north.\n','\n',char(10)));
INSERT INTO rooms VALUES(2240,22,'A path',replace('This path leads up the side of the mountain.  A clearing lies below you.\nThere is a cave opening to the west.  The path continues up the mountain.\n','\n',char(10)));
INSERT INTO rooms VALUES(2241,22,'A cave opening',replace('You stand before a huge cave opening.  You hearing heavy breathing from\nwithin the cave.  There are a few skeletons lying about.  The cave lies to \nthe south.  The path is back to the east.\n','\n',char(10)));
INSERT INTO rooms VALUES(2242,22,'The path continues',replace('The path continues up the mountain to the top.  The path also goes down.\nThats it, nothing more to see.\n','\n',char(10)));
INSERT INTO rooms VALUES(2243,22,'The top of the mountain',replace('You are standing at the top of the mountain.  It feels more like the top of\nthe world.  To your north lies a huge platinum door.  You hear very pronounced\ngrumbling from behind the doors.  It sounds like something huge and hungry.\nBut if you don''t have the key you don''t have to worry because you can''t get it.\nIf you do have the key I would suggest not going in.  Some believe the Five\nHeaded dragon Tiamat was imprisoned here by the gods.  But who believes in \nfairy tales.  Well, if you''re scared, you can always go down the mountain.\n','\n',char(10)));
INSERT INTO rooms VALUES(2244,22,'Well',replace('O\n h\n   !\n\n     N\n      o\n       !\n\n   I warned you!  You have fallen into the bottomless pit.  You life flashes\nright before your eyes.  Pretty pathetic isn''t it?  Next time you''ll know\nto listen to the God of Laughs.\n','\n',char(10)));
INSERT INTO rooms VALUES(2300,23,'The dark woods',replace('You are travelling through woods that are as dark as night. The trees above\nblock all light and wind. The air is stagnant and smells of death and decay.\nThe lack of sounds and other signs of life make your skin crawl and you feel\nvery much like turning back and heading for safer areas. The path leads north\ninto more open lands while it also leads south into the darkness of the forest.\nA small sign is posted here.\n','\n',char(10)));
INSERT INTO rooms VALUES(2301,23,'The dark woods',replace('You wearily travel through the darkness of the forest. Huge skeletal trees\nline the edges of the path and tower above you. Errant rays of light spear\ndown through the gaps in the canopy above and provide small spots of light\nthat seem to attract what little foliage can grow on the dark forest floor.\nThe path winds north and south into darkness.\n','\n',char(10)));
INSERT INTO rooms VALUES(2302,23,'The small intersection in the forest',replace('The forest path splits here in three directions. Small paths lead to the east,\nnorth, and south. The trees above leave a gap which allows light to fill the\nintersection. It is almost as though you are in a circle of light that\nprovides sanctuary in this land of darkness.\nSomething has been scrawled in the dirt in blood here.\n','\n',char(10)));
INSERT INTO rooms VALUES(2303,23,'The edge of the forest and hills',replace('You stand at the edge of a dark forest. A path leads north into the forest and\nits deadly darkness and silence. Looking west, you see a path that leads up\ninto a foothills region. Standing here on the boundary between light and\ndarkness, you feel very vulnerable and alone.\n','\n',char(10)));
INSERT INTO rooms VALUES(2304,23,'In the dense forest',replace('You walk along a small path leading through a dark forest. No sounds can be\nheard and little light penetrates the canopy of trees above you. The air here\nsmells musty and you long for a fresh breath. You see an intersection of paths\nto the west. The path you are on leads south into the darkening woods.\n','\n',char(10)));
INSERT INTO rooms VALUES(2305,23,'The dark forest path',replace('You continue on through darkness and gloom. The path below you has become a\nwet quagmire. It is difficult to walk, and you make squishing sounds as you\nmove on. Looking east, you see a swampy path. The main path leads north and\nsouth into darkness.\n','\n',char(10)));
INSERT INTO rooms VALUES(2306,23,'A turn in the path',replace('The forest path turns here towards the north and west. To the north, you see\nthat the ground has become dank and swampy, while the western path appears\nto be entering a hilly area. You hear sounds of swamp creatures to the north\neast.\n','\n',char(10)));
INSERT INTO rooms VALUES(2307,23,'The bloody intersection',replace('This is a small intersection. Paths lead east, west, and south. You are struck\nby the carnage here when you enter the clearing. There appears to have been a\ngreat battle here. Blood is everywhere and the ground is all torn up. Pieces\nof beaten armour and broken blades lie all around. Examining the tracks here\nlead you to believe that the dead and wounded were dragged off in two \ndirections, south and east.\n','\n',char(10)));
INSERT INTO rooms VALUES(2308,23,'The rocky path',replace('The path here winds among the low rocky hills. The long trek up and down the\nhills begins to tire you greatly. Looking east, you see a small clearing. More\nhills are to the north of here.\n','\n',char(10)));
INSERT INTO rooms VALUES(2309,23,'The rocky path',replace('The path here is very rocky and treacherous. The travelling is rough and you\nslip and fall often. Looking south, you see that the path continues into the\nhills. Smoother ground is to the east, but the path seems to lead into a dark\nforest in that direction.\n','\n',char(10)));
INSERT INTO rooms VALUES(2310,23,'Up the rocky hillside',replace('You are climbing on a rocky hillside. As you scramble about, loose rocks and\nsmall boulders bounce and fall down below you. Looking to the east and west,\nyou see more stable ground. The hillside itself goes on higher to the south\nand it drops away to the north.\n','\n',char(10)));
INSERT INTO rooms VALUES(2311,23,'The sparse foothills',replace('You are in foothills that are sparsely covered by scraggly bushes and weather\nbeaten trees. There are little signs of life here. Only bare rock and dry dirt\ncan be seen. Looking east, you see a small pass that will allow you to leave\nthe foothills. The foothills themselves extend to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(2312,23,'Standing on level ground',replace('You are standing at the edge of a steep set of foothills. Looking down, you\nsee what appears to be a marshy, dark forest. It reeks of death and decay.\nEven here, you catch its scent on the winds. From here, you can travel south\ndeeper into the foothills or to the west where a small pass will allow you to\nclimb down.\n','\n',char(10)));
INSERT INTO rooms VALUES(2313,23,'In the foothills',replace('You are in a barren set of foothills. Looking around, all you see are dead\nplants and boulders. From the south, you get a whiff of salty air. Barren paths\nlead east, north, and south into more barren hills.\n','\n',char(10)));
INSERT INTO rooms VALUES(2314,23,'Before the huge tree',replace('You enter a large ring of boulders. Sheltered by this wall of stones, a small\ncluster of plants have sprung up. In the center of this group of trees and\nbushes is a huge gnarled tree. It appears to have been twisted and torn by\nthe forces of nature. It sways and moans as a strong wind from the south tears\nthrough its old feeble branches. The hills themselves lead in all directions.\n','\n',char(10)));
INSERT INTO rooms VALUES(2315,23,'Before the dark cave',replace('You stand directly before a huge dark cave. The rocks and boulders outside the\ncave are covered with blood stains and all types of broken and shattered bones\nlie around. An unbearable stench comes from within the cave itself. The dark\ncave entrance looms to the east. The hills themselves lead towards the\nnorth, south, and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(2316,23,'Inside the horrid cave',replace('The stench is overwhelming. You can hardly breathe as you enter the cave.\nLooking around, you realize that some bizarre and horrible creature uses this\ncave as a home. Skeletal remains lie all over. Several half-eaten corpses are\nrotting away slowly in the gloomy darkness. In the back of the cave, you see a\nlarge pile of rotting cloth, fur, and plant matter. Light and safety is\ntowards the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(2317,23,'The hills overlooking the shore',replace('Standing at the edge of the foothills, you are able to look down upon a rocky\nshoreline. It appears as though a vast ocean is to the south. Sea birds have\nmade their nests here in the rocks and you are heartened by the presence of\nlife here. It is possible to climb down to the shore here. The hills\nthemselves are to the north. The edge of the hills leads to the east along the\nshoreline.\n','\n',char(10)));
INSERT INTO rooms VALUES(2318,23,'The hills overlooking the shoreline',replace('You stand on a barren section of hills that overlook a rocky shoreline. The\nstiff ocean wind has blown the rocks smooth here and you have to lean forward\na bit to keep your balance. The salty sea air fills your nostrils and you\nnotice signs of life in the rocky crags here. You can climb down towards the\nshore or head north into the hills themselves. The rocky summit you are\nstanding leads east and west along the shoreline.\n','\n',char(10)));
INSERT INTO rooms VALUES(2319,23,'The hills above the shoreline',replace('You stand on a rocky summit overlooking a rough shoreline below. The sea wind\nblows hard across the rocks here and they have been worn smooth with time.\nLooking around, you notice that you can safely climb down towards the shore.\nThe hills themselves stretch towards the north. The rough summit you stand\nupon leads west along the shoreline.\n','\n',char(10)));
INSERT INTO rooms VALUES(2320,23,'The rocky shore',replace('You are at the base of the rocky hills. Stretching to the south and east, you\nsee a rocky shore. To the southeast, you see a small altar of some sorts that\nglows with an eerie blue light. It is possible to climb up into the hills here.\n','\n',char(10)));
INSERT INTO rooms VALUES(2321,23,'The rocky shoreline',replace('You are on a rocky shore that borders a vast sea. A stiff wind blows here and\nwhistles among the rocks. You see an altar of some sort built on the shore to\nthe south. The shore itself leads east and west. Looking up, you see foothills\nand rocky crags.\n','\n',char(10)));
INSERT INTO rooms VALUES(2322,23,'The rocky shore',replace('You stand at the base of some rocky hills, where they meet a rocky shore. A\nvast sea is to your south. Looking to the southwest, you see a small altar\nthat glows with a eerie blue light. The shore stretches out to the south and\nwest. It is possible to climb up into the hills here.\n','\n',char(10)));
INSERT INTO rooms VALUES(2323,23,'The edge of the sea',replace('You walk along the water''s edge. The vastness of the ocean is staggering as\nyou look out across it. You notice a small altar that glows with blue light\nto the east. The shore itself extends north away from the water''s edge.\n','\n',char(10)));
INSERT INTO rooms VALUES(2324,23,'The Blood Sea Portal',replace('You stand on a small pedestal like altar that has been built on the shore here.\nStanding here, you can look out across the sea. You can almost imagine that\nyou see a far away island. Dominating the altar is a small blue portal of\nlight. It is possible to walk south into the portal. The shore itself extends\nto the north, east, and west.\nThere are small inscriptions on the rock at the base of the portal.\n','\n',char(10)));
INSERT INTO rooms VALUES(2325,23,'The edge of the sea',replace('You walk along the water''s edge. The tide appears to have risen. Very little\ndebris is washed up on shore. You slip and slide as you tread across the\nslippery rocks that make up the shore. To the west you see a small altar that\nradiates blue light. The shore extends north away from the water''s edge.\n','\n',char(10)));
INSERT INTO rooms VALUES(2326,23,'Floating in blue light',replace('You seem to be floating in blue weightlessness. You tumble head over heels and\nfinally right yourself. Gaining your bearings, you notice that there are two\n"windows" in the sea of blue here. One to the south shows an image of a snowy\nplain. Another window the the north shows an image of a rocky shore.\n','\n',char(10)));
INSERT INTO rooms VALUES(2327,23,'The swampy path',replace('This damp path seems to lead into a deep, dark swamp. The trees above block\nout all light and stifle the wind. You smell swamp gas and hear damp squashing\nsounds all around you. The path leads east deeper into the swamp. You also see\na dark forest to the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(2328,23,'The swampy path',replace('You tread lightly in a wet, swampy path. All around you, you see pools of\nquicksand and rotting vegetation. Unlike the forest to the west, the swamp is\nteeming with life. Some of it is harmless, some is not. The path leads east\nand west into more swamp.\n','\n',char(10)));
INSERT INTO rooms VALUES(2329,23,'The swampy path',replace('You weave your way through the treacherous swamp. Gas rises all around you and\na damp mist covers the ground, making it impossible to travel safely, without\ncarefully picking your way around obstacles. Large, gnarled trees rise above\nyou. Their moss covered branches block out all traces of the sun. The path\nhere leads east and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(2330,23,'The turn in the swampy path',replace('You come upon a bend in the swampy path. The ground here is fairly sturdy,\nas this place is elevated above the rest of the swamp. Looking around, you see\na dark, mist filled swamp. Small paths lead south and west into the mist.\n','\n',char(10)));
INSERT INTO rooms VALUES(2331,23,'The swampy path',replace('You tread lightly through the mirky water and sludge that makes up the path\nyou follow. To the east, there is a thick wall of mist. You can see nothing\nwithin it. Harder ground rises to the north.\n','\n',char(10)));
INSERT INTO rooms VALUES(2332,23,'Lost in the Mist',replace('You wander, hopelessly lost. Swirling mist obscures your vision and clouds\nyour mind. You lose all concept of direction. Small, silent giggles can be\nheard all around. You can wander in any direction.\n','\n',char(10)));
INSERT INTO rooms VALUES(2333,23,'Lost in the Mist',replace('You are in a thick misty area. The mist swirls around you, seeming to taunt\nyou and dare you to escape. You feel a slight electric charge in the mist. It\nalmost caresses your body as it floats about you. You can wander in any\ndirection.......\n','\n',char(10)));
INSERT INTO rooms VALUES(2334,23,'Lost in the Mist',replace('You try to peer through the mist......You see nothing. It swirls about you,\ncovering you in a damp sheen. There is no sound, all light is eagerly devoured\nby the mist. You feel totally and hopelessly lost.\n','\n',char(10)));
INSERT INTO rooms VALUES(2335,23,'Lost in the Mist',replace('You stumble through the marsh here. The swamp seems to have swallowed you up\nand denied you exit. This mist is your jailor. You cannot tell where you are.\nYou hear quiet laughter all about you.\n','\n',char(10)));
INSERT INTO rooms VALUES(2336,23,'Lost in the Mist',replace('You wander, lost, for what seems an eternity. Then....From nowhere....You see\nwhat appears to be trees and hills to the east. The mist itself thickens to\nthe west, while it grows thin to the east.\n','\n',char(10)));
INSERT INTO rooms VALUES(2337,23,'Lost in the Mist',replace('You wander through the thick mist. It swirls all about you and makes it hard\nto breathe. The ground below you makes a soft squishing sound as you trudge\non, but this noise is absorbed by the mist and does not travel. You can wander\nin any direction.\n','\n',char(10)));
INSERT INTO rooms VALUES(2338,23,'Lost in the Mist',replace('You wander, lost hopelessly. The mist swirls all about you. You can discern no\ndirection. You stumble blindly through the mist, oblivious to your\nsurroundings.\n','\n',char(10)));
INSERT INTO rooms VALUES(2339,23,'The solid path',replace('A solid path rises out of the misty swamp. It leads north, into what appears\nto be a forested area. The trees, above, allow light and air to penetrate and\nyou can see the sky above. A thick bank of mist is to your west.\n','\n',char(10)));
INSERT INTO rooms VALUES(2340,23,'A forested path',replace('The path here leads north through a thick forest. High bushes and forest\nundergrowth line both sides of the trail. Looking north, you see a thin line\nof smoke rising up above the tree line. You also notice a crude wooden gate\nfarther north on the trail. The trail itself leads south into murky territory.\n','\n',char(10)));
INSERT INTO rooms VALUES(2341,23,'The gate before the Ogre Village',replace('You stand before a huge pair of crude, wooden gates. They are thrown open.\nLooking inside the gates, you see a crude village. Large humanoid creatures\nare milling to and fro.......Ogres! You can head north through the gate or\nsouth into the forest.\n','\n',char(10)));
INSERT INTO rooms VALUES(2342,23,'Among the crude huts',replace('You walk among the huts of the ogre village. The village appears to be cut\nfrom the heart of the forest itself. The swamp, nearby, provides the ogres\nwith a prime hunting ground. Small paths lead north and east.\n','\n',char(10)));
INSERT INTO rooms VALUES(2343,23,'Inside the gates',replace('You stand just north of the gates to the village. Looking around, you see many\ncrude huts and cooking fires. To the north, you see a huge fire pit. Behind \nit, there appears to be a hut of sorts. Small paths lead east and west among \nthe crude huts. The gates to the south provide an exit from the village.\n','\n',char(10)));
INSERT INTO rooms VALUES(2344,23,'Among the crude huts',replace('You walk through the crude village. Small huts made of wood and thatch\nsurround you. Every so often, you can hear grunts and snarls inside the huts.\nThe smell here is unbearable. You wonder what type of creature could possibly\nlive in such squalor. Small paths lead west and north here.\n','\n',char(10)));
INSERT INTO rooms VALUES(2345,23,'The gathering place',replace('This appears to be the clearing the ogres use to assemble. It is quite large\nand has a raised mound in the center that contains a crude throne. The ground\nin front of the throne is quite worn, as if it is sat on quite often. You get\nthe impression that this place is a crude sort of auditorium. Small paths lead\neast and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(2346,23,'The firepit before the lodge',replace('You stand at the edge of a huge firepit. The heat from the burning embers\nmakes you sweat as you stand here. Large spits above the pit are empty but\nthey appear to be quite large enough to hold hapless adventurers. A large\nlodge is towards the north, while paths lead east, west, and south into the\nvillage itself.\n','\n',char(10)));
INSERT INTO rooms VALUES(2347,23,'The village dump',replace('The smell here overpowers you. All around you are the rotting remains of the\nvillage''s refuse. Partially eaten corpses, rotting food, and other truly\ndisgusting things have been discarded here. Paths lead south and west towards\nfresher air.\n','\n',char(10)));
INSERT INTO rooms VALUES(2348,23,'The entryway to the lodge',replace('You are at the entry hall to a large lodge. Animal pelts and other trophies\nline the walls here. Large chests on either side of the door appear to be\nlocked. The lodge stretches north, while the doors to the south provide an\nexit into the village.\n','\n',char(10)));
INSERT INTO rooms VALUES(2349,23,'The throne room',replace('You stand in a large, crudely decorated throne room. A huge throne adorned\nwith humanoid skulls sits against the west wall. A crude, blood stained altar\nis against the east wall. A doorway is directly to the north, long strands of\nbeads blocking the view of the other side. Crude torches light the hall and \nsmoke clings to the ceiling.\n','\n',char(10)));
INSERT INTO rooms VALUES(2350,23,'The chieftain''s room',replace('This appears to be the ogre chieftain''s private quarters. A huge pile of furs\nis in the far corner. Large chests fill the room. All of them have heavy pad\nlocks. The room is filled with trophies of dead enemies. It is quite lavishly\ndecorated for such a crude inhabitant as an ogre. A beaded doorway is to the\nsouth.\n','\n',char(10)));
INSERT INTO rooms VALUES(2351,23,'The frigid wastelands',replace('You wander through the frigid wastelands. Your breath is a cloud before you.\nThe cold cuts to the bone. Swirling snow and wind make impossible for you to\ndiscern any directions.\n','\n',char(10)));
INSERT INTO rooms VALUES(2352,23,'The frigid wastelands',replace('You wander through the frigid wastelands. Your breath is a cloud before you.\nThe cold cuts to the bine. Swirling snow and wind make it impossible to\ndiscern any directions.\n','\n',char(10)));
INSERT INTO rooms VALUES(2353,23,'The Glacier Temple',replace('You are in a small temple. It appears to be built entirely from ice. The ice\nwalls are frosted and are opaque. There is a small blue portal here. You can\ngo north, to enter the portal. Looking south, you see a world of white outside\nthe open doorway. Swirling snow and bright light obscure your view.\n','\n',char(10)));
INSERT INTO rooms VALUES(2354,23,'The frigid wastelands',replace('You wander through the frigid wastelands. Your breath is a cloud before you.\nThe cold cuts to the bone. Swirling snow and wind make it impossible for you\nto discern any directions.\n','\n',char(10)));
INSERT INTO rooms VALUES(2355,23,'The frigid wastelands',replace('You wander through the frigid wastelands. Your breath is a cloud before you.\nThe cold cuts to the bone. Swirling snow and wind make it impossible for you\nto discern any directions.\n','\n',char(10)));
INSERT INTO rooms VALUES(2356,23,'The frigid wastelands',replace('You wander through the frigid wastelands. Your breath is a cloud before you.\nThe cold cuts to the bone. Swirling snow and wind make it impossible for you\nto discern any directions.\n','\n',char(10)));
INSERT INTO rooms VALUES(2357,23,'The frigid wastelands',replace('You wander through the frigid wastelands. Your breath is a cloud before you.\nThe cold cuts to the bone. Swirling snow and wind make it impossible for you\nto discern any directions.\n','\n',char(10)));
INSERT INTO rooms VALUES(2358,23,'The frigid wastelands',replace('You wander through the frigid wastelands. Your breath is a cloud before you.\nThe cold cuts to the bone. Swirling snow and wind make it impossible for you\nto discern any direction.\n','\n',char(10)));
INSERT INTO rooms VALUES(2359,23,'The frigid wastelands',replace('You wander through the frigid wastelands. Your breath is a cloud before you.\nThe cold cuts to the bone. Swirling snow and wind make it impossible for you\nto discern any directions.\n','\n',char(10)));
INSERT INTO rooms VALUES(2360,23,'The edge of the frigid wastes',replace('You stand at the base of a steep rocky cliff. To the north, a vast arctic\nwasteland stretches out. The snow falls lightly here and the wind is not\nvery fierce. You can climb up the rocky cliff or head north into the arctic\nwastes.\n','\n',char(10)));
INSERT INTO rooms VALUES(2361,23,'On the cliffside',replace('You cling to the side of the cliff. Looking down, you are terrified by the\nsheer distance to the ground below. You can climb up higher into the cliffs,\nbut the area above is obscured by clouds and you cannot tell what lies waiting\nabove.\n','\n',char(10)));
INSERT INTO rooms VALUES(2362,23,'Before the gates of Mahn-Tor',replace('You stand at the edge of a high cliff. Directly south, set back off the\ncliff''s edge, you see a huge pair of gates. These gates appear to be carved\nalmost completely out of ice. A huge city and keep appear to be on the other\nside of these gates. There is also a possibility of climbing down the cliff \nface.\n','\n',char(10)));
INSERT INTO rooms VALUES(2363,23,'The city streets of Mahn-Tor',replace('You walk among the ice and snow covered shops and homes. Most of the doors are\nclosed and only the light from the windows betrays the presence of inhabitants.\nA cold wind blows through here, scattering fine clouds of snow all about. Small\nstreets lead south and east.\n','\n',char(10)));
INSERT INTO rooms VALUES(2364,23,'Inside the gates of Mahn-Tor',replace('You stand just inside the gates to the city of Mahn-Tor. The city itself\nspreads out in front of you. The buildings are sturdy, as they appear to be\nmade from the very rock of this mountain. Snow falls all around and a fine\nsheet of ice can be seen covering all but the most used walk ways. Small city\nstreets lead east and west, while a main road appears to lead south.\n','\n',char(10)));
INSERT INTO rooms VALUES(2365,23,'The city streets of Mahn-Tor',replace('You trudge among the icy streets of Mahn-Tor. The streets themselves are made\nof cobblestone and are quite treacherous. Small homes and businesses along\nthe street are closed tight and light from their windows throws eerie shadows\nacross the dark street. Small streets lead west and south here.\n','\n',char(10)));
INSERT INTO rooms VALUES(2366,23,'The city streets of Mahn-Tor',replace('You trudge through the snow covered streets. The street itself is made of\ncobblestones and the footing is quite treacherous. To the south, you see what\nappears to be a small tavern. Bright lights shine through the windows. Small\nstreets also lead north and east.\nA small sign hangs outside the tavern.\n','\n',char(10)));
INSERT INTO rooms VALUES(2367,23,'The Square of Mahn-Tor',replace('This appears to be the main square of Mahn-Tor. A huge fountain graces the\ncenter of the square, but the extreme cold has turned it into an ice\nsculpture. The water has frozen in arcs through the air. Snow and ice covers\nthe square and small streets lead east and west. To the north, you see\nthe gates to the city. You also notice a small store to the south.\nA small sign hangs outside the store.\n','\n',char(10)));
INSERT INTO rooms VALUES(2368,23,'The streets of Mahn-Tor',replace('You walk among the small stores and homes of Mahn-Tor. The cobblestone streets\nare covered with ice and snow. Small snow drifts have formed at the edges of\nthe streets. The wind blows fiercely. Small streets lead in all directions.\nThere appears to be a large building to the east, but the snow obscures your\nview.\n','\n',char(10)));
INSERT INTO rooms VALUES(2369,23,'The Inn of the Broken Horn',replace('You enter a warm tavern. The room is lit mainly by two huge fireplaces at each\nend of the room. Small tables and a large bar furnish the room. The\ninhabitants of the inn are all minotaurs of varying size and disposition. Most\nseem to regard you with suspicion. Few approach you. A large door leads\nnorth, out of the bar and back out into the cold.\n','\n',char(10)));
INSERT INTO rooms VALUES(2370,23,'The Mahn-Tor Equipment Shop',replace('You are in a crude equipment shop. The store is filled with racks of various\nitems that adventurers could use. Large fireplaces light and heat the room.\nA large desk occupies the back of the room. The door to the shop lies to the\nnorth.\n','\n',char(10)));
INSERT INTO rooms VALUES(2371,23,'The Mahn-Tor General Store',replace('You enter a small store that is dark and cold. Old empty shelves line the\nwalls and snow blows across the dirty stone floor. It is evident that this\nstore was once used, but it is no more. A small doorway leads north out into\nthe chilling snow and wind.\n','\n',char(10)));
INSERT INTO rooms VALUES(2372,23,'Gorak''s Training Room',replace('This room is full of all sorts of weapons and armours. Pieces of old targets\nand practice dummies lie all around. The walls are chipped and scored from\nweapon blows. This is obviously the room of an avid warrior. A red door leads\neast.\n','\n',char(10)));
INSERT INTO rooms VALUES(2373,23,'Darkoth''s Dark Study',replace('This room is dark. It reeks of death and evil. Arcane symbols and a small\naltar fill the room. Blood runs from the altar. It is evident that this room\nis used for unholy purposes. A black door leads west.\n','\n',char(10)));
INSERT INTO rooms VALUES(2374,23,'Tyrgoth''s Inner Sanctum',replace('Idols to the gods of good fill the room. White furniture and decorations give\nthe room a holy appearance. It is evident that some being of supreme goodness\nlives here. A white door leads east.\n','\n',char(10)));
INSERT INTO rooms VALUES(2375,23,'The road to the Keep of Mahn-Tor',replace('You walk up a steep rocky road. It leads up a steep grade to the east. At the\nend of this steep road, you see a huge keep. Snow swirls all about you and you\nfeel your breath freeze as it leaves your lungs. Blurry lights to the east and\nwest are all you can see from here.\n','\n',char(10)));
INSERT INTO rooms VALUES(2376,23,'A small guard house',replace('You enter a small guard house. A huge fireplace lights and warms the room.\nLooking around, you see that the room is fairly well furnished. Thick rugs\nand curtains help insulate the room and the beds themselves look quite warm.\nA table in the center of the room has the remnants of a card game strewn\nacross it. A small door leads south.\n','\n',char(10)));
INSERT INTO rooms VALUES(2377,23,'Before the Keep of Mahn-Tor',replace('You stand before a huge keep that has been carved into the side of the\nmountain. Huge wooden gates before you provide entrance to the keep. It\nappears as though the cold here has convinced the guards to seek warmth\ninside. You see the lights of the city to the west. You also notice small\nguard houses to the north and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(2378,23,'A small guard house',replace('You enter a small, but warm, guard house. Deep rugs and thick curtains\ninsulate the room. A huge fireplace lights and warms the room. Outside, you\nhear the roar of the freezing wind. A small door leads north out into the cold.\n','\n',char(10)));
INSERT INTO rooms VALUES(2379,23,'The entryway to the Keep of Mahn-Tor',replace('You are at the entry hall to the huge keep. The high vaulted ceiling is carved\nfrom solid stone. Huge stone pillars rise up from the floor to meet the\nceiling far above. The architecture appears to be dwarven. A huge pair of\ngates stand to the west, protecting the keep from the harsh cold outside. A\nlarge hall leads east, deeper into the keep.\n','\n',char(10)));
INSERT INTO rooms VALUES(2380,23,'The Hall',replace('You are in a huge hall. Large tapestries line the walls and huge statues of\nvarious make and appearance are spread about. The ceiling above supports huge\ncandelabras, which light the room. To the east, you see a bright light and\nhear sounds of inhabitation. Looking west, you see the entry gates to the keep.\n','\n',char(10)));
INSERT INTO rooms VALUES(2381,23,'The Grand Hall',replace('You are in the main hall of the Keep of Mahn-Tor. This hall is huge. The wide\nfloor of the hall is an expanse of marble. It shimmers in the light thrown\noff by the torches that line the walls. To the east, you see what appears to\nbe a huge golden throne. The hall itself stretches south and a smaller hall\nleads to the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(2382,23,'The Great Hall',replace('You stand in the great hall of the keep. Huge pillars rise up to the vaulted\nceiling and torch light glimmers off the marble floor here. You are amazed at\nthe sheer size of the hall. The hall itself leads north and east. You notice a\nsmaller hall leading south, deeper into the keep.\n','\n',char(10)));
INSERT INTO rooms VALUES(2383,23,'Standing before the throne',replace('You stand before the throne of Mahn-Tor. This golden throne is so huge that it\ntakes up almost the entire wall, stretching far above the floor. Sitting upon\nit, you feel small and feeble. It is evident that this throne is more of a\ndecoration than anything else. Only the largest of kings could sit upon it.\nThe hall leads south and west into other parts of the keep.\n','\n',char(10)));
INSERT INTO rooms VALUES(2384,23,'The Great Hall',replace('You are in a great hall. Huge torches light the room and their light shimmers\noff the marble floor below you. To the north, you see a huge golden throne.\nLooking up, you grow dizzy at the height to which the vaulted ceiling rises.\nThe hall itself leads north and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(2385,23,'The secret hallway',replace('You are in a small, torch lit hall. It leads from east to west. A large gold\ndoor is to the west. To the east, you see a heavy stone door.\n','\n',char(10)));
INSERT INTO rooms VALUES(2386,23,'Entry to the Royal Chambers',replace('You are at the entrance to the royal chambers of the keep. A plush shag rug\ncovers the stone floor. Large candelabras hang from the ceiling, lighting the\nroom. A huge fireplace warms the room. Beaded doorways lead south and east. A\nhuge stone door stands in the west wall.\n','\n',char(10)));
INSERT INTO rooms VALUES(2387,23,'The Guard Post',replace('The hall here has been built into a guard post of sorts. It appears as though\nit would be quite easy to defend in times of emergency. Obviously, something\nimportant lies beyond. A small hall leads south, while the main hall can be\nseen to the north.\n','\n',char(10)));
INSERT INTO rooms VALUES(2388,23,'The guarded hall',replace('You walk down a torch lit hallway. It has been carved out of pure stone. It is\nvery quiet in this hall. You notice rows of colored doors on each wall. To\nyour east, you see a yellow door. To your west, you see a red door. The hall\nitself leads south and north.\n','\n',char(10)));
INSERT INTO rooms VALUES(2389,23,'The guarded hall',replace('You walk down a small, quiet, torch lit hallway. Doors of different colors are\nin each wall. To your east, you see a maroon door. To your west, you see a\nblack door. The hall itself leads north and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(2390,23,'Sumaron''s Sanctum',replace('You enter a temple of sorts. A small altar is here and relics of many\nreligions lie around. It is evident that this is the room of a studying cleric.\nA yellow door leads west.\n','\n',char(10)));
INSERT INTO rooms VALUES(2391,23,'Amyrok''s Arcane Study',replace('This room is full of shelves which hold various spell components. The center\nof the room is occupied by a huge pentagram. The entire room smells of smoke\nand incense. The room is obviously used extensively by a practicing mage. A\nmaroon door leads west.\n','\n',char(10)));
INSERT INTO rooms VALUES(2392,23,'The guarded hall',replace('You walk down a quiet hall. The stone walls here are wet with moisture.\nColored doors can be seen in the walls here. To your east, you see a green\ndoor. To your west, you see a white door. The hall itself leads north and\nsouth.\n','\n',char(10)));
INSERT INTO rooms VALUES(2393,23,'The Harem Room',replace('This appears to be the harem room of the Keep. Huge piles of furs and beds\nfill the room. The lighting is dim, but the room is very warm. You can hear\nmusic playing quietly from somewhere. Beaded doorways lead north and east.\n','\n',char(10)));
INSERT INTO rooms VALUES(2394,23,'Nasturn''s Humble Abode',replace('This room is filled with all types of natural items. Trees and plants have\nbeen lovingly cultivated and grown by hand, in large pots. The room is like an\nindoor garden. A green door leads west.\n','\n',char(10)));
INSERT INTO rooms VALUES(2395,23,'The main living room',replace('This room is decorated with sturdy stone furniture that is carved and gilded.\nLarge candles light the room. A thick rug covers the floor. Thick furs and\ntapestries decorate the walls. Beaded doorways lead south and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(2396,23,'The Master Bedroom',replace('This appears to be the master bedroom. A huge bed fills the rooms. Piles of\nfurs and other rich furnishings adorn the room. Candles are everywhere and\nthey help a huge fireplace light the room. The lavishness of the room\noverwhelms you. Beaded doorways lead north and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(2397,23,'The end of the guarded hall',replace('You are at the end of the hall. Colored doors line the walls to the north. To\nyour west, you see a brown door. To you east, you see a grey door. The hall\nitself leads north back along the rows of doors.\n','\n',char(10)));
INSERT INTO rooms VALUES(2398,23,'Dorgar''s Dismal Domicile',replace('This room is dirty and unkempt. Odds and ends of different items lie all over.\nIt is apparent that some type of pack-rat lives here. It appears as though\nnothing has ever entered this room and ever left again. A grey door leads west.\n','\n',char(10)));
INSERT INTO rooms VALUES(2399,23,'Belrak''s Green Room',replace('This room is full of green. The furniture and all other items show the color\nof nature. The room smells of pine and forest odors. From the items here, it\nappears as though a woodsman of some sorts lives here. A brown door leads east.\n','\n',char(10)));
INSERT INTO rooms VALUES(2801,28,'Wastedump',replace('This room is filled with bone shards and fragments.  Something (or things)\nvery big lives here.  A small plaque is on the wall.\n','\n',char(10)));
INSERT INTO rooms VALUES(2802,28,'Troll''s Larder',replace('This room has blood and grime all over the walls.  You see maggots and other\ninsects crawling up them.  The resident is definitely uncivilized.  Half-eaten\nand rotting body parts scatter the floor, each having its own colony of flies,\nworms, and maggots.\n','\n',char(10)));
INSERT INTO rooms VALUES(2803,28,'Troll''s Living Room',replace('This small cave opens to the north, south, east, and west.  You are\novercome by the stench and consider turning around.\n','\n',char(10)));
INSERT INTO rooms VALUES(2804,28,'The Playpen',replace('The walls are covered with blood (and body parts!?!?).  Plastered on the far\nwall you see what looks like a human arm.  A half-eaten body lies here with\nits chest ripped out.  The predator seems disinterested in it.\n','\n',char(10)));
INSERT INTO rooms VALUES(2805,28,'Troll''s Bedroom',replace('Obviously something REALLY big lives here.  The stench is quite unbearable.\nThere are piles and piles of rotten and half-eaten body parts of animals,\norcs, (and humans?) strewn across the floor.  There is a larger, more\nprominent pile of rotten parts over in a corner.  It seems to have been\nflattened by something.\n','\n',char(10)));
INSERT INTO rooms VALUES(2900,29,'Obsidian hills',replace('You see before you some shiny black hills. There is very little vegetation\nhere. The hills appear to lead to a high mountain to the south east\n','\n',char(10)));
INSERT INTO rooms VALUES(2901,29,'Obsidian hills',replace('You see before you some shiny black hills. There is very little vegetation\nhere. The hills appear to lead to a high mountain to the south east\n','\n',char(10)));
INSERT INTO rooms VALUES(2902,29,'Obsidian hills',replace('You see before you some shiny black hills. There is very little vegetation\nhere. The hills appear to lead to a high mountain to the south east\n','\n',char(10)));
INSERT INTO rooms VALUES(2903,29,'Mountain side',replace('The mountain is very high and looks to be quite old. There are a few cracks\nin the side of the mountain\n','\n',char(10)));
INSERT INTO rooms VALUES(2904,29,'Mountain side',replace('The mountain is very high and looks to be quite old. There is smoke coming\nfrom the top of the mountain.\n','\n',char(10)));
INSERT INTO rooms VALUES(2905,29,'Mountain top',replace('You''ve reached the top of the mountain. You can see more smoke from up here.\nThe smoke seems to come from a hole to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(2906,29,'Entrance to the mountain',replace('The smoke comes from inside the hole.  It also looks like there is a path\nthat leads down.\n','\n',char(10)));
INSERT INTO rooms VALUES(2907,29,'Mountain top',replace('You are standing at the top of the mountain. The mountain looks like it has\nbeen ravaged by something.\n','\n',char(10)));
INSERT INTO rooms VALUES(2908,29,'Mountain top',replace('You are standing at the top of the mountain. There are several cracks in the\nground and you don''t feel safe!\n','\n',char(10)));
INSERT INTO rooms VALUES(2909,29,'Mountain top',replace('You are standing on the top of the mountain and think you should move north.\n','\n',char(10)));
INSERT INTO rooms VALUES(2910,29,'Inside the mountain',replace('You are standing inside the mountain.\n','\n',char(10)));
INSERT INTO rooms VALUES(2911,29,'Guard room',replace('You are standing in a room with beds, tables, and fire newts!\nThere are paintings on the wall.  They show battle scenes.\n','\n',char(10)));
INSERT INTO rooms VALUES(2912,29,'Guard room',replace('You are standing in a room with beds, chairs, tables, and fire newts!\nThere are paintings on the wall that show great leaders.\n','\n',char(10)));
INSERT INTO rooms VALUES(2913,29,'Inside the mountain',replace('You are standing inside the mountain.\n','\n',char(10)));
INSERT INTO rooms VALUES(2914,29,'Store room',replace('You see nothing special in this room.  There are some boxes and fire newt\nworkers here.  There is also some trash piled up in the room.\n','\n',char(10)));
INSERT INTO rooms VALUES(2915,29,'Workers'' quarters',replace('You are standing in the workers'' quarters.  There are several workers here.  \nThe room is messy and has nothing of value in it.  The party the night before\nmust have destroyed everything.\n','\n',char(10)));
INSERT INTO rooms VALUES(2916,29,'Bottom of the mountain',replace('You are standing at the bottom of the shaft.\n','\n',char(10)));
INSERT INTO rooms VALUES(2917,29,'The tunnel',replace('You are standing in a dry, dark tunnel.\n','\n',char(10)));
INSERT INTO rooms VALUES(2918,29,'Bend in the tunnel',replace('You are standing in a dark tunnel.\n','\n',char(10)));
INSERT INTO rooms VALUES(2919,29,'The tunnel',replace('You are standing in a dark tunnel.\n','\n',char(10)));
INSERT INTO rooms VALUES(2920,29,'Fire Newt House',replace('You are standing in a fire newt house.  There is a mother fire newt here\nplaying with her children.  The room is full of newt toys- they look very\nboring.\n','\n',char(10)));
INSERT INTO rooms VALUES(2921,29,'The tunnel',replace('You are standing in a dark tunnel.\n','\n',char(10)));
INSERT INTO rooms VALUES(2922,29,'Fire Newt House',replace('You are standing in a fire newt house.  There is a fire newt mother here\nplaying with her children.  The room has several torn baby newt diapers here\n... how disgusting!\n','\n',char(10)));
INSERT INTO rooms VALUES(2923,29,'The tunnel',replace('You are standing in the dark tunnel.\n','\n',char(10)));
INSERT INTO rooms VALUES(2924,29,'Entrance to the town hall',replace('You are standing in the entrance to the town hall.  The room is large and\nornate.\n','\n',char(10)));
INSERT INTO rooms VALUES(2925,29,'The Waiting Room',replace('You are standing in the waiting room of the town hall.  There is a big door\nto the west.  The room has pictures of the villages history.\n','\n',char(10)));
INSERT INTO rooms VALUES(2926,29,'The Leader''s Office',replace('You are standing in the fire newt leader''s office.\n','\n',char(10)));
INSERT INTO rooms VALUES(2927,29,'Outside the temple',replace('You are standing outside the fire newt temple.  The temple has some very\nlarge arches and towers.\n','\n',char(10)));
INSERT INTO rooms VALUES(2928,29,'Entrance to the temple',replace('You are standing at the entrance to the temple.  The temple is very neat. \nThe sates are set in straight rows and the alter is very large.\n','\n',char(10)));
INSERT INTO rooms VALUES(2929,29,'Inside the Temple',replace('You are standing inside the fire newt temple.\n','\n',char(10)));
INSERT INTO rooms VALUES(2930,29,'The room before the doors',replace('You are standing before a pair of huge doors.\n','\n',char(10)));
INSERT INTO rooms VALUES(2931,29,'The Egg Room',replace('You are standing in a room that has several dozen piles of eggs.  There is\na chest on the floor also.\n','\n',char(10)));
INSERT INTO rooms VALUES(3001,30,'The Temple Of Midgaard',replace('You are in the southern end of the temple hall in the Temple of Midgaard.\nThe temple has been constructed from giant marble blocks, eternal in\nappearance, and most of the walls are covered by ancient wall paintings\npicturing Gods, Giants and peasants.\n   Large steps lead down through the grand temple gate, descending the huge\nmound upon which the temple is built and ends on the temple square below.\n   Equally large steps lead UP through a small door into the ENTRANCE to MUD \nSCHOOL.  (type ''up'' to go to MUD SCHOOL.)  A small plaque is on this wall.\n','\n',char(10)));
INSERT INTO rooms VALUES(3002,30,'Cleric''s Inner Sanctum',replace('This is the inner sanctum.  A picture of the mighty Thor, is hanging on\nthe wall, just above the altar which is set against the western wall.  A well\nin the middle of the floor leads down into darkness.  Vile smells waft from\nthe depths.\n','\n',char(10)));
INSERT INTO rooms VALUES(3003,30,'Cleric''s Bar',replace('The bar is one of the finest in the land, lucky it is members only.  Fine\nfurniture is set all around the room.  A small sign is hanging on the wall.\n','\n',char(10)));
INSERT INTO rooms VALUES(3004,30,'Entrance to Cleric''s Guild',replace('The entrance hall is a small modest room, reflecting the true nature of\nthe Clerics.  The exit leads east to the temple square.  A small entrance to\nthe bar is in the northern wall.\n','\n',char(10)));
INSERT INTO rooms VALUES(3005,30,'The Temple Square',replace('You are standing on the temple square.  Huge marble steps lead up to the\ntemple gate.  The entrance to the Clerics Guild is to the west, and the old\nGrunting Boar Inn, is to the east.  Just south of here you see the market\nsquare, the center of Midgaard.\n','\n',char(10)));
INSERT INTO rooms VALUES(3006,30,'Entrance to the Grunting Boar Inn',replace('You are standing in the entrance hall of the Grunting Boar Inn.  The hall\nhas been wisely decorated with simple but functional furniture.  A small\nstaircase leads up to the defunct reception room and the bar is to the east.\n','\n',char(10)));
INSERT INTO rooms VALUES(3007,30,'The Grunting Boar',replace('You are standing in the bar.  The bar is set against the northern wall, old\narchaic writing, carvings and symbols cover its top.  A fireplace is built into\nthe western wall, and through the southeastern windows you can see the temple\nsquare.  This place makes you feel like home.\nA small sign with big letters is fastened to the bar.\n','\n',char(10)));
INSERT INTO rooms VALUES(3008,30,'The Defunct Reception',replace('You are standing in a dusty, defunct reception.  The staircase leads\ndown to the entrance hall.\n','\n',char(10)));
INSERT INTO rooms VALUES(3009,30,'The Bakery',replace('You are standing inside the small bakery.  A sweet scent of Danish and\nfine bread fills the room.  The bread and Danish are arranged in fine order\non the shelves, and seem to be of the finest quality.\nA small sign is on the counter.\n','\n',char(10)));
INSERT INTO rooms VALUES(3010,30,'The General Store',replace('You are inside the general store.  All sorts of items are stacked on shelves\nbehind the counter, safely out of your reach.\nA small note hangs on the wall.\n','\n',char(10)));
INSERT INTO rooms VALUES(3011,30,'The Weapon Shop',replace('You are inside the weapon shop.  There is a small note on the counter.\n','\n',char(10)));
INSERT INTO rooms VALUES(3012,30,'Main Street',replace('You are at the end of the main street of Midgaard.  South of here is the\nentrance to the Guild of Magic Users.  The street continues east towards the\nmarket square.  The magic shop is to the north and to the west is the city\ngate.\n','\n',char(10)));
INSERT INTO rooms VALUES(3013,30,'Main Street',replace('You are on the main street passing through the City of Midgaard.  South of\nhere is the entrance to the Armoury, and the bakery is to the north.  East of\nhere is the market square.\n','\n',char(10)));
INSERT INTO rooms VALUES(3014,30,'Market Square',replace('You are standing on the market square, the famous Square of Midgaard.\nA large, peculiar looking statue is standing in the middle of the square.\nRoads lead in every direction, north to the temple square, south to the\ncommon square, east and westbound is the main street.\n','\n',char(10)));
INSERT INTO rooms VALUES(3015,30,'The Main Street',replace('You are on Main Street crossing through town.  To the north is the general\nstore, and the main street continues east.  To the west you see and hear the\nmarket place and to the south is the Jeweller''s Shop.\n','\n',char(10)));
INSERT INTO rooms VALUES(3016,30,'The Main Street',replace('The main street, to the north is the weapon shop and to the south is the\nGuild of Swordsmen.  To the east you leave town and to the west the street\nleads to the market square.\n','\n',char(10)));
INSERT INTO rooms VALUES(3017,30,'Entrance to Mage''s Guild',replace('The entrance hall is a small, poor lighted room.\n','\n',char(10)));
INSERT INTO rooms VALUES(3018,30,'Mage''s Bar',replace('The bar is one of the wierdest in the land.  Mystical images float around\nthe air.  Illusions of fine furniture appear all around the room.\n','\n',char(10)));
INSERT INTO rooms VALUES(3019,30,'Mage''s Laboratory',replace('This is the Magical Experiments Laboratory.  Dark smoke-stained stones\narch over numerous huge oaken tables, most of these cluttered with strange-\nlooking pipes and flasks.  The floor is covered with half-erased pentagrams\nand even weirder symbols, and a blackboard in a dark corner has only been\npartially cleaned, some painful-looking letters faintly visible.  A well in\nthe middle of the floor leads down into darkness.  Vile smells waft from the\ndepths.\n','\n',char(10)));
INSERT INTO rooms VALUES(3020,30,'The Armoury',replace('The armoury with all kinds of armours on the walls and in the window.  You\nsee helmets, shields and chain mails.  To the north is the main street.\nOn the wall is a small note.\n','\n',char(10)));
INSERT INTO rooms VALUES(3021,30,'Entrance Hall to the Guild of Swordsmen',replace('The entrance hall to the Guild of Swordsmen.  A place where one has to be\ncareful not to say something wrong (or right).  To the east is the bar and to\nthe north is the main street.\n','\n',char(10)));
INSERT INTO rooms VALUES(3022,30,'The Bar of Swordsmen',replace('The bar of swordsmen, once upon a time beautifully furnished.  But now the\nfurniture is all around you in small pieces.  To the south is the yard, and\nto the west is the entrance hall.\n','\n',char(10)));
INSERT INTO rooms VALUES(3023,30,'The Tournament and Practice Yard',replace('The practice yard of the fighters.  To the north is the bar.  A well leads\ndown into darkness.\n','\n',char(10)));
INSERT INTO rooms VALUES(3024,30,'Eastern End of Poor Alley',replace('You are at the poor alley.  South of here is the Grubby Inn and to the\neast you see common square.  The alley continues further west.\n','\n',char(10)));
INSERT INTO rooms VALUES(3025,30,'The Common Square',replace('The common square, people pass you, talking to each other.  To the west is\nthe poor alley and to the east is the dark alley.  To the north, this square\nis connected to the market square.  From the south you notice a nasty smell.\n','\n',char(10)));
INSERT INTO rooms VALUES(3026,30,'The Dark Alley',replace('The dark alley, to the west is the common square and to the south is the\nGuild of Thieves.  The alley continues east.\n','\n',char(10)));
INSERT INTO rooms VALUES(3027,30,'Entrance Hall to the Guild of Thieves',replace('The entrance hall to the thieves'' and assassins'' guild.  A place where you\ncan lose both your life and your money, if you are not careful.  To the north\nis the dark alley and to the east is the thieves'' bar.\n','\n',char(10)));
INSERT INTO rooms VALUES(3028,30,'The Thieves Bar',replace('The bar of the thieves.  Once upon a time this place was beautifully\nfurnished, but now it seems almost empty.  To the south is the yard, and to\nthe west is the entrance hall.\n   (Maybe the furniture has been stolen?!)\n','\n',char(10)));
INSERT INTO rooms VALUES(3029,30,'The Secret Yard',replace('The secret practice yard of thieves and assassins.  To the north is the\nbar.  A well leads down into darkness.\n','\n',char(10)));
INSERT INTO rooms VALUES(3030,30,'The Dump',replace('The dump, where the people from the city drop their garbage.  Through the\ngarbage you can see a large junction of pipes, looks like the entrance to the\nsewer system.  South of here you see the river and to the north is the common\nsquare.\n','\n',char(10)));
INSERT INTO rooms VALUES(3031,30,'The Pet Shop',replace('The Pet Shop is a small crowded store, full of cages and animals of\nvarious sorts and sizes.  There is a sign on the wall.\n','\n',char(10)));
INSERT INTO rooms VALUES(3032,30,'Pet Shop Store',replace('This is the small dark room in which the Pet Shop Boy keeps his pets.\nIt is vital that this room be immediately after the pet shop.\n','\n',char(10)));
INSERT INTO rooms VALUES(3033,30,'The Magic Shop',replace('You are in a small room that smells of rare chemicals and spices.\nDividing the room in two is a large desk, and on the wall behind it are\nnumerous shelves crammed with jars, bottles, books and scrolls of all\nsorts and sizes.\n','\n',char(10)));
INSERT INTO rooms VALUES(3034,30,'The Jeweller''s Shop',replace('You are in a small, beautifully furnished room.  The warm light emanating\nfrom the small oil lamps on the walls is reflected in the hard, polished\nsurface of the big mahogany desk that stands in the centre of the room.\nA small sign with golden letters stands on the desk.\n','\n',char(10)));
INSERT INTO rooms VALUES(3035,30,'The Leather Shop',replace('An acrid smell fills this large room.  Along the walls are numerous\nshelves containing all sorts of animal hide and in the crackling fireplace\nhangs a big iron pot with boiling water.  In the middle of the room is a\nlarge oak table.\nA wooden sign is hanging above the fireplace.\n','\n',char(10)));
INSERT INTO rooms VALUES(3040,30,'Inside the West Gate of Midgaard',replace('You are by two small towers that have been built into the city wall and\nconnected with a footbridge across the heavy wooden gate.  Main Street leads\neast and Wall Road leads south from here.\n','\n',char(10)));
INSERT INTO rooms VALUES(3041,30,'Inside the East Gate of Midgaard',replace('You are by two small towers that have been built into the city wall and\nconnected with a footbridge across the heavy wooden gate.  Main Street leads\nwest from here.  South of here is the wall road, but it looks dirty and \nnot too safe.\n','\n',char(10)));
INSERT INTO rooms VALUES(3042,30,'Wall Road',replace('You are walking next to the western city wall.  The road continues further\nsouth and the city gate is just north of here.\n','\n',char(10)));
INSERT INTO rooms VALUES(3043,30,'Wall Road',replace('You are walking next to the western city wall.  Wall Road continues further\nnorth and south.  A small, poor alley leads east.\nSome letters have been written on the wall here.\n','\n',char(10)));
INSERT INTO rooms VALUES(3044,30,'Poor Alley',replace('You are in narrow and dirty alley leading east and west.  The leather shop\nis to the north.\n','\n',char(10)));
INSERT INTO rooms VALUES(3045,30,'Alley at Levee',replace('You are standing in the alley which continues east and west.  South of\nhere you see the levee.  North is the Pet Shop.\n','\n',char(10)));
INSERT INTO rooms VALUES(3046,30,'Eastern end of Alley',replace('You are standing at the eastern end of the alley.  An old three-story\nwarehouse is directly south of here, and the Mob Factory is east.\n','\n',char(10)));
INSERT INTO rooms VALUES(3047,30,'Wall Road',replace('You are standing on the road next to the western city wall which\ncontinues north.  South of here is a bridge across the river.\n','\n',char(10)));
INSERT INTO rooms VALUES(3048,30,'Grubby Inn',replace('You are inside the old Grubby Inn.  This place has not been cleaned for\nseveral decades, vile smells make you dizzy.\n','\n',char(10)));
INSERT INTO rooms VALUES(3049,30,'Levee',replace('You are at the levee.  South of here you see the river gently flowing west.\nThe river bank is very low making it possible to enter the river.\n','\n',char(10)));
INSERT INTO rooms VALUES(3050,30,'Abandoned Warehouse',replace('You are inside the only room in the old warehouse.  The place is very dusty\nand appears to have been unused for many years.  The skylight spills\nviolet-tinged light.\n','\n',char(10)));
INSERT INTO rooms VALUES(3051,30,'On the Bridge',replace('You are standing on the stone bridge crosses the river.  The bridge is\nbuilt out from the western city wall and the river flows west through an\nopening in the wall ten feet below the bridge.\n','\n',char(10)));
INSERT INTO rooms VALUES(3052,30,'Outside the West Gate of Midgaard',replace('You are by two small towers that have been built into the city wall and\nconnected with a footbridge across the heavy wooden gate.  To the west you\ncan see the edge of a big forest. A small dusty trail leads north along the\nwall.\n','\n',char(10)));
INSERT INTO rooms VALUES(3053,30,'Outside the East Gate of Midgaard',replace('You are by two small towers that have been built into the city wall and\nconnected with a footbridge across the heavy wooden gate.  To the east the\nplains stretch out in the distance. To the north a small dusty trail follow\nthe city wall.\n','\n',char(10)));
INSERT INTO rooms VALUES(3054,30,'By the Temple Altar',replace('You are by the temple altar in the northern end of the Temple of Midgaard.\nA huge altar made from white polished marble is standing in front of you and\nbehind it is a ten foot tall sitting statue of Odin, the King of the Gods.\n','\n',char(10)));
INSERT INTO rooms VALUES(3057,30,'In the air...',replace('WOW you can fly!  You are floating in the air above Temple Square of Midgaard.\n','\n',char(10)));
INSERT INTO rooms VALUES(3100,30,'Northwest end of Concourse',replace('You are at the concourse, the city wall is just west.  A small promenade\ngoes east, and the bridge is just north of here.  The concourse continues\nsouth along the city wall.\n','\n',char(10)));
INSERT INTO rooms VALUES(3101,30,'Promenade',replace('The river gently flows west just north of here.  The promenade continues\nfurther east and to the west you see the city wall.  Park Road leads south\nfrom here.\n','\n',char(10)));
INSERT INTO rooms VALUES(3102,30,'Promenade',replace('The river gently flows west just north of here.  The promenade continues\nboth east and west.  South of here you see the entrance to the park, and a\nsmall building seems to be just west of the entrance.\n','\n',char(10)));
INSERT INTO rooms VALUES(3103,30,'Promenade',replace('The river gently flows west just north of here.  The promenade continues\nboth east and west.  A small path leads south.  Looking across the river you\nsee the levee.\n','\n',char(10)));
INSERT INTO rooms VALUES(3104,30,'Northeast end of Concourse',replace('You are at the Concourse.  The city wall is just east and a small\npromenade goes west.  Looking across the river you see a building that\nresembles a warehouse.  The Concourse continues south along the city wall.\n','\n',char(10)));
INSERT INTO rooms VALUES(3105,30,'Park Entrance',replace('You are standing just inside the small park of Midgaard.  To the north is\nthe promenade and a small path leads south into the park.  To your east is\nthe famous Park Cafe.\n','\n',char(10)));
INSERT INTO rooms VALUES(3106,30,'Park Cafe',replace('You are inside Park Cafe, a very well lighted, cosy place. The cafe\nis built from large logs. Through the windows in the northern wall you\nsee the river, and through the southern window you see many vigorous\ncolorful plants.\n','\n',char(10)));
INSERT INTO rooms VALUES(3107,30,'Small path through the park',replace('You are walking along a small path through the park.  The path continues\nsouth and east.\n','\n',char(10)));
INSERT INTO rooms VALUES(3108,30,'Small path in the park',replace('You are standing on a small path inside the park.  The park entrance is\njust north of here, and Park Cafe is just east of the entrance.  The path\nleads further east and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(3109,30,'Small path in the park',replace('You are on a small path running through the park.  It continues west and\nsouth and just north of here you see the southern wall of Park Cafe.\n','\n',char(10)));
INSERT INTO rooms VALUES(3110,30,'Cityguard Head Quarters',replace('You are inside a tidy office.  A big desk made from dark wood is standing\nin the centre of the room.\n','\n',char(10)));
INSERT INTO rooms VALUES(3111,30,'Park Road',replace('The road continues north and south.  A building is just west of here, you\nnotice a sign on the door.  The park entrance is to the east.\n','\n',char(10)));
INSERT INTO rooms VALUES(3112,30,'Western Park Entrance',replace('You are standing at the western end of the park.  A small path leads east\ninto the park and going west through the entrance you will reach Park Road.\n','\n',char(10)));
INSERT INTO rooms VALUES(3113,30,'A path in the park',replace('You are in the park.  The paths lead north and west.  Westwards is the\npark entrance and to the east you see a small pond.\n','\n',char(10)));
INSERT INTO rooms VALUES(3114,30,'The Pond',replace('You are swimming around in the pond, feeling rather stupid.  You can get\nback on the path from the eastern and western end of the pond.\n','\n',char(10)));
INSERT INTO rooms VALUES(3115,30,'A path in the park',replace('You are in the park.  The paths lead north and east.  Eastwards is the\npark entrance and to the west you see a small pond.\n','\n',char(10)));
INSERT INTO rooms VALUES(3116,30,'Eastern Park Entrance',replace('You are standing at the eastern end of the park.  A small path leads west\ninto the park.  Going east through the entrance you will reach Emerald\nAvenue.\n','\n',char(10)));
INSERT INTO rooms VALUES(3117,30,'Emerald Avenue',replace('You are at Emerald Avenue which continues north and south.  To the west is\nthe park entrance and to the east is the not very big Town Hall of Midgaard.\n','\n',char(10)));
INSERT INTO rooms VALUES(3118,30,'Park Road',replace('You are on Park Road which leads north and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(3119,30,'Emerald Avenue',replace('You are standing at a bend on Emerald Avenue.  The road leads north and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(3120,30,'Road Crossing',replace('You are in the middle of the road cross.  Roads lead in all directions.\nA huge black iron chain as thick as a tree trunk is fastened into the ground\nat the centre of the road cross.  Its other end leads directly upwards towards\nthe sky.\nA road sign is here.\n','\n',char(10)));
INSERT INTO rooms VALUES(3121,30,'Emerald Avenue',replace('You are standing at a bend on Emerald Avenue.  The road leads south and\neast.\n','\n',char(10)));
INSERT INTO rooms VALUES(3122,30,'Park Road',replace('You are on Park Road which leads south and north.  Elm Street is east of\nhere.\n','\n',char(10)));
INSERT INTO rooms VALUES(3123,30,'Elm Street',replace('You are on Elm street.  Park Road is to the west and Elm Street continues\nin eastward direction.\n','\n',char(10)));
INSERT INTO rooms VALUES(3124,30,'End of Elm Street',replace('You are at the end of Elm Street.  An old elm tree grows here.\n','\n',char(10)));
INSERT INTO rooms VALUES(3125,30,'Emerald Avenue',replace('You are on Emerald Avenue which continues north.\nThe Concourse is south of here.\n','\n',char(10)));
INSERT INTO rooms VALUES(3126,30,'Park Road',replace('You are on Park Road which continues north.  The Concourse is south of here.\n','\n',char(10)));
INSERT INTO rooms VALUES(3127,30,'On the Concourse',replace('You are at the southwest corner of the city wall.  The Concourse leads\nboth north and east.\n','\n',char(10)));
INSERT INTO rooms VALUES(3128,30,'On the Concourse',replace('The Concourse continues both east and west.  Emerald Avenue is north of\nhere.\n','\n',char(10)));
INSERT INTO rooms VALUES(3129,30,'On the Concourse',replace('The Concourse continues both east and west.  Park Road is north of here\nand an iron grate leads south to the graveyard.\nA bronze sign has been set on the wall next to the grate.\n','\n',char(10)));
INSERT INTO rooms VALUES(3130,30,'On the Concourse',replace('You are at the southeast corner of the city wall.  The Concourse leads\nboth north and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(3131,30,'Park Road',replace('You are at Park Road which continues north and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(3132,30,'Emerald Avenue',replace('You are standing on the north end of Emerald Avenue.  To the north is the\npromenade and to the east is the small street Penny Lane.\n','\n',char(10)));
INSERT INTO rooms VALUES(3133,30,'Emerald Avenue',replace('You are standing at a bend on Emerald Avenue.  To the east the road goes on\nand to the south is the Road Crossing.\n','\n',char(10)));
INSERT INTO rooms VALUES(3134,30,'Emerald Avenue',replace('You are standing at a bend on Emerald Avenue.  To the west the road goes on\nand to the north is the Road Crossing.\n','\n',char(10)));
INSERT INTO rooms VALUES(3135,30,'Park Road',replace('You are at a bend on Park Road.  To the north the road goes on and to the\neast is the Road Crossing.  To the south, the ancient cliffs rise from deep\nunder the ground, forming a wall.\n','\n',char(10)));
INSERT INTO rooms VALUES(3136,30,'Park Road',replace('You are at a bend on Park Road.  To the south the road goes on and to the\nwest is the Road Crossing.\n','\n',char(10)));
INSERT INTO rooms VALUES(3137,30,'The Waiting Room',replace('You are standing in the waiting room at the town hall.  Wooden chairs stand\nalong the walls and a long desk is placed in the middle of the room.\n','\n',char(10)));
INSERT INTO rooms VALUES(3138,30,'The Mayor''s Office',replace('You are in the not very big office of the Mayor of Midgaard.  A large and\npolished but completely empty desk is standing in front of an armchair that\nlooks so comfortable that it most of all resembles a bed with the head end\nraised slightly.\n','\n',char(10)));
INSERT INTO rooms VALUES(3139,30,'Penny Lane',replace('You are on Penny Lane.  Emerald Avenue is to the west and Penny Lane\ncontinues in eastward direction.\n','\n',char(10)));
INSERT INTO rooms VALUES(3140,30,'Penny Lane',replace('You are on Penny Lane.  The narrow road continues north and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(3141,30,'End of Penny Lane',replace('You are at the end of Penny Lane.  The only exit appears to be south.\n','\n',char(10)));
INSERT INTO rooms VALUES(3142,30,'Captain''s Office',replace('You are in the Office of the Captain of the Guard.  The Midgaard Coat of\nArms is hanging on the north wall and a heavy steel door is to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(3143,30,'The Jail',replace('You are in a dark and humid jail.  The dark stone walls are hard and cold\nto the touch.  A heavy steel door is to the north.\n','\n',char(10)));
INSERT INTO rooms VALUES(3200,30,'Under the Bridge',replace('The arch under the bridge is covered by seaweed for one foot above the\nsurface of the river.  The water gently flows through an opening in the lower\npart of the city wall.\n','\n',char(10)));
INSERT INTO rooms VALUES(3201,30,'On the River',replace('North of here you see the miserable buildings of the poor alley.  The\nriver flows west towards the bridge.  The riverbanks are too steep to climb.\n','\n',char(10)));
INSERT INTO rooms VALUES(3202,30,'On the River',replace('North of here you see the dump.  The river flows from east to west.  The\nriverbanks are too steep to climb.\n','\n',char(10)));
INSERT INTO rooms VALUES(3203,30,'On the River',replace('The levee is directly north of here.  The river flows in an east west\ndirection.\n','\n',char(10)));
INSERT INTO rooms VALUES(3204,30,'On the River',replace('You see the warehouse on the northern riverbank.  East of here you see the\ncity wall.  The river flows west towards the levee.\n','\n',char(10)));
INSERT INTO rooms VALUES(3205,30,'On the River',replace('The river enters from a hole in the eastern city wall.  The hole has been\nblocked by several vertically positioned iron bars set into the wall.\n','\n',char(10)));
INSERT INTO rooms VALUES(3405,34,'Inside the Chapel',replace('You are in a small, dark chapel.  The dark brown glass in the tiny windows\ndo not let much light through.  A few rows of worn wooden benches stand here.\n','\n',char(10)));
INSERT INTO rooms VALUES(3408,34,'Stairwell into Darkness',replace('You sense even more danger coming from below but are urged onward ...\n','\n',char(10)));
INSERT INTO rooms VALUES(3409,34,'The Acolyte''s Bedroom',replace('This is why you were not welcomed at the entrance by the tomb''s faithful\nservants ... blood and gore is ankle deep in here.\nOh NO! the door shut behind you!  It''s a trap!\nA bloodied corpse of an acolyte is lying here ...\nA bloodied corpse of an acolyte is lying here ...\nA bloodied corpse of an acolyte is lying here ...\n','\n',char(10)));
INSERT INTO rooms VALUES(3410,34,'The Lower Chambers and Tombs of the Undead',replace('The stench of death is heavy in these caverns.\n','\n',char(10)));
INSERT INTO rooms VALUES(3411,34,'The Lower Chambers and Tombs of the Undead',replace('The stench of death is heavy in these caverns.\n','\n',char(10)));
INSERT INTO rooms VALUES(3412,34,'The Grand Hall of Kings',replace('You are at the west end of the Grand Hall of Kings.  There is a doorway to the\nsouth with something strange written above it.  Also on the floor are dried\nblood stains, but their color seems a little wrong.\n','\n',char(10)));
INSERT INTO rooms VALUES(3413,34,'The Shrine of Shohan',replace('BLOOD EVERYWHERE!\nThe walls are coated with blood, bits of bloody flesh lie at your feet,\nand torn clothing is scattered about.  It wouldn''t disturb you in the least\nexcept that it is all FRESH!  What ever used to pass as an altar here,\nlies overturned and smashed.  Doors lead to the south and to the north.\n','\n',char(10)));
INSERT INTO rooms VALUES(3414,34,'The Tomb of Shohan',replace('Once beautiful, this place has been turned into a slaughterhouse by the hands\nof evil beings ... even more blood and dead, rotting flesh.  This place looks\nlike the feeding grounds of beasts and monsters.  The overturned sarcophagus\nof the once powerful King Shohan lies here.  A door leads to the north and a\ndoorway has been hewn to the east.\n','\n',char(10)));
INSERT INTO rooms VALUES(3415,34,'The Lower Chambers and Tombs of the Undead',replace('The stench of death is heavy in these caverns.\n','\n',char(10)));
INSERT INTO rooms VALUES(3416,34,'Entrance to the Lower Chambers',replace('You can tell that this area wasn''t a part of the original construction.\nThe walls have been hewn by a mighty force look as though they were CLAWED.\nThe passage slopes upward here and also continues to the north.\n','\n',char(10)));
INSERT INTO rooms VALUES(3417,34,'The Grand Hall of Kings',replace('This is the western wing of the Grand Hall of Kings.  Your only exits are to\nthe east and west in this gloomy hallway.\n','\n',char(10)));
INSERT INTO rooms VALUES(3418,34,'The Shrine of Cristis',replace('Different than the rest, this place has not been desecrated.  An altar still\nstands here and the walls show scenes from the life of Cristis the Kind,\na ruler of the outlying regions west of Midgaard.  There is a stone staircase\nleading down.  The Ghost of Cristis the Kind stands here.\n','\n',char(10)));
INSERT INTO rooms VALUES(3419,34,'The Tomb of Cristis',replace('Everything here has simply been destroyed.   Exits lead north and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(3420,34,'The Lower Chambers and Tombs of the Undead',replace('The stench of death is heavy in these caverns.\n','\n',char(10)));
INSERT INTO rooms VALUES(3421,34,'Entrance Chamber to the Grand Hall of Kings',replace('Whoever built this place must have been very rich indeed!  Though you did\nenter through a rather small door this place has enough room to hold several\nscore of people.  The floor has a beautifully woven carpet, and the walls are\ncovered in finely crafted tapestries. You can tell that these things must have\nbeen worth much but they have not lasted well throughout the ages.  Massive\ndoors lead off to the south and a large stone staircase leads up.\n','\n',char(10)));
INSERT INTO rooms VALUES(3422,34,'The Grand Hall of Kings',replace('A long hallway stretches east and west.  On the southern side of the hall\nthere are many doors, each with the name of a king who has died and is\nentombed here.  The hallway is beautiful yet chilling.  Even though the area\nhas been kept well by acolytes, there remains a stench of the undead.\n','\n',char(10)));
INSERT INTO rooms VALUES(3423,34,'The Shrine of Crotus',replace('Mostly rubble, this place used to be the shrine of the famous king Crotus,\nwho saved the northern regions from being overrun by the goblin hordes of\n100 years ago.  If not for him, Midgaard of course would have eventually been\nconquered as well.  Though Crotus was a goodly king, it was rumored that he\nturned to the dark ways in his dying years ... and died an evil man.\n','\n',char(10)));
INSERT INTO rooms VALUES(3424,34,'The Tomb of Crotus',replace('A sarcophagus lies in the middle of the room and seems undisturbed.\nA hole has been knocked into the east wall.\n','\n',char(10)));
INSERT INTO rooms VALUES(3425,34,'The Lower Chambers and Tombs of the Undead',replace('The stench of death is heavy in these caverns.\n','\n',char(10)));
INSERT INTO rooms VALUES(3426,34,'The Lower Chambers and Tombs of the Undead',replace('The stench of death is heavy in these caverns.\n','\n',char(10)));
INSERT INTO rooms VALUES(3427,34,'The Grand Hall of Kings',replace('You are in the western part of the Grand Hall of Kings.  To the south is a\ndoor and to the east and west the hall continues.\n','\n',char(10)));
INSERT INTO rooms VALUES(3428,34,'The Shrine of Mitnar',replace('Mitnar was a gruesome beast of a man ... he loved battle ... and nothing\nelse.  Warriors did love Mitnar, and all fighting men honored him.\nOn the wall is depicted battle after battle after battle.\nA small opening has been shaped carefully to the east.\n','\n',char(10)));
INSERT INTO rooms VALUES(3429,34,'The Tomb of Mitnar',replace('The wall paintings show men and women warriors alike bowing down to Mitnar,\nprisoners of war being put to the sword by Mitnar, and great heaps of gold\nand weapons under the feet of Mitnar.  Where his coffin was, there is now\nonly a rectangular blemish on the floor of the dusty room.\n','\n',char(10)));
INSERT INTO rooms VALUES(3430,34,'The Lower Chambers and Tombs of the Undead',replace('The stench of death is heavy in these caverns.\n','\n',char(10)));
INSERT INTO rooms VALUES(3431,34,'The Lower Chambers and Tombs of the Undead',replace('The stench of death is heavy in these caverns.\n','\n',char(10)));
INSERT INTO rooms VALUES(3432,34,'The Grand Hall of Kings',replace('You are still walking through the gloomy hallway.\n','\n',char(10)));
INSERT INTO rooms VALUES(3433,34,'The Shrine of Frath',replace('Little chunks of dried meat are spattered throughout this room.  The walls\nare covered in gore.  Almost as if they were painted ... ICK!  You can\nalmost make out the design!\n','\n',char(10)));
INSERT INTO rooms VALUES(3434,34,'The Tomb of Frath',replace('UGH!  The sarcophagus is opened up and the mummified body lies out in the\nopen, ripped to pieces.  Gnawed pieces of flesh and bone are strewn here.\n','\n',char(10)));
INSERT INTO rooms VALUES(3435,34,'The Lower Chambers and Tombs of the Undead',replace('The stench of death is heavy in these caverns.\n','\n',char(10)));
INSERT INTO rooms VALUES(3436,34,'The Lower Chambers and Tombs of the Undead',replace('The stench of death is heavy in these caverns.\n','\n',char(10)));
INSERT INTO rooms VALUES(3437,34,'The Grand Hall of Kings',replace('You are at the western end of the Grand Hall of Kings.  There is a\ndoor leading north and the hallway continues west.\n','\n',char(10)));
INSERT INTO rooms VALUES(3438,34,'The Shrine of Jubal',replace('This was once beautiful.  Now the huge tapestries have been torn down and the\ncarpeting pulled up ... the paintings on the ceiling are unreadable and the\naltar is crumbled.\n','\n',char(10)));
INSERT INTO rooms VALUES(3439,34,'The Tomb of Jubal',replace('The smell coming off of the opened sarcophagus is nauseating.  The floor is\nslightly crumpled and walls are raked ... but the worst part is the mummy ...\nJubal the Benevolent is missing his head!\n','\n',char(10)));
INSERT INTO rooms VALUES(3440,34,'The Lower Chambers and Tombs of the Undead',replace('The stench of death is heavy in these caverns.\n','\n',char(10)));
INSERT INTO rooms VALUES(3441,34,'The Lower Chambers and Tombs of the Undead',replace('The stench of death is heavy in these caverns.\n','\n',char(10)));
INSERT INTO rooms VALUES(3442,34,'The Lower Chambers and Tombs of the Undead',replace('The stench of death is heavy in these caverns.\n','\n',char(10)));
INSERT INTO rooms VALUES(3443,34,'The Lower Chambers and Tombs of the Undead',replace('The stench of death is heavy in these caverns.\n','\n',char(10)));
INSERT INTO rooms VALUES(3444,34,'The Lower Chambers and Tombs of the Undead',replace('The stench of death is heavy in these caverns.\n','\n',char(10)));
INSERT INTO rooms VALUES(3445,34,'The Lower Chambers and Tombs of the Undead',replace('The stench of death is heavy in these caverns.\n','\n',char(10)));
INSERT INTO rooms VALUES(3446,34,'The Lower Chambers and Tombs of the Undead',replace('The stench of death is heavy in these caverns.\n','\n',char(10)));
INSERT INTO rooms VALUES(3447,34,'The Lower Chambers and Tombs of the Undead',replace('The stench of death is heavy in these caverns.\n','\n',char(10)));
INSERT INTO rooms VALUES(3448,34,'The Lower Chambers and Tombs of the Undead',replace('This room has been totally hollowed out and smoothed, and a pit has been\ndrilled in the center of the floor.  There are extensive gruesome paintings\nof beasts and monsters terrorizing the countryside; vampires sucking the\nblood of beasts and humans alike.\n','\n',char(10)));
INSERT INTO rooms VALUES(3449,34,'The Lower Chambers and Tombs of the Undead',replace('The stench of death is heavy in these caverns.\n','\n',char(10)));
INSERT INTO rooms VALUES(3450,34,'Entrance to the Forbidden Catacombs',replace('You have entered the forbidden catacombs.  This cave system must have been\nbuilt long ago.  The air is dank and smells of something dead ...  or maybe\nundead.  Enter here at your own risk ... something evil abides.\n','\n',char(10)));
INSERT INTO rooms VALUES(3451,34,'The Catacombs',replace('Stone walls, musty air ... the earth seems to moan softly.\n','\n',char(10)));
INSERT INTO rooms VALUES(3452,34,'The Catacombs',replace('Stone walls, musty air ... the earth seems to moan softly.\n','\n',char(10)));
INSERT INTO rooms VALUES(3453,34,'The Catacombs',replace('Stone walls, musty air ... the earth seems to moan softly.\n','\n',char(10)));
INSERT INTO rooms VALUES(3454,34,'The Catacombs',replace('Stone walls, musty air ... the earth seems to moan softly.\n','\n',char(10)));
INSERT INTO rooms VALUES(3455,34,'The Catacombs',replace('Stone walls, musty air ... the earth seems to moan softly.\n','\n',char(10)));
INSERT INTO rooms VALUES(3456,34,'The Catacombs',replace('Stone walls, musty air ... the earth seems to moan softly.\n','\n',char(10)));
INSERT INTO rooms VALUES(3457,34,'The Catacombs',replace('Stone walls, musty air ... the earth seems to moan softly.\n','\n',char(10)));
INSERT INTO rooms VALUES(3458,34,'The Catacombs',replace('Stone walls, musty air ... the earth seems to moan softly.\n','\n',char(10)));
INSERT INTO rooms VALUES(3459,34,'The Catacombs',replace('Stone walls, musty air ... the earth seems to moan softly.\n','\n',char(10)));
INSERT INTO rooms VALUES(3460,34,'Den of the Vampire',replace('Your mind whirls in the hideous madness of this place.  The stench\nis horrendous and dead bodies, sucked of life, lay all over.  One coffin\nlies in the center of the room ... waiting for YOU!\n','\n',char(10)));
INSERT INTO rooms VALUES(3461,34,'The Catacombs',replace('Stone walls, musty air ... the earth seems to moan softly.\n','\n',char(10)));
INSERT INTO rooms VALUES(3462,34,'The Catacombs',replace('Stone walls, musty air ... the earth seems to moan softly.\n','\n',char(10)));
INSERT INTO rooms VALUES(3463,34,'The Catacombs',replace('Stone walls, musty air ... the earth seems to moan softly.\n','\n',char(10)));
INSERT INTO rooms VALUES(3464,34,'The Catacombs',replace('Stone walls, musty air ... the earth seems to moan softly.\n','\n',char(10)));
INSERT INTO rooms VALUES(3465,34,'The Gilded Hallway',replace('Wow!  Although this hallway is quite filthy and dusty, it is noticeably\ndifferent than the rest of the catacombs ... but you don''t feel safe yet.\nThe walls faintly show ancient detailed etchings in gold and silver of\nancient rituals ... not all of which seem pleasant.  The hallway continues\nnorth into the catacombs and further south as long as you can see.\n','\n',char(10)));
INSERT INTO rooms VALUES(3466,34,'The Gilded Hallway',replace('Ancient etchings and writing in intricate gold and silver designs fill these\nwalls.  You are tempted to linger and examine them closely.  Your light source\nflickers off the walls showing you exits north and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(3467,34,'The Gilded Hallway',replace('Ancient etchings and writing in intricate gold and silver designs fill these\nwalls.  You are tempted to linger and examine them closely.  Your light source\nflickers off the walls showing you exits north and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(3468,34,'The Gilded Hallway',replace('Ancient etchings and writing in intricate gold and silver designs fill these\nwalls.  You are tempted to linger and examine them closely.  Your light source\nflickers off the walls showing you exits north and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(3469,34,'The Gilded Hallway',replace('Ancient etchings and writing in intricate gold and silver designs fill these\nwalls.  You are tempted to linger and examine them closely.  Your light source\nflickers off the walls showing you exits north.\n','\n',char(10)));
INSERT INTO rooms VALUES(3470,34,'A Secret Passageway',replace('A secret passage!  You wonder where it may lead!\n','\n',char(10)));
INSERT INTO rooms VALUES(3471,34,'A Secret Passageway',replace('A secret passage!  You wonder where it may lead!\n','\n',char(10)));
INSERT INTO rooms VALUES(3472,34,'The Short Way to Hell ...',replace('You fall ...\n            hmm .... it''s getting really HOT!\nYou fall ...\n                        you fall ...\n     Slowly you are cooking as you fall further ... your skin is burning and\nyour hair evaporates ...\n\n                                           you fall ...\n\n                 and fall ...\n\n                                     AND STOP!\n\nWelcome to HELL!\n\nBut even in Hell we give you another chance.\n\n','\n',char(10)));
INSERT INTO rooms VALUES(3475,34,'Inside the coffin',replace('You are inside a coffin.  It seems rather cramped in here.  You can climb\nup out of the coffin, or you can wait for here the real occupant to join you.\n','\n',char(10)));
INSERT INTO rooms VALUES(3500,35,'The Plains',replace('You are standing on the plains. This is a vast desolate place where the\nwind can howl undisturbed since nothing but you bars its way. However you\nare not the first to wander here. Before you somebody has left a small path.\nThe path looks rather bewildered and is not the kind of path to lead to\nanywhere significant or important but it seems to have made up its mind to\nenter the hills far away north.\n','\n',char(10)));
INSERT INTO rooms VALUES(3501,35,'The Lane',replace('You are strolling along a pleasant, shady lane. The road is lined on both\nsides by tall, stately trees which lend the scene with a sense of quiet\nserenity. You can follow the road north or south.\n','\n',char(10)));
INSERT INTO rooms VALUES(3502,35,'The Cross Roads',replace('The roads cross here.  Midgaard is to the west.  To the east, you see the\nstately oaks and poplars of the holy grove.  A wide path leads south through\nthe dwarven forest, and another path leads down.  To the north is a very\ndesolate trail.\n','\n',char(10)));
INSERT INTO rooms VALUES(3503,35,'City Entrance',replace('You stand on the outskirts of a large city - Midgaard; the capital of this\nland. The road leads east into the peace and quiet - and dangers - of the\nforest; and to the west it becomes the main street of the town; surrounded by\na confusion of shops, bars, and market places.  Another path wanders off to\nthe south.\n','\n',char(10)));
INSERT INTO rooms VALUES(3504,35,'The South Bridge',replace('You are standing on a small, rickety bridge leading from the Midgaard\nCity Dump, to the forest of Miden''nir (Goblinic for Green Blood). You can\nsmell the Dump to the north, or go south where there is fresh air and\ngreenery.\n','\n',char(10)));
INSERT INTO rooms VALUES(3505,35,'The Trail to Miden''nir',replace('You are in a light forest. A path leads south, but the passage to the\neast is easy enough. To the west, smoke can be seen rising above the\ntreetops. The sprawl of Midgaard lies north of here.\n','\n',char(10)));
INSERT INTO rooms VALUES(3506,35,'The Miden''nir',replace('You are in a dark forest. To the east, mountains block passage. From\nhere, only the lighter forest to the west or south offer a way to travel.\n','\n',char(10)));
INSERT INTO rooms VALUES(3507,35,'The Miden''nir',replace('The forest is deep here and the wind blows through the trees and\nthrough your hair. To the north, the forest gets lighter. However, the\nsouthern and western paths place you even deeper in the wood.\n','\n',char(10)));
INSERT INTO rooms VALUES(3508,35,'On a Small Path',replace('A path is here, leading east and south through the dark woods of\nMiden''nir. Mountains slash the scenery to the west of here.\n','\n',char(10)));
INSERT INTO rooms VALUES(3509,35,'The Miden''nir',replace('The trees of Miden''nir are lush and green, hiding the evil that lurks\nin these woods. The trees become too thick to the west, but you may go\nnorth, south or travel toward the mountains that lie east of here.\n','\n',char(10)));
INSERT INTO rooms VALUES(3510,35,'A Crossroads',replace('Here footworn paths meet leading north, south and east. The trees seem to\nbe closing in on you at this point, and you can barely see the sky\nthrough the thick branches above your head.\n','\n',char(10)));
INSERT INTO rooms VALUES(3511,35,'The Trail',replace('You are on a north-south trail through the woods. To the west, impassable\nmountains glare at you, and the thick woods and undergrowth prevent any\nmovement westward.\n','\n',char(10)));
INSERT INTO rooms VALUES(3512,35,'The Miden''nir',replace('The trees of Miden''nir are lush and green, hiding the evil that lurks\nin these woods. You can go north toward the mountains, or west to the\nforest, but the steep mountains prevent any movement east.\n','\n',char(10)));
INSERT INTO rooms VALUES(3513,35,'The Miden''nir',replace('The forest is dark, and becomes even darker west.  You sense\nthat there is something evil hidden in these woods.  The forest gets\nlighter to the north.  The wind kicks up as you ponder your options.\n','\n',char(10)));
INSERT INTO rooms VALUES(3514,35,'Deep Forest',replace('It is quite dark here, forest surrounds you. With each step, the forest\nseems to close around you, and get darker and more foreboding.  It might just\nbe time to head back to somewhere safe.\n','\n',char(10)));
INSERT INTO rooms VALUES(3515,35,'Light Forest',replace('The forest is light here and you can easily pick your way through the \ntrail.  To the east, the forest becomes thick and darker. South, the trail\ncontinues.\n','\n',char(10)));
INSERT INTO rooms VALUES(3516,35,'Muddy Ground',replace('The ground is quite muddy here and puddles are all around. Your boots\nmake a disgusting SQUISH as you walk here. You can go in any of the\nfour cardinal directions from here. Hopefully, it will be dryer.\n','\n',char(10)));
INSERT INTO rooms VALUES(3517,35,'Near the Mountains',replace('The most prominent feature here is the mountains that lie to the east.\nYou can only go north and west from here as the rocks stop all other\nmovement.\n','\n',char(10)));
INSERT INTO rooms VALUES(3518,35,'The Fading Trail',replace('The trail becomes nearly unpassable here. You can go north\nas the forest is relatively light. To the south, you can see a path.\n','\n',char(10)));
INSERT INTO rooms VALUES(3519,35,'The Dark Path',replace('You are hemmed in by trees on either side of you.  The path\ncontinues north and south, and while is much to thick to explore west,\nyou can head off into the woods to the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(3520,35,'The Dark Forest',replace('You stomp your way through the underbrush.  The dark forest of Miden''nir\nget pretty thick here, and the branches high above your head are so thick that\nthey block out all direct sunlight.  While it is much too thick to go\nfurther east, you might be able to make your way though the forest to the\nsouth and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(3521,35,'Carnage',replace('Here, you see a gruesome sight. Blood is everywhere... on the trees and\nsoaked into the ground. Two carcasses lie in front of you, seeming to look\nup at you. The forest is impassible to the south, but the other directions\nlook ok.\n','\n',char(10)));
INSERT INTO rooms VALUES(3522,35,'Deep in the Forest of Miden''nir',replace('There is a sickening stench here. It smells of blood and death.\nTo the north, you catch glimpses of daylight. To the east, you\nsimply cannot see. The trees are close and stifling.\n','\n',char(10)));
INSERT INTO rooms VALUES(3523,35,'The Dark Forest',replace('The branches above you block out all direct sunlight, making the forest\nin this area rather dark.  The forest continues east, where it meets the\nmountains. The air is still and stuffy - a stench comes from the west and an\nugly feeling causes the hair to rise on the back of your neck!\n','\n',char(10)));
INSERT INTO rooms VALUES(3550,35,'At The Foot of The Mountains',replace('You find yourself at the foot of the mountains, where it is much to steep\nto continue north or east.  You see the lush, green forest of Miden''nir to the\nsouth and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(3551,35,'The Deep in the Forest of Miden''nir',replace('The branches above you block out all direct sunlight, making the forest\nin this area very dark.  The forest continues west, but mountains block\nfurther exploration in all other directions, except south, where you notice a\nsmall tunnel dug into the mountainside.\n','\n',char(10)));
INSERT INTO rooms VALUES(3552,35,'A Tunnel in the Mountains',replace('The walls of this tunnel were carved out many years ago by the goblins of\nthis forest.  The floor is well worn, and continues south, into the\nmountain, or back north out into the forest.\n','\n',char(10)));
INSERT INTO rooms VALUES(3553,35,'A Tunnel in the Mountains',replace('The tunnel gets lighter to the north, presumably leading out, while to\nthe south the passage gets smaller and smaller.  A small alcove has been\ncarved into the east wall.\n','\n',char(10)));
INSERT INTO rooms VALUES(3554,35,'A Small Alcove',replace('A small alcove has been carved out here.  There are a bunch of twigs\nand leaves thrown into a pile here, probably serving as a bed.\n','\n',char(10)));
INSERT INTO rooms VALUES(3555,35,'A Tunnel in the Mountains',replace('As you explore further into the mountainside, the tunnel gets smaller and\nsmaller to the south.  You almost have to hunch over to make your way thru\nthis area.  A small archway to the south leads into a large chamber.\n','\n',char(10)));
INSERT INTO rooms VALUES(3556,35,'The Goblin Headquarters',replace('The tunnel widens into a large (well, large for goblins) cavern that\nserves as the living quarters for the goblins of Miden''nir.  The bones of\nnumbers woodland creatures are strewn about the room, the remanents of a\nrecent meal.\n','\n',char(10)));
INSERT INTO rooms VALUES(3570,35,'The Front of the Inn',replace('You are standing on a well-worn path which opens into a clearing.\nAn old, wooden building is here with smoke billowing from its\nchimney. A painted sign is visible on the porch to the west. You\ncould go north or south around the building or leave this place and\nreturn to the forest.\n','\n',char(10)));
INSERT INTO rooms VALUES(3571,35,'North of the Inn',replace('You are standing north of the inn. Things don''t look much different\nfrom this angle.  The air here is filled with smells of smoke and cooking.\nSouth, the front porch is waiting for you... or you can see if there is\na back door.\n','\n',char(10)));
INSERT INTO rooms VALUES(3572,35,'South of the Inn',replace('You are standing south of the inn.  You could easily go north and enter\nthrough the front door, or west and to the rear of the establishment.  You\nhere some muffled cries from a tiny trail leading south of here.\n','\n',char(10)));
INSERT INTO rooms VALUES(3573,35,'Behind the Inn',replace('You now stand behind the inn. The smell here is not so pleasant as\nthe keeper and his help throw a good deal of garbage here. A couple of\npiles of rubbish are to the west, but you will smell the worse for\nmeddling there. As a clean alternative, you can go north or east around\nthe inn.\n','\n',char(10)));
INSERT INTO rooms VALUES(3574,35,'The Woodsman Inn',replace('You are in the common room of the Woodsman Inn. A thin haze of smoke sits\nin the air here. The Inn is often empty, as the forest has become overrun by\ngoblins as of late, and it is no longer safe in these parts. The bar is just\nnorth of here. If you''d rather have your own table, one is empty to the\nsouth.\n','\n',char(10)));
INSERT INTO rooms VALUES(3575,35,'The Ambush Point',replace('This is a overgrown foot-trail south of the inn. It leads west, but you\nwould be hard pressed to follow it far. A number of bushes are trampled on\nand some medium sized branches have been knocked down.  Obviously there has\nbeen a battle here rather recently.\n','\n',char(10)));
INSERT INTO rooms VALUES(3576,35,'The Bar',replace('This is where people use to come and enjoy the food, drink and hospitality\nof the innkeeper, but as of late, he only serves the few adventurers that\nmanage to survive a trip thru the forest. You can leave south and return to the\ncommon room.\n','\n',char(10)));
INSERT INTO rooms VALUES(3577,35,'The Bard''s Table',replace('You are in a darker corner in the Inn.  A large round table with a few\nwooden chairs sits here.  There is a large stain on the table, the remnants\nof a spilled drink.\n','\n',char(10)));
INSERT INTO rooms VALUES(3578,35,'Garbage dump',replace('You stand knee deep in garbage.  YECCH!!! It smells terrible and who knows\nwhat vermin live in these piles of filth ...\n','\n',char(10)));
INSERT INTO rooms VALUES(3579,35,'A Quieter Section of the Inn',replace('There seems to be no one in this end of the Woodsman, probably a safe place\nto rest and lick your wounds ...\n','\n',char(10)));
INSERT INTO rooms VALUES(3581,35,'On the Trail of the Horsemen',replace('The path continues east and west of here.  You notice fresh tracks in\nthe soft ground that show the horsemen fled to the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(3582,35,'On the Trail of the Horsemen',replace('The path continues east and south.  You notice fresh tracks in\nthe soft ground that show the horsemen turned, and fled south.\n','\n',char(10)));
INSERT INTO rooms VALUES(3583,35,'On the Trail of the Horsemen',replace('The trail of the horsemen continues east and north along this path through\nthe forest.  The tracks are still fresh, so they must be near.\n','\n',char(10)));
INSERT INTO rooms VALUES(3584,35,'A Dead End Trail',replace('The path comes to an abrupt end here, as the trees close around you and\nmake any further exploration impossible.  Fresh tracks cover the ground, and\nend right here.  The horsemen must be nearby.\n','\n',char(10)));
INSERT INTO rooms VALUES(3600,36,'A Gravel Road on the Graveyard',replace('You are on a well-kept gravel road that leads north-south through the\ngraveyard.  On both sides of the road grow dark evergreen trees.  An iron\ngrate is to the north and narrow gravel paths lead east and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(3601,36,'A Gravel Road on the Graveyard',replace('You are on a well-kept gravel road that leads north-south through the\ngraveyard.  On both sides of the road grow dark evergreen trees.\n','\n',char(10)));
INSERT INTO rooms VALUES(3602,36,'A Gravel Road on the Graveyard',replace('You are on a well-kept gravel road that leads north-south through the\ngraveyard.  On both sides of the road grow dark evergreen trees.\n','\n',char(10)));
INSERT INTO rooms VALUES(3603,36,'A Gravel Road on the Graveyard',replace('You are on a well-kept gravel road that leads north-south through the\ngraveyard.  On both sides of the road grow dark evergreen trees.\n','\n',char(10)));
INSERT INTO rooms VALUES(3604,36,'In front of the Chapel',replace('You are on an open space before a small chapel.  A gravel road leads north\nthrough the graveyard and the chapel entrance is to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(3606,36,'A Gravel Path on the Graveyard',replace('You are on a gravel path winding its way between dark evergreen trees on\nthe graveyard.  An old tomb is here.\n','\n',char(10)));
INSERT INTO rooms VALUES(3607,36,'In a dusty Tomb',replace('You are in a dark burial chamber beneath a large tomb stone.\nThe only exit appears to be up.\n','\n',char(10)));
INSERT INTO rooms VALUES(3608,36,'A Gravel Path on the Graveyard',replace('You are on a gravel path winding its way between dark evergreen trees on\nthe graveyard.  The path leads north and west.  An old tomb is here.\n','\n',char(10)));
