INSERT INTO rooms VALUES(3612,36,'A Gravel Path on the Graveyard',replace('You are on a gravel path winding its way between dark evergreen trees on\nthe graveyard.  The path leads north and east.  A small shed is to the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(3613,36,'In a shed on the Graveyard',replace('You are in a small shed that looks as if it is used to store all sorts of\ngardening equipment.  The only exit appears to be through a door to the east.\n','\n',char(10)));
INSERT INTO rooms VALUES(3614,36,'A Gravel Path on the Graveyard',replace('You are on a gravel path winding its way between dark evergreen trees on\nthe graveyard.  The path leads south and west.  An old tomb is here.\n','\n',char(10)));
INSERT INTO rooms VALUES(3615,36,'In a dusty Tomb',replace('You are in a dark burial chamber beneath a large tomb stone.\nThe only exit appears to be up.\n','\n',char(10)));
