INSERT INTO rooms VALUES(3700,37,'Entrance to Mud School',replace('This is the entrance to the Merc Mud School.  Go north to go through mud\nschool.  If you have been here before and want to go directly to the arena,\ngo south.\n','\n',char(10)));
INSERT INTO rooms VALUES(3701,37,'A Room in Mud School',replace('You are in a square white room.  The walls are all blank, with no windows.\nLight fluoresces off the ceiling in soft white tones.  Of course, there is a\nsign on the wall.  The exits are west and south.  A small plaque is on the\nwall.\n','\n',char(10)));
INSERT INTO rooms VALUES(3702,37,'The Center Room',replace('You are in a square white room.  The walls are all blank, with no windows.\nLight fluoresces off the ceiling in soft white tones.  Of course, there is a\nsign on the wall.  Exits lead in ALL directions.\n','\n',char(10)));
INSERT INTO rooms VALUES(3703,37,'A Room in Mud School',replace('You are in a square white room.  The walls are all blank, with no windows.\nLight fluoresces off the ceiling in soft white tones.  Of course, there is a\nsign on the wall.  Exits lead north and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(3704,37,'A Room in Mud School',replace('You are in a square white room.  The walls are all blank, with no windows.\nLight fluoresces off the ceiling in soft white tones.  Of course, there is a\nsign on the wall.  The only exit is east.\n','\n',char(10)));
INSERT INTO rooms VALUES(3705,37,'A Room in Mud School',replace('You are in a square white room.  The walls are all blank, with no windows.\nLight fluoresces off the ceiling in soft white tones.  Of course, there is a\nsign on the wall.  The only exit is north.\n','\n',char(10)));
