INSERT INTO rooms VALUES(3708,37,'A Room in Mud School',replace('You are in a square white room.  The walls are all blank, with no windows.\nLight fluoresces off the ceiling in soft white tones.  Of course, there is a\nsign on the wall.  The only exit is down.\n','\n',char(10)));
INSERT INTO rooms VALUES(3709,37,'A Room in Mud School',replace('You are in a square white room.  The walls are all blank, with no windows.\nLight fluoresces off the ceiling in soft white tones.  Of course, there is a\nsign on the wall.  Exits reach west and down.\n','\n',char(10)));
INSERT INTO rooms VALUES(3710,37,'The Blob Cage',replace('You are in a smelly cage.  Strangely, the walls are still clean!\nYou see a sign here.  The only exit is up.\n','\n',char(10)));
INSERT INTO rooms VALUES(3711,37,'A Room in Mud School',replace('You are in a square white room.  The walls are all blank, with no windows.\nLight fluoresces off the ceiling in soft white tones.  Of course, there is a\nsign on the wall.\n','\n',char(10)));
INSERT INTO rooms VALUES(3712,37,'The Cage Room',replace('You are in the cage room.  All around are 4 cages.  Light fluoresces off the\nceiling in soft white tones.  Of course, there is a big sign on the wall.\nExits lead into the cardinal directions plus down.\n','\n',char(10)));
INSERT INTO rooms VALUES(3713,37,'A Cage',replace('You are in a cage.  Blood and gore are everywhere.  The keepers must be lax\nin the upkeep here!  There is a sign on the wall.  The only exit is south.\n','\n',char(10)));
INSERT INTO rooms VALUES(3714,37,'A Cage',replace('You are in a cage.  Blood and gore are everywhere.  The keepers must be lax\nin the upkeep here!  There is a sign on the wall.  The only exit is east.\n','\n',char(10)));
INSERT INTO rooms VALUES(3715,37,'A Cage',replace('You are in a cage.  Blood and gore are everywhere.  The keepers must be lax\nin the upkeep here!  There is a sign on the wall.  The only exit is north.\n','\n',char(10)));
INSERT INTO rooms VALUES(3716,37,'A Cage',replace('You are in a cage.  Blood and gore are everywhere.  The keepers must be lax\nin the upkeep here!  There is a sign on the wall.  The only exit is west.\n','\n',char(10)));
INSERT INTO rooms VALUES(3717,37,'A Room in Mud School',replace('You are in a square white room.  The walls are all blank, with no windows.\nLight fluoresces off the ceiling in soft white tones.  Of course, there is a\nsign on the wall.  Find your own exit here.\n','\n',char(10)));
INSERT INTO rooms VALUES(3718,37,'The Store in Mud School',replace('You are in a cramped room.  Stacked neatly on shelves everywhere are items\nand packages.  Light fluoresces off the ceiling in soft white tones.  Of\ncourse, there is a sign on the wall.  The only exit is north.\n','\n',char(10)));
INSERT INTO rooms VALUES(3719,37,'A Room in Mud School',replace('You are in a square white room.  The walls are all blank, with no windows.\nLight fluoresces off the ceiling in soft white tones.  Of course, there is a\nsign on the wall.  The exits are north and west, with a door to the east.\n','\n',char(10)));
INSERT INTO rooms VALUES(3720,37,'The Darkened Room',replace('This room was purposefully darkened so that you would need to hold on to a\nlight source to go through.  The walls are, of course, blank, and white.\nThe only exit is south.\n','\n',char(10)));
INSERT INTO rooms VALUES(3721,37,'The End of Mud School!',replace('This is a very bright room, with a marble pedestal in the center.  Behind\nthe pedestal stands a person cloaked in Silver.  Tapestries flow from every\nwall, and you feel very happy to be here right now.  There is a big sign here.\nThe only exit is on the other side of the gate north of you.\n','\n',char(10)));
INSERT INTO rooms VALUES(3722,37,'South Wall of Arena',replace('You are in the Arena.  Remember, if you wish to get out of this Arena, just\ngo up.  Ceilings can barely be seen in this huge Arena.  You feel as if you are\nbeing watched by some divine being.\n','\n',char(10)));
INSERT INTO rooms VALUES(3723,37,'South Wall of Arena',replace('You are in the Arena.  Remember, if you wish to get out of this Arena, just\ngo up.  Ceilings can barely be seen in this huge Arena.  You feel as if you are\nbeing watched by some divine being.\n','\n',char(10)));
