INSERT INTO rooms VALUES(3748,37,'The Center of the Dungeon',replace('You are in the center of a large room.  A faint light from above shows that\nthe floors are all covered with slime.  A feeling of dread comes over you as\nyou notice that this is NOT a great place to go.  Exits go in all directions.\nOf special note is the one that brings you back up!!!\n','\n',char(10)));
INSERT INTO rooms VALUES(3749,37,'The North West Corner of the Dungeon',replace('You are against a wall in the dungeon.  It is quite dark here.  The lack of\nany windows in the area explains the smell around you.\n','\n',char(10)));
