INSERT INTO rooms VALUES(3755,37,'The South Wall of the Dungeon',replace('You are against a wall in the dungeon.  It is quite dark here.  The lack of\nany windows in the area explains the smell around you.\n','\n',char(10)));
INSERT INTO rooms VALUES(3756,37,'The South East Corner of the Dungeon',replace('You are against a wall in the dungeon.  It is quite dark here.  The lack of\nany windows in the area explains the smell around you.\n','\n',char(10)));
INSERT INTO rooms VALUES(3757,37,'A Room in Mud School',replace('You are in a room in Mud School.  Pastels cover these walls, due to Hatchet''s\nmood for the day.  To the west is Furey''s Training Room, and to the east is\nHatchet''s Guild Room.  North of you is the next Station of Mud School.\nThere is a sign on the wall (type ''LOOK SIGN'' to read it).\n','\n',char(10)));
INSERT INTO rooms VALUES(3758,37,'Furey''s Training Room',replace('You are in Furey''s Training Room.  Around you are all sorts of physical\nand mental training tools.  The whole room is filled with magic, holiness, \nand sweat.  There is a sign on the wall.\n','\n',char(10)));
INSERT INTO rooms VALUES(3759,37,'Hatchet''s Guild Room',replace('You are in a room filled with weapons, books, and many combat dummies, some\ncut and stabbed many times, others burnt to a crisp.  The room is filled with\nsweat and an aura of magic.  There is a sign on the wall.\n','\n',char(10)));
INSERT INTO rooms VALUES(3760,37,'A Safe Room',replace('You are in a safe room, away from all the mean rabbits and snails of the Arena.\nYou can rest here, and go up to go back to the Temple of Midgaard.\n','\n',char(10)));
INSERT INTO rooms VALUES(3900,39,'West trail around Midgaard',replace('You are on a dusty trail following the outside wall of Midgaard.\nTo the east the wall towers over you and to the west you see the\nforest of Haon-Dor. The trail leads north and south along the wall. \n','\n',char(10)));
INSERT INTO rooms VALUES(3901,39,'West trail around Midgaard',replace('You are on a dusty trail following the outside wall of Midgaard.\nTo the east the wall towers over you and to the west you see the\nforest of Haon-Dor. The trail leads north and south along the wall. \n','\n',char(10)));
INSERT INTO rooms VALUES(3902,39,'Northwest corner of dusty trail.',replace('You are standing outside the northwestern corner of the city wall.\nThe trail leads east following the north wall and south towards the gate.  \n','\n',char(10)));
INSERT INTO rooms VALUES(3903,39,'Dusty trail along north wall.',replace('You are walking on the trail following the outside of Midgaard''s\nnorthern wall.  \n','\n',char(10)));
INSERT INTO rooms VALUES(3904,39,'The long dusty trail following the north wall.',replace('You are walking along the north wall. This is the rear of the Temple.\nIt is not as pompous and impressive from this side. To the north the plains\nextend towards the horizon.\nYou notice some markings on the wall here.\n','\n',char(10)));
INSERT INTO rooms VALUES(3905,39,'Dusty trail along north wall.',replace('You are walking on the trail following the outside of Midgaard''s\nnorthern wall.  \n','\n',char(10)));
INSERT INTO rooms VALUES(3906,39,'Northeast corner of dusty trail.',replace('You are standing outside the northeastern corner of the city wall.\nThe trail leads west following the north wall and south towards the gate.  \n','\n',char(10)));
INSERT INTO rooms VALUES(3907,39,'East trail around Midgaard',replace('You are on a dusty trail following the outside wall of Midgaard.\nTo the west the wall towers over you and far to the east you see\nsome mountains. The trail leads north and south along the wall. \n','\n',char(10)));
INSERT INTO rooms VALUES(3908,39,'East trail around Midgaard',replace('You are on a dusty trail following the outside wall of Midgaard.\nTo the west the wall towers over you and far to the east you see\nsome mountains. The trail leads north and south along the wall. \n','\n',char(10)));
INSERT INTO rooms VALUES(4000,39,'The hills',replace('You are on a small bewildered path winding its way between the hills in\nlack of better things to do. To the south you have a splendid view over the\nflat, vast, desolate plains. To the north the hills grow steadily darker and\nforeboding. This is the cause of no sunset, it is rather the power of evil\npenetrating these quiet hills. Glancing around you notice only a single bird.\n','\n',char(10)));
INSERT INTO rooms VALUES(4001,39,'The hills',replace('You are surrounded by dark and sinister hills. Although they seemed fairly\nsmall from a distance you now get the feeling that they''re closing in on you,\ntowering over you, overwhelming you ...  The small path seems to have second\nthoughts about these hills because it starts winding unnecessarily, turning\nseveral times around itself.  To the south the hills have a lighter hue of\ndark. To the north however, the hills have become nightblack holes in the\ndistant mountains.\n','\n',char(10)));
INSERT INTO rooms VALUES(4002,39,'End of the path',replace('At this point the path has had enough. With a terrified shudder it cowers\nto the ground, only staying here because you''re standing on it. with a slight\nfeeling of unease you look around noticing only a few bushes and a large sign\ncarved into the mountain.  You feel you can hear the cry of help from a\nthousand silent voices all coming from an even darker hole in the mountain to\nthe north marking the entrance to a cave (or a grave :-).\n','\n',char(10)));
INSERT INTO rooms VALUES(4010,39,'The cave',replace('You are in a large cave. The ceiling is lost somewhere above the reach of\nyour light. The floor, however, is highly illuminated, your light flickering\nover several tombstones. Only one is whole, the rest have been shattered by\nsome savage blow. The remaining tombstone looks disturbingly new...\nA small breeze of fresh air enters from the south (probably lost too). Take a\ngood breath, it may be your last mouthful of air in a long, long time that\nothers haven''t breathed before you.\nTo the north a small tunnel continues into the mountain.\n','\n',char(10)));
INSERT INTO rooms VALUES(4011,39,'The tunnel',replace('You squeeze your way through a small, narrow tunnel. The sharp-edged rocks\nprotruding from the walls threaten to scratch and cut you. \nTo the south you sense a freshness in the air which is rather unusual in these\ndamp, stuffy tunnels. To the north the tunnel continues.\n','\n',char(10)));
INSERT INTO rooms VALUES(4012,39,'The tunnel',replace('You are in a part of the tunnel that looks uncannily like the rest except\nthat it goes in a east-north direction. To the north the tunnel widens into\na cave.\n','\n',char(10)));
INSERT INTO rooms VALUES(4013,39,'The tunnel',replace('This tunnel, leading east-west, seems seldom used.  A thick layer of dust\ncovers the floor, making the air stuffy and dry. \n','\n',char(10)));
INSERT INTO rooms VALUES(4014,39,'The tunnel',replace('You are walking in a narrow tunnel. The walls are only roughly shaped,\nsharp rocks protruding everywhere, even from the floor making you stumble in\nthe flickering light. To the south the tunnel narrows even more making it\nalmost impossible to pass. To the north it slowly widens into a cave. There\nis a branch of the tunnel going west.\n','\n',char(10)));
INSERT INTO rooms VALUES(4015,39,'The tunnel',replace('You are in a corner tunnel leading west and north.\n','\n',char(10)));
INSERT INTO rooms VALUES(4016,39,'The large cave',replace('You are in a large cave, the cave continues east and west, to the south\nyou notice a small tunnel.\n','\n',char(10)));
INSERT INTO rooms VALUES(4017,39,'The large cave',replace('You are in the east end of the large cave.\n','\n',char(10)));
INSERT INTO rooms VALUES(4018,39,'The cave',replace('You are in the south end of a cave, to the south you see a tunnel. You\nnotice a large pile of bones in the corner.\n','\n',char(10)));
INSERT INTO rooms VALUES(4019,39,'The tunnel',replace('You are in a north-south leading tunnel.\n','\n',char(10)));
INSERT INTO rooms VALUES(4020,39,'The hole',replace('You are by a hole in the floor, you can leave down, or north.\n','\n',char(10)));
INSERT INTO rooms VALUES(4021,39,'The hole',replace('A hole in the floor leads down here.\n','\n',char(10)));
INSERT INTO rooms VALUES(4022,39,'The damp tunnel',replace('You are in a damp tunnel.  Your clothes feel wet.  The tunnel continues\nto the north; to the west you see a hole in the floor; and to the east\nthere is a large cave.\n','\n',char(10)));
INSERT INTO rooms VALUES(4023,39,'The large cave',replace('You are in the western part of the large cave, to the south you see\na damp tunnel.\n','\n',char(10)));
INSERT INTO rooms VALUES(4024,39,'The damp tunnel',replace('You are in a corner of a damp tunnel.  You can go west or south.\n','\n',char(10)));
INSERT INTO rooms VALUES(4025,39,'The cave',replace('You are in the north end of a cave.  To the east you see many tunnels.\n','\n',char(10)));
INSERT INTO rooms VALUES(4026,39,'The many tunnels',replace('You are at the intersection of many tunnels.\n','\n',char(10)));
INSERT INTO rooms VALUES(4027,39,'The tunnel',replace('You are in a north-south leading tunnel, you also notice a tunnel to\nthe west. From the north you sense the fresh air!\n','\n',char(10)));
INSERT INTO rooms VALUES(4028,39,'The smelly tunnel',replace('You are in a north-south leading tunnel, you see a small light\nto the north. You notice a strange smell from the north..\n','\n',char(10)));
INSERT INTO rooms VALUES(4029,39,'The cave',replace('You are in a cave that is filled with fresh air, you sense the\nwind blowing from the north. To the south you see a small tunnel\ncontinue into the mountain.\n','\n',char(10)));
INSERT INTO rooms VALUES(4030,39,'The light cave',replace('You are in a light cave, through a hole large above you, you see \nthe sky. A small tunnel to the south is the only way out.\n','\n',char(10)));
INSERT INTO rooms VALUES(4031,39,'The valley',replace('You are in a small valley, surrounded by hills and a mountain to \nthe south. In the mountain there is a cave.\n','\n',char(10)));
INSERT INTO rooms VALUES(4032,39,'The foothills',replace('You are on a winding path that leads through the foothills on the\nother side of the mountain.  The path continues north.\n','\n',char(10)));
INSERT INTO rooms VALUES(4033,39,'The intersection in the foothills',replace('The small path you are following splits here.  The path continues\nnorth and south or you can follow a trail east into the mountains.\n','\n',char(10)));
INSERT INTO rooms VALUES(4034,39,'The grassy area of the foothills',replace('The grass here is unusually high.  You notice several areas where\nsomeone or something large has crush spots of the down.  Several very\nlarge rocks litter this area.  You can go north, west or south.\n','\n',char(10)));
INSERT INTO rooms VALUES(4035,39,'The foothills end',replace('At this point you are leaving the foothills.  You see a plains area\nto the north of here.  You can spot a small city in the distance from\nhere.\n','\n',char(10)));
INSERT INTO rooms VALUES(4036,39,'The plains',replace('The plains.  Exits are south.\n','\n',char(10)));
INSERT INTO rooms VALUES(4037,39,'The foothills path',replace('Exits are east and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(4038,39,'Base of the mountain',replace('Exits are east and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(4039,39,'A trail up the mountain',replace('Exits are east and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(4040,39,'The mountain top.',replace('Exits are north, east, and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(4041,39,'The lion''s den',replace('Exits are south.\n','\n',char(10)));
INSERT INTO rooms VALUES(4042,39,'The level foothills',replace('Exits are east and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(4043,39,'The cave entrance',replace('Exits are east and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(4044,39,'The hill giant cave',replace('Exits are east.\n','\n',char(10)));
INSERT INTO rooms VALUES(4050,39,'The tunnel',replace('The tunnel turns here, continuing to the east and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(4051,39,'The tunnel',replace('You are in a narrow east-west tunnel.\n','\n',char(10)));
INSERT INTO rooms VALUES(4052,39,'The tunnel',replace('You are at a turn, the tunnel continues south and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(4053,39,'The tunnel',replace('You are at a turn, the tunnel continues north and east.\n','\n',char(10)));
INSERT INTO rooms VALUES(4054,39,'The light cave',replace('You are in a cave, to south from you there is a large fire that lights\nthe entire cave, to the east and west tunnels leads off.\n','\n',char(10)));
INSERT INTO rooms VALUES(4055,39,'The maze',replace('You are in a maze of small damp tunnels.  The only exit is west.\n','\n',char(10)));
INSERT INTO rooms VALUES(4056,39,'The light cave',replace('You are in a light cave, a large fire in front of you lights the room.\nThe cave continues to the north and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(4057,39,'The maze',replace('You are in a maze of small damp tunnels.\n','\n',char(10)));
INSERT INTO rooms VALUES(4058,39,'The maze',replace('You are in a maze of small damp tunnels.\n','\n',char(10)));
INSERT INTO rooms VALUES(4059,39,'The tunnel',replace('You are in a tunnel, only exit is to the east. You sense that the\ntunnel leads slightly down.\n','\n',char(10)));
INSERT INTO rooms VALUES(4060,39,'The tunnel',replace('You are in a small tunnel, to the west the tunnel continues and \nto the east you see some light.\n','\n',char(10)));
INSERT INTO rooms VALUES(4061,39,'The light cave',replace('You are in the south end of a light cave.\n','\n',char(10)));
INSERT INTO rooms VALUES(4062,39,'The maze',replace('You are in a maze of small damp tunnels.\n','\n',char(10)));
INSERT INTO rooms VALUES(4063,39,'The maze',replace('You are in a maze of small damp tunnels.\n','\n',char(10)));
INSERT INTO rooms VALUES(4064,39,'The tunnel',replace('You are at the eastern end of a tunnel.\n','\n',char(10)));
INSERT INTO rooms VALUES(4065,39,'The maze',replace('You are in a maze of small damp tunnels.\n','\n',char(10)));
INSERT INTO rooms VALUES(4066,39,'The maze',replace('You are in a maze of small damp tunnels.\n','\n',char(10)));
INSERT INTO rooms VALUES(4067,39,'The maze',replace('You are in a maze of small damp tunnels.\n','\n',char(10)));
INSERT INTO rooms VALUES(4068,39,'The large cave',replace('You are in the northwest end of a large cave.\n','\n',char(10)));
INSERT INTO rooms VALUES(4069,39,'The large cave',replace('You are in the northeast end of a large cave. To the north the\nis a small damp tunnel.\n','\n',char(10)));
INSERT INTO rooms VALUES(4070,39,'The large cave',replace('You are in the southwest end of a large cave.\n','\n',char(10)));
INSERT INTO rooms VALUES(4071,39,'The large cave',replace('You are in the southeast end of a large cave. To the east you\nnotice a small tunnel.\n','\n',char(10)));
INSERT INTO rooms VALUES(4072,39,'The tunnel',replace('You are in a narrow tunnel, which leads both to the east and the\nsouth. There is also an exit towards the west, where you see a large\ncave.\n','\n',char(10)));
INSERT INTO rooms VALUES(4073,39,'End of tunnel',replace('The tunnel stops here.\n','\n',char(10)));
INSERT INTO rooms VALUES(4074,39,'The hole',replace('You are at a small hole in the floor, you can either leave north\nor try your luck and leave down into the unknown!\n','\n',char(10)));
INSERT INTO rooms VALUES(4100,39,'The tunnel',replace('Suddenly you feel that the tunnel leads slightly down.\n','\n',char(10)));
INSERT INTO rooms VALUES(4101,39,'The long tunnel',replace('You are in a long east-west leading tunnel. The tunnel is quite\nwide at this point.\n','\n',char(10)));
INSERT INTO rooms VALUES(4102,39,'The long tunnel',replace('You are in a long east-west leading tunnel. The tunnel becomes\nnarrow to the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(4103,39,'The long tunnel',replace('You are in a long east-west leading tunnel. The tunnel is quite\nnarrow at this point. You notice a small hole leading south.\n','\n',char(10)));
INSERT INTO rooms VALUES(4104,39,'The long tunnel',replace('You are in a long east-west leading tunnel. The tunnel starts sloping\ndown towards the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(4105,39,'The golden cave',replace('You are in a giant cave, all the walls are shining with a soft golden\nlight. The cave continues to the south and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(4106,39,'The golden cave',replace('You are in a giant cave, all the walls are shining with a soft golden\nlight. The cave continues to the south and east, to the north is a narrow\ntunnel.\n','\n',char(10)));
INSERT INTO rooms VALUES(4107,39,'The passage',replace('You are in a small passage, it leads south, to the west is a golden\ncave.\n','\n',char(10)));
INSERT INTO rooms VALUES(4108,39,'The golden cave',replace('You are in a giant cave, all the walls are shining with a soft golden\nlight. The cave continues to the north and west, east from you there is\na small passage.\n','\n',char(10)));
INSERT INTO rooms VALUES(4109,39,'The golden cave',replace('You are in a giant cave, all the walls are shining with a soft golden\nlight. The cave continues to the south, east and north.\n','\n',char(10)));
INSERT INTO rooms VALUES(4110,39,'The tunnel',replace('You are at the end of the tunnel.\n','\n',char(10)));
INSERT INTO rooms VALUES(4111,39,'The tunnel',replace('You are in a small tunnel, it leads from east to the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(4112,39,'The tunnel',replace('You are in a larger tunnel, it leads from west to east.\n','\n',char(10)));
INSERT INTO rooms VALUES(4113,39,'The passage',replace('You are in a passage that leads towards the south. To the east \nyou see a tunnel.\n','\n',char(10)));
INSERT INTO rooms VALUES(4114,39,'The golden cave',replace('You are in a giant cave, all the walls are shining with a soft golden\nlight. The cave continues to the north, to the west you see a dark \npassage.\n','\n',char(10)));
INSERT INTO rooms VALUES(4115,39,'The dark passage.',replace('You are in a dark passage, that leads east. In the ceiling you notice\na small hole, just big enough to pass through.\n','\n',char(10)));
INSERT INTO rooms VALUES(4116,39,'The passage',replace('You are in a passage that leads north-south. You notice a small\nlight to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(4117,39,'The secret chamber',replace('You are in a secret chamber.\n','\n',char(10)));
INSERT INTO rooms VALUES(4118,39,'The cave',replace('You are in a light cave, from torches several feet above your\nhead fire lights the room. The cave continues to the west and south.\nTo the north a small hole leads to a tunnel.\n','\n',char(10)));
INSERT INTO rooms VALUES(4119,39,'The cave',replace('You are in a light cave, from torches several feet above your\nhead fire lights the room. The cave continues to the east and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(4120,39,'The passage',replace('You are in a north-south leading passage. To the south you see light.\n','\n',char(10)));
INSERT INTO rooms VALUES(4121,39,'The secret tunnel',replace('You are in a secret tunnel that leads west, you feel evilness\napproaching you as you continue west.\n','\n',char(10)));
INSERT INTO rooms VALUES(4122,39,'The secret chamber',replace('You are in a secret chamber, the room is filled with an evil\nfeeling.\n','\n',char(10)));
INSERT INTO rooms VALUES(4123,39,'The cave',replace('You are in a light cave, from torches several feet above your\nhead fire lights the room. The cave continues to the north and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(4124,39,'The cave',replace('You are in a light cave, from torches several feet above your\nhead fire lights the room. The cave continues to the east and north.\nTo the west a passage leads north.\n','\n',char(10)));
INSERT INTO rooms VALUES(4125,39,'The passage',replace('You are in a passage, to the east you see a cave. Light from the\ncave lights up the passage. To the north the passage leads into\nthe darkness.\n','\n',char(10)));
INSERT INTO rooms VALUES(4150,39,'The dark hole',replace('You are standing at a hole, a small passage leads south. You see\nsome inscriptions on the wall, most of ''em the usual stuff, like:\n''Super Snude was here'' and ''Why does the mayor likes secretaries with\nsmall hands?'' - But one inscription gets your attention, it says:\nThe Balrog is ALIVE ...\n','\n',char(10)));
INSERT INTO rooms VALUES(4151,39,'The small passage',replace('You are in a small passage, to the north you see a hole, and to\nthe south you see a large tunnel. The air is damp in this area.\n','\n',char(10)));
INSERT INTO rooms VALUES(4152,39,'The tunnel',replace('You suddenly feel that the tunnel leads down.\n','\n',char(10)));
INSERT INTO rooms VALUES(4153,39,'The large tunnel',replace('You are in a large tunnel leading from the south to the east. The\nair is damp in the area.\n','\n',char(10)));
INSERT INTO rooms VALUES(4154,39,'The large tunnel',replace('You are in a large east-west leading tunnel, the air is damp and\nthe floor is wet.\n','\n',char(10)));
INSERT INTO rooms VALUES(4155,39,'The large tunnel',replace('You are in a large tunnel, the tunnel leads west, and to the east\nyou notice a long tunnel. The air is damp in this area.\n','\n',char(10)));
INSERT INTO rooms VALUES(4156,39,'The long tunnel',replace('You are standing in a long north-south tunnel.\n','\n',char(10)));
INSERT INTO rooms VALUES(4157,39,'The wet tunnel',replace('You are in a wet, north-south leading tunnel, the floor is\npartly covered by water.\n','\n',char(10)));
INSERT INTO rooms VALUES(4158,39,'The small maze',replace('You are in a small maze, exits leads off to the east,  south\nand west. The floor is partly covered by water.\n','\n',char(10)));
INSERT INTO rooms VALUES(4159,39,'The small maze',replace('You are in a small maze, exits leads off only to the south\nand west. The air is damp in this maze.\n','\n',char(10)));
INSERT INTO rooms VALUES(4160,39,'In the tunnel at the inscription',replace('You are in a north-south leading tunnel, the air is damp. On\nthe wall there is an inscription.\n','\n',char(10)));
INSERT INTO rooms VALUES(4161,39,'The wet tunnel',replace('You are in a north-south leading tunnel.  The floor is fully\ncovered by water.\n','\n',char(10)));
INSERT INTO rooms VALUES(4162,39,'The small maze',replace('You are in a small maze. The floor is mainly covered by\nwater, exits leads north, east and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(4163,39,'The small maze',replace('You are in a small maze, where the air is damp. Exits\nleads to the north and east.\n','\n',char(10)));
INSERT INTO rooms VALUES(4164,39,'The entrance to the small maze',replace('You are in a north-south leading tunnel, and the air is damp.\nTo the west you see a small maze.\n','\n',char(10)));
INSERT INTO rooms VALUES(4165,39,'In the water',replace('You are standing in water, the tunnel continues both to the\nnorth and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(4166,39,'The wet maze',replace('You are in a part of the maze where the floor is fully covered\nby water. The maze continues to the north, east and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(4167,39,'The wet maze',replace('You are in a small maze, the floor is covered by water, the\nmaze continues east, west and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(4168,39,'The end of the tunnel',replace('The tunnel suddenly stops here, only exit is to the east.\nThe air is damp here.\n','\n',char(10)));
INSERT INTO rooms VALUES(4169,39,'In the water',replace('You are standing in the water, exits leads both north and east.\n','\n',char(10)));
INSERT INTO rooms VALUES(4170,39,'In the water',replace('You are standing in the water, it continues east and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(4171,39,'End of maze',replace('You are at the end of the small maze which continues north.\nAbove you a hole leads up.\n','\n',char(10)));
INSERT INTO rooms VALUES(4172,39,'At the sand bar',replace('You are on a little sand bar in the water.\n','\n',char(10)));
INSERT INTO rooms VALUES(4700,47,'The Spiral Stair',replace('A spiral stone stair leads up higher in the mountain, spiraling into the\nspine of the Dra-Korrin.  A small glint of light can be seen far up the\nstair shaft.\n','\n',char(10)));
INSERT INTO rooms VALUES(4701,47,'Mines',replace('A small glint of the burning torches is all that lights the way here.  Spots\nalong the jagged wall show that these mines are rich as gold and silver glitters\nall around you.\n','\n',char(10)));
INSERT INTO rooms VALUES(4702,47,'Mines',replace('This small dark tunnel continues to the north where to light no longer allows\nnormal sight.  To the east the small mine leads a a better lit area and you can\nsmell a brisk fresh air.\n','\n',char(10)));
INSERT INTO rooms VALUES(4703,47,'Mines',replace('This small tunnel is only five to six feet high and possibly the same\ndimensions wide.  It travels on a slight downslope to the west and to the south\nsome light can be seen.\n','\n',char(10)));
INSERT INTO rooms VALUES(4704,47,'Mines',replace('The small mine continues east and west here, small rocks and precious jewels\nscattered about.  There is a small tunnel that leads to the south here.\n','\n',char(10)));
INSERT INTO rooms VALUES(4705,47,'Unfinished Mine',replace('This is a small area that has been left unfinished at the moment.  It would\nhave continued south from the main shaft that is to the north of here.\n','\n',char(10)));
INSERT INTO rooms VALUES(4706,47,'Mines',replace('This small shaft of the mines continues its tunneling east and west.  Small\nglints of metal can be seen within the walls.\n','\n',char(10)));
INSERT INTO rooms VALUES(4707,47,'Turn in the Mine',replace('The small shaft travels east and south here, the masterful mining skills that\nmade this turn possible are evidently by the smooth cuts in the walls.  Almost\nas if a hot knife made its way through some warm butter.\n','\n',char(10)));
INSERT INTO rooms VALUES(4708,47,'Mines',replace('This is a three-way intersection in these mazes of mines with directions\ngoing north, west, and south which travels further down into the heart of the\nmountain itself.\n','\n',char(10)));
INSERT INTO rooms VALUES(4709,47,'Dwarven mine',replace('The walls of this mine are chipped and cut to perfection.  Workmanship of\nthis type could only have been done by the masterful Dwarven race.  Tunnels\ncontinue to the south and east, and the tunnel travels upward to the north.\n','\n',char(10)));
INSERT INTO rooms VALUES(4710,47,'Dwarven mine',replace('Tunnels spread off in all directions except to the west where the wall is made\nof a dark and bleak stone.  A small glow emanates from the walls of the mines,\nbut not enough to see by.\n','\n',char(10)));
INSERT INTO rooms VALUES(4711,47,'Dwarven mine',replace('The small shaft ends abruptly at a jewel encrusted wall.  To the north the\nsmall shaft continues some past some small rocks.\n','\n',char(10)));
INSERT INTO rooms VALUES(4712,47,'Dwarven mine',replace('This section of small shaft is a turning point and continues to the west and to\nthe south.  Small glints of gold and silver can be seen in the walls.\n','\n',char(10)));
INSERT INTO rooms VALUES(4713,47,'Dwarven mine',replace('The small shaft continues north and south deep inside this large mountain.  A\nlight glow can be seen in the walls, but not enough to see by.\n','\n',char(10)));
INSERT INTO rooms VALUES(4714,47,'Dwarven mines',replace('This section of the small shafts is a intersection of three separate tunnels.\nThey lead north, east, and west.  A faint glow is within the walls of this\nsmall intersection.\n','\n',char(10)));
INSERT INTO rooms VALUES(4715,47,'Dwarven mines',replace('The small shaft of glittering gold and silver travels east and south here.\nThe faint glow from within the walls give you a sense of safety.\n','\n',char(10)));
INSERT INTO rooms VALUES(4716,47,'Dwarven mines',replace('The small Dwarven carved shaft continues to the north and to the east here.\nSmall clumps of precious metals can be seen within the rocky walls.\n','\n',char(10)));
INSERT INTO rooms VALUES(4717,47,'Dwarven mines',replace('The small shaft of the mine continues to the west and to the south here.  A\nsmall amount of light can be seen to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(4718,47,'End of the mine',replace('The south section of the small tunnel is covered in a blue light, and also\nradiating a aura of heat.  The eastern and western walls also glow but not as\nfierce as the southern section.\n','\n',char(10)));
INSERT INTO rooms VALUES(4719,47,'Dwarven mines',replace('Small shafts lead off in all directions except northerly, where the wall seems\nto have a tinted blue color to it.  The southern tunnel seems to end a small\nways down.\n','\n',char(10)));
INSERT INTO rooms VALUES(4720,47,'Unfinished shaft',replace('The walls here are jagged and unfinished in there cuts, leaving sharp and\njagged edges at every turn.  The only exit appears to be to the north.\n','\n',char(10)));
INSERT INTO rooms VALUES(4721,47,'Dwarven mines',replace('This small shaft travels to the west and to the south, sporting small clumps\nof precious metals as they go.\n','\n',char(10)));
INSERT INTO rooms VALUES(4722,47,'Dwarven mines',replace('A slight downslope is present as this tunnel continues to the south and to the\nnorth.  To the south is where the small slope is present, traveling slightly\nfurther down into the depths of the mountain.\n','\n',char(10)));
INSERT INTO rooms VALUES(4723,47,'Unfinished mine',replace('The southern wall of this mine has been left uncarved and unfinished as you\ncan see that the amount of metals in the walls have decreased slightly here.\nThe tunnel leads to the north out of this dead end.\n','\n',char(10)));
INSERT INTO rooms VALUES(4724,47,'Dwarven mine',replace('This small shaft travels to the east and west while along the way several\nspots of precious metal and rock jut forth from the red rock.\n','\n',char(10)));
INSERT INTO rooms VALUES(4725,47,'Dwarven mine',replace('The small tunnel continues to the west and to the south from this turning\npoint.  Small spots of gold and silver can be seen in the walls.\n','\n',char(10)));
INSERT INTO rooms VALUES(4726,47,'Dwarven mines',replace('This is a north and south shaft that has been carved to perfection.  The walls\nare almost square here, giving it a hall like appearance.\n','\n',char(10)));
INSERT INTO rooms VALUES(4727,47,'Dwarven mines',replace('The small shaft here continues to the north and to the east. As it slopes\nslightly downward to the east, the walls have a more unfinished look to them.\n','\n',char(10)));
INSERT INTO rooms VALUES(4728,47,'Dwarven mines',replace('This small east-west shaft, which travels slightly downward to the east, has\na distinct smell to it.  The smell is revolting, coming close to that of rotting\nflesh.\n','\n',char(10)));
INSERT INTO rooms VALUES(4729,47,'Dwarven mines',replace('This intersection combines three tunnels, the western tunnel leading up.  To\nthe south is darkness, but there is a disgusting stench emanating from a very\nlarge cavern.\n','\n',char(10)));
INSERT INTO rooms VALUES(4730,47,'Dwarven mines',replace('This is a small north and south passage that is bleak and void of any gold or\nsilver in the walls.  It continues into darkness to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(4731,47,'Dwarven mines',replace('This small shaft ends abruptly at the southern wall.  There is a faint blue\nglow to the southern wall but no metals of jewels are present.\n','\n',char(10)));
INSERT INTO rooms VALUES(4732,47,'Duergar Outcamp',replace('This is a large cavern that stinks of decay and death.  To the north there is\na rather large hut, while to the west there is a small fire and several big\nboulders.\n','\n',char(10)));
INSERT INTO rooms VALUES(4733,47,'Duergar Barracks',replace('Several small cots line the walls here  inside this large thatched hut.  Small\nscraps of food and several small disfigured bodies lie about, no doubt the\nremains of some unfortunate dwarf.\n','\n',char(10)));
INSERT INTO rooms VALUES(4734,47,'Small cave',replace('Many small and disfigured bodies have been piled up here stinking up the whole\ncavern.  Blood stains line the walls and entrails are strewn about the floor.\n','\n',char(10)));
INSERT INTO rooms VALUES(4735,47,'By a small fire',replace('Several large rocks surround a petty little fire that has formed a cloud in\nthe ceiling of this large cavern.  A window of the hut looks out over this small\nmeeting area.  To the north a small dark cave can be seen.\n','\n',char(10)));
INSERT INTO rooms VALUES(4736,47,'Carved Tunnel',replace('This small tunnel has been carved to perfection, the walls are smooth and the\nfloor has been worn soft through years of passage.  The red coloring of the\nrock gives this small tunnel a soft glow.\n','\n',char(10)));
INSERT INTO rooms VALUES(4737,47,'Carved Tunnel',replace('The walls of the small tunnel have been carved to perfection as well as the\nfloor that has been worn smooth.  It travels south and west leading off into\ndarkness.\n','\n',char(10)));
INSERT INTO rooms VALUES(4738,47,'Carved Tunnel',replace('The walls here are red and smooth as they have been carved into perfection.\nThe floor has been worm smooth with use and clear of any rubble.\n','\n',char(10)));
INSERT INTO rooms VALUES(4739,47,'Stone Gates',replace('Two monstrous pillars of stone support a great stone gate that leads south\ninto a gigantic cavern with a small city inside.  The redden rock of the of\nmountain gives this small gate and cavern within a slight reddish glow.\n','\n',char(10)));
INSERT INTO rooms VALUES(4740,47,'Walkway',replace('A small stone walkway leads its way through the immense cavern and all of its\nscattered boulders and misplaced stalagmites.  To the south you can see a large\narea of many multicolored rock, rising up in the center of which is a small\nbuilding.\n','\n',char(10)));
INSERT INTO rooms VALUES(4741,47,'Rock Garden',replace('A small path works its way through all types of multicolored boulders of all\nsizes and shapes.  Despite it''s hardness and great size it has a certain\nbeauty to it.\n','\n',char(10)));
INSERT INTO rooms VALUES(4742,47,'Rock Garden',replace('A small path works its way south and west from this section of a enormously\nlarge, yet beautiful conglomeration of rocks and boulders.\n','\n',char(10)));
INSERT INTO rooms VALUES(4743,47,'Rock Garden',replace('A small path works its way north and south through this large display of many\ndifferent colored boulders and rocks.  A large building can be seen rising above\nthe boulders directly to the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(4744,47,'Rock Garden',replace('A small path works its way to the north and to the west as the many different\ncolored boulders and rocks perform a array of beauty before you.\n','\n',char(10)));
INSERT INTO rooms VALUES(4745,47,'Rock Garden',replace('A small path works its way west and east through this array of multicolored\nboulders and rocks.  To the north a smooth path leads to a large and immaculate\nstone building.\n','\n',char(10)));
INSERT INTO rooms VALUES(4746,47,'Rock Garden',replace('A small path works its way east and north through this small section of the\nlarge array of boulders and rocks of all different colors.\n','\n',char(10)));
INSERT INTO rooms VALUES(4747,47,'Rock Garden',replace('A small path works its way north and south through this small section of the\nlarge garden of multicolored boulders.  Directly to the east a large building\ncan be seen rising above the piles of boulders.\n','\n',char(10)));
INSERT INTO rooms VALUES(4748,47,'Rock Garden',replace('A small path works its way east and south through this section of the great\nmulticolored array of boulders and rock formations.\n','\n',char(10)));
INSERT INTO rooms VALUES(4749,47,'Temple of Juargan',replace('This large building is circular in shape and open on all sides, as the ceiling\nis supported by pillars made of the deep red stone from the heart of the\nDra-Korrin.\n  In the center there is rests a large throne, formed of red rock.\n','\n',char(10)));
INSERT INTO rooms VALUES(4750,47,'Walkway',replace('A small stone walkway travels east and west through the many stalagmites and\nstray boulders that scatter the floor of the great cavern.\n','\n',char(10)));
INSERT INTO rooms VALUES(4751,47,'Walkway',replace('A small stone walkway travels east and south through the debris of many\nboulders and stalagmites.  Another small walkway leads west to a small building\npushing a black smoke from its roof.\n','\n',char(10)));
INSERT INTO rooms VALUES(4752,47,'Blacksmith''s Home',replace('A large black forge lies in the center of this small house pushing waves of\nheat into your face, barley allowing you to stand within the entranceway.  A\nlarge trough of water and several anvils are resting here as well.\n','\n',char(10)));
INSERT INTO rooms VALUES(4753,47,'Walkway',replace('A small walkway travels north and south through the many scattered boulders\nand stalagmites.  A separate, less used path leads to the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(4754,47,'Path in the Rock',replace('A small path leads west further into the less carved rock while to the east\nthe larger walkway can be seen.\n','\n',char(10)));
INSERT INTO rooms VALUES(4755,47,'Path in the Rock',replace('This small uncarved path travels south and east as the edge of the cavern\nblocks any travel further west.  The wall of the cavern has a deep red color to\nit and with the many stalactites parts resemble dripping blood.\n','\n',char(10)));
INSERT INTO rooms VALUES(4756,47,'Path in the Rock',replace('This small, uncarved path leads north and south along the cavern wall, over\nmany boulders at points.  To the east you can see a path leading up to a small\nhole in a large boulder.\n','\n',char(10)));
INSERT INTO rooms VALUES(4757,47,'Path in the Rock',replace('A small path travels over boulders and crevices to the north and east.  The\nedge of the cavern lies to the west while mounds of boulders are heaped to the\nsouth.\n','\n',char(10)));
INSERT INTO rooms VALUES(4758,47,'Path in the Rock',replace('A small and unused path travels over boulders and by many large hole as it\nmakes its way to the west.  To the east the small path ends in the larger walk-\nway of the city.  To the south a path leads to a small hut perched on top of a\nlarge boulder.\n','\n',char(10)));
INSERT INTO rooms VALUES(4759,47,'Walkway',replace('A stone walkway travels north and south through this section of this rocky\ncity.  To the west you can see a uncarved and hug mound of rock and boulder.\n','\n',char(10)));
INSERT INTO rooms VALUES(4760,47,'Walkway',replace('A stone walkway travels north and south through this section of the city.  A\nsmall and unused path can be seen traveling west into the uncut and jagged rock.\n','\n',char(10)));
INSERT INTO rooms VALUES(4761,47,'Pasty''s Dwelling',replace('This is a small stone dwelling with a large oven on the south wall.  There are\nmany tables and chairs placed about the place and by the oven there is a table\npiled with grains and a small bowl of dough.\n','\n',char(10)));
INSERT INTO rooms VALUES(4762,47,'Walkway',replace('A stone walkway travels north and east through this section of the stone city.\nA small path leads south to a small rock dwelling.\n','\n',char(10)));
INSERT INTO rooms VALUES(4763,47,'Walkway',replace('A stone walkway leads west from here.  To the east the small walkway ends in a\nlarge building, and to the south a small path leads to a small stone dwelling.\n','\n',char(10)));
INSERT INTO rooms VALUES(4764,47,'Leatherbies Home',replace('This is a small stone dwelling with many sizes of leather strewn about the\nplace.  A small table with a few chairs sits in the center of the house.\n','\n',char(10)));
INSERT INTO rooms VALUES(4765,47,'The Stone Jewel',replace('Many different colors and sizes of jewels hang from the walls of this well\nkept dwelling.  A small counter sits on the far wall with other small tables\nlining the walls.\n','\n',char(10)));
INSERT INTO rooms VALUES(4766,47,'Guard Barrack',replace('Many small cots line the walls of this large building as it serves for the\nhomes of many brave Dwarven men who pledge their lives to the suppression of\ntheir Duergar enemies.  A small archway leads south to a lower level.\n','\n',char(10)));
INSERT INTO rooms VALUES(4767,47,'Alcove',replace('A small alcove serves as a turning point for this small, dark tunnel that goes\nnorth and west from here.\n','\n',char(10)));
INSERT INTO rooms VALUES(4768,47,'Entrance to Tomb',replace('A large archway leads north to a dark vault.  An old stench emanates from it,\nas dust seems to continually flow from the old arch.  There is a small tunnel\nthat travels east into a darkness.\n','\n',char(10)));
INSERT INTO rooms VALUES(4769,47,'Ancients Tomb',replace('Two large stone sarcophagus''s lie stagnant in the center of this small tomb.\nThe walls are lined with holes that contain many coffers containing, no doubt,\nthe remains of some ancient dwarf.\n  A great stone door leads to the west, it has many inscriptions upon it.\n','\n',char(10)));
INSERT INTO rooms VALUES(4770,47,'Ancients Vault',replace('This is more of a small alcove than anything else.  The ceiling is covered\nwith many descriptive carvings, as are the walls and floor.  Where it not for\nthe years of decay and no upkeep, this would be a glamorous chamber.\n','\n',char(10)));
INSERT INTO rooms VALUES(4771,47,'Siven''s Stone',replace('A small and dark little room entombed within a large boulder, a very strange\nplace to want to live.  There is a small table in the center, but the room is\nvoid of any other objects.\n','\n',char(10)));
INSERT INTO rooms VALUES(4772,47,'The small cave',replace('You barely squeeze through into this cave, and you don''t see much to it\neither.  All you see are piles of stones.  At least none of the stones has\nfallen over your exit north.\n','\n',char(10)));
INSERT INTO rooms VALUES(4773,47,'Beneath the waterfall',replace('As you wring your clothes, you see sunlight reflect beautifully off the\nwaterfall, forming at rainbow.  With the sparkling illumination, you think you\nsee a cave to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(4774,47,'By the beautiful waterfall',replace('You see a VERY beautiful waterfall here.  It looks almost as if diamonds are\nfalling down the mountain.  (You reach out and grab and no, it IS only water.)\nIt looks so nice here, you feel like taking a nap.\nThe trail leads north and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(4775,47,'A valley',replace('You see a fresh green valley.  Flowers blossom everywhere around you, and you\nhave a big urge to giggle.  To the north, you can see the source of this\ngreenness, a waterfall.  To the west, you see the trail along the valley.\n','\n',char(10)));
INSERT INTO rooms VALUES(4776,47,'A valley',replace('You see a fresh green valley.  Flowers blossom everywhere around you, and you\nhave a big urge to giggle.  The valley continues to the east, or you can take\na steep trail up.\n','\n',char(10)));
INSERT INTO rooms VALUES(4777,47,'At the end of the hills',replace('What a view!  From here, you can see a waterfall toward the east, and lush\ngreen forests south-east.  To the north, you see the Mountains of Moria.  To\nthe west, you see the dirty trail again.  A trail leads down to the valley\nbelow.\n','\n',char(10)));
INSERT INTO rooms VALUES(4778,47,'A trail along the hills',replace('The dirt road you are treading on is as gentle as you can believe.  Rocks\ncatch on you as you try to keep your balance.  The trail continues east and\nback west to relative safety.\n','\n',char(10)));
INSERT INTO rooms VALUES(4779,47,'A trail along the hills',replace('The trail flattens out a bit, giving you time to breathe.  You don''t see much\nwater and don''t think the sun is going to help your thirst.  The closest shade\nappears to be the dwarf forest, which is VERY far away.\n','\n',char(10)));
INSERT INTO rooms VALUES(4780,47,'Up the hill',replace('You continue to climb this hill as sweat breaks out upon your forehead.  It\nlooks like you are close to the plateau.  Down is the relative comfort of\nground again, but you are SO close to the top!\n','\n',char(10)));
INSERT INTO rooms VALUES(4781,47,'Up the hill',replace('You continue to climb this hill as sweat breaks out upon your forehead.  It\nlooks like you are close to the plateau.  Down is the relative comfort of\nground again, but you are SO close to the top!\n','\n',char(10)));
INSERT INTO rooms VALUES(4782,47,'Up the hill',replace('You continue to climb this hill as sweat breaks out upon your forehead.  It\nlooks like you are close to the plateau.  Down is the relative comfort of\nground again, but you are SO close to the top!\n','\n',char(10)));
INSERT INTO rooms VALUES(4783,47,'Up the hill',replace('You continue to climb this hill as sweat breaks out upon your forehead.  It\nlooks like you are close to the plateau.  Down is the relative comfort of\nground again, but you are SO close to the top!\n','\n',char(10)));
INSERT INTO rooms VALUES(4784,47,'The hills',replace('You sigh as the trail continues straight up into the mountain.  West leads\nback to the more stable ground, but you wonder what''s on the other side of this\nlittle hill.....\n','\n',char(10)));
INSERT INTO rooms VALUES(4785,47,'The hills',replace('You see all around you ... hills.  You''re lucky you get to get so much\nexercise today!  You wonder if you should save your breath and go back west or\ncontinue east toward the hills.  There is a trail leading south towards\na black glassy mountain range.  A small plaque is on the rock.\n','\n',char(10)));
INSERT INTO rooms VALUES(5001,50,'A long tunnel',replace('You encounter some rapids as you enter this tunnel cut out of\nthe mountains by the river.\n','\n',char(10)));
INSERT INTO rooms VALUES(5002,50,'A long tunnel',replace('The tunnel branches off north.\n','\n',char(10)));
INSERT INTO rooms VALUES(5003,50,'A long tunnel',replace('The tunnel branches off south.\n','\n',char(10)));
INSERT INTO rooms VALUES(5004,50,'A long tunnel',replace('The tunnel branches off to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(5005,50,'An underground lake',replace('You are floating on a jet-black underground lake fed by dripping\nwater and lime from above. The tunnel continues to the east and the river\nleads back west. To the north is a roughly-hewn hallway. There is also\na tunnel south.\n','\n',char(10)));
INSERT INTO rooms VALUES(5006,50,'A long narrow tunnel',replace('The tunnel rises sharply to the east.\n','\n',char(10)));
INSERT INTO rooms VALUES(5007,50,'A wide tunnel',replace('The tunnel continues east and west. To the east the tunnel dives\ndown into a bright light.\n','\n',char(10)));
INSERT INTO rooms VALUES(5008,50,'Cave-in',replace('You stand at the edge of a large pile of rubble created from the last\nrockslide.\n','\n',char(10)));
INSERT INTO rooms VALUES(5009,50,'At the foot of the rubble',replace('You are at the bottom of a large pile of rubble. A tunnel branches\noff to the north and east.\n','\n',char(10)));
INSERT INTO rooms VALUES(5010,50,'Cave entrance',replace('You stand in the middle of a large and beautiful cave. A path leads\ndeeper into the darkness.\n','\n',char(10)));
INSERT INTO rooms VALUES(5011,50,'Giant cave',replace('This cavern overwhelms you. The walls and ceiling seem miles away.\nBones of previous adventurers lie strewn on the cavern floor.\n','\n',char(10)));
INSERT INTO rooms VALUES(5012,50,'Narrow bend',replace('The tunnel turns to the south and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(5013,50,'Large cave',replace('You are standing in a large cave. Many furs are spread out on the floor.\n','\n',char(10)));
INSERT INTO rooms VALUES(5014,50,'Damp hallway',replace('The walls here are extremely damp, as well as the floor.\n','\n',char(10)));
INSERT INTO rooms VALUES(5015,50,'Underground pool',replace('You are wading in a knee deep pool of lime-water.\n','\n',char(10)));
INSERT INTO rooms VALUES(5016,50,'Damp hallway',replace('The walls of the tunnel are extremely damp here. You hear the faint\nsound of running water to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(5017,50,'Narrow crawlway',replace('This crawlway is just big enough for a human to crawl through or a\nhalfling to walk through.\n','\n',char(10)));
INSERT INTO rooms VALUES(5018,50,'Large cavern',replace('You have entered a very large cavern. The rock formations would amaze\nalmost any dwarf.\n','\n',char(10)));
INSERT INTO rooms VALUES(5019,50,'Fungus patch',replace('As you walk through the fungus patch, you are shot at by many millions of\nspores. You can hardly breathe.\n','\n',char(10)));
INSERT INTO rooms VALUES(5020,50,'Fungus path',replace('As you walk along the path, millions of spores are shot at you. You can\nhardly breathe.\n','\n',char(10)));
INSERT INTO rooms VALUES(5021,50,'Fungus temple',replace('You find yourself standing inside of a giant mushroom. The inside\nis decorated in the fashion of a temple.\n','\n',char(10)));
INSERT INTO rooms VALUES(5022,50,'Sloping passage',replace('You follow a path sloping down from the fungus temple.\n','\n',char(10)));
INSERT INTO rooms VALUES(5023,50,'Sloping passage',replace('You are on a path that gently slopes up from the underground pool.\n','\n',char(10)));
INSERT INTO rooms VALUES(5024,50,'The Great Eastern Desert',replace('A vast desert stretches for miles, the sand constantly shifting around you.\nYou feel lost.\n','\n',char(10)));
INSERT INTO rooms VALUES(5025,50,'The Great Eastern Desert',replace('A vast desert stretches for miles, the sand constantly shifting around you.\nYou feel lost.\n','\n',char(10)));
INSERT INTO rooms VALUES(5026,50,'The Great Eastern Desert',replace('A vast desert stretches for miles, the sand constantly shifting around you.\nYou feel lost.\n','\n',char(10)));
INSERT INTO rooms VALUES(5027,50,'The Great Eastern Desert',replace('A vast desert stretches for miles, the sand constantly shifting around you.\nYou feel lost.\n','\n',char(10)));
INSERT INTO rooms VALUES(5028,50,'The Great Eastern Desert',replace('A vast desert stretches for miles, the sand constantly shifting around you.\nYou feel lost.\n','\n',char(10)));
INSERT INTO rooms VALUES(5029,50,'The Great Eastern Desert',replace('A vast desert stretches for miles, the sand constantly shifting around you.\nYou feel lost.\n','\n',char(10)));
INSERT INTO rooms VALUES(5030,50,'The Great Eastern Desert',replace('A vast desert stretches for miles, the sand constantly shifting around you.\nYou feel lost.\n','\n',char(10)));
INSERT INTO rooms VALUES(5031,50,'The Great Eastern Desert',replace('A vast desert stretches for miles, the sand constantly shifting around you.\nYou feel lost.\n','\n',char(10)));
INSERT INTO rooms VALUES(5032,50,'The Great Eastern Desert',replace('A vast desert stretches for miles, the sand constantly shifting around you.\nYou feel lost.\n','\n',char(10)));
INSERT INTO rooms VALUES(5056,50,'A nomad camp',replace('This small group of desert nomads has stopped for the day to rest\nand refresh themselves beside this beautiful oasis. Three tents and some\ncamels make up the party. From within two of the tents you hear muffled\nvoices, obviously surprised at your visit.\n','\n',char(10)));
INSERT INTO rooms VALUES(5057,50,'Inside a small tent',replace('This is a small and simple tent with few possessions in sight. Lying\nhere and there are young-looking men and women, possibly slaves to the\nleader of this band.\n','\n',char(10)));
INSERT INTO rooms VALUES(5058,50,'Beside the camels',replace('Here stand about ten camels, all hitched to some stakes plugged into\nthe ground. To the east you see a small tent while to the north you see a\nlarger, fancier tent.\n','\n',char(10)));
INSERT INTO rooms VALUES(5059,50,'The warrior''s tent.',replace('This tent has a few furnishings, but mainly it holds the band''s\nprotectors. They all stare at you coldly as you enter.\n','\n',char(10)));
INSERT INTO rooms VALUES(5060,50,'The main tent',replace('This tent is as lavishly decorated on the inside as it is on the\noutside. A fancy carpet lies on the sand and numerous baskets line the\nwalls.\n','\n',char(10)));
INSERT INTO rooms VALUES(5061,50,'The main tent',replace('This is where the leader of this band of nomads resides. He is\ndefinitely rich as you inspect the tapestries, baskets, and a few\npaintings as well.\n','\n',char(10)));
INSERT INTO rooms VALUES(5062,50,'Strange Glowing Sand',replace('A vast desert stretches for miles, the sand constantly shifting around you.\nBut this patch of desert looks different ... the sand glows.  You see a\nfuturistic city to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(5063,50,'The wind-swept ledge',replace('Being very careful not to lose your balance, you look around and\nfind that this canyon is about a half a kilometer deep. To the west is\na dark cave leading under the desert sands.\n','\n',char(10)));
INSERT INTO rooms VALUES(5064,50,'The cave mouth',replace('The air in here is MUCH cooler than outside. From the west you hear\nstrange sounds, but can see nothing. The cave slopes down into the\ndarkness.\n','\n',char(10)));
INSERT INTO rooms VALUES(5065,50,'The mysterious lair.',replace('You have stumbled upon the home of something. From the treasure\nhaphazardly strewn about and the rotting carcasses, you would guess that\nthis is a dragon''s lair. As to what type, you can''t really say. The cave\nnarrows out into a tunnel to the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(5066,50,'A wide tunnel',replace('This tunnel seems to go on forever into the darkness. You carefully\nfeel your way along the walls.\n','\n',char(10)));
INSERT INTO rooms VALUES(5067,50,'A narrower tunnel',replace('The tunnel becomes very narrow and you fight to squeeze your way through.\nThe floor seems to level off a little.\n','\n',char(10)));
INSERT INTO rooms VALUES(5068,50,'A narrow crack',replace('This part of the tunnel is the hardest to move through as the walls\nmove in to meet you.\n','\n',char(10)));
INSERT INTO rooms VALUES(5069,50,'A small cavern.',replace('It is dark and damp and bats hang from the ceiling. A narrow crack is\nin the east wall. The floor now slopes upwards.\n','\n',char(10)));
INSERT INTO rooms VALUES(5070,50,'A small shaft',replace('From within this shaft you can see a narrow hole in the roof just\nlarge enough for one person. Back east is the cavern.\n','\n',char(10)));
INSERT INTO rooms VALUES(5100,51,'City Entrance',replace('You are at the entrance to a small underground city. A great adamantite\ngate lies open to the west allowing entrance into the city.\n','\n',char(10)));
INSERT INTO rooms VALUES(5101,51,'City street',replace('You walk along a highly ornate street going north-south. A large gate\nlies to the east while a building lies to the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(5102,51,'City street',replace('You walk along a highly ornate city street going north and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(5103,51,'City street',replace('You walk along a highly ornate city street going east-west. A large house\nstands to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(5104,51,'3rd House',replace('You stand inside the 3rd house of the city; it is fairly well decorated\nby drow standards having a few statues, murals and such. A door leads to the\nsouth.\n','\n',char(10)));
INSERT INTO rooms VALUES(5105,51,'Throne Room',replace('The throne room of the 3rd house is about as decorated as the inner\ncourtyard except with a blood covered altar in the center of the room.\n','\n',char(10)));
INSERT INTO rooms VALUES(5106,51,'City street',replace('You walk along a highly ornate city street going east-west. To the north\nis a large building.\n','\n',char(10)));
INSERT INTO rooms VALUES(5107,51,'City street',replace('You walk along a highly ornate city street leading north and east. To the\nsouth is an extremely large house.\n','\n',char(10)));
INSERT INTO rooms VALUES(5108,51,'2nd House',replace('You stand inside the 2nd house of the city. The room is highly decorated\nwith statues of spiders and murals everywhere.\n','\n',char(10)));
INSERT INTO rooms VALUES(5109,51,'Throne Room',replace('The throne room of the 2nd house is just a little more decorative than\nthe inner courtyard having an altar in the center of the room.\n','\n',char(10)));
INSERT INTO rooms VALUES(5110,51,'Main Gate',replace('You are at the entrance to the 1st house of the city. A large gate, almost\nas big and elegant as the one at the entrance to the city, stands here.\n','\n',char(10)));
INSERT INTO rooms VALUES(5111,51,'1st House',replace('You stand in the inner courtyard of the 1st and largest house in the city.\nThe room is extremely large and decorative. Mural and paintings hang on the\nwalls depicting some battles and a spider queen.\n','\n',char(10)));
INSERT INTO rooms VALUES(5112,51,'Throne Room',replace('The throne room of the 1st house is in one word...awesome. It is so\nhorrifying it is almost beautiful.\n','\n',char(10)));
INSERT INTO rooms VALUES(5113,51,'Main Chamber',replace('This is the council chamber for the Matron Mother herself. A huge table\nand chairs surrounding it sits in the center of the room.\n','\n',char(10)));
INSERT INTO rooms VALUES(5114,51,'City street',replace('You walk along a highly ornate city street leading north-south and east.\n','\n',char(10)));
INSERT INTO rooms VALUES(5115,51,'City street',replace('You walk along a highly ornate city street leading south. A building is\nto the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(5116,51,'Cleric Academy',replace('This is the most lavish of the academies being that it is for the clerics.\n','\n',char(10)));
INSERT INTO rooms VALUES(5117,51,'City street',replace('You walk along a highly ornate city street going east-west. To the north\nis a giant temple.\n','\n',char(10)));
INSERT INTO rooms VALUES(5118,51,'Warrior''s Academy',replace('This looks more like a barracks than a school.\n','\n',char(10)));
INSERT INTO rooms VALUES(5119,51,'Entrance to the Temple of Lloth',replace('The temple is the largest building in the city. Even it''s doors are beyond\nimagination. Inside of the temple entrance, the walls are made of gold and\nadamantite.\n','\n',char(10)));
INSERT INTO rooms VALUES(5120,51,'Mage''s Academy',replace('The mages academy is fairly well decorated see that the drow prefer magic\nover physical power greatly.\n','\n',char(10)));
INSERT INTO rooms VALUES(5121,51,'City street',replace('You walk along a highly ornate city street going eastward. To the north is\na building.\n','\n',char(10)));
INSERT INTO rooms VALUES(5122,51,'Slave Chamber',replace('The room is in shambles. Straw is strewn all about the room as beds for the\nunfortunate creatures who have fallen prey to drow imperialism.\n','\n',char(10)));
INSERT INTO rooms VALUES(5123,51,'City street',replace('You walk along a highly ornate city street leading west and south. To the\nnorth is a relatively small house.\n','\n',char(10)));
INSERT INTO rooms VALUES(5124,51,'4th house',replace('You stand inside the 4th house of the city. Its inner courtyard is rather\ndull by drow standards and rather small as well.\n','\n',char(10)));
INSERT INTO rooms VALUES(5125,51,'Throne Room',replace('The throne room is basically similar to the inner courtyard in regards\nto decor. there is a small throne behind the altar but that is about it.\n','\n',char(10)));
INSERT INTO rooms VALUES(5126,51,'Entrance Way',replace('You stand in the entrance way to the temple which opens up to the north\ninto a large hallway going east and west. Small statues of spiders line the\nentrance way''s walls.\n','\n',char(10)));
INSERT INTO rooms VALUES(5127,51,'Hallway',replace('You are in a long hallway lined with adamantite. The walls are engraved\nwith pictures of elves and spiders. The hallway continues east and west. As you\nlook down the hallway you can make out one or two figures moving away from you.\nTo the north is a obsidian stairway.\n','\n',char(10)));
INSERT INTO rooms VALUES(5128,51,'Long Hallway',replace('You are in a long hallway lined with adamantite. The walls are engraved\nwith pictures of elves and spiders. The hallway continues east and west. As you\nlook down the hallway you can make out one or two figures moving away from you.\n','\n',char(10)));
INSERT INTO rooms VALUES(5129,51,'Long Hallway',replace('You are in a long hallway lined with adamantite. The walls are engraved\nwith pictures of elves and spiders. The hallway continues east and west. As you\nlook down the hallway you can make out one or two figures moving away from you.\nTo the north is a door.\n','\n',char(10)));
INSERT INTO rooms VALUES(5130,51,'Long Hallway',replace('You are in a long hallway lined with adamantite. The walls are engraved\nwith pictures of elves and spiders. The hallway continues east and west. As you\nlook down the hallway you can make out one or two figures moving away from you.\n','\n',char(10)));
INSERT INTO rooms VALUES(5131,51,'Long Hallway',replace('You are in a long hallway lined with adamantite. The walls are engraved\nwith pictures of elves and spiders. The hallway continues east and west. As you\nlook down the hallway you can make out one or two figures moving away from you.\n','\n',char(10)));
INSERT INTO rooms VALUES(5132,51,'Long Hallway',replace('You are in a long hallway lined with adamantite. The walls are engraved\nwith pictures of elves and spiders. The hallway continues east and west. As you\nlook down the hallway you can make out one or two figures moving away from you.\nTo the south is a door.\n','\n',char(10)));
INSERT INTO rooms VALUES(5133,51,'Warrior''s Barracks',replace('The room is a complete mess. None of the beds are made, clothes and other\nitems have been left all about the room. Well drow warriors never were known\nfor neatness.\n','\n',char(10)));
INSERT INTO rooms VALUES(5134,51,'Long Hallway',replace('You are in a long hallway lined with adamantite. The walls are engraved\nwith pictures of elves and spiders. The hallway continues east and west. As you\nlook down the hallway you can make out one or two figures moving away from you.\n','\n',char(10)));
INSERT INTO rooms VALUES(5135,51,'Grand Stairway',replace('You are standing at the bottom of a giant obsidian and adamantite\nstairway. The edges are trimmed with gold.\n','\n',char(10)));
INSERT INTO rooms VALUES(5136,51,'Grand Hallway',replace('You are standing in the middle of a grand hallway. The walls are\nof the purest adamantite with gold trim. Mosaics line the walls.\n','\n',char(10)));
INSERT INTO rooms VALUES(5137,51,'Mage''s Barracks',replace('The mage''s living quarters is rather clean with the exception of a few\nused component containers. It is rather well decorated as well. Cots line the\nfloor for the mages to sleep on. the only door is to the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(5138,51,'Grand Hallway',replace('You are walking down a grand hallway, heavily decorated with adamantite\nand gold. To the north the hall goes down a flight of stairs while a door is\ntoo the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(5139,51,'Cleric''s Barracks',replace('The bed chamber is brightly decorated with spider shaped statues, murals\nand the like. Large beds line the floor making this a comfortable room to live\nin.\n','\n',char(10)));
INSERT INTO rooms VALUES(5140,51,'Grand Stairway',replace('You are climbing a set of obsidian stairs surrounded by adamantite walls.\nTo the north are a set of large golden doors.\n','\n',char(10)));
INSERT INTO rooms VALUES(5141,51,'Main Chamber',replace('This is the south side of a large auditorium used for services by the\ndrow priestesses. In the center is a large sacrificial pit and beyond that is\nan altar.\n','\n',char(10)));
INSERT INTO rooms VALUES(5142,51,'Eastern side of Chamber',replace('You are on the eastern side of the chamber overlooking the pit. To the east\nis a door while to the north is an altar.\n','\n',char(10)));
INSERT INTO rooms VALUES(5143,51,'Sacrificial Pit',replace('A you climb down into the pit thousands of spiders cover you tearing your\nbody to shreds.\n\nLloth thanks you for your sacrifice.\n\nYou''ve fallen, and you can''t get up!!!\n','\n',char(10)));
INSERT INTO rooms VALUES(5144,51,'Western side of Chamber',replace('You are on the western side of the main chamber overlooking a sacrificial\npit. To the north is an altar.\n','\n',char(10)));
INSERT INTO rooms VALUES(5145,51,'The Altar',replace('You are standing in front of a highly and freshly bloodstained altar.\nEngraved on the top of the altar is a giant spider with a human head. Looking\ndown from the altar you see a large sacrificial pit.\n','\n',char(10)));
INSERT INTO rooms VALUES(5146,51,'Slave Cells',replace('This is the main room to the cell chambers for the slaves to be\nsacrificed. You notice there are no guards around.\n','\n',char(10)));
INSERT INTO rooms VALUES(5147,51,'Slave Pen',replace('Rotten meat and breads lie about the floor while shackles hang from the\nwalls. The room wreaks of death. You almost become nauseous and decide to leave\nthe room since you were obviously too late to save the slave.\n','\n',char(10)));
INSERT INTO rooms VALUES(5148,51,'Dais',replace('You stand upon a dais behind the altar. Above you is a enormous illusion\nof a female drow turning into a giant spider and back again. There is a door\nto the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(5149,51,'The Treasury',replace('This is obviously only a temporary storage place for the collected\ntreasure being rather bare.\n','\n',char(10)));
INSERT INTO rooms VALUES(5150,51,'Weaponsmaster''s Chamber',replace('This one person bedchamber is very elegant. The owner must be held in high\nto get this kind of treatment.\n','\n',char(10)));
INSERT INTO rooms VALUES(5200,52,'The Grand Gate of Thalos',replace('You stand in the archway of a gigantic stone archway. The two\nsteel gates have been forced open and have rusted in place. A hollow\ngust of wind blows by you into the deserted, and seemingly destroyed,\ncity.\n','\n',char(10)));
INSERT INTO rooms VALUES(5201,52,'Main Street',replace('This was once a magnificent street, but now is in total ruin. The\nstreets are barren and windswept and the silence is unending.  A dark alley\nleads north and south.  Howls and screams echo through the deserted city.\n','\n',char(10)));
INSERT INTO rooms VALUES(5202,52,'Main Street',replace('This was once a magnificent street, but now is in total ruin. The\nstreets are barren and windswept and the silence is unending. On one\nside is a collapsed house while on the other is the entrance to a large\nruined mansion. Eerie sounds echo within the mansion. Near the center of\ntown you see a large domed building, relatively intact.\n','\n',char(10)));
INSERT INTO rooms VALUES(5203,52,'A Garden Path',replace('A circular path surrounds a magnificent domed temple in the center of\nthe city. Flowers have withered away and the once lush trees are bare.\nVines and ivy snake up the sides of the temple and entangle themselves\naround your feet. A sudden volley of howls pierces the air.\n','\n',char(10)));
INSERT INTO rooms VALUES(5204,52,'A Garden Path',replace('A circular path surrounds a magnificent domed temple in the center of\nthe city. Flowers have withered away and the once lush trees are bare.\nVines and ivy snake up the sides of the temple and entangle themselves\naround your feet. A sudden volley of howls pierces the air.\n','\n',char(10)));
INSERT INTO rooms VALUES(5205,52,'A Garden Path',replace('A circular path surrounds a magnificent domed temple in the center of\nthe city. Flowers have withered away and the once lush trees are bare.\nVines and ivy snake up the sides of the temple and entangle themselves\naround your feet. A sudden volley of howls pierces the air.\n','\n',char(10)));
INSERT INTO rooms VALUES(5206,52,'A Garden Path',replace('A circular path surrounds a magnificent domed temple in the center of\nthe city. Flowers have withered away and the once lush trees are bare.\nVines and ivy snake up the sides of the temple and entangle themselves\naround your feet. A sudden volley of howls pierces the air.\n','\n',char(10)));
INSERT INTO rooms VALUES(5207,52,'The market place',replace('You stand in the middle of a large square lined on each side with\nbaskets, carts, and stands of all shapes and sizes. Abandoned, these\nlittle shops still contain some of their goods once sold to a demanding\npublic.\n','\n',char(10)));
INSERT INTO rooms VALUES(5208,52,'The market place',replace('You stand at the end of the market square. Stands and carts line\neach side, filled with remnants of fine foods and exquisite goods.\n','\n',char(10)));
INSERT INTO rooms VALUES(5209,52,'A Side Street',replace('This small side street leads east and west into back alleys while\nto the south you see the temple. The incessant howling tears at your mind.\n','\n',char(10)));
INSERT INTO rooms VALUES(5210,52,'A Side Street',replace('You are in the common section of the city. Ruined buildings made of\nclay and stone is all the view has to offer. Most of these homes are\nnothing but piles of rubble, but some look almost safe enough to venture\ninto. The street continues north and south and buildings line the street.\n','\n',char(10)));
INSERT INTO rooms VALUES(5211,52,'A Side Street',replace('This small side street leads away from the garden path to the south.\nAround you stand large piles or rubble where the houses of commoners\nused to be. A lone howl makes you worry greatly about your safety here.\n','\n',char(10)));
INSERT INTO rooms VALUES(5212,52,'A side street',replace('This small side street leads south away from the temple into the\nbusiness section of town. The destruction that leveled this city was not\nbiased; these important looking buildings have been almost totally\ndestroyed. There is a hole in the wall of a very large structure to the\neast.\n','\n',char(10)));
INSERT INTO rooms VALUES(5213,52,'A side street',replace('This small side street is lined with the remains of once great\nbuildings. To the north is a dark, foreboding structure while to the\nsouth lies the entrance to a small tavern. The street continues north\nand south.\n','\n',char(10)));
INSERT INTO rooms VALUES(5214,52,'A side street',replace('You are at the end of a long street leading to the center of the city.\nA long dark alley runs east and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(5215,52,'Under a ruined watchtower',replace('You stand at the base of a tall watchtower built to protect the city\nfrom invaders. From the looks of things, it did not do a good job.\n','\n',char(10)));
INSERT INTO rooms VALUES(5216,52,'A back alley',replace('This alley leads to the rear of what used to be a meat stand. You wince\nat the stench. South is one of the city watchtowers.\n','\n',char(10)));
INSERT INTO rooms VALUES(5217,52,'The meat stand',replace('A large stand has been set up here with metal hooks and wooden racks\nin the background. Hanging on the hooks are very small scraps of meat\nand other game. This stand is relatively empty, and a sudden burst of\nhowling and screaming makes you realize why this is so.\n','\n',char(10)));
INSERT INTO rooms VALUES(5218,52,'A back alley',replace('A narrow alley leads east to a wider street and west to one of\nthe city watchtowers.\n','\n',char(10)));
INSERT INTO rooms VALUES(5219,52,'The guild house',replace('You are standing in what once was this city''s ONLY guild house.\nTables and chairs have been smashed and broken weapons lie strewn about\nthe floor as if some massive battle had taken place here. Draped along\nthe back wall is a tattered, jet-black banner with the symbol of the\nDarkside set upon it.\n','\n',char(10)));
INSERT INTO rooms VALUES(5220,52,'The produce stand',replace('A large cart sits here carrying rotted fruit and vegetables. Flys\nswarm all about what seems to be the last remaining bits of food left\nin the city.\n','\n',char(10)));
INSERT INTO rooms VALUES(5221,52,'The smithy',replace('In here you find tools and anvils used to make various weapons\nand items. The walls have been stripped clean and only a few incomplete\npieces of armor and weaponry are left.\n','\n',char(10)));
INSERT INTO rooms VALUES(5222,52,'The tapestry stand',replace('Tattered and torn tapestries and rugs lie heaped in piles. Fancy\nrobes and various articles of clothing are now just rags. You stare at\nthe strange piles for a long time until a piercing howl makes you\nthink these might be beds.\n','\n',char(10)));
INSERT INTO rooms VALUES(5223,52,'A back alley',replace('A narrow alley leads north to one of the city watchtowers while\nto the south there lies a market stand full of torn clothes and rugs.\n','\n',char(10)));
INSERT INTO rooms VALUES(5224,52,'Under the watchtower',replace('You stand under one of the city watchtowers built to protect\nthe city from invaders. Obviously, it failed.\n','\n',char(10)));
INSERT INTO rooms VALUES(5225,52,'The jewelery stand',replace('A table has been tipped over, spilling fine jewelery and gems\nacross the market place. Most of these trinkets are battered and\ntarnished and few would have any value anymore.\n','\n',char(10)));
INSERT INTO rooms VALUES(5226,52,'A ruined clay dwelling',replace('This was once a very plain house with nothing more than a few chairs\nand a bed. A cold fireplace suggests that the city has been abandoned\nfor quite a while. Almost nothing remains of this humble abode.\n','\n',char(10)));
INSERT INTO rooms VALUES(5227,52,'A collapsed stone dwelling',replace('This small house has completely collapsed upon itself leaving piles\nof debris here and there. A few rafters still stand with thatched straw\nhanging down and a hot wind gusts through the hollow dwelling.\n','\n',char(10)));
INSERT INTO rooms VALUES(5228,52,'A back alley',replace('A narrow alley leads east to one of the city watchtowers and west to\na small side street.\n','\n',char(10)));
INSERT INTO rooms VALUES(5229,52,'An abandoned shop',replace('From the outside this place looks like an ordinary pile of rubble,\nbut inside these cramped quarters you discover what used to be a shop\nfilled with armor, weapons, and various other goods. A small sign flutters\nin the wind.\n','\n',char(10)));
INSERT INTO rooms VALUES(5230,52,'The Tavern of the Sun',replace('A glorious place in it''s prime, this tavern now lies in ruin; tables\nand chairs are broken scattered, bottles and glasses shattered, and\na small performance stage crushed. Musical instruments and personal\nbelongings lie under the rubble, but the people they once belonged to are\nnot with them. Looking up you see that the entire second floor and roof\nhas fallen in, leaving a gaping hole above.\n','\n',char(10)));
INSERT INTO rooms VALUES(5231,52,'South wing of the city hall',replace('You stand in a large room attached to this end of the hallway which\nleads back north to the reception area.  Pedestals and columns have fallen\nand most of the valuable items have been taken, leaving worthless debris.\nA few chairs have survived, as well as a large curved desk. To the east\nis a vine-covered archway leading out into a private courtyard.\n','\n',char(10)));
INSERT INTO rooms VALUES(5232,52,'The city hall',replace('This is the main reception area of Thalos'' city hall. The walls have\nbeen charred and scored massively and debris is spread from wall to wall.\nA large gaping hole in the west wall allows you to see out to one of\nthe city''s side streets. Obviously no one will be seeing you through today.\nHallways lead south and east.\n','\n',char(10)));
INSERT INTO rooms VALUES(5233,52,'East wing of the city hall',replace('Here lies the remnants of a fancy office, possibly the mayor''s. A few\nwithered plants and broken pieces of furniture make this place anything\nbut fancy, though. The only thing remaining intact here is a large\nglass cabinet. A long hallway leads west back to the reception area and\nan ivy-covered archway leads south into a private courtyard.\n','\n',char(10)));
INSERT INTO rooms VALUES(5234,52,'The private gardens and courtyard of Thalos',replace('What a shame that this mass destruction also touched this once\nbeautiful place. The temple''s garden path has nothing on this garden.\nFlowers and trees have been smashed into the ground and lawn benches\nthrown through walls. A large marble fountain in the center of the\ncourtyard still stands, though, defying any attempts to destroy its\nbeauty. Above stands the remnants of one of the watchtowers. Archways\nnorth and west lead back into the city hall.\n','\n',char(10)));
INSERT INTO rooms VALUES(5235,52,'A small guard house',replace('This was once the barracks for Thalos'' cityguards. Now just an empty\nshell, this small shack still stands guarding the entrance both to the\ncity and to the city hall.\n','\n',char(10)));
INSERT INTO rooms VALUES(5236,52,'A collapsed home',replace('All that''s left of this house is a few scattered piles of rubble\nand a very large blast crater. Obviously someone or something important\nwas once housed here. A shrieking howl chills your blood.\n','\n',char(10)));
INSERT INTO rooms VALUES(5237,52,'A tall dwelling',replace('This seems to be the tallest structure remaining in the city. At\none time this could have been an inn of some sort, but now it''s just\na mess. The back wall as been completely knocked down revealing an\nentrance into another building through yet another collapsed wall.\nBetween the two buildings are a few blast craters and boulders. An old\nset of wooden steps leads up to a creaking second floor.\n','\n',char(10)));
INSERT INTO rooms VALUES(5238,52,'A small shack',replace('This cramped dwelling could not have housed more than one person. Now\nwith the back wall missing, it could hold many more. Looking around you\nfind broken shelves and workbenches with various vials and pouches spilling\ncontents all across the floor. This was possibly the magic shop of the\ncity. The doorway to the east is blocked, making the only exit back west.\n','\n',char(10)));
INSERT INTO rooms VALUES(5239,52,'A back alley',replace('A narrow back alley goes south to main street and north towards\na watchtower. A mass of howls catches you of guard.\n','\n',char(10)));
INSERT INTO rooms VALUES(5240,52,'A back alley',replace('A narrow back alley leads north to one of the city watchtowers\nand south towards main street. To the west is a doorway to a small\nhouse blocked by debris.\n','\n',char(10)));
INSERT INTO rooms VALUES(5241,52,'Under a watchtower',replace('You stand under a tall watchtower. Narrow back alleys lead west and\nsouth and a very weak looking ladder leads up into the tower.\n','\n',char(10)));
INSERT INTO rooms VALUES(5242,52,'A bath house',replace('This was once the bath house for the commoners of the city. Hot\nsteamy water still wells up from a hole in the floor. Obviously there\nis a hot spring located under the city (making the decision to put\na city here seem much more reasonable). Closer inspection of the water\nyields a dead body floating around in it, skin melted away from months\nof floating in there. The west wall has collapsed revealing another\ncollapsed house.\n','\n',char(10)));
INSERT INTO rooms VALUES(5243,52,'A back alley',replace('A narrow back alley leads west to a small side street and east to one\nof the city watchtowers. Great amounts of steam issue forth from the\nbuilding to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(5244,52,'An upright house',replace('This home is practically the only one around that is still standing.\nExcept for the massive hole in the east wall, everything else looks\nintact, including the windows. Great amounts of steam issue forth from\nthe hole in the east wall.\n','\n',char(10)));
INSERT INTO rooms VALUES(5245,52,'On the second floor',replace('The minute you step off onto this floor you realize it was a mistake.\nThe old rotted floorboards suddenly give way and you fall down, impaling\nyourself on jagged boards below.\n\nYou''ve fallen, and you can''t get up!!!\n','\n',char(10)));
INSERT INTO rooms VALUES(5246,52,'The north-west watchtower',replace('You stand atop one of the city watchtowers. The view is magnificent\nfrom here and you can see all the way to the western mountains. No wonder\nthis place stood for so long.\n','\n',char(10)));
INSERT INTO rooms VALUES(5247,52,'The south-west watchtower',replace('You stand atop one of the city watchtowers. The view is magnificent\nfrom here and you can see all the way to the western mountains. To the\nsouth the desert stretches to the horizon. No wonder this place stood\nfor so long.\n','\n',char(10)));
INSERT INTO rooms VALUES(5248,52,'The north-east watchtower',replace('You stand atop one of the city watchtowers. The view is magnificent\nfrom here and you can see a great floating pyramid to the north-east.\nDesert sand stretches to the horizon. No wonder this place stood for so\nlong.\n','\n',char(10)));
INSERT INTO rooms VALUES(5250,52,'The Temple of Thalos',replace('You stand within one of the most holy places in the realm. This\nstunning domed temple once housed the city''s worshipers en masse.\nUnfortunately, it succumbed to the destruction brought on this city.\nLong benches lie toppled and the altar desecrated. Large chunks of stone\nhave fallen from the walls and roof, sending sunlight streaming in on\nyou. A few books lie about, conveying to you a holy message in a\nstrange tongue.\n     Wind gusts through the four archways and howls and screams can be\nheard from all parts of the city.\n','\n',char(10)));
INSERT INTO rooms VALUES(5251,52,'A back alley',replace('A narrow alley leads east to a wider street and west to one of\nthe city watchtowers.\n','\n',char(10)));
INSERT INTO rooms VALUES(5252,52,'Under a ruined watchtower',replace('You stand at the base of a tall watchtower built to protect the city\nfrom invaders. From the looks of things, it did not do a good job.\n','\n',char(10)));
INSERT INTO rooms VALUES(5253,52,'A back alley',replace('A narrow alley leads south to one of the city watchtowers.\n','\n',char(10)));
INSERT INTO rooms VALUES(5254,52,'The south-east watchtower',replace('You stand atop one of the city watchtowers. The view is magnificent\nfrom here and you can see all the way to the western mountains. To the\nsouth the desert stretches to the horizon. No wonder this place stood\nfor so long.  There is a small plaque on the stones.\n','\n',char(10)));
INSERT INTO rooms VALUES(5255,52,'A back alley',replace('A narrow alley leads north to the main street, and south toward a tall\nwatchtower.  A ruined building is to the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(5256,52,'A trail at the end of the dwarf forest',replace('The trail ends here, with short, dry stumps of trees all around you.\nTo the west, you can see the ruins of a huge city.  Something about it gives\nyou an uneasy feeling.  To the east is your way back to home and safety.\n','\n',char(10)));
INSERT INTO rooms VALUES(5257,52,'A trail at the end of the dwarf forest',replace('A side trail here leads from the dwarf forest.  It is definitely drier\nand hotter here.  The trail continues to the west, and to the east, you see\nthe T-intersection.\n','\n',char(10)));
INSERT INTO rooms VALUES(5258,52,'The dwarf forest',replace('You see more stunted trees here.  A side trail leads west from here.\nTo the east, you THINK you see a trail, but you can never be sure.\n','\n',char(10)));
INSERT INTO rooms VALUES(5259,52,'The dwarf forest',replace('You see more stunted trees here.  It looks almost as if this place was\ncursed by a god to be short and dry.  The trail leads north and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(5260,52,'The dwarf forest',replace('You see more stunted trees here.  It looks almost as if this place was\ncursed by a god to be short and dry.  The trail leads north and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(5261,52,'The dwarf forest',replace('You see many stunted trees here.  You don''t see any leaves on these barren\ntrees.  No grass grows on the ground.\n','\n',char(10)));
INSERT INTO rooms VALUES(5262,52,'The dwarf forest',replace('You see more stunted trees here.  It looks almost as if this place was\ncursed by a god to be short and dry.  The trail leads east and west.  It looks\ndark toward the east.\n','\n',char(10)));
INSERT INTO rooms VALUES(5263,52,'The darker dwarf forest',replace('You see a more dense foliage in these stunted trees.  The gloom caused\nby them is enhanced by a draft coming from all around.  The trail turns south\nfrom the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(5264,52,'The darker dwarf forest',replace('You see a more dense foliage in these stunted trees.  The gloom caused\nby them is enhanced by a draft coming from all around.  The trail turns east\nfrom the north.\n','\n',char(10)));
INSERT INTO rooms VALUES(5265,52,'The darker dwarf forest',replace('You see a more dense foliage in these stunted trees.  The gloom caused\nby them is enhanced by a draft coming from all around.  The trail leads\neast and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(5266,52,'The darker dwarf forest',replace('You see a more dense foliage in these stunted trees.  The gloom caused\nby them is enhanced by a draft coming from all around.  The trail leads\ndown into a valley and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(5267,52,'A valley in the dark dwarf forest',replace('You are in a valley in the dark dwarf forest.  Short black grass grows\naround you.  Trails lead in all directions.\n','\n',char(10)));
INSERT INTO rooms VALUES(5268,52,'A small ugly cave',replace('You see a small cave.  Skeletons of many types of creatures litter the area.\nObviously, no fox lives here!  The oppression makes you want to leave and\nvomit.\n','\n',char(10)));
INSERT INTO rooms VALUES(5269,52,'A small ugly cave',replace('You are in a small ugly cave.  More skeletons lie around.  It is obvious\nthat the owner doesn''t want you here.  The exit north is still visible.\nSome writings are on this wall.\n','\n',char(10)));
INSERT INTO rooms VALUES(5270,52,'Down the path into a dead end',replace('You are down the path.  There is no obvious exit in this place, exit the\none back up north.  All around you, you see skeletons.\n','\n',char(10)));
INSERT INTO rooms VALUES(5271,52,'The Valley in the dark dwarf forest',replace('You are in a valley in the forest.  To the north is a trail out of this\ndark valley.  South is more of this valley.\n','\n',char(10)));
INSERT INTO rooms VALUES(5272,52,'A dim trail in the dwarf forest',replace('You are in a dim trail in the dwarf forest.  Not much light passes through\nhere.  To the south is a gloomy valley, while to the north the light grows\nbrighter.\n','\n',char(10)));
INSERT INTO rooms VALUES(5273,52,'A dim trail in the dwarf forest',replace('You are in a dim trail in the dwarf forest.  Not much light passes through\nhere.  The trail runs north and south, and the light seems to come from the\nnorth.  To the east, you see a small path into darkness.\n','\n',char(10)));
INSERT INTO rooms VALUES(5274,52,'A dim trail in the dwarf forest',replace('You are in a dim trail in the dwarf forest.  Not much light passes through\nhere.  The trail runs north and south, and the light seems to come from the\nnorth.\n','\n',char(10)));
INSERT INTO rooms VALUES(5275,52,'A bend in the dim trail in the dwarf forest',replace('You are in a dim trail in the dwarf forest.  Not much light passes through\nhere.  The trail runs south and west.  The trail west looks much friendlier\nthan the one leading south.\n','\n',char(10)));
INSERT INTO rooms VALUES(5276,52,'A trail in the dwarf forest',replace('You are in a trail in the dwarf forest.  The trees are stunted and it\nlooks dry around here.  The trail leads east and west.  It looks dimmer to\nthe east.\n','\n',char(10)));
INSERT INTO rooms VALUES(5277,52,'A trail in the dwarf forest',replace('You are in a trail in the dwarf forest.  The trees are stunted and it\nlooks dry around here.  The trail leads east and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(5278,52,'A trail in the dwarf forest',replace('You are in a trail in the dwarf forest.  The trees are stunted and it\nlooks dry around here.  The trail leads east and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(5279,52,'The bend in the trail in the dwarf forest',replace('You are in a bend in the trail in the forest.  The trees are stunted, but\nnot so dry around here.  The trail leads east, and to the south, you see a\nwaterfall.\n','\n',char(10)));
INSERT INTO rooms VALUES(5280,52,'A dark bend in the forest',replace('You are in a dark bend in the forest.  To the west, you see the trail\nleading back to the dwarven forest, and to the south, you see a dark and\ndismal path.\n','\n',char(10)));
INSERT INTO rooms VALUES(5300,53,'The Grand Gate of Thalos',replace('You stand in the archway of a gigantic stone archway. The two\nsteel gates look indestructible, yet they are elaborate in engravings.  You can\nhear laughter and good cheer from the other side of these gates.  Obviously, \nthe city is teeming with activity!  There is a small gold plaque on mounted\non the archway.\n','\n',char(10)));
INSERT INTO rooms VALUES(5301,53,'Main Street',replace('This is a magnificent street, immaculate all over. The streets are filled\nwith people rushing from building to building and a balmy zephyr blows by\nyou.  The whole city is teeming with activity.  A cobbled alley leads north\nand south.  Children run pass you as they play tag.\n','\n',char(10)));
INSERT INTO rooms VALUES(5302,53,'Main Street',replace('This is a magnificent street, immaculate all over.  The streets are filled\nwith people rushing from building to building and a balmy zephyr blows by you.\nThe whole city is teeming with activity.  On one side is a beautiful house \nwhile on the other is the entrance to a large mansion.  Sounds of people hard\nat work echo within the mansion.  Near the center of town you see a large \ndomed building, magnificent and immense.\n','\n',char(10)));
INSERT INTO rooms VALUES(5303,53,'A Garden Path',replace('A circular path surrounds a magnificent domed temple in the center\nof the city. Flowers grow on the sides of the path and the lush trees are \nladen with fruit.  Vines and ivy snake up the sides of the temple, making this\ntemple truly a blend of nature and man''s work of art.\n','\n',char(10)));
INSERT INTO rooms VALUES(5304,53,'A Garden Path',replace('A circular path surrounds a magnificent domed temple in the center\nof the city. Flowers grow on the sides of the path and the lush trees are\nladen with fruit.  Vines and ivy snake up the sides of the temple, making this\ntemple truly a blend of nature and man''s work of art.\n','\n',char(10)));
INSERT INTO rooms VALUES(5305,53,'A garden path',replace('A circular path surrounds a magnificent domed temple in the center\nof the city. Flowers grow on the sides of the path and the lush trees are\nladen with fruit.  Vines and ivy snake up the sides of the temple, making this\ntemple truly a blend of nature and man''s work of art.\n','\n',char(10)));
INSERT INTO rooms VALUES(5306,53,'A Garden Path',replace('A circular path surrounds a magnificent domed temple in the center\nof the city. Flowers grow on the sides of the path and the lush trees are\nladen with fruit.  Vines and ivy snake up the sides of the temple, making this\ntemple truly a blend of nature and man''s work of art.\n','\n',char(10)));
INSERT INTO rooms VALUES(5307,53,'The market place',replace('You stand in the middle of a large square lined on each side with\nbaskets, carts, and stands of all shapes and sizes.  The little shops are \nfilled with goods sold to the demanding public.\n','\n',char(10)));
INSERT INTO rooms VALUES(5308,53,'The market place',replace('You stand in the middle of a large square lined on each side with\nbaskets, carts, and stands of all shapes and sizes.  The little shops are\nfilled with goods sold to the demanding public.\n','\n',char(10)));
INSERT INTO rooms VALUES(5309,53,'A Side Street',replace('This small side street leads east and west into back alleys while\nto the south you see a beautifully designed temple. Shrieks of little\nchildren playing games in the distance catch your attention.\n','\n',char(10)));
INSERT INTO rooms VALUES(5310,53,'A Side Street',replace('You are in the common section of the city. More buildings made of\nclay and stone be dazzles you. Most of these homes are designed so\nbeautifully you just cant keep your eyes off them.  The street\ncontinues north and south and buildings line the street.\n','\n',char(10)));
INSERT INTO rooms VALUES(5311,53,'A Side Street',replace('This small side street leads away from the garden path to the south.\nAround you stand large numbers of commoners'' houses.  Many citizens\npass by you with a friendly hello.  You almost feel like home here.\n','\n',char(10)));
INSERT INTO rooms VALUES(5312,53,'A side street',replace('This small side street leads south away from the temple into the\nbusiness section of town. To the east is the famous City Hall of Thalos.  \nWell disciplined guards stand at attention, watching over the city hall, but\nyou don''t see any source of threats in THIS city.  North is a garden path,\nwest is a smithy, and this side street continues south.\n','\n',char(10)));
INSERT INTO rooms VALUES(5313,53,'A side street',replace('This small side street is lined with great beautifully designed\nbuildings. To the north is the magnificent temple while to the\nsouth lies the entrance to a small friendly tavern. The street continues\nnorth and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(5314,53,'A side street',replace('You are at the end of a long street leading to the center of the city.\nA long alley runs east and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(5315,53,'Under another grand watchtower',replace('You stand at the base of a tall ivy covered watchtower built to\nprotect the city from invaders.  You get the feeling of safety here in\nThalos.\n','\n',char(10)));
INSERT INTO rooms VALUES(5316,53,'A back alley',replace('This alley leads to the rear of meat stand. The aroma of fresh and\nchar-broiled meat catches your sense of smell.  You wipe the drool\noff your chin the instant you know it is there.\n','\n',char(10)));
INSERT INTO rooms VALUES(5317,53,'The meat stand',replace('A large stand has been set up here with metal hooks and wooden racks\nin the background.  Hanging on the hooks are huge slabs of meat\nand other game.  This stand is packed with produce, and a sudden burst\nof laughter catches you by surprise as little children play around\nyour ankles.\n','\n',char(10)));
INSERT INTO rooms VALUES(5318,53,'A back alley',replace('A narrow alley leads east to a wider street and west to one of\nthe city watchtowers.\n','\n',char(10)));
INSERT INTO rooms VALUES(5319,53,'The guild house',replace('You are standing in this city''s ONLY guild house.  Tables and chairs\nare set about for the occupants'' comfort.  Weapons are stacked neatly on the\nweapons rack.  Each weapon looks polished, sharpened, and oiled.\nDraped along the back wall is the proud banner of Thalos in all its glory.\n','\n',char(10)));
INSERT INTO rooms VALUES(5320,53,'The produce stand',replace('A large cart sits here carrying fresh fruit and vegetables.\nHungry children swarm all about the tasty treats the merchants are\ngiving out for free.\n','\n',char(10)));
INSERT INTO rooms VALUES(5321,53,'The smithy',replace('In here you find tools and anvils used to make various weapons\nand items. The walls are fully stocked with pieces of armor and weaponry.\n','\n',char(10)));
INSERT INTO rooms VALUES(5322,53,'The tapestry stand',replace('Beautiful tapestries and rugs hang all over the walls.  Fancy\nrobes and various articles of clothing hang about for sale. You stare with\nawe at how much work must have been put into these cloths.\n','\n',char(10)));
INSERT INTO rooms VALUES(5323,53,'A back alley',replace('A narrow alley leads north to one of the city watchtowers while\nto the south there lies a market stand full of expensive clothes and rugs.\n','\n',char(10)));
INSERT INTO rooms VALUES(5324,53,'Under the watchtower',replace('You stand under one of the city watchtowers built to protect\nthe city from invaders.  You know that you are safe from any danger.\n','\n',char(10)));
INSERT INTO rooms VALUES(5325,53,'The jewelery stand',replace('A table stands covered with fine jewelery and gems.  The jeweler\nstands proudly over his collection as he polishes and cleans each one.\n','\n',char(10)));
INSERT INTO rooms VALUES(5326,53,'A simple clay dwelling',replace('This is a very plain house with a few chairs and a bed.\nA warmed and lit fireplace suggests that the dwelling is currently\noccupied.  You should leave before the owner finds you here.\n','\n',char(10)));
INSERT INTO rooms VALUES(5327,53,'A stone dwelling',replace('This small house is the dwelling of a humble citizen of Thalos.\nA few rafters stand with thatched straw blowing with the wind gusts\nblowing through the city.\n','\n',char(10)));
INSERT INTO rooms VALUES(5328,53,'A back alley',replace('A narrow alley leads east to one of the city watchtowers and west to\na small side street.\n','\n',char(10)));
INSERT INTO rooms VALUES(5329,53,'A busy shop',replace('From the outside this place looks like an ordinary building,\nbut inside these cramped quarters you discover a shop filled with\narmor, weapons, and various other goods. A small sign posted on the wall\nflutters in the wind.\n','\n',char(10)));
INSERT INTO rooms VALUES(5330,53,'The Tavern of the Sun',replace('A glorious place, this tavern is second home for many citizens of\nThalos.  Tables and chairs are set in rows, bottles and glasses filled, and\na small performance stage teaming with dazzling entertainment. Musical\ninstruments and personal belongings lie in piles belonging to each member\nof this room.\n','\n',char(10)));
INSERT INTO rooms VALUES(5331,53,'South wing of the city hall',replace('You stand in a large room attached to this end of the hallway which\nleads back north to the reception area. Pedestals and columns stand\nfaithfully.  Valuable items hang from the walls each to be admired\nby onlookers.  Chairs lie around, and a large curved desk. To the east\nis a vine-covered archway leading out into a private courtyard.\n','\n',char(10)));
INSERT INTO rooms VALUES(5332,53,'The city hall',replace('This is the main reception area of Thalos'' city hall. The walls have\nbeen painted in pure white and thick lush carpet line the floor wall to wall.\nA side door on the west wall allows you to go out to one of the city''s side \nstreets.  Hallways lead south and east.\n','\n',char(10)));
INSERT INTO rooms VALUES(5333,53,'East wing of the city hall',replace('Here lies fancy office, possibly the mayor''s. A few green plants\nand pieces of furniture make this place breathtaking.  There is a large\nglass cabinet along the wall. A long hallway leads west back to the\nreception area and an ivy-covered archway leads south into a private\ncourtyard.\n','\n',char(10)));
INSERT INTO rooms VALUES(5334,53,'The private gardens and courtyard of Thalos',replace('You stare in awe as the beauty of this place takes you by\nsurprise.  Exotic flowers and trees are planted in neat rows and lawn\nbenches line the walk ways.  A large marble fountain in the center of the\ncourtyard stands. Above stands one of the four watchtowers. Archways\nnorth and west lead back into the city hall.\n','\n',char(10)));
INSERT INTO rooms VALUES(5335,53,'A small guard house',replace('This is the barracks for Thalos'' cityguards.  Guards populate this\nshack ready, willing, and able to ward off any trouble.  This small\nshack stands guarding both to the entrance to the city and to the city hall.\n','\n',char(10)));
INSERT INTO rooms VALUES(5336,53,'An impressive house',replace('This house houses the Defender of Thalos.  He represents all that\nis good and right in this city.  As the most skilled fighting machine,\nhe is the commander of the guard.\n','\n',char(10)));
INSERT INTO rooms VALUES(5337,53,'A Public Library',replace('This seems to be the tallest structure in the city.  Rows and rows of books\nline the 20 foot tall bookcases, and a quiet serenity can be felt by all here.\n','\n',char(10)));
INSERT INTO rooms VALUES(5338,53,'The Library Addition',replace('There are more shelves and tables here.  Vials of strange potions line a\nsection of the wall, and books and other items of power line another.  The exit\nis to the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(5339,53,'A back alley',replace('A narrow back alley goes south to main street and north towards\na watchtower.  People quietly pass you by.\n','\n',char(10)));
INSERT INTO rooms VALUES(5340,53,'A back alley',replace('A narrow back alley leads north to one of the city watchtowers\nand south towards main street.  The shade cast by the watchtower is very\nrefreshing.\n','\n',char(10)));
INSERT INTO rooms VALUES(5341,53,'Under a watchtower',replace('You stand under a tall watchtower. Narrow back alleys lead west and\nsouth and a sturdy ladder leads up into the tower.\n','\n',char(10)));
INSERT INTO rooms VALUES(5342,53,'A bath house',replace('This is the bath house for the commoners of the city. Hot steamy water \nwells up from a hole in the floor. Obviously there is a hot spring located \nunder the city (making the decision to put a city here seem much more \nreasonable). To the west is another room.\n','\n',char(10)));
INSERT INTO rooms VALUES(5343,53,'A back alley',replace('A narrow back alley leads west to a small side street and east to one\nof the city watchtowers. Great amounts of steam issue forth from the\nbuilding to the south.  It looks very inviting.\n','\n',char(10)));
INSERT INTO rooms VALUES(5344,53,'A Resting Room',replace('You are in a resting room.  Soft mats line the floor, and you see many\npeople just relaxing on them.  The comfort of this place is so inviting, you \nwant to join them.  Great amounts of steam issue forth from the hole in the \neast wall.\n','\n',char(10)));
INSERT INTO rooms VALUES(5345,53,'On the second floor of the library',replace('You see more books here.  Through windows, you have a glorious view of\na nearby bay.  Birds fly by your window.\n','\n',char(10)));
INSERT INTO rooms VALUES(5346,53,'The north-west watchtower',replace('You stand atop one of the city watchtowers. The view is magnificent\nfrom here and you can see all the way to the western mountains.  You are \nconfident nothing can touch this tower.\n','\n',char(10)));
INSERT INTO rooms VALUES(5347,53,'The south-west watchtower',replace('You stand atop one of the city watchtowers. The view is magnificent\nfrom here and you can see all the way to the western mountains. To the\nsouth bay stretches to the horizon.  You are confident nothing can touch this\ntower.\n','\n',char(10)));
INSERT INTO rooms VALUES(5348,53,'The north-east watchtower',replace('You stand atop one of the city watchtowers. The view is magnificent\nfrom here.  Green fields stretch to the horizon.  You are confident nothing\ncan touch this tower.\n','\n',char(10)));
INSERT INTO rooms VALUES(5350,53,'The Temple of Thalos',replace('You stand within one of the most holy places in the realm. This stunning \ndomed temple houses the city''s worshipers en masse. Long benches line the \naisles and the altar glistens with the gold and platinum inlay.The walls and \nroof are all made of ceramic, making this place reflect the sun well.  \n    The greenery around the temple itself makes this place a great blend of\nnature and man''s works of art.\n','\n',char(10)));
INSERT INTO rooms VALUES(5351,53,'A back alley',replace('A narrow alley leads east to a wider street and west to one of\nthe city watchtowers.  Little kids play tag around you.\n','\n',char(10)));
INSERT INTO rooms VALUES(5352,53,'Under a watchtower',replace('You stand at the base of a tall watchtower built to protect the city\nfrom invaders.  From the looks of things, its doing a great job.\n','\n',char(10)));
INSERT INTO rooms VALUES(5353,53,'A back alley',replace('A narrow alley leads south to one of the city watchtowers.\n','\n',char(10)));
INSERT INTO rooms VALUES(5354,53,'The south-east watchtower',replace('You stand atop one of the city watchtowers. The view is magnificent\nfrom here and you can see all the way to the western mountains. To the\nsouth the you see the bay.  You''re confident nothing can touch this tower.\n','\n',char(10)));
INSERT INTO rooms VALUES(5355,53,'A back alley',replace('A narrow alley leads north to the main street, and south toward a tall\nwatchtower.  A building is to the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(5356,53,'A trail at the end of the dwarf forest',replace('The trail ends here, with tall, leafy, green trees all around you.\nTo the west, you can see a huge beautiful and radiant city.  Something\nabout it gives you a relaxed feeling.  To the east is your way back home.\n','\n',char(10)));
INSERT INTO rooms VALUES(5357,53,'A trail at the end of the dwarf forest',replace('A side trail here leads from the dwarf forest.  It is definitely milder\nhere.  The trail continues to the east from here.\n','\n',char(10)));
INSERT INTO rooms VALUES(5358,53,'The dwarf forest',replace('You see tall, healthy green trees here.  The trail bends north to\nwest from here.\n','\n',char(10)));
INSERT INTO rooms VALUES(5359,53,'The dwarf forest',replace('You see more big green trees here.  It looks almost as if this place was\nblessed by a god to be green and mild.  The trail leads north and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(5360,53,'The dwarf forest',replace('You see more big green trees here.  It looks almost as if this place was\nblessed by a god to be green and mild.  The trail leads north and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(5361,53,'The dwarf forest',replace('You see many big green trees here.  You see many leaves on these huge\ntrees.  Grass layer the ground with 2 inches of padding.\n','\n',char(10)));
INSERT INTO rooms VALUES(5362,53,'The Cross Roads',replace('The roads cross here.  Midgaard is to the west.  To the east, you see the\nstately oaks and poplars of the holy grove.  A wide path leads south through\nthe dwarven forest.  To the north is a very desolate trail.\n','\n',char(10)));
INSERT INTO rooms VALUES(5363,53,'The Lane',replace('You are strolling along a pleasant, shady lane. The road is lined on both\nsides by tall, stately trees which lend the scene with a sense of quiet\nserenity. You can follow the road north or south.\n','\n',char(10)));
INSERT INTO rooms VALUES(5364,53,'City Entrance',replace('You stand on the outskirts of a construction site - Midgaard; the capital\nof this land. The road leads east into the peace and quiet - and dangers -\nof the forest; and to the west it becomes the main street of the town;\nsurrounded by building foundations of unfinished shops, houses, and temple. \n','\n',char(10)));
INSERT INTO rooms VALUES(5365,53,'The Plains',replace('You are standing on the plains. This is a vast desolate place where the\nwind can howl undisturbed since nothing but you bars its way. However you\nare not the first to wander here. Before you somebody has left footprints.\nThe footprints make a path that looks rather bewildered and is not the kind\nof path to lead to anywhere significant or important but it seems to have\nmade up its mind to enter the hills far away north.  A little distance\nfurther, you lose the trail and decide not to get lost.\n','\n',char(10)));
INSERT INTO rooms VALUES(5366,53,'The holy grove',replace('You are standing amidst the ancient oaks and poplars in the holy grove. You\ncan feel a strange sensation of contentedness and relief seeping through You,\nas if great burdens have been lifted from Your shoulders. From here, friendly-\nlooking paths lead east and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(5367,53,'The holy grove',replace('You are standing amidst the ancient oaks and poplars in the holy grove. You\nfeel unusually happy here, as if great burdens have been lifted from Your\nshoulders. From here, pleasant-looking paths lead east, west and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(5368,53,'A clearing in the woods',replace('You are standing in a clearing in the light woods. Somehow, this place\nseems powerfully DIFFERENT from the rest of the forest, as if something is\nseverely strained in the fabric of reality here.\n','\n',char(10)));
INSERT INTO rooms VALUES(5369,53,'The holy grove',replace('You are standing amidst the ancient oaks and poplars in the holy grove. You\nfeel calm and relaxed here, as if great burdens have been lifted from Your\nshoulders. From here, pleasant-looking paths lead east, north and south. To\nthe west, through the trees, You can see the road to Midgaard''s construction\nsite.\n','\n',char(10)));
INSERT INTO rooms VALUES(5370,53,'The sacred glade',replace('You are standing in the middle of the sacred glades, where the citizens of\nThalos come to celebrate the spring, where farmers give thanks for bountiful\nharvest in the fall, and where lovers stroll in summer. You feel seasons of\nremembered happiness and joy taking Your sorrows and worries away from You,\nleaving You calm and invigorate, ready for the world. Paths lead into the\nholy grove to the east, north and west, while to the south a wide, sunny field\nslopes down to a sparkling lake.\n','\n',char(10)));
INSERT INTO rooms VALUES(5371,53,'The holy grove',replace('You are standing amidst the ancient oaks and poplars in the holy grove. You\ncan feel a strange sensation of joy and calm seeping through You, as if great\nburdens have been lifted from Your shoulders. To the south, You glimpse an open\narea through the trees, while paths lead away north and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(5372,53,'The holy grove',replace('You are standing amidst the tall, majestic trees in the southern end of the\nholy grove. Paths lead north and east. To the east, You can see a wide, open\nfield, sloping gently down towards a bright, glittering lake. Somehow, here\nyou feel an inexplicable happiness, as if the world''s troubles no longer\nreally matter to you.\n','\n',char(10)));
INSERT INTO rooms VALUES(5373,53,'The sunny field',replace('You are standing in the middle of a wide, summery, sunlit field. There is a\nfragrance of spring in the air, a sound of summer and a feeling of eternal\nSaturday afternoon. To the south is a clear, sparkling lake, and to the north\nand west is the holy grove. In the wood''s edge, to the east, is construction,\nshimmering softly through the colors of the rainbow. You feel as if You\ncould spend the rest of your life here, lying on your back and looking at the\npatterns of the clouds as they gently drift across the sky.\n','\n',char(10)));
INSERT INTO rooms VALUES(5374,53,'The croquet lawn',replace('You are standing on a immaculately manicured green lawn, the kind you only\nget after 200 years of meticulous work. There is a winding stone path leading\nfrom the wood''s edge to the north, to the softly shimmering, rainbow-colored\ndome covering construction to the south. This place enjoys a perpetual cool,\nsunny summers after-noon.\n','\n',char(10)));
INSERT INTO rooms VALUES(5375,53,'The Void',replace('You are standing in the middle of something you cannot explain.  You see\nstars yet you cannot see what you are standing on.  You are not standing\non any sort of physical ''ground'' as you can see yet you are not floating\neither.  Occasionally, the starry ''sky'' fades into a fuzzy, yet bright,\nrainbow then back to its normal state.  In the middle of this room is\na ladder standing vertical.\n','\n',char(10)));
INSERT INTO rooms VALUES(5376,53,'The Void',replace('You are standing in the middle of something you cannot explain.  You see\nstars yet you cannot see what you are standing on.  You are not standing\non any sort of physical ''ground'' as you can see yet you are not floating\neither.  Occasionally, the starry ''sky'' fades into a fuzzy, yet bright,\nrainbow then back to its normal state.\n','\n',char(10)));
INSERT INTO rooms VALUES(5377,53,'The Void',replace('You are standing in the middle of something you cannot explain.  You see\nstars yet you cannot see what you are standing on.  You are not standing\non any sort of physical ''ground'' as you can see yet you are not floating\neither.  Occasionally, the starry ''sky'' fades into a fuzzy, yet bright,\nrainbow then back to its normal state.\n','\n',char(10)));
INSERT INTO rooms VALUES(5378,53,'The Void',replace('You are standing in the middle of something you cannot explain.  You see\nstars yet you cannot see what you are standing on.  You are not standing\non any sort of physical ''ground'' as you can see yet you are not floating\neither.  Occasionally, the starry ''sky'' fades into a fuzzy, yet bright,\nrainbow then back to its normal state.  In the middle of this room is\na ladder standing vertical.\n','\n',char(10)));
INSERT INTO rooms VALUES(5379,53,'The Temple Of Midgaard',replace('You are in the southern end of the temple hall in the Temple of Midgaard.\nThe temple has been constructed from giant marble blocks, eternal in\nappearance, and most of the walls are covered by ancient wall paintings\npicturing Gods, Giants and peasants.\n   Large steps lead down through the grand temple gate, descending the huge\nmound upon which the temple is built and ends on the temple square below.\n   You notice that this building is quite new.  A small plaque is on this wall.\n','\n',char(10)));
INSERT INTO rooms VALUES(5380,53,'The Temple Square',replace('You are standing on the temple square.  Huge marble steps lead up to the\ntemple gate.  The ground is just dirt but there are plans to make the road\ncobble stone.  Just south of here you see a blooming market square, the\ncenter of Midgaard.\n','\n',char(10)));
INSERT INTO rooms VALUES(5381,53,'Market Square',replace('You are standing on the market square, the Square of Midgaard.  It seems\nthat a large, peculiar looking statue is being built here in the middle of\nthe square.  Roads lead to the north and east, north to the temple square,\neast is the main street.\n','\n',char(10)));
INSERT INTO rooms VALUES(5382,53,'The Main Street',replace('You are on Main Street crossing through this booming town.  The main\nstreet continues east.  To the west you see and hear a small market place.\n','\n',char(10)));
INSERT INTO rooms VALUES(5383,53,'The Main Street',replace('The main street, to the east you leave town and to the west the street\nleads to the market square.\n','\n',char(10)));
INSERT INTO rooms VALUES(5384,53,'Inside the East Gate of Midgaard',replace('You are by two small newly built towers that have been built into the\ncity wall and connected with a footbridge across the heavy wooden gate.\nMain Street leads west from here.\n','\n',char(10)));
INSERT INTO rooms VALUES(5385,53,'Outside the East Gate of Midgaard',replace('You are by two small towers that have been built into the city wall and\nconnected with a footbridge across the heavy wooden gate.  To the east the\nplains stretch out in the distance.\n','\n',char(10)));
INSERT INTO rooms VALUES(5386,53,'By the Temple Altar',replace('You are by the temple altar in the northern end of the Temple of Midgaard.\nA huge altar made from white polished marble is standing in front of you and\nbehind it is a ten foot tall sitting statue of Odin, the King of the Gods.\n','\n',char(10)));
INSERT INTO rooms VALUES(5550,55,'Village street',replace('You stand at the small village street in Ofcol.\nFrom here you see small houses and only few people.\nNorth of here the village street continues up to the small\nsquare where some people are gathered as always.\n','\n',char(10)));
INSERT INTO rooms VALUES(5551,55,'Village street',replace('You are standing on the village street of Ofcol.\nEast from here is a small alley and north you enter the village\nsquare. Towards the south you can leave Ofcol.\n','\n',char(10)));
INSERT INTO rooms VALUES(5552,55,'Village square',replace('The village square is a place where inhabitants of Ofcol gather\nto talk, trade and sell items and just have a good time.\nYou see a small shop to the west and the local inn to the north.\nIf you leave south you go to village street.\n','\n',char(10)));
INSERT INTO rooms VALUES(5553,55,'The small alley',replace('You are in a small, quiet alley.  From here you see the village street\nto the west and a small room lies to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(5554,55,'The future training room',replace('This is the future site of a training room.  The only exit is north\nleading to the small alley.\n','\n',char(10)));
INSERT INTO rooms VALUES(5555,55,'Luxan''s mixed shop',replace('You are standing in a small shop, filled with all kinds of goods.\nHere you might be able to find just the thing you''re looking for.\nThe only exit is east to village square.\n','\n',char(10)));
INSERT INTO rooms VALUES(5556,55,'The Local Inn',replace('You are in the local inn, where the peaceful citizens of Ofcol\ngather to have a drink or 5 if they have dry throats.\nYou can''t help thinking that Ofcol is a dry city, when you see the\nmany people here.\nThe only exit is south to the village square.\n','\n',char(10)));
INSERT INTO rooms VALUES(5577,55,'Ravan''s hideout',replace('This place is a small, cosy place where no one disturbs you all\nthe time. The room has little decoration except for some pictures\non the wall.\nYou notice that there are no exits from this room.\n','\n',char(10)));
INSERT INTO rooms VALUES(6000,60,'The edge of the forest',replace('You are standing at the eastern edge of a big forest.  To the east is the West\nGate of Midgaard and to the west is a narrow trail, leading in through the\nforest.  A dimly lit path leads north.\n','\n',char(10)));
INSERT INTO rooms VALUES(6001,60,'A trail through the light forest',replace('You are on a trail leading through the forest.  To the east is the forest edge\nand to the west, the trail leads further into the forest.\n','\n',char(10)));
INSERT INTO rooms VALUES(6002,60,'A trail through the light forest',replace('You are on a narrow trail leading east and west through the forest.  To the\nwest, the forest gradually becomes more dense.  A small forest path leads\nsouth.\n','\n',char(10)));
INSERT INTO rooms VALUES(6003,60,'A trail through the dense forest',replace('You are on a trail leading east and west through the dense forest.  To the\neast, the forest gradually seems to become lighter.\n','\n',char(10)));
INSERT INTO rooms VALUES(6004,60,'A trail through the dense forest',replace('You are on a trail leading east and west through the dense forest.  To the\nwest, the trees are so huge and their crowns so dense that forest remains in\ntotal darkness.  A small path leads south through the trees.\n','\n',char(10)));
INSERT INTO rooms VALUES(6005,60,'A small path in the dense forest',replace('You are on a small path leading through the dense forest.  The crowns of the\nold trees leave the forest in an unreal twilight illumination.  The path\ncontinues north and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(6006,60,'A small path in the dense forest',replace('You are on a small path leading through the dense forest.  The crowns of the\nold trees leave the forest in an unreal twilight illumination.  The path\ncontinues north and east.\n','\n',char(10)));
INSERT INTO rooms VALUES(6007,60,'An intersection in the dense forest',replace('You are on a small path leading through the dense forest.  The crowns of the\nold trees leave the forest in an unreal twilight illumination.  The forest\ngradually lightens to the east.  Paths lead east, west and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(6008,60,'The forest clearing',replace('You are in a clearing in the forest.  Lots of fresh stumps of varying sizes\nprotrude from the ground and heavy logs are stacked neatly in a big pile\nsupported by stakes set into the ground.  Paths lead north, east and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(6009,60,'Outside a small cabin in the forest',replace('You are outside a small cabin built entirely from heavy logs.  There is a\nwooden door to the north and small paths lead west and south through the trees.\n','\n',char(10)));
INSERT INTO rooms VALUES(6010,60,'Inside the cabin',replace('You are inside a small one-room cabin made entirely from heavy logs.  It is\nvery sparsely furnished, containing only most basic housekeeping equipment,\nsuch as a bed, a chair and a table.\n','\n',char(10)));
INSERT INTO rooms VALUES(6011,60,'A small path through the light forest',replace('You are on a small path leading through the forest.  The trees are tall and\nslender.  Paths lead north and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(6012,60,'An intersection in the dense forest',replace('You are on a small path leading through the dense forest.  The crowns of the\nold trees leave the forest floor in an unreal twilight illumination.  Paths\nlead north, east and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(6013,60,'A small path in the dense forest',replace('You are on a small path leading through the dense forest.  The crowns of the\nold trees leave the forest in an unreal twilight illumination.  The path\ncontinues east and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(6014,60,'An intersection in the dense forest',replace('You are on a small path leading through the dense forest.  The forest gradually\nlightens to the north.  Paths lead north, east and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(6015,60,'A small path in the dense forest',replace('You are on a small path leading through the dense forest.  The crowns of the\nold trees leave the forest in an unreal twilight illumination.  The path\ncontinues south and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(6016,60,'A small path in the dense forest',replace('You are on a small path leading through the dense forest.  The crowns of the\nold trees leave the forest in an unreal twilight illumination.  The path\ncontinues north and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(6017,60,'A small path in the dense forest',replace('You are on a small path leading through the dense forest.  The forest seems to\nbecome lighter to the west.  The path continues north and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(6018,60,'An intersection in the light forest',replace('You are on a small path leading through the forest.  A path leads north to a\nsmall field and other paths lead east and west into the dense forest.\n','\n',char(10)));
INSERT INTO rooms VALUES(6019,60,'A small path in the dense forest',replace('You are on a small path leading through the dense forest.  The forest seems to\nbecome lighter to the east.  The path continues north and east.\n','\n',char(10)));
INSERT INTO rooms VALUES(6020,60,'A small path in the dense forest',replace('You are on a small path leading through the dense forest.  The crowns of the\nold trees leave the forest in an unreal twilight illumination.  The path\ncontinues south and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(6021,60,'A small path in the dense forest',replace('You are on a small path leading through the dense forest.  To the west there is\na cave entrance.  The path continues north and east.\n','\n',char(10)));
INSERT INTO rooms VALUES(6022,60,'Inside the cave',replace('You are in a natural cave.  Various sorts of debris cover the stone floor,\nemitting a rather unpleasant smell that makes the air thick and hard to\nbreathe.  The only obvious exit is east.\n','\n',char(10)));
INSERT INTO rooms VALUES(6023,60,'On a small, grassy field',replace('You are in a small, grassy field somewhere in the forest.  The tall grass\nnearly reaches your waist, and the surrounding oaks and beeches form an almost\nwall-like thicket on all sides of the field.  A small path leads south through\nthe trees.\n','\n',char(10)));
INSERT INTO rooms VALUES(6100,60,'A narrow trail through the deep, dark forest',replace('You are on a narrow trail winding its way between the enormous, grey trunks.\nThe crowns of the trees must be very dense, as they leave the forest floor in\nutter darkness.  The trail leads east and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(6101,60,'A narrow trail through the deep, dark forest',replace('You are on a dusty trail winding its way east-west between huge, ancient trees\nwhose grey trunks remind you of ancient pillars in a enormous, deserted hall.\nTo the south, a frail path leads away from the trail.\n','\n',char(10)));
INSERT INTO rooms VALUES(6102,60,'A narrow trail through the deep, dark forest',replace('You are on a dusty trail winding its way east-west between huge, ancient trees\nthat stand close on all sides.  Not a sound is to be heard - everything is\nominously quiet.\n','\n',char(10)));
INSERT INTO rooms VALUES(6103,60,'A narrow trail through the deep, dark forest',replace('You are where the dusty trail bends, as to avoid conflict with a colossal\ntrunk to the west.  Not a sound is to be heard - everything is ominously quiet.\nThe trail leads east and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(6104,60,'A small path in the deep, dark forest',replace('You are on a narrow path leading through the deep, dark forest.  You feel as if\nthe ancient trees observe you in watchful silence.  The path continues north\nand south.\n','\n',char(10)));
INSERT INTO rooms VALUES(6105,60,'A small path in the deep, dark forest',replace('You are on a narrow path leading through the deep, dark forest.  Ancient grey\ntrees loom all around you.  The path continues north and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(6106,60,'A junction in the deep, dark forest',replace('You are by a junction where three paths meet.  Ancient grey trees tower above\nyou on all sides.  Paths lead east, south and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(6107,60,'A small path in the deep, dark forest',replace('You are on a narrow path leading through the deep, dark forest.  Ancient grey\ntrees loom all around you.  The path continues north and east.\n','\n',char(10)));
INSERT INTO rooms VALUES(6108,60,'A narrow trail through the deep, dark forest',replace('You are on a dusty trail winding its way between huge, ancient trees\nstanding close on all sides.  The trail leads north and west and to the south,\na frail path leads away from the trail.\n','\n',char(10)));
INSERT INTO rooms VALUES(6109,60,'A narrow trail through the deep, dark forest',replace('You are on a dusty trail winding its way east-west between huge, ancient trees\nthat stand close on all sides.  Not a sound is to be heard - everything is\nominously quiet.\n','\n',char(10)));
INSERT INTO rooms VALUES(6110,60,'A narrow trail through the deep, dark forest',replace('You are on a dusty trail winding its way between huge, ancient trees that stand\nclose on all sides.  The trail leads east and south.  To the north, a narrow\npath leads away from the trail.\n','\n',char(10)));
INSERT INTO rooms VALUES(6111,60,'A narrow trail through the deep, dark forest',replace('You are on a dusty trail winding its way north-south between huge, ancient\ntrees that loom ominously above you.\n','\n',char(10)));
INSERT INTO rooms VALUES(6112,60,'A narrow trail through the deep, dark forest',replace('You are on a dusty trail winding its way between huge, ancient trees\nstanding close on all sides.  The trail leads north and west and to the east,\na frail path leads away from the trail.\n','\n',char(10)));
INSERT INTO rooms VALUES(6113,60,'A small path in the deep, dark forest',replace('You are on a narrow path leading through the deep, dark forest.  Ancient grey\ntrees loom in all directions.  The path continues south and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(6114,60,'A junction in the deep, dark forest',replace('You are by a junction where three paths meet.  Ancient grey trees tower above\nyou on all sides.  Paths lead north, east and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(6115,60,'A small path in the deep, dark forest',replace('You are on a narrow path leading through the deep, dark forest.  You feel as\nif the ancient trees observe you in watchful silence.  The path continues north\nand west.\n','\n',char(10)));
INSERT INTO rooms VALUES(6116,60,'A small path in the deep, dark forest',replace('You are on a narrow path leading through the deep, dark forest.  Giant, grey\ntrees loom ominously on all sides.  The path continues east and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(6117,60,'A junction in the deep, dark forest',replace('You are by a junction where three paths meet.  Ancient, grey trees seem to\nobserve you silently you from all sides.  Paths lead north, east and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(6118,60,'A small path in the deep, dark forest',replace('You are on a narrow path leading through the deep, dark forest.  Ancient,\ngrey trees loom everywhere.  The path continues south and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(6119,60,'A small path in the deep, dark forest',replace('You are on a narrow path leading through the deep, dark forest.  Huge, ancient\ntrees are on all sides.  The path continues north and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(6120,60,'On the river bank in the deep, dark forest',replace('You are on a narrow path leading through the deep, dark forest.  To the south a\nfast river is flowing westwards through the forest.  Ancient grey trees loom on\nboth banks.  The path continues north and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(6121,60,'A dead end path on the river bank in the deep, dark forest',replace('You are on a narrow path leading through the deep, dark forest.  The ancient\ntrees stand so close that the path disappears between the dusty roots.  To the\nsouth a dark river flows from east to west.  The only exit appears to be east.\n','\n',char(10)));
INSERT INTO rooms VALUES(6122,60,'A small path in the deep, dark forest',replace('You are on a narrow path leading through the deep, dark forest.  Giant, grey\ntrees loom ominously all around.  The path continues east and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(6123,60,'A junction on the river bank in the deep, dark forest',replace('You are by a junction where three paths meet.  Ancient, grey trees seem to\nobserve you silently you from all around.  To the south a dark river flows from\neast to west through the forest.  Paths lead north, east and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(6124,60,'A dead end path in the deep, dark forest',replace('You are on a narrow path leading through the deep, dark forest.  The ancient\ntrees stand so close that the path disappears between the dusty roots.  To the\nsouth a dark river flows from east to west.  The only exit appears to be west.\n','\n',char(10)));
INSERT INTO rooms VALUES(6125,60,'A small path on the river bank in the deep, dark forest',replace('You are on a narrow path leading through the deep, dark forest.  Ancient grey\ntrees loom everywhere.  To the south you smell marsh gas.  The path continues\nnorth and east.\n','\n',char(10)));
INSERT INTO rooms VALUES(6126,60,'A narrow trail through the deep, dark forest',replace('You are on a dusty trail winding its way between huge, ancient trees standing\nclose on all sides.  The trail leads north and west, and to the south a frail\npath leads away from the trail.\n','\n',char(10)));
INSERT INTO rooms VALUES(6127,60,'A narrow trail through the deep, dark forest',replace('You are on a dusty trail winding its way between huge, ancient trees\nstanding close on all sides.  The trail leads east and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(6128,60,'A narrow trail through the deep, dark forest',replace('You are on a dusty trail winding its way east-west between huge, ancient trees\nthat stand close on all sides.  Not a sound is to be heard - everything is\nominously quiet.\n','\n',char(10)));
INSERT INTO rooms VALUES(6129,60,'A narrow trail through the deep, dark forest',replace('You are on a dusty trail winding its way east-west between huge, ancient trees\nthat stand close on all sides.  Not a sound is to be heard - everything is\nominously quiet.\n','\n',char(10)));
INSERT INTO rooms VALUES(6130,60,'A narrow trail through the deep, dark forest',replace('You are on a dusty trail winding its way westwards just below huge sticky\nwires suspended like ropes between the trees.  To the west the path seems to\nbe completely covered in a giant web made from huge threads covered with glue.\nThis place gives you the creeps.\n','\n',char(10)));
INSERT INTO rooms VALUES(6131,60,'The spider web',replace('You are walking along the narrow path, ducking under the sticky ropes as you\nadvance...\n\n>\nA huge, poisonous spider drops from above!\nA huge, poisonous spider drops from above!\nA huge, poisonous spider drops from above!\n\n>\nThe huge, poisonous spider stings you!  You resist the poison!\nThe huge, poisonous spider stings you!  You are poisoned!\nThe huge, poisonous spider stings you!  You are poisoned!\n\n>\nYou''ve fallen, and you can''t get up!!!!!\n','\n',char(10)));
INSERT INTO rooms VALUES(6132,60,'Up in the tree',replace('You are hanging on the outside of a huge tree trunk covered in a sticky\nsubstance.  Directly to the west is an immense spider web suspended between\nnumerous of the giant trees including the one you are hanging on.\n','\n',char(10)));
INSERT INTO rooms VALUES(6133,60,'On the spider web',replace('You are balancing carefully on the giant sticky threads that holds the giant\nweb in place.  To the east is a giant tree trunk and to the west is an entrance\nto a cave-like structure made from many layers of spider web.\n','\n',char(10)));
INSERT INTO rooms VALUES(6134,60,'The Den of the Queen Spider',replace('You are inside a cave-like structure that seems to be made entirely from\ncountless layers of spider web.  Temperature and humidity is very high making\nit hard to breathe the foul air that lingers here.  The walls are covered with\nopen cocoons.\n','\n',char(10)));
INSERT INTO rooms VALUES(6135,60,'A dusty trail in the deep, dark forest',replace('You are on a dusty trail leading through the deep, dark forest.  Ancient grey\ntrees loom all around you.  The trail continues north and east.\n','\n',char(10)));
INSERT INTO rooms VALUES(6136,60,'A dusty trail in the deep, dark forest',replace('You are on a dusty trail leading through the deep, dark forest.  Ancient,\ngrey trees loom everywhere.  The trail continues south and west.  A broad\nirregular path leads eastwards away from the trail.\n','\n',char(10)));
INSERT INTO rooms VALUES(6137,60,'At the end of the trail through the deep, dark forest',replace('You are on a dusty trail leading through the deep, dark forest.  Ancient grey\ntrees loom all around you.  You see a dark grove north of you.\nThe only other exit is east.\n','\n',char(10)));
INSERT INTO rooms VALUES(6142,60,'Outside a cave in the deep, dark forest',replace('You are at the end of a broad, irregular path.  To the north is a very large\nominous-looking cave opening.  The trees here have many marks as if something\nwith huge claws has been tearing at them in rage.\n','\n',char(10)));
INSERT INTO rooms VALUES(6143,60,'The cave of the Green Dragon',replace('You are in a big natural cave.  The floor is littered with bones of all sorts\nand the stench is so massive that you could cut it with a knife.  The only exit\nis to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(6144,60,'A small path in the deep, dark forest',replace('You are on a narrow path leading through the deep, dark forest.  Ancient,\ngrey trees loom everywhere.  The tree trunks here seem to be covered in some\nsticky substance.  The path continues south and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(6150,60,'The narrow trail.',replace('This trail looks much spookier than any other thats you have seen.  The usual\nanimal claw marks and bites on the trees are getting far and few between. The\ntrail continues north.\n','\n',char(10)));
INSERT INTO rooms VALUES(6151,60,'The narrow trail.',replace('This area of the trail is also very peculiar.  You can see no signs of animal\nlife what so ever.  The structure of the surrounding trees forces the path to\nmake a sharp turn to the east.\n','\n',char(10)));
INSERT INTO rooms VALUES(6152,60,'The circle of trees.',replace('The trees here seem to form a circle around a HUGE tree that is in the center\nof them.  You notice a wooden door carved into the huge tree to the east.  The\ntrail that you followed to get here seems to end at the base of the tree.\n','\n',char(10)));
INSERT INTO rooms VALUES(6153,60,'Inside the great tree.',replace('You have stepped inside of this hollowed tree.  From here steps lead down into\ndarkness or you can exit the tree by going west.\n','\n',char(10)));
INSERT INTO rooms VALUES(6154,60,'The underground hallway.',replace('This hallway is apparently one of the roots of the tree hollowed out.  The hall\nleads south to a room where you hear strange noises or you can go up the steps.\n','\n',char(10)));
INSERT INTO rooms VALUES(6155,60,'The cultist temple.',replace('This temple is built to some god that you don''t worship.  It is a nice place\nto visit but you feel very uncomfortable about spending much time here.\nThe wooden altar seems almost to glow as you enter the room.  The only exit is\nthe way you came in.\n','\n',char(10)));
INSERT INTO rooms VALUES(6200,62,'On the spider web',replace('You are balancing carefully on the giant sticky threads that holds the giant\nweb in place.  To the south leads a strand to a cave-like structure made from\nmany layers of a spider web.  Another silky strand continues to the north.\n','\n',char(10)));
INSERT INTO rooms VALUES(6201,62,'On the spider web',replace('You are balancing carefully on the giant sticky threads that holds the giant\nweb in place.  To the north leads a strand to a cave-like structure made from\nmany layers of a spider web.\n','\n',char(10)));
INSERT INTO rooms VALUES(6202,62,'On the spider web',replace('You are balancing carefully on the giant sticky threads that holds the giant\nweb in place.  To the east leads a strand to a cave-like structure made from\nmany layers of a spider web.\n','\n',char(10)));
INSERT INTO rooms VALUES(6203,62,'On the spider web',replace('You are balancing carefully on the giant sticky threads that holds the giant\nweb in place. A single silky strand lead to the south, while another leads\noff into the northern direction.\n','\n',char(10)));
INSERT INTO rooms VALUES(6301,62,'Webbed Entrance',replace('Sticky, sticky, sticky!  The ground is cluttered with leaves, decayed\nremains of webbed crickets, beetle, rats, dogs (?), and even humans.\nYou begin to wonder about what lies ahead.  The air is damp here,\nand even the little light that shines through the canopy seems\nabsorbed into the webbing.\n','\n',char(10)));
INSERT INTO rooms VALUES(6302,62,'Webby Passage',replace('You find that footing here is very good, almost too good.  The\nlimbs are coated with cobwebs and seem unusually strong for tree\nbranches.  Paths lead in four directions.  The eastward path goes\ndown a bit.\n','\n',char(10)));
INSERT INTO rooms VALUES(6303,62,'Wasp Hive',replace('Drones scuttle about in this room.  The cells on the walls\nare honeycomb in shape and many of the maggots and wasps you see\nhave fang-marks on there bodies.  You sense some order in their markings.\n','\n',char(10)));
INSERT INTO rooms VALUES(6304,62,'Webby Passage',replace('Another webby passage, all sticky and wet.  Tiny ballooning\nspiders fill the air.  It seems that these young ones are newborns.\n','\n',char(10)));
INSERT INTO rooms VALUES(6305,62,'Beneath the Busy Path',replace('You hear the sounds of crawling arachnids above.  The rhythms of\nthe footsteps suggest a primitive order in there movement.  The light\nseems brighter upwards.\n','\n',char(10)));
INSERT INTO rooms VALUES(6306,62,'On the Busy Path',replace('Spiders, spiders, everywhere!  It is almost ant-like in efficiency\nwith one big difference.  The spiders here are carrying ant-corpses,\nas well as rats, wolves, and humans.\n','\n',char(10)));
INSERT INTO rooms VALUES(6307,62,'On the Busy Path',replace('Spiders, spiders, everywhere!  It is almost ant-like in efficiency\nwith one big difference.  The spiders here are carrying ant-corpses,\nas well as cats, wolves, and humans.\n','\n',char(10)));
INSERT INTO rooms VALUES(6308,62,'On the Busy Path',replace('Spiders, spiders, everywhere!  It is almost ant-like in efficiency\nwith one big difference.  The spiders here are carrying ant-corpses,\nas well as cats, dogs, and humans.\n','\n',char(10)));
INSERT INTO rooms VALUES(6309,62,'A Split in the Path',replace('As always, there is a split in the road.  One road is strewn\nwith cricket feelers.  The other is well-kept and suitable for smooth\ntravelling.  The webbing that was prevalent in earlier rooms is almost\nnon-existent now.\n','\n',char(10)));
INSERT INTO rooms VALUES(6310,62,'Fuzzy Tree Limb',replace('You are on a "fuzzy" tree limb.  Interesting, since the branches\nseem to have "hairs" sprouting from its bark.  As you look\ncloser you see millions of aphids covering each limb.\n','\n',char(10)));
INSERT INTO rooms VALUES(6311,62,'Tree Trunk',replace('You feel that you can rest here safely.  There is evidence of\nwebbing here, but it is of a finer quality.\n','\n',char(10)));
INSERT INTO rooms VALUES(6312,62,'Tree Lair Entrance',replace('It seems the inhabitant of this place does not web her\nvictims, as evidenced by the remains before you.  The area\nis cluttered with desiccated corpses, apparently bitten\nbut unwebbed, and drained of their life juices.\n','\n',char(10)));
INSERT INTO rooms VALUES(6313,62,'Wolf Spider Lair',replace('Very dark, as all lairs of spiders are.  Not much of furnishings\nsave an exit.  The wolf spider keeps no corpses here, but rather\nthrows them out at her leisure.\n','\n',char(10)));
INSERT INTO rooms VALUES(6320,62,'The Webless Path',replace('Strange.  No webbing here.  In fact, no sounds whatsoever.\nThe path continues northward, where you find that you may have to\ntightrope your way across a ravine.\n','\n',char(10)));
INSERT INTO rooms VALUES(6321,62,'Above the Ravine',replace('Stranger still.  Your feet get a real firm grip on the spiderline.\nYou are above a deep ravine.  This line connects you between two trees.\nBelow you can see a prismatic web with lots of animal bones caught in it:\nsome bear and small deer bones in fact.  No human skeletons are visible\n(yet).\n','\n',char(10)));
INSERT INTO rooms VALUES(6322,62,'The Rainbow Web',replace('This is the rainbow web--each strand, each link, a hue of violently\nsharp colors and contrasts.  The resident here seems to have a command\nof light as well.\n','\n',char(10)));
INSERT INTO rooms VALUES(6323,62,'The Web Forest',replace('The trees here take on a different appearance--they are not trees\nanymore, but disjointed make-shift silken made shafts, sticky to the touch,\nand webby in texture.  This is another world it would appear.\n','\n',char(10)));
INSERT INTO rooms VALUES(6324,62,'The Slave Pit',replace('You have entered the slave pit.  A voice blares in the distance,\n"Get back to work, maggots!"  Rails upon rails of mined gold and silver\nclutter the trail beneath you.\n','\n',char(10)));
INSERT INTO rooms VALUES(6325,62,'The Tether Path',replace('Another tether path just like the rest of them.  Surprisingly well\n-lit by the golden orbs that hang from the sides, you can see the paths\nbecome finer and finer in quality.\n','\n',char(10)));
INSERT INTO rooms VALUES(6326,62,'A Road Crossing',replace('Another shifty little strand of webs, almost ethereal in nature.\n','\n',char(10)));
INSERT INTO rooms VALUES(6327,62,'A Leader Strand',replace('This strand is weightier, more sturdy.  It shimmers as you step on\nit.  You are definitely not in the Midgaardian realms anymore.  Just\nwhere you are you can''t tell.  It feels like you''re moving through\nether.  You can still get back down to more surer lands.\n','\n',char(10)));
INSERT INTO rooms VALUES(6328,62,'The Entrance of the Ethereal Web',replace('You are at the entrance to ethereal web.  Flickering in and out,\nin and out, each strand reveals a different hue from black to green\nto blue.\n','\n',char(10)));
INSERT INTO rooms VALUES(6330,62,'The Young Wormkin''s Crib',replace('A playpen of sorts, with maggots of wasps and other baby vermin\nlying about.  You feel that humans have been played with here too,\nand eaten later.  You sense that the maker of this place has\nan appetite for dragon meat, and uses this room as a breeding\narea.\n','\n',char(10)));
INSERT INTO rooms VALUES(6331,62,'The Base of the Web',replace('Large strands connect at this point.  The node shimmers and\nflickers within the ether.  You see many flying creatures--\ninsects, pegasi, and dragon wormkins--navigate the dangerous\npassages of the web.  Exits go in many directions.\n','\n',char(10)));
INSERT INTO rooms VALUES(6332,62,'Through the Trees',replace('This part of the web intersects through the branches of some\ntrees.  Various leaves and other debris that the many drones\nhave not picked up yet lie here.\n','\n',char(10)));
INSERT INTO rooms VALUES(6333,62,'Above the Clouds',replace('You can see all of Midgaard in this ethereal web.  Many\nof the larger dragons that do wish to fly seem to fly\naway from the sticky strands of the web.\n','\n',char(10)));
INSERT INTO rooms VALUES(6334,62,'On A Cloud',replace('Rather thick in consistency.  You realize this is not\na typical cloud, but it might be the nest of an aerial creature.\n','\n',char(10)));
INSERT INTO rooms VALUES(6335,62,'A Link in the Ethereal Web',replace('This is another link in the ethereal web.  Various creatures\nseem to get caught (or hypnotized) by its sticky strands.\n','\n',char(10)));
INSERT INTO rooms VALUES(6336,62,'The Tenuous Strand',replace('Very windy here since it goes up into the sky somewhat.\nStill, it''s safe enough to move around.\n','\n',char(10)));
INSERT INTO rooms VALUES(6340,62,'The Elder Wormkin''s Room',replace('A more mature wormkin it seems resides here.  Various tomes of\narcane lore clutter the area, along with shards of armor and weaponry.\n','\n',char(10)));
INSERT INTO rooms VALUES(6341,62,'Another Tree Limb',replace('Once again the web crosses another tree limb.  To the side you\nsee the possible entrance to another creatures lair.\n','\n',char(10)));
INSERT INTO rooms VALUES(6342,62,'The Bird Spider''s Lair',replace('This is a big game hunter among most spiders.  Crush jewels\nand other weapons suggest the inhabitant must have powerful jaws.\nBeware!\n','\n',char(10)));
INSERT INTO rooms VALUES(6345,62,'A Link in the Ethereal Web',replace('This is another link in the ethereal web.  Various creatures\nseem to get caught (or hypnotized) by its sticky strands.\n','\n',char(10)));
INSERT INTO rooms VALUES(6346,62,'The Quiet Tree Top',replace('Here is a quiet tree top.\n','\n',char(10)));
INSERT INTO rooms VALUES(6347,62,'On The Web',replace('RRRRRRRRRRROOOOOOOOOOOOOAAAAAAAAAAAAAARR!  You hear the roar\nof a powerful beast.  Dragon, you think.  You shiver in your boots\nas you tiptoe on this section of the web.\n','\n',char(10)));
INSERT INTO rooms VALUES(6350,62,'The Ki-Rin Chamber',replace('A wise ki-rin was entrapped here many years ago.  It is from her\nthat the ruler of this realm steals his magical strength.\n','\n',char(10)));
INSERT INTO rooms VALUES(6355,62,'A Link in the Ethereal Web',replace('This is another link in the ethereal web.  Various creatures\nseem to get caught (or hypnotized) by its sticky strands.  To\nthe north you sense the heavy breathing of a fiery animal.\n','\n',char(10)));
INSERT INTO rooms VALUES(6360,62,'Yevaud''s Lair',replace('Yevaud, the Usurper of Midgaard, resides here.  A voice cries\nout, "BEWARE, the Usurper of Midgaard lives here!  FLEE while you can!"\nBut even Yevaud has his master...or so you deduce.\n','\n',char(10)));
INSERT INTO rooms VALUES(6365,62,'A Link in the Ethereal Web',replace('This is another link in the ethereal web.  Various creatures\nseem to get caught (or hypnotized) by its sticky strands.  A single\nspider line lies to the north, while ghastly seemings are due\nsouthward.  The grim entrance of Arachnos'' Lair is downward.\n','\n',char(10)));
INSERT INTO rooms VALUES(6366,62,'Entrance to the Donjonkeep',replace('A dark path at the end of the web strand, you see ahead\na torch lit chamber where the souls of unavenged adventurers\ncome and gnash their teeth.  The howls and screams of many echo\nthrough the hall ways.  You see one definite path ahead.\n','\n',char(10)));
INSERT INTO rooms VALUES(6367,62,'The Guardian''s Room',replace('A chair sits here for a tireless guardian who ensures that no\nsoul escapes.  The room is undecorated.\n','\n',char(10)));
INSERT INTO rooms VALUES(6368,62,'Realm of the Hopeless',replace('Here you see many misguided souls who think they still live.\nThey search for those who killed them without warrant, and seek the\nfree souls of living beings to inhabit and perhaps adventure once\nmore.\n','\n',char(10)));
INSERT INTO rooms VALUES(6369,62,'Realm of the Hopeless',replace('Here you see many misguided souls who think they still live.\nThey search for those who killed them without warrant, and seek the\nfree souls of living beings to inhabit and perhaps adventure once\nmore.\n','\n',char(10)));
INSERT INTO rooms VALUES(6370,62,'The Donjonkeep',replace('No souls have ever lived in this place.  The wails of slaves\nand the howls of wolves are the only way you can describe the sounds\nyou hear.  The walls are thin and wispy.  The only light you receive\nis the shimmering from the strand of the ethereal web you used to get\nhere.\n','\n',char(10)));
INSERT INTO rooms VALUES(6371,62,'The Single Spider Line',replace('A single spider line supports you once more.  As you look\nacross the ether you seen a single shack up ahead with a light in\nthe window.  You sense a great evil coming from the east and feel\ninclined to go back on the ethereal web and take your chances there.\n','\n',char(10)));
INSERT INTO rooms VALUES(6372,62,'The Single Spider Line',replace('A single spider line supports you once more.  The shack comes\ncloser into view and you are even more inclined to go back now.\n','\n',char(10)));
INSERT INTO rooms VALUES(6373,62,'The Hermit''s Corner',replace('Here you see evidence of a vagrant''s abode.  The shack is to the\neast, if you dare enter it.  You get the sneaking feeling you should\ngo back now.  The skies above you darken and roar with the laughter\nof thunder.\n','\n',char(10)));
INSERT INTO rooms VALUES(6380,62,'Mahatma''s Inescapable Trap',replace('Mahatma, that silly thief, is here, and he steals everything you\nhave.  He says, ''Here, have a quick trip to the Temple of Midgaard.''\nHe plunges a black dagger into your back ...\n','\n',char(10)));
INSERT INTO rooms VALUES(6390,62,'The Entrance to the Arachnos'' Lair',replace('All strands inevitably lead here, the center of the web, the\nentrance to Arachnos'' Lair.\n','\n',char(10)));
INSERT INTO rooms VALUES(6391,62,'The Sticky Chamber',replace('You can still bail out since your knees are shaking from the\nanticipation (or is it fear?).  The sky is clear on this strand of\nweb, surprisingly unsticky.  The strand does not vibrate like the\nothers.  A few ballooning spiders pass by, cackling "You''re gonna\ndie, you''re gonna fry.  Good bye!"\n','\n',char(10)));
INSERT INTO rooms VALUES(6392,62,'The Great Door',replace('Before you you see a large, web-like door.  Various designs\nof ancient runes and names of Midgaard heroes are etched into\nthe webwork.  Perhaps lists of victims?  You can''t tell.\n','\n',char(10)));
INSERT INTO rooms VALUES(6399,62,'The Lair of Arachnos',replace('This is the lair of the Empress Spider, Arachnos.  A lavishly\nadorned rainbow web, her lair allows her to move to any universe\nshe wishes by using her magical strands to the Prime Material Plane.\nCoffers upon coffers of gold, magical jewels and gems await.  Unfor-\ntunately Arachnos is a baggy spider too, and webs all her treasures\nto her beautiful silken body.\n','\n',char(10)));
INSERT INTO rooms VALUES(6500,65,'Path to Dwarven Village',replace('You are walking down a path that leads to the dwarven village.  Above you\nyou see a hill, and to the north the path continues toward\nthe mountains.\n','\n',char(10)));
INSERT INTO rooms VALUES(6501,65,'Path, base of mountain',replace('Now you are at the bottom of a rugged mountain.  The forest around you is\nvery dense, and it seems very dark to the north.\n','\n',char(10)));
INSERT INTO rooms VALUES(6502,65,'Path, middle of mountain',replace('Standing on the middle of the mountain, you can easily see the turning\npoint to the south, and the top of the mountain is very near to the north.\n','\n',char(10)));
INSERT INTO rooms VALUES(6503,65,'Top of mountain',replace('You are now on the top of the mountain.  To the south you see a path\nleading down the mountain.  To the east and west you see entrances to\nwhat seems like mines.\n','\n',char(10)));
INSERT INTO rooms VALUES(6504,65,'Narrow Path',replace('This is a narrow path leading to the Dwarven Kingdom.  It looks less\ntravelled than the others, and it is very creepy.  The path opens up\nto the south, and continues to the north.\n','\n',char(10)));
INSERT INTO rooms VALUES(6505,65,'Entrance to Mountain',replace('Here is an entrance to the mountain.  The door looks very well built,\nand you can hear noise coming from within.\n','\n',char(10)));
INSERT INTO rooms VALUES(6506,65,'Bend in Narrow Path',replace('This is a narrow path that bends to the east here.  The trees hang over\nthe path, and it is very overgrown.  The narrow path continues to the\nsouth and to the east.\n','\n',char(10)));
INSERT INTO rooms VALUES(6507,65,'Narrow path',replace('This path is very narrow, and it continues to the north and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(6508,65,'Narrow north-south path',replace('This path leads to the north and south.  To the north you can see a\ndoor, and to the south the path continues.\n','\n',char(10)));
INSERT INTO rooms VALUES(6509,65,'Door to Kingdom',replace('Here the path turns to the west.  You can see a door in front of you,\nand the path continues to the west and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(6510,65,'Path to the Castle',replace('You are on a path that will eventually lead to the castle.  It\ncontinues north to the castle, and there is a door on the western wall.\n','\n',char(10)));
INSERT INTO rooms VALUES(6511,65,'Still on the path to the Castle',replace('You are still on the path to the castle, or back to the\nDwarven village, whichever way you wish to go.  The path\ncontinues to the north and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(6512,65,'Door to Castle',replace('Here there is a door to the castle to the east.  The castle\nis elegantly designed, and looks much like a roll of toilet paper\nstanding on end.  A sign says:\n\n              ******************************************\n              *  WELCOME TO THE CASTLE OF STRANGELOVE  *\n              *      Here, celibacy is uninvited       *\n              ******************************************\n','\n',char(10)));
INSERT INTO rooms VALUES(6513,65,'Inside the entrance',replace('Everything here is covered in soot and very grimy.  The path continues\nto the east and north, and there is a door to the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(6514,65,'Path',replace('You are on a path in the dwarven village which leads north to the shops\nand south to the corner of the area.\n','\n',char(10)));
INSERT INTO rooms VALUES(6515,65,'Turn in road',replace('You are on a path that leads to a Hide & Tooth shop to the west, and the\npath continues to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(6516,65,'Hide & Tooth Shop',replace('You are in the Hide & Tooth shop.  Here you may buy the finest in Dwarven\nweapons and armors. The path continues to the north and east.\n','\n',char(10)));
INSERT INTO rooms VALUES(6517,65,'Path to the north of shop',replace('You are on a path to the north of the Hide & Tooth shop.  The path continues\nto the north, and there is Granite Head''s bakery to the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(6518,65,'North of Shops',replace('Here the path bends to the east towards the barracks. To the\nsouth you can see the shops.\n','\n',char(10)));
INSERT INTO rooms VALUES(6519,65,'Path by Hospital',replace('Here the path passes by the Hospital to the north.  It continues\nto the east to the barracks, and to the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(6520,65,'Path next to barracks',replace('Here the path continues west, and east to the barracks.\n','\n',char(10)));
INSERT INTO rooms VALUES(6521,65,'Entrance to barracks',replace('Here there is an entrance to the barracks to the south, and\nthe path continues to the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(6522,65,'Guard House',replace('You are in the guard house to the west of the entrance\nto the castle.  There are nude posters covering the walls.\n','\n',char(10)));
INSERT INTO rooms VALUES(6523,65,'First Barrack room',replace('Here is the first of two main rooms of barracks.  The\nbarracks continue to the south, and you can leave the room\nto the north.\n','\n',char(10)));
INSERT INTO rooms VALUES(6524,65,'Back of Barracks',replace('Here is the back of the dwarven barracks.  There are rows\nof beds here, and there is a stench that is unbearable.\n','\n',char(10)));
INSERT INTO rooms VALUES(6525,65,'Inside of Castle Strangelove',replace('You are just inside the castle.  It is very tubular in shape,\nand it is very featureless.  There is a set of stairs that lead\nup, and the door leads out of the castle to the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(6526,65,'A store room',replace('There is a layer of dust on the floor at least 3 inches thick!  It is\nprobable that not many people have been in here for many months.\n','\n',char(10)));
INSERT INTO rooms VALUES(6527,65,'Wine cellar',replace('This room smells like wine, and you can only assume it used to be\na wine cellar at one time.\n','\n',char(10)));
INSERT INTO rooms VALUES(6528,65,'Stairs in castle',replace('The stairs continue to circle up and down here.\n','\n',char(10)));
INSERT INTO rooms VALUES(6529,65,'Stairs',replace('You are still circling around on the stairs.  You are starting to\nget dizzy from going around and around and around and around and\naround.  The stairs continue up and down.\n','\n',char(10)));
INSERT INTO rooms VALUES(6530,65,'Top of stairs',replace('You are at the top of the stairs in the castle.  There is an exit\nto the east, and the stairs lead down.\n','\n',char(10)));
INSERT INTO rooms VALUES(6531,65,'Queen''s waiting room',replace('This is the Queen''s waiting room.  Here the men literally\n''wait'' for the queen.  You''ve heard that the queen really likes\nto get to ''know'' her people, in the biblical sense.  The queen''s\nbedroom is to the north, and you can see stairs to the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(6532,65,'Bedroom',replace('This is the Queen''s bedroom.  The bed is all ruffled, and there\nis a stack of dirty sheets piled in the corner.\n\nA note has been scrawled in lipstick on the mirror:\n\n    I''m out looking for my birth control pills.\n    Why don''t you sleep into something comfortable while you''re waiting?\n','\n',char(10)));
INSERT INTO rooms VALUES(6534,65,'Hospital',replace('You are inside the Dwarven Hospital.  It smells like rubbing\nalcohol, and there is blood all over the walls.\n','\n',char(10)));
INSERT INTO rooms VALUES(6535,65,'Granite Head''s Bakery',replace('The aroma coming from this room is sensuous.  You can almost taste\nthe pastries dissolving in your mouth.\n','\n',char(10)));
INSERT INTO rooms VALUES(6540,65,'Dark path',replace('This path is very well worn, and there is an entrance to the mines to the\neast, while the path continues to the north and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(6541,65,'Mine entrance',replace('The little path here leads down toward the mines, while the worn path\ncontinues to the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(6542,65,'Inside the mine',replace('There are holes everywhere from the places that the workers blew\naway the rock to get to whatever they were looking for.  A path leads\ndown and up.\n','\n',char(10)));
INSERT INTO rooms VALUES(6543,65,'Path in the mine',replace('You are deep inside the mine, and you feel very uncomfortable.  The\npath continues to the east, and leads to the mineshaft to the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(6544,65,'Mine crossroad',replace('You are at a crossroad in the mine.  There is a door to the north,\nand the path continues to the south, east, and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(6545,65,'Coal Room',replace('You are inside the storage area for the raw materials\nthat are found down here.  The room is very unsturdy as the\nsupports are very rickety.\n','\n',char(10)));
INSERT INTO rooms VALUES(6546,65,'Mine Maze',replace('You have entered the maze of the mines.  To the east you\ncan see some inscriptions, and you can exit to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(6547,65,'Maze inscription',replace('You are inside the maze, but not far enough in that you could get lost.\n','\n',char(10)));
INSERT INTO rooms VALUES(6548,65,'Maze',replace('You are in a maze.\n','\n',char(10)));
INSERT INTO rooms VALUES(6549,65,'Maze',replace('You are in a maze.\n','\n',char(10)));
INSERT INTO rooms VALUES(6550,65,'Maze',replace('You are in a maze.\n','\n',char(10)));
INSERT INTO rooms VALUES(6551,65,'Mining equipment room',replace('This is the storage room for equipment used by the\nDwarven miners.  It is very small, and you can tell that\nnot many miners actually use any equipment.\n','\n',char(10)));
INSERT INTO rooms VALUES(6552,65,'Solved the Maze.',replace('You have solved the maze.  You can tell by the last few moves\nthat there is no way that a dumb worker could have figured that\nout.  It seems pretty desolate here.  To the south is a bleak room.\nTo the north, you see the maze.  There is a sign above the south exit:\n\n    Those who enter, plan on a timely death.\n    Especially if you''re loyal to the queen.\n','\n',char(10)));
INSERT INTO rooms VALUES(6553,65,'The Mazekeeper''s Room',replace('You have entered the Mazekeeper''s room.  There are pictures of\nthe Queen with darts thrown in it.  Spray-painted on the wall are\nthings like ''the queen shall suffer'' and ''Catholics Rule''.\n','\n',char(10)));
INSERT INTO rooms VALUES(6554,65,'Bottom of mineshaft',replace('You are at the bottom of the mineshaft.  The air here is very sooty, and\nit is very hard to breath.  The mineshaft leads up and east.\n','\n',char(10)));
INSERT INTO rooms VALUES(6601,66,'The Dwarven Drop Off',replace('This is where the dwarven mommies and daddies come to drop off their\nannoying little brats.  You have the urge to leave.  There is a sign here.\n','\n',char(10)));
INSERT INTO rooms VALUES(6602,66,'Day Care Center',replace('You are in the north-east corner of the main part of the center.  Toys and\ntoddlers are all over the room.  There is a kitchen to the east.\n','\n',char(10)));
INSERT INTO rooms VALUES(6603,66,'Day Care Center',replace('You are in the north-west corner of the main part of the center.  Toys and\ntoddlers are all over the room.  There is a bathroom to the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(6604,66,'Day Care Center',replace('You are in the south-east corner of the main part of the center.  Toys and\ntoddlers are all over the room.  There is a playground to the east.\n','\n',char(10)));
INSERT INTO rooms VALUES(6605,66,'Day Care Center',replace('You are in the south-west corner of the main part of the center.  Toys and\ntoddlers are all over the room.  There is a staircase to the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(6606,66,'The Messy Bathroom',replace('You hold your nose as you realize you have made the worst mistake of your\nlife.  The air is rancid and the walls are stained.\n','\n',char(10)));
INSERT INTO rooms VALUES(6607,66,'The Staircase',replace('You stand on top of a staircase leading down, and wonder what mystery could\nlie down under.  Beware!\n','\n',char(10)));
INSERT INTO rooms VALUES(6608,66,'The Playground',replace('You are in the north-west corner of the playground.\n','\n',char(10)));
INSERT INTO rooms VALUES(6609,66,'The Playground',replace('You are in the north-east corner of the playground.\n','\n',char(10)));
INSERT INTO rooms VALUES(6610,66,'The Playground',replace('You are in the south-west corner of the playground.\n','\n',char(10)));
INSERT INTO rooms VALUES(6611,66,'The Playground',replace('You are in the south-east corner of the playground.\n','\n',char(10)));
INSERT INTO rooms VALUES(6612,66,'Entrance to the Mini-Maze',replace('You stand in the entrance to a small, but confusing maze.  You really hope\nthat you don''t get lost.\n','\n',char(10)));
INSERT INTO rooms VALUES(6613,66,'Mini-Maze',replace('You are in a small passage that looks just like every other one.\n','\n',char(10)));
INSERT INTO rooms VALUES(6614,66,'Mini-Maze',replace('You are in a small passage that looks just like every other one.\n','\n',char(10)));
INSERT INTO rooms VALUES(6615,66,'Mini-Maze',replace('You are in a small passage that looks just like every other one.\n','\n',char(10)));
INSERT INTO rooms VALUES(6616,66,'Mini-Maze',replace('You are in a small passage that looks just like every other one.\n','\n',char(10)));
INSERT INTO rooms VALUES(6624,66,'End of the Mini-Maze',replace('You stand at the end of your journey.  There is a big sign here and you had\nbetter read it!\n','\n',char(10)));
INSERT INTO rooms VALUES(6626,66,'Messy Kitchen',replace('You stand in the kitchen and eating area of the day care center.  Pots and\npans are everywhere, while the toddlers continue to create chaos.\n','\n',char(10)));
INSERT INTO rooms VALUES(6631,66,'The End?',replace('You have reached the final lair.  It is dominated by a huge five headed\ndragon (actually an overgrown brat with a Halloween mask).\n','\n',char(10)));
INSERT INTO rooms VALUES(7001,70,'The muddy sewer',replace('You are standing in mud to your knees. This is not the kind of place\nfor a picnic. The muddy sewer stretches further into the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(7002,70,'The muddy sewer junction',replace('The muddy sewer stretches into the dark to the south. It looks as if \nno person has ever sat his foot here before. It''s too muddy for that\nanyway. The sewer leads north, south and east from here.\n','\n',char(10)));
INSERT INTO rooms VALUES(7003,70,'The mudhole',replace('You stand in mud all the way up to your thighs and it''s not too \ncomfortable since you are used to a somewhat different environment.\nThe sewer leads to the north of here. In the middle you can just make\nout an enormous drainpipe leading down.\n','\n',char(10)));
INSERT INTO rooms VALUES(7004,70,'The Dark Pit',replace('You are standing by the edge of a dark pit that leads down into even\ndeeper darkness. >BWWAAADDRR< - The smell from down there is unbearable.\nThe sewer stretches into the darkness to the east.\n','\n',char(10)));
INSERT INTO rooms VALUES(7005,70,'The muddy sewer',replace('You are standing in the middle of a bend of the sewer pipe. It is very\ndark around here and the mud is sticking to your legs, not very pleasant.\nThe pipe leads east and south from here.\n','\n',char(10)));
INSERT INTO rooms VALUES(7006,70,'The muddy sewer',replace('You are standing in something that reminds you very much of porridge, this\nhas the advantage that it''s not hot, it''s rather cold actually. The pipe \nbends to the north and east.\n','\n',char(10)));
INSERT INTO rooms VALUES(7007,70,'The muddy sewer bend',replace('This isn''t your idea of a place to stay too long. You''re in up to your\nknees in something that resembles mud, but you''re not quite sure. The\nbend in which you stand leads west and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(7008,70,'A muddy intersection',replace('You have both your feet safely stuck in mud. It isn''t the mud that''s wrong\nit''s the smell, the sounds, the total darkness that surrounds you. Everything\nhere is so depressing. The pipe leads on with a trail of thick mud to the\nnorth, east and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(7009,70,'The Sewer Junction',replace('You stand in the middle of a huge junction of sewer pipes right under\nwhat you''d think was an air shaft. The sewer pipes lead to the north,\nsouth, east and west. It look quite impossible to force your way up.\n','\n',char(10)));
INSERT INTO rooms VALUES(7010,70,'A bend in sewer pipe',replace('You are in a bend in the sewer pipe. A strong smell seeps in from the north.\nThe sewer goes north and east.\n','\n',char(10)));
INSERT INTO rooms VALUES(7011,70,'The muddy sewer pipe',replace('You have entered a kind of tube intersection that leads south, west and east.\nYour legs are covered in mud up to the knees. REAL yucky! \n','\n',char(10)));
INSERT INTO rooms VALUES(7012,70,'The bend in the Muddy sewer',replace('This is not your idea of a holiday. You stand in mud up to your knees.\nIt''s absolutely inconceivable how all this mud could have been placed\nhere. The pipe leads to the west and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(7013,70,'A MUDDY intersection',replace('You wouldn''t want to know the true feeling of standing in this mud up to \nyour hips. >BWAADR<. All that fills your mind right now is the dream of \na hot bath. This is NOT very clean mud you know, remember you''re in the\nsewer! The pipes leads north, south and east.\n','\n',char(10)));
INSERT INTO rooms VALUES(7014,70,'Muddy sewer',replace('You stand in a bend of the pipe system of the sewer with mud up to your\nthighs. Contemplating a higher level of existence here would be utterly\ninappropriate, as the smell would keep any intelligent creature from even\nthinking of anything but getting away from this foul end of the WORLD.\nThe bend goes from north to west.\n','\n',char(10)));
INSERT INTO rooms VALUES(7015,70,'The old well',replace('You are standing by an old and worn well from before this century. The sewer\nleads to the east from here and the well leads down into darkness. Metal\nbars implanted in the side of the well lead down as a ladder.\n','\n',char(10)));
INSERT INTO rooms VALUES(7016,70,'The ordinary bend',replace('You are in the middle of a bend in the pipe system of the sewer system, \nWHAT a place!!! The pipe leads to the south and the east.\n','\n',char(10)));
INSERT INTO rooms VALUES(7017,70,'The sewer junction',replace('You are in a junction that leads north, west and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(7018,70,'The ordinary junction',replace('This looks like an ordinary junction, actually it seems very quiet\nhere. The pipelines lead west, east and north.\n','\n',char(10)));
INSERT INTO rooms VALUES(7021,70,'A quiet pipe junction',replace('This is the kind of place to rest, though the smell could be a LOT better\nthan this. The sewer goes east, north and west from here.\n','\n',char(10)));
INSERT INTO rooms VALUES(7022,70,'The odd room with smooth walls',replace('As you enter you hear a loud click from one of the walls ... and you fall\nand fall and fall ...\n.\n.\n.\n.\n ... And come to an abrupt end. THIS is strange indeed. There''s an arched\nentryway leading down.\n','\n',char(10)));
INSERT INTO rooms VALUES(7024,70,'The sewer',replace('You are standing in mud up to your ankles. This is an intersection with \nsewer pipes leading east, south and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(7025,70,'Another intersection',replace('You have never seen anything so BORING...This is an intersection with pipes\nleading north, south and east.\n','\n',char(10)));
INSERT INTO rooms VALUES(7026,70,'A junction',replace('This one seems interesting, a big difference from all the other junctions.\nIt seems cleaner than the rest of them. Weird. Something that looks like \nan air shaft leads upwards, but it looks far too slippery to climb.\nThe pipes lead to the south, west and north.\n','\n',char(10)));
INSERT INTO rooms VALUES(7028,70,'The sewer junction',replace('You stand in a junction of sewer pipes leading north, east and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(7029,70,'The Triple Junction',replace('You stand in the middle of a huge junction of concrete sewer pipes. The \npipes lead into three different directions : east, south and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(7030,70,'The Quadruple Junction Under the Dump',replace('You are standing in something that reminds you of an entry to an ant hive.\nThere are enormous concrete pipes leading north, south, east and west. \nThere''s also a metal ladder built into the concrete wall leading up through\na layer of garbage. \n','\n',char(10)));
INSERT INTO rooms VALUES(7031,70,'A triple junction',replace('You stand in a junction with pipes leading west, north and east.\n','\n',char(10)));
INSERT INTO rooms VALUES(7034,70,'A bend in the sewer pipe',replace('You can look in two directions where the pipe leads : south and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(7035,70,'The sewer pipe bend',replace('You can look in two different directions where the pipe goes : west and \nnorth.\n','\n',char(10)));
INSERT INTO rooms VALUES(7036,70,'The pit',replace('You stand in a section of a pipe that leads to a dead end. In the floor\nthere''s a pit leading down. There are bars set in the side of the pit wall\nfunctioning as a ladder.\n','\n',char(10)));
INSERT INTO rooms VALUES(7037,70,'The round room',replace('As you enter the room it starts rotating - at first slowly, later faster\nand faster - You get totally confused as to where up and down is, but you are\ncertain that the doorway is in the opposite direction of what it was when\nyou entered. It now leads east. There was only this one exit.\n','\n',char(10)));
INSERT INTO rooms VALUES(7038,70,'The three way junction',replace('You are standing in a junction of pipes that lead west, east and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(7039,70,'The Sewer Store Room',replace('You stand in a small room lit by a single torch set in the wall. The only \nway out of here is to the north.\n','\n',char(10)));
INSERT INTO rooms VALUES(7041,70,'The Shaft',replace('You are standing by the edge of a deep, dark shaft leading down. A single\nladder is your tool to work your way down if you so wish. The sewer pipe\nleads south from here.\n','\n',char(10)));
INSERT INTO rooms VALUES(7043,70,'The Sewer Entrance',replace('You stand in the middle of a pipe that leads from north to south. Above you\nan air shaft leads up into sunlight. It seems totally impossible to go up\nthat way.\n','\n',char(10)));
INSERT INTO rooms VALUES(7044,70,'The junction going three ways',replace('You are in a passageway in the pipes of the sewer system leading north, east\nand west.\n','\n',char(10)));
INSERT INTO rooms VALUES(7045,70,'The Sewer Room',replace('You are standing in a large room with chairs set in the walls. You have the\nfeeling of being watched. To the south there''s an entry to a larger room.\nThe room is lit by five torches, also set in the walls. To the west there\nis a doorway leading out to the sewers.\n','\n',char(10)));
INSERT INTO rooms VALUES(7046,70,'The Sewer room',replace('This is a Room with walls that glitters like gold though not quite like it.\nThis is strange as it looks as if the glitter lights the whole room. It\nlooks very bright. To the south the floor is covered with yucky water. The\nNorth leads to sort of a Guard Room.\n','\n',char(10)));
INSERT INTO rooms VALUES(7047,70,'The Pool in the Sewer',replace('You stand in water to your waist.  To the north is the entrance to this room.\nA single door leads east.\n','\n',char(10)));
INSERT INTO rooms VALUES(7048,70,'The Sewers',replace('You stand in a dead end of the sewer. The only way out is south.\nYou can see a shaft leading up but it looks too difficult to go up\nthat way.\n','\n',char(10)));
INSERT INTO rooms VALUES(7049,70,'The junction',replace('You stand in a junction leading north, west and east.\n','\n',char(10)));
INSERT INTO rooms VALUES(7050,70,'The small room',replace('The only thing in this room of interest is a chair, and that''s tight to the \nrock floor. A doorway leads south and another leads east into darkness.\n','\n',char(10)));
INSERT INTO rooms VALUES(7051,70,'The Sewer pipe',replace('You are in what reminds you of a foul sewer, as if you liked being here! \nYou can see two exits leading either north or south.\n','\n',char(10)));
INSERT INTO rooms VALUES(7052,70,'The Grand Sewer',replace('You are in a Grand Sewer Pipe. This stretches toward the south. It''s large \nindeed! A doorway leads to the east from here.\n','\n',char(10)));
INSERT INTO rooms VALUES(7053,70,'The South end of the Grand Pipe',replace('You stand in water to your knees. A doorway leads west from here. The Pipe\nstretches north.\n','\n',char(10)));
INSERT INTO rooms VALUES(7055,70,'The Edge of The Water Sewer',replace('You stand in a room where half of the floor is covered in water. The water\nleads east and a doorway leads west.\n','\n',char(10)));
INSERT INTO rooms VALUES(7056,70,'The Dark hallway',replace('You can''t see much of this, even with a light. The hallway goes into a\npassageway to the south. A doorway leads west.\n','\n',char(10)));
INSERT INTO rooms VALUES(7057,70,'The dark passageway',replace('You can''t see anything but the ground where you put your feet. The \npassageway seems to continue south and north.\n','\n',char(10)));
INSERT INTO rooms VALUES(7058,70,'The dark passageway',replace('You can''t see anything but the ground where you put your feet. The\npassageway seems to continue south and north.\n','\n',char(10)));
INSERT INTO rooms VALUES(7059,70,'The dark passageway',replace('You can''t see anything but the ground where you put your feet. The\npassageway seems to continue south and north.\n','\n',char(10)));
INSERT INTO rooms VALUES(7060,70,'The dark passageway',replace('You can''t see anything but the ground where you put your feet. The\npassageway seems to continue west and north. To the east there''s water\ncovering the floor and that leads through an arched entry to a watery\nsewer.\n','\n',char(10)));
INSERT INTO rooms VALUES(7061,70,'The Watery Sewer Bend',replace('You can''t see anything but the water you''re in up to your hips. The sewer\nseems to bend and lead south and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(7062,70,'The Watery sewer',replace('You can''t see anything but the water you''re in up to your hips. The sewer\nseems to lead south and north.\n','\n',char(10)));
INSERT INTO rooms VALUES(7063,70,'The Watery sewer',replace('You can''t see anything but the water you''re in up to your hips. The sewer\nseems to lead south and north.\n','\n',char(10)));
INSERT INTO rooms VALUES(7064,70,'The Watery Sewer Junction',replace('You can''t see anything but the water you''re in up to your hips. The sewer\nseems to lead into a junction going south, north and east.\n','\n',char(10)));
INSERT INTO rooms VALUES(7065,70,'The Watery sewer',replace('You can''t see anything but the water you''re in up to your hips. The sewer\nseems to lead south and north.\n','\n',char(10)));
INSERT INTO rooms VALUES(7066,70,'The Watery sewer junction',replace('You can''t see anything but the water you''re in up to your hips. The sewer\nseems to lead into a junction that goes north, south and east.\n','\n',char(10)));
INSERT INTO rooms VALUES(7067,70,'The Watery sewer',replace('You can''t see anything but the water you''re in up to your hips. The sewer\nseems to lead south and north.\n','\n',char(10)));
INSERT INTO rooms VALUES(7068,70,'The Watery sewer bend',replace('You can''t see anything but the water you''re in up to your hips. The sewer\nseems to bend and lead west and north.\n','\n',char(10)));
INSERT INTO rooms VALUES(7069,70,'A ledge by the dark pool',replace('You can''t see much here but the echo tells you that there''s quite a drop\ndown. You can just make out a huge dark pool out there in the darkness, \nmostly because of the trickling of water. The water from the sewer actually\nwashes over this ledge and makes it quite slippery. From here it drops, \nlike a waterfall, into the pool far down.\n','\n',char(10)));
INSERT INTO rooms VALUES(7070,70,'A ledge by the dark pool',replace('You can''t see much here but the echo tells you that there''s quite a drop\ndown. You can just make out a huge dark pool out there in the darkness,\nmostly because of the trickling of water. The water from the sewer actually\nwashes over this ledge and makes it quite slippery. From here it drops,\nlike a waterfall, into the pool far down. Under you there is a small fissure\nin the rock. It seems big enough to contain a few people.\n','\n',char(10)));
INSERT INTO rooms VALUES(7099,70,'The fissure under the ledge',replace('This is a small fissure in the solid rock. Under you lies the deep dark pool.\nThe water trickles quietly down from the ledge above you. The water smells \nlike the water in a sewer.\n','\n',char(10)));
INSERT INTO rooms VALUES(7101,70,'Under the mudhole',replace('You stand in a small room with a great big opening in the ceiling. From this\nopening there''s mud dripping down in large lumps. >YUCK<. You can smell the \nfoul stench of the slimy sediment as you try not to get covered by the \nfalling sludge. To the east there is an entryway leading out from here and \nit seems absolutely impossible to force the muddy decent.\n','\n',char(10)));
INSERT INTO rooms VALUES(7102,70,'Under the Dark Pit',replace('Nice place you found yourself. You stand in the middle of a room with only\ntwo exits, Up and East. A tall ladder is left here so that you can climb\nup through the Pit without the use of a rope.\n','\n',char(10)));
INSERT INTO rooms VALUES(7103,70,'A muddy bend in the sewer system',replace('You are standing in what looks like a bend in the pipe system of the\nsewer. The ''floor'' is covered completely by mud! This includes covering\nyour legs up to your knees as well. The pipe leads west and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(7104,70,'A junction in the sewer pipes',replace('You stand in the middle of what looks like a triple junction of pipes\ngoing east, west and north.\n','\n',char(10)));
INSERT INTO rooms VALUES(7105,70,'Down the old well',replace('You are dangling on the slippery sides of the old well leading down and up.\nThe only secure point here is the metal bars that are cemented into the \nsides, the ones that you cling frantically to so that you don''t fall. Who\nknows how deep this well is?\n','\n',char(10)));
INSERT INTO rooms VALUES(7106,70,'The northwestern corner of the ledge',replace('You stand, swaying out from the ledge, with only a couple of inches of safe, \nsolid ledge under your feet. The ledge continues to the east but not back\nsouth. It seems that the ledge is too narrow to turn on so you''ll have to\ncontinue forward.\n','\n',char(10)));
INSERT INTO rooms VALUES(7107,70,'The narrow ledge',replace('You are in the progress of walking all the way around the ledge since there''s\nno way of turning around on this all too narrow path. There IS another exit\nfrom here but that leads right into mid-air and with high probability of a\nfree fall session afterwards.\n','\n',char(10)));
INSERT INTO rooms VALUES(7108,70,'The narrow ledge',replace('You are in the progress of walking all the way around the ledge since there''s\nno way of turning around on this all too narrow path. There IS another exit\nfrom here but that leads right into mid-air and with high probability of a\nfree fall session afterwards.\n','\n',char(10)));
INSERT INTO rooms VALUES(7109,70,'The narrow ledge',replace('You are in the progress of walking all the way around the ledge since there''s\nno way of turning around on this all too narrow path. There IS another exit\nfrom here but that leads right into mid-air and with high probability of a\nfree fall session afterwards.\n','\n',char(10)));
INSERT INTO rooms VALUES(7110,70,'The narrow ledge',replace('You are in the progress of walking all the way around the ledge since there''s\nno way of turning around on this all too narrow path. There IS another exit\nfrom here but that leads right into mid-air and with high probability of a\nfree fall session afterwards.\n','\n',char(10)));
INSERT INTO rooms VALUES(7111,70,'The southwestern corner of the ledge',replace('This seems like a ledge that is a little broader than the one just to the \nnorth of here. The ledge seems to lead around some sort of Abyss of total \ndarkness. The ledge seems to have an odd-looking edge here.\n','\n',char(10)));
INSERT INTO rooms VALUES(7112,70,'An odd intersection',replace('You stand in a rather odd intersection of pipes. The pipes actually don''t\nresemble pipes anymore. They look more like a real stone tunnel, or a\npassageway hewn directly into the rock. The ways from here lead north, east\nand west.\n','\n',char(10)));
INSERT INTO rooms VALUES(7113,70,'The narrow ledge going east to west',replace('You are in the process of walking all the way around the ledge since there''s\nno way of turning around on this all too narrow path. There IS another exit\nfrom here but that leads right into mid-air and with high probability of a\nfree fall session afterwards.\n','\n',char(10)));
INSERT INTO rooms VALUES(7114,70,'Mid-air',replace('You''ve just stepped into the most unlucky position in the whole of Merc Mud.\nThe result of such a foolish act should be punished with death, you know.\nWith an acceleration of approximately 9.82 metres per second per second, you\nare now descending the Abyss. What awaits you at the bottom will continue to\nbe a mystery. Bye Cruel World.\n\nYou''ve fallen, and you can''t get up!!!\n','\n',char(10)));
INSERT INTO rooms VALUES(7115,70,'The Broad ledge',replace('You are standing on a ledge that seems quite a lot larger than the rest \nof the ledges. This one leads to the west and the east, plus it has an exit\ngoing to the south. Though you could jump into mid-air, but it probably \nwouldn''t be such a good idea. The way south is in utter darkness.\n','\n',char(10)));
INSERT INTO rooms VALUES(7116,70,'The northeastern corner of the ledge',replace('You stand, swaying out from the ledge, with only a couple of inches of safe,\nsolid ledge under your feet. The ledge continues to the west and leads south\nfrom here into darkness.\n','\n',char(10)));
INSERT INTO rooms VALUES(7117,70,'The narrow eastern ledge',replace('You are in the progress of walking all the way around the ledge since there''s\nno way of turning around on this all too narrow path. There IS another exit\nfrom here but that leads right into mid-air and with high probability of a\nfree fall session afterwards. And THAT is west of here so watch your step.\n','\n',char(10)));
INSERT INTO rooms VALUES(7118,70,'The narrow eastern ledge',replace('You are in the progress of walking all the way around the ledge since there''s\nno way of turning around on this all too narrow path. There IS another exit\nfrom here but that leads right into mid-air and with high probability of a\nfree fall session afterwards. And THAT is west of here so watch your step.\n','\n',char(10)));
INSERT INTO rooms VALUES(7119,70,'The narrow eastern ledge',replace('You are in the progress of walking all the way around the ledge since there''s\nno way of turning around on this all too narrow path. There IS another exit\nfrom here but that leads right into mid-air and with high probability of a\nfree fall session afterwards. And THAT is west of here so watch your step.\n','\n',char(10)));
INSERT INTO rooms VALUES(7120,70,'The narrow eastern ledge',replace('You are in the progress of walking all the way around the ledge since there''s\nno way of turning around on this all too narrow path. There IS another exit\nfrom here but that leads right into mid-air and with high probability of a\nfree fall session afterwards. And THAT is west of here so watch your step.\nYou also see a small opening to the east.\n','\n',char(10)));
INSERT INTO rooms VALUES(7121,70,'The southeastern corner of the ledge',replace('This seems like a ledge that is a little broader than the one just to the\nnorth of here. The ledge seems to lead around some sort of abyss of total\ndarkness.\n','\n',char(10)));
INSERT INTO rooms VALUES(7122,70,'Under the pit',replace('You stand in a completely dark cavern leading west. The wall looks weird here.\n','\n',char(10)));
INSERT INTO rooms VALUES(7123,70,'Under The Shaft',replace('A ladder leads up from here to the Shaft.\nA small opening leads west from here.\n','\n',char(10)));
INSERT INTO rooms VALUES(7129,70,'The sewer line.',replace('You are in a narrow part of the sewer. Down the sewer continues and to the\nnorth is the ledge.\n','\n',char(10)));
INSERT INTO rooms VALUES(7130,70,'The sewer pipe.',replace('You are in an odd sewer pipe You see some odd scratches on the pipe wall, as\nfrom a gigantic rat. You can see some slimy water gently running down into\na sewer drain, and north the drain continues.\n','\n',char(10)));
INSERT INTO rooms VALUES(7190,70,'Mid-air',replace('You''ve just stepped into the most unlucky position in the whole of DikuMUD.\nThe result of such a foolish act should be punished with death, you know.\nWith an acceleration of approximately 9.82 metres per second per second, you\nare now descending the Abyss. What awaits you at the bottom will continue to\nbe a mystery. Bye Cruel World.\n\nYou''ve fallen, and you can''t get up!!!\n','\n',char(10)));
INSERT INTO rooms VALUES(7199,70,'The Edge of the Water',replace('The pool side is dimly lit up by your light. You can see absolutely nothing\nelse nearby. The darkness her seems enormously oppressive here. The air is\ndamp and the rock on which you stand is slippery. The pool seems too dark \nto make anything clear. The rock can be climbed upwards from here.\n','\n',char(10)));
INSERT INTO rooms VALUES(7200,70,'The Treasury',replace('You are in a small but well equipped treasury.  You can see some writing on\nthe wall.  The ceiling has a funny glow, which enables you to see.  You can\nget back into the inner lair through the stone door which is east.\n','\n',char(10)));
INSERT INTO rooms VALUES(7201,70,'The inner Lair',replace('You are in a octagonal room with smooth purple stone walls.  The floor is \nmade from black stone.  In the western wall you see a large black stone door.\n','\n',char(10)));
INSERT INTO rooms VALUES(7202,70,'The Lair',replace('On the floor you see a lot of human decay, like bones and skulls. You also\nsee a lot of slime. On the wall is a torch sitting in its sconce. To the north \nare a wooden door.\n','\n',char(10)));
INSERT INTO rooms VALUES(7203,70,'The Lair',replace('On the floor you see a lot of human decay, like bones and skulls. You also\nsee a lot of slime. On the wall is a torch sitting in its sconce.\n','\n',char(10)));
INSERT INTO rooms VALUES(7204,70,'The Lair',replace('On the floor you see a lot of human decay, like bones and skulls. You also\nsee a lot of slime. On the wall is a torch sitting in its sconce.\n','\n',char(10)));
INSERT INTO rooms VALUES(7205,70,'The Lair',replace('On the floor you see a lot of human decay, like bones and skulls. You also\nsee a lot of slime. On the wall is a torch sitting in its sconce.\n','\n',char(10)));
INSERT INTO rooms VALUES(7206,70,'The lair.',replace('On the floor you see a lot of human decay, like bones and skulls. You also\nsee a lot of slime. On the wall is a torch sitting in its sconce.\n','\n',char(10)));
INSERT INTO rooms VALUES(7207,70,'The lair.',replace('On the floor you see a lot of human decay, like bones and skulls. You also\nsee a lot of slime. On the wall is a torch sitting in its sconce.\n','\n',char(10)));
INSERT INTO rooms VALUES(7208,70,'The lair entrance.',replace('You are in a dry part of the sewer. To the north is a wooden door, you \ncan see some slime at the lower part of the door. You also see some skulls\nand some broken bones.\n','\n',char(10)));
INSERT INTO rooms VALUES(7209,70,'The crawlway.',replace('You are in a narrow crawlway.  You don''t notice anything interesting here.\n','\n',char(10)));
INSERT INTO rooms VALUES(7210,70,'The four-way junction.',replace('You are in a sewer junction. To the north is a small hole, to the west is a\nnarrow crawlway and to the east and south the sewer continues.\n','\n',char(10)));
INSERT INTO rooms VALUES(7211,70,'The small cave.',replace('You are in a collapsed sewer drain, which now is more like a small cave.\n','\n',char(10)));
INSERT INTO rooms VALUES(7212,70,'The sewer drain.',replace('You are in a dry sewer drain which bends to the north.\n','\n',char(10)));
INSERT INTO rooms VALUES(7213,70,'The sewer drain.',replace('You are in a dry sewer drain which bends to the east.\n','\n',char(10)));
INSERT INTO rooms VALUES(7214,70,'The drain end.',replace('You are at the end of the drain around you the sewer has collapsed, the only\nexit is west.\n','\n',char(10)));
INSERT INTO rooms VALUES(7215,70,'The half-wet drain.',replace('You are in a sewer drain where the floor is covered with water. To the north\nit looks more dry, south however the drain runs down into some water.\n','\n',char(10)));
INSERT INTO rooms VALUES(7216,70,'Under water in the sewer.',replace('You swim in some dirty water and is holding you breath. You''ll better \ncontinue before you drown. It is a good thing that you can hold your light\nabove water-level.\n','\n',char(10)));
INSERT INTO rooms VALUES(7217,70,'The half-dry drain.',replace('You are in a half-dry sewer drain. To the north the drain runs a little bit\ndownwards into some water to the east you can see a small hole. To the west\nyou see another drain.\n','\n',char(10)));
INSERT INTO rooms VALUES(7218,70,'The very small room.',replace('You are in a very small room, it is pretty uninteresting.\n','\n',char(10)));
INSERT INTO rooms VALUES(7219,70,'A dry sewer drain.',replace('You are in a dry but dirty sewer drain. The drain continues east and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(7220,70,'A boring drain.',replace('You are in yet another sewer drain.\n','\n',char(10)));
INSERT INTO rooms VALUES(7221,70,'The sewer drain.',replace('You are in a sewer drain, there is nothing special inhere, except for a \nloud echo.\n','\n',char(10)));
INSERT INTO rooms VALUES(7222,70,'The sewer drain.',replace('You are in a drain, with some slimy water on the floor.\n','\n',char(10)));
INSERT INTO rooms VALUES(7223,70,'The sewer bend.',replace('You find yourself in an ordinary sewer bend, which bend from west to north.\n','\n',char(10)));
INSERT INTO rooms VALUES(7224,70,'The sewer junction',replace('You stand in a junction of three sewer drains. You see some odd scratches on\nthe pipe wall, as from a gigantic rat.North and south the sewer continues \nas usual, but west it looks a little strange.\n','\n',char(10)));
INSERT INTO rooms VALUES(7225,70,'The sewer',replace('You are in a sewer, where the slimy water runs down through a tiny hole.\nYou see some odd scratches on the pipe wall, as from a gigantic rat. There \nis a sewer drain south.\n','\n',char(10)));
INSERT INTO rooms VALUES(7229,70,'The strange sewer',replace('You are in a very strange sewer indeed, there are some odd scratches on the\npipe wall, as from a gigantic rat. And you can see a lot of organic decay\nlike bones from animals AND humans. West the drain runs slightly upwards.\n','\n',char(10)));
INSERT INTO rooms VALUES(7230,70,'The damp sewer',replace('You are in a sewer drain with a funny damp substance on the floor, in the \nsubstance you see a lot of decay. You see some odd scratches on the wall, as\nfrom a gigantic rat. Both to the east and west the pipe seems to run down.\n','\n',char(10)));
INSERT INTO rooms VALUES(7231,70,'The strange sewer',replace('You are in an ordinary sewer except for a lot of scratches on the sewer wall,\nad a lot of debris on the floor.\n','\n',char(10)));
INSERT INTO rooms VALUES(7232,70,'The sewer',replace('You are in a sewer with more scratches on the walls. And of course a whole lot\nof decay. The drain runs east and north.\n','\n',char(10)));
INSERT INTO rooms VALUES(7233,70,'The sewer drain',replace('You stand in in a sewer drain, you are able to see some kind of cave-like\nroom. You see some odd scratches on the drain wall, as from a gigantic rat. \nThe sewer leads south.\n','\n',char(10)));
INSERT INTO rooms VALUES(7234,70,'The rat''s lair',replace('You are in a little cave. You are able to see quite a lot of debris on the \nfloor. There is a sewer drain west of here.\n','\n',char(10)));
INSERT INTO rooms VALUES(7279,70,'The Wall of the Abyss',replace('You hang onto some steps leading down into utter darkness. There''s an exit \nleading up as well, though you''ll have to open the tiny rock again to do so.\n','\n',char(10)));
INSERT INTO rooms VALUES(7280,70,'The entrance.',replace('You are in a very dark room. You notice that some faces are\nstaring at you from inside the walls. In the middle of the room\nthere is a small altar. To the north there is a small round\ndoor.\n','\n',char(10)));
INSERT INTO rooms VALUES(7281,70,'The corridor.',replace('The corridor is glowing oppressively in a red hue. You can hear wailing\nthrough an open black hole to the east. To the south there is a round door.\n','\n',char(10)));
INSERT INTO rooms VALUES(7282,70,'The Realm of lost souls',replace('You are standing in nothing. All around you there are stars.\nSometimes a shadow flies closely by you, wailing very loudly. \nTo the north there is a small bright hole. To the west there is \na small red hole.\n','\n',char(10)));
INSERT INTO rooms VALUES(7283,70,'The T-crossing',replace('You are in a small hallway. There are doors to the east and to\nthe west. To the south there are a black hole. There is writing\nin the wall. Wails can be heard from the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(7284,70,'The firedeath',replace('This room is very hot. There are flames surrounding you.  You can\nsee no exits at all!  Skeletons are lying all over the floor.\n','\n',char(10)));
INSERT INTO rooms VALUES(7285,70,'The tortureroom.',replace('You are standing in a middle of a square room. Along the walls skeletons \nare hanging in rusty chains. In the middle of the room there is a big metal \nbox, covered with dust. To the south you can just make out a small exit.\n','\n',char(10)));
INSERT INTO rooms VALUES(7286,70,'The hells yard',replace('You are standing in a lot of mud. A disgusting smell surrounds\nthe place, and makes you fell sick. Small flames sometimes shoot\nup from the hot mud. To the west there is a small door. To the \nnorth you can see an iron door.\n','\n',char(10)));
INSERT INTO rooms VALUES(7301,70,'The Entrance to the Realm of silence',replace('This is an utterly silent place. As you look around you see that there\nhasn''t been a living thing in a long time. The dust lies here in a thick\nlayer on the floor and on the furniture. On the wall hangs a bleak and \nworn tapestry. A winding stone staircase leads up into darkness. On the \nwall to the west you can see a huge torch stuck into the solid rock.\nA large portcullis blocks your way to the north.\n','\n',char(10)));
INSERT INTO rooms VALUES(7399,70,'On the walls of the Abyss',replace('You are clutching the steps on the wall so that you don''t fall to the ground\ndown below.\nA large sign says : I haven''t gotten any further ... Yet. But  I''m pushing\n                    to get finished with this sewer. \n                                           Greetings and Good Health :)\n\n                                                     Redferne The Gentle\nThis stops your journey down, the only exit is up.\n','\n',char(10)));
INSERT INTO rooms VALUES(7400,70,'Cave entrance',replace('You are standing in the cave entrance. It is very dark\ndown here. There is writing at the wall. There is an exit\nto the north. A stairway leads up.\n','\n',char(10)));
INSERT INTO rooms VALUES(7401,70,'Cave tunnel',replace('You are walking in a tunnel. It is very cold. You\ncan feel the presence of a living thing ... SOMEWHERE.\n','\n',char(10)));
INSERT INTO rooms VALUES(7402,70,'Cave room',replace('You are standing in a room. It''s much cooler now.\nThe walls are glowing.\n','\n',char(10)));
INSERT INTO rooms VALUES(7403,70,'Cave T-cross',replace('You are standing in a mud-like substance. The smell here is\nawful, it is rotten. To the west you can see some light.\n','\n',char(10)));
INSERT INTO rooms VALUES(7404,70,'Cave turning-point',replace('The mud are getting deeper. You are wondering, ''Would\nit be an idea to leave, before I disappear?''. To the\nsouth you notice a flat round stone are blocking the\nway. To the west you can see mud.\n','\n',char(10)));
INSERT INTO rooms VALUES(7405,70,'The secret room',replace('There is dust all over the place. It looks like nobody\nhas been here for ages. In the middle of the room you see\na socket with a crystal globe. The globe glows with a\npulsing light. To the north you see a stone door. To the\nsouth you see a grey block.\n','\n',char(10)));
INSERT INTO rooms VALUES(7406,70,'The mudhole',replace('You are standing in a lot of mud. The mud goes to your\nchest. You feel the presence of something IN the mud.\nThe only obvious exit is to the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(7407,70,'Tunnel',replace('The mud goes to your knees. Otherwise the tunnel looks\nvery normal.\n','\n',char(10)));
INSERT INTO rooms VALUES(7408,70,'The long tunnel',replace('Here There is almost no mud, as you stand at the top\nof a small rock. Just beside you there are a sign which\nsays ''WARNING! The worms are dangerous!''.\n','\n',char(10)));
INSERT INTO rooms VALUES(7409,70,'The hot room',replace('You are very surprised, as this room for a change are\nhot instead of cold. To the north it goes downwards into\nsome mud. There are also an exit to the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(7410,70,'The small room',replace('As you look around you notice a small statue. There are\nexits to the west and to the east.\n','\n',char(10)));
INSERT INTO rooms VALUES(7411,70,'The stalagmite cave',replace('You are standing in a stalagmite cave. Water is dripping\nfrom the walls. It is very cold in here.\n','\n',char(10)));
INSERT INTO rooms VALUES(7412,70,'The stalagmite tunnel',replace('You has entered a small tunnel. Here it is quite dry.\nMaybe it would be an idea to rest here.\n','\n',char(10)));
INSERT INTO rooms VALUES(7413,70,'The spongy room',replace('You definitely NOT like this area. It is very dank, and most\nof the places it is wet.\n','\n',char(10)));
INSERT INTO rooms VALUES(7414,70,'The stalagmite T-cross',replace('You are standing in a cross. To the north you can see\nsome light. Otherwise it is dark.\n','\n',char(10)));
INSERT INTO rooms VALUES(7415,70,'The blind end room',replace('This room is obviously a blind end. To the north you see\na primitive picture.\n','\n',char(10)));
INSERT INTO rooms VALUES(7416,70,'The treasure room',replace('This room is rich ornamented. The walls has carves showing\npersons dancing around a sun which is drawn at the floor. It\nlooks very old, and it is very dusty. To the south you see a\nsecret door.\n','\n',char(10)));
INSERT INTO rooms VALUES(7417,70,'The square lair',replace('You are standing in the south-east part of the lair. You can\nsee a skeleton lying at the wall.\n','\n',char(10)));
INSERT INTO rooms VALUES(7418,70,'The square lair',replace('You are standing in the north-east part of the lair. You see\na sign at the wall\n','\n',char(10)));
INSERT INTO rooms VALUES(7419,70,'The square lair',replace('You are standing in the north-west part of the lair. Here''s\nanother sign. There are a exit from the lair to the north.\n','\n',char(10)));
INSERT INTO rooms VALUES(7420,70,'The lair end',replace('You can see a table in front of you. It''s very dusty.\nAround the table five skeletons are siting. Exits are\nnorth and east.\n','\n',char(10)));
INSERT INTO rooms VALUES(7421,70,'East tunnel',replace('You are standing in dark tunnel, the exits are east\nand west. To the west you see a wooden door.\n','\n',char(10)));
INSERT INTO rooms VALUES(7422,70,'North tunnel',replace('You are standing in a dark tunnel, it leads upwards.\n','\n',char(10)));
INSERT INTO rooms VALUES(7423,70,'The L-shaped room.',replace('You are standing in deep darkness. To the south there is a small exit.\nTo the east you can see a gaping hole.\n','\n',char(10)));
INSERT INTO rooms VALUES(7424,70,'The Circular hall.',replace('You are standing in round hall. To the north, east and south you\ncan see a stone head hanging on the walls.\n','\n',char(10)));
INSERT INTO rooms VALUES(7425,70,'Dusty tunnel',replace('You are standing in dust. This place has not been\ntouched for a long time. Otherwise it is quite boring\nhere, looks like a place to rest! To the west you see\nthe outline of a door. A tunnel leads to the east.\n','\n',char(10)));
INSERT INTO rooms VALUES(7426,70,'The crossing',replace('You are standing in a crossing of hallways. You can leave this place\nin every direction, except up and down. In the dust you notice strange\nfootprints.\n','\n',char(10)));
INSERT INTO rooms VALUES(7427,70,'The L-shaped room',replace('You are standing in a L-shaped room. You can hear noises from the long\ntunnel to the east. You can feel fear! A sign is hanging on the wall.\n','\n',char(10)));
INSERT INTO rooms VALUES(7428,70,'Dragons lair',replace('You can see burned walls, the floorstones are fiery red.  All kinds of bones\nare scattered all over the floor.  On the walls you can see some burned\nshapes.  You smell burned flesh.  Two creatures are melted into the floor.\nYou''re next.\n','\n',char(10)));
INSERT INTO rooms VALUES(7429,70,'The burned room',replace('You are in a room, which once had been quite burned.\nThere is writing on the wall.\n','\n',char(10)));
INSERT INTO rooms VALUES(7430,70,'The wind tunnel',replace('You are standing in a tunnel. Above you, you can feel\na breeze.\n','\n',char(10)));
INSERT INTO rooms VALUES(7431,70,'The glittering room',replace('This room are all bright. In the walls you can see some\nsilver. Exits are: West, east and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(7432,70,'The secret passageroom',replace('You have entered a tiny room. There WAS an exit down, and an\nexit to the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(7433,70,'End of long tunnel',replace('You are at a end of a long tunnel. Right in front of you,\nyou can see a grey mass. To the east you can see a tremendous\nlong tunnel, but you know that, you has just been there.\n','\n',char(10)));
INSERT INTO rooms VALUES(7434,70,'Stair-room',replace('You are standing in a small room. Drawings of faces in pain\nare on the walls. You can fell darkness is ruling the place.\nthere are two exits: south and down.\n','\n',char(10)));
INSERT INTO rooms VALUES(7435,70,'Dark tunnel',replace('You are standing in a dark tunnel. It continues to the north\nand to the south. Bones are spread on the floor\n','\n',char(10)));
INSERT INTO rooms VALUES(7436,70,'Entrance to lair',replace('The smell here is awful.  To the south you can see some smoke.\nA tunnel leads north, and east.\n','\n',char(10)));
INSERT INTO rooms VALUES(7437,70,'North-eastern part of Basilisks cave',replace('It is hard to see here because of the smoke. To the north you\ncan see barely see a small tunnel. Other exits are to the south\nand to the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(7438,70,'South-eastern part of basilisks cave',replace('There are a very small hole in wall, from where the smoke\nare coming from. Otherwise it is pitch dark. Exits are north\nand west.\n','\n',char(10)));
INSERT INTO rooms VALUES(7439,70,'North-western part of basilisks cave',replace('You can see some hay spread on the floor. The smell is awful here,\nand it makes you feel sick.  The basilisk sleeps here.\nWatch out ... Maybe it is not far away.\n','\n',char(10)));
INSERT INTO rooms VALUES(7440,70,'South-western part of basilisks cave',replace('You can see nothing but smoke. \n','\n',char(10)));
INSERT INTO rooms VALUES(7441,70,'The small cave',replace('You are standing in small cave. You can see\nsome light in the end. Exits are north and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(7442,70,'The northern end of the pool',replace('You have wet feet, you are standing in water. The water looks calm. You can\nsee that it''s a big lake. Light seeps from the water.\n','\n',char(10)));
INSERT INTO rooms VALUES(7443,70,'The pool',replace('You are swimming in water. It is getting deep here. It is dark in this end.\n','\n',char(10)));
INSERT INTO rooms VALUES(7444,70,'The south end of the pool',replace('You standing in water up to you neck. You can only see water.\n','\n',char(10)));
INSERT INTO rooms VALUES(7445,70,'The pool',replace('You are swimming in DARKNESS. You feel something\ntouching your right leg.\n','\n',char(10)));
INSERT INTO rooms VALUES(7800,78,'A Path from the Plains',replace('You are on a path away from the Plains of Ofcol.  The path doesn''t look well\ntread, but it is relatively well kept.  To the south are the Plains of Ofcol,\nwhile this path leads north.\n','\n',char(10)));
INSERT INTO rooms VALUES(7801,78,'Along the Path',replace('You are on the path away from the Plains of Ofcol.  The main path leads north\nto an overlook and south back toward the Plains of Ofcol.  Western and eastern\nside paths can be seen, probably deer trails by the width of them.\n','\n',char(10)));
INSERT INTO rooms VALUES(7802,78,'A Small Trail',replace('This small deer trail leads north and east.\n','\n',char(10)));
INSERT INTO rooms VALUES(7803,78,'A Small Trail',replace('This small deer trail leads north and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(7804,78,'The Overlook',replace('You are above a large valley.  Below you, you see humanoid forms wandering\naround the valley.  Rich green grass covers the valley, with some small trees\ndotting the landscape.  To the south is the trail back toward Ofcol.\n','\n',char(10)));
INSERT INTO rooms VALUES(7805,78,'The Entrance to the Valley of the Elves',replace('You are at the entrance to the Valley of the Elves.  Elves stare at your\nintrusion, but most are too busy to bother with you.  The valley spreads to\nthe north, while enlarging toward the east and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(7806,78,'The Edge of the Valley',replace('You are at the edge of the Valley of the Elves.  High above you, you see a small\ntrail circling the entire valley.  The valley continues north and east.\n','\n',char(10)));
INSERT INTO rooms VALUES(7807,78,'The Edge of the Valley',replace('You are at the edge of the Valley of the Elves.  High above you, you see a small\ntrail circling the entire valley.  The valley continues north and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(7808,78,'The Edge of the Valley',replace('You are at the edge of the Valley of the Elves.  High above you, you see a small\ntrail circling the entire valley.  The valley continues north and east.\n','\n',char(10)));
INSERT INTO rooms VALUES(7809,78,'The Valley of the Elves',replace('You are in the Valley of the Elves.  The valley continues in all directions.\n','\n',char(10)));
INSERT INTO rooms VALUES(7810,78,'The Valley of the Elves',replace('You are in the Valley of the Elves.  The valley continues in all directions.\nThe entrance to the valley is towards the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(7811,78,'The Valley of the Elves',replace('You are in the Valley of the Elves.  The valley continues in all directions.\n','\n',char(10)));
INSERT INTO rooms VALUES(7812,78,'The Edge of the Valley',replace('You are at the edge of the Valley of the Elves.  High above you, you see a small\ntrail circling the entire valley.  The valley continues north and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(7813,78,'The Edge of the Valley',replace('You are at the edge of the Valley of the Elves.  A steep trail leads up toward\nthe deer trail circling the valley.  The valley continues north, south, and\neast.\n','\n',char(10)));
INSERT INTO rooms VALUES(7814,78,'The Valley of the Elves',replace('You are in the Valley of the Elves.  The valley continues in all directions.\n','\n',char(10)));
INSERT INTO rooms VALUES(7815,78,'The Valley of the Elves',replace('You are in the Valley of the Elves.  The valley continues in all directions.\n','\n',char(10)));
INSERT INTO rooms VALUES(7816,78,'The Valley of the Elves',replace('You are in the Valley of the Elves.  The valley continues in all directions.\n','\n',char(10)));
INSERT INTO rooms VALUES(7817,78,'The Edge of the Valley',replace('You are at the edge of the Valley of the Elves.  A steep trail leads up toward\nthe deer trail circling the valley.  The valley continues north, south, and\nwest.\n','\n',char(10)));
INSERT INTO rooms VALUES(7818,78,'The Edge of the Valley',replace('You are at the edge of the Valley of the Elves.  High above you, you see a\nsmall trail circling the entire valley.  The valley continues south and east.\n','\n',char(10)));
INSERT INTO rooms VALUES(7819,78,'The Valley of the Elves',replace('You are in the Valley of the Elves.  The valley continues in all directions.\n','\n',char(10)));
INSERT INTO rooms VALUES(7820,78,'The Valley of the Elves',replace('You are in the Valley of the Elves.  The valley continues in all directions.\n','\n',char(10)));
INSERT INTO rooms VALUES(7821,78,'The Valley of the Elves',replace('You are in the Valley of the Elves.  The valley continues in all directions.\n','\n',char(10)));
INSERT INTO rooms VALUES(7822,78,'The Edge of the Valley',replace('You are at the edge of the Valley of the Elves.  High above you, you see a small\ntrail circling the entire valley.  The valley continues south and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(7823,78,'The Edge of the Valley',replace('You are at the edge of the Valley of the Elves.  High above you, you see a small\ntrail circling the entire valley.  The valley continues south and east.\n','\n',char(10)));
INSERT INTO rooms VALUES(7824,78,'The Edge of the Valley',replace('You are in the Valley of the Elves.  The valley continues in all directions.\nTo the north, a small, narrow trail leads away from the valley.\n','\n',char(10)));
INSERT INTO rooms VALUES(7825,78,'The Edge of the Valley',replace('You are at the edge of the Valley of the Elves.  High above you, you see a small\ntrail circling the entire valley.  The valley continues south and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(7826,78,'A Trail Leading from the Valley',replace('You are on a narrow trail leading away from the Valley of the Elves.  This\ntrail leads north and south.  A rope ladder leads up to a rope bridge.\n','\n',char(10)));
INSERT INTO rooms VALUES(7827,78,'Along the Trail',replace('You are on the trail away from the Valley of the Elves.  The hills around you\nkeep this trail narrow.  The trail continues east, south, and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(7828,78,'A Bend in the Trail',replace('You are on the trail away from the Valley of the Elves.  The hills around you\nkeep this trail narrow.  The trail continues north and back west.\n','\n',char(10)));
INSERT INTO rooms VALUES(7829,78,'A Smaller Valley',replace('You are in another valley within these hills. To the north, you can see a\nbuilding, and to the south you see the trail away from this valley.  The\nwest and east paths surround this building.\n','\n',char(10)));
INSERT INTO rooms VALUES(7830,78,'A Trail in the Valley',replace('You are on the trail in the Valley of the Elves.  This trail leads north and\neast.  To the north-east is a building.\n','\n',char(10)));
INSERT INTO rooms VALUES(7831,78,'A Trail in the Valley',replace('You are on the trail in the Valley of the Elves.  This trail leads west and\neast.  To the north is a building.\n','\n',char(10)));
INSERT INTO rooms VALUES(7832,78,'A Trail in the Valley',replace('You are on the trail in the Valley of the Elves.  This trail leads north and\nsouth.  To the east is a building.\n','\n',char(10)));
INSERT INTO rooms VALUES(7833,78,'A Trail in the Valley',replace('You are on the trail in the Valley of the Elves.  This trail leads north and\nwest.  To the north-west is a building.\n','\n',char(10)));
INSERT INTO rooms VALUES(7834,78,'The Elf Home',replace('You are in the home of the valley elves.  The building continues to the north\nand the east, and the exit is to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(7835,78,'The Kitchen',replace('You are in a community kitchen for this valley elven home.  Pots and pans line\nthe walls, along with shelves filled with many foodstuffs.  A big oven is to one\nside, and you can smell elfcakes being baked.\nThere is a doorway to the north and one to the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(7836,78,'A Trail in the Valley',replace('You are on the trail in the Valley of the Elves.  This trail leads north and\nsouth.  To the west is a building.\n','\n',char(10)));
INSERT INTO rooms VALUES(7837,78,'A Trail in the Valley',replace('You are on the trail in the Valley of the Elves.  This trail leads north and\nsouth.  To the east is a building.\n','\n',char(10)));
INSERT INTO rooms VALUES(7838,78,'The Living Room',replace('You are in the living room of the elven home.  Mats cover the floor, and a\non a table is a bowl full of fruits.  Through the window you can see the\nvalley, with its wild flowers and tall, green grasses.\n','\n',char(10)));
INSERT INTO rooms VALUES(7839,78,'The Storage Room',replace('You are in the storage room of the elven home.  Sacks of flour cover one side,\nand cleaning accessories cover the other side.  You find nothing of use here.\nA staircase leads up.\n','\n',char(10)));
INSERT INTO rooms VALUES(7840,78,'A Trail in the Valley',replace('You are on the trail in the Valley of the Elves.  This trail leads north and\nsouth.  To the west is a building.\n','\n',char(10)));
INSERT INTO rooms VALUES(7841,78,'A Trail in the Valley',replace('You are on the trail in the Valley of the Elves.  This trail leads south and\neast.  To the south-east is a building.\n','\n',char(10)));
INSERT INTO rooms VALUES(7842,78,'A Trail in the Valley',replace('You are on the trail in the Valley of the Elves.  This trail leads west and\neast.  To the south is a building.\n','\n',char(10)));
INSERT INTO rooms VALUES(7843,78,'A Trail in the Valley',replace('You are on the trail in the Valley of the Elves.  This trail leads east and\nwest.  To the south is a building.\n','\n',char(10)));
INSERT INTO rooms VALUES(7844,78,'A Trail in the Valley',replace('You are on the trail in the Valley of the Elves.  This trail leads south and\nwest.  To the south-west is a building.\n','\n',char(10)));
INSERT INTO rooms VALUES(7845,78,'The Elders'' Room',replace('You are in the room of the valley elf elders.  Books written in strange\nlanguages line the numerous shelves, and scrolls cover a table.  There is a\nsmooth spheric object in the center of the room.\n','\n',char(10)));
INSERT INTO rooms VALUES(7846,78,'The Storage Room',replace('You are in a storage room.  Many useless (to you) items fill this room.\n','\n',char(10)));
INSERT INTO rooms VALUES(7847,78,'The Sleeping Quarters',replace('You are in the sleeping quarters of the valley elves.  Cots line the floor,\nwith two windows showing a view of the valley.  Books in strange languages\nline the shelves, but nothing of interest is here.\n','\n',char(10)));
INSERT INTO rooms VALUES(7848,78,'Study',replace('You are in the study room of the valley elves.  Comfortable mats are on the\nfloor, and musical instruments are neatly stacked on shelves.  Books in\nstrange languages line some other elves.  A stairway leads down to the\nfirst floor.\n','\n',char(10)));
INSERT INTO rooms VALUES(7849,78,'Along a Windy Trail on the Rim of the Valley',replace('You are on a narrow trail on the rim of the Valley of the Elves.  Below you,\nyou can see the valley, filled with wild flowers and tall, green grasses.\n','\n',char(10)));
INSERT INTO rooms VALUES(7850,78,'Along a Windy Trail on the Rim of the Valley',replace('You are on a narrow trail on the rim of the Valley of the Elves.  Below you,\nyou can see the valley, filled with wild flowers and tall, green grasses.\n','\n',char(10)));
INSERT INTO rooms VALUES(7851,78,'Along a Windy Trail on the Rim of the Valley',replace('You are on a narrow trail on the rim of the Valley of the Elves.  Below you,\nyou can see the valley, filled with wild flowers and tall, green grasses.\n','\n',char(10)));
INSERT INTO rooms VALUES(7852,78,'Along a Windy Trail on the Rim of the Valley',replace('You are on a narrow trail on the rim of the Valley of the Elves.  Below you,\nyou can see the valley, filled with wild flowers and tall, green grasses.\n','\n',char(10)));
INSERT INTO rooms VALUES(7853,78,'Along a Windy Trail on the Rim of the Valley',replace('You are on a narrow trail on the rim of the Valley of the Elves.  Below you,\nyou can see the valley, filled with wild flowers and tall, green grasses.\nA safe trail leads down into the valley.\n','\n',char(10)));
INSERT INTO rooms VALUES(7854,78,'Along a Windy Trail on the Rim of the Valley',replace('You are on a narrow trail on the rim of the Valley of the Elves.  Below you,\nyou can see the valley, filled with wild flowers and tall, green grasses.\n','\n',char(10)));
INSERT INTO rooms VALUES(7855,78,'Along a Windy Trail on the Rim of the Valley',replace('You are on a narrow trail on the rim of the Valley of the Elves.  Below you,\nyou can see the valley, filled with wild flowers and tall, green grasses.\n','\n',char(10)));
INSERT INTO rooms VALUES(7856,78,'Along a Windy Trail on the Rim of the Valley',replace('You are on a narrow trail on the rim of the Valley of the Elves.  Below you,\nyou can see the valley, filled with wild flowers and tall, green grasses.\n','\n',char(10)));
INSERT INTO rooms VALUES(7857,78,'Along a Windy Trail on the Rim of the Valley',replace('You are on a narrow trail on the rim of the Valley of the Elves.  Below you,\nyou can see the valley, filled with wild flowers and tall, green grasses.\n','\n',char(10)));
INSERT INTO rooms VALUES(7858,78,'On the Rope Bridge',replace('You are on the rope bridge.  From here, you can see the whole Valley of the\nElves.  To the south, you see the main valley.  To the north-east, you see a\nsmaller valley with a building in the center of it.  To the north-west, you\ncan see a very small valley with a shack in it''s center.  A rope ladder\nleads down into a trail.\n','\n',char(10)));
INSERT INTO rooms VALUES(7859,78,'Along a Windy Trail on the Rim of the Valley',replace('You are on a narrow trail on the rim of the Valley of the Elves.  Below you,\nyou can see the valley, filled with wild flowers and tall, green grasses.\n','\n',char(10)));
INSERT INTO rooms VALUES(7860,78,'Along a Windy Trail on the Rim of the Valley',replace('You are on a narrow trail on the rim of the Valley of the Elves.  Below you,\nyou can see the valley, filled with wild flowers and tall, green grasses.\n','\n',char(10)));
