INSERT INTO rooms VALUES(7863,78,'Along a Windy Trail on the Rim of the Valley',replace('You are on a narrow trail on the rim of the Valley of the Elves.  Below you,\nyou can see the valley, filled with wild flowers and tall, green grasses.\nA safe trail leads down into the valley.\n','\n',char(10)));
