INSERT INTO rooms VALUES(7866,78,'Along a Windy Trail on the Rim of the Valley',replace('You are on a narrow trail on the rim of the Valley of the Elves.  Below you,\nyou can see the valley, filled with wild flowers and tall, green grasses.\n','\n',char(10)));
INSERT INTO rooms VALUES(7867,78,'Along a Windy Trail on the Rim of the Valley',replace('You are on a narrow trail on the rim of the Valley of the Elves.  Below you,\nyou can see the valley, filled with wild flowers and tall, green grasses.\n','\n',char(10)));
INSERT INTO rooms VALUES(7868,78,'A Bend in the Trail',replace('You are on a bend in the trail leading from the main valley.  The hills around\nyou make this trail quite narrow.\n','\n',char(10)));
INSERT INTO rooms VALUES(7869,78,'A Bend in the Trail',replace('You are on a bend in the trail leading from the main valley.  The hills around\nyou make this trail quite narrow.  To the west, you can see an even smaller\nvalley, with looks like a small shack in the center of it.\n','\n',char(10)));
INSERT INTO rooms VALUES(7870,78,'The Small Valley',replace('You are in the small valley.  Strangely, tall trees grow here, almost as if some\nmagic was used to help them grow.  The exit from this valley is to the east, and\nthe entrance to the shack is to the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(7871,78,'The Small Valley',replace('You are in the small valley.  Strangely, tall trees grow here, almost as if some\nmagic was used to help them grow.  To the south-west is a small shack.\n','\n',char(10)));
INSERT INTO rooms VALUES(7872,78,'The Small Valley',replace('You are in the small valley.  Strangely, tall trees grow here, almost as if some\nmagic was used to help them grow.  To the north-west is a small shack.\n','\n',char(10)));
INSERT INTO rooms VALUES(7873,78,'The Small Valley',replace('You are in the small valley.  Strangely, tall trees grow here, almost as if some\nmagic was used to help them grow.  To the south is a small shack.\n','\n',char(10)));
