INSERT INTO rooms VALUES(7876,78,'The Small Valley',replace('You are in the small valley.  Strangely, tall trees grow here, almost as if some\nmagic was used to help them grow.  To the north-east is a small shack.\n','\n',char(10)));
INSERT INTO rooms VALUES(7877,78,'The Small Valley',replace('You are in the small valley.  Strangely, tall trees grow here, almost as if some\nmagic was used to help them grow.  To the north is a small shack.\n','\n',char(10)));
INSERT INTO rooms VALUES(7878,78,'Inside the Small Shack',replace('You are inside the small shack.  A small stove is on the side, with soup\ncooking over it.  You see nothing valuable.\n','\n',char(10)));
INSERT INTO rooms VALUES(7879,78,'Beneath the Small Shack',replace('You are beneath the small shack, in a tunnel that leads south.  It feels\nquite warm down here.\n','\n',char(10)));
INSERT INTO rooms VALUES(7880,78,'The Den of the Pyrohydra',replace('You are in the den of the pyrohydra.  All the walls are charred, and this\nroom is filled with a smell close to that of burning tar.\n','\n',char(10)));
INSERT INTO rooms VALUES(7881,78,'The Workroom',replace('This room looks like it is used for magical studies.  Potions bubble over\nburners, and the whole room spells of herbs and dead animal flesh.  A furnace\nto the side casts a bright light in this room.  The whole room radiates with\na magical aura.\n','\n',char(10)));
INSERT INTO rooms VALUES(7882,78,'The Storage Room',replace('This room is used to store scrolls, potions, and other magical items.  The\nwhole room radiates with a magical aura.\n','\n',char(10)));
INSERT INTO rooms VALUES(7883,78,'WAY Far Down into the Valley',replace('You have fallen trying to go down this steep hill.  Maybe that wasn''t that\ngood an idea, huh?\n\n\nYou''ve fallen, and you can''t get up!\n','\n',char(10)));
INSERT INTO rooms VALUES(7900,79,'Outside Redferne''s residence',replace('A huge cloud forms the plateau on which you are now standing. The wind here\nis absolutely quiet and the sun is shining warmly upon you. From under the\ncloud you can hear the faint sounds of Midgaard. Right before you to the\nnorth lies the grand Mansion of Naris, the residence of the Greater God\nRedferne.\n','\n',char(10)));
INSERT INTO rooms VALUES(7901,79,'The Southern end of the hall',replace('You are standing in a vast hall that is dimly lit, but wherefrom the\nlight comes, is a mystery. The walls seem to radiate warmth and give\nthe pleasant feeling of being welcome here. A large portrait is hanging\non one of the walls. A large wooden staircase leads up into the tower.\nTo the east there is a high passage away from the hall. This ends\nshortly after by a tall oak door. The enormous hall extends further\nnorth from here. To the south you can see a huge, and VERY heavy-\nlooking iron-wrought door. It looks like this is the only exit from\nthis magnificent old house. To the west you can see a large ashen door.\n','\n',char(10)));
INSERT INTO rooms VALUES(7902,79,'Redferne''s Library',replace('This is truly a magnificent place! Books and scrolls lie together on every\nshelf. A large globe, with the map of the Mud-world upon it, stands in the\ndimly lit north-western corner of the room. Two large and comfortable-\nlooking leather arm-chairs adorn the center of the library together with\na huge oak desk. Dim light radiates from an enormous crystal chandelier\nhanging down from the ceiling approximately 10 feet off the floor. To the\neast there is a great old ashen door. A large glass window is set in the\nwest wall.\n','\n',char(10)));
INSERT INTO rooms VALUES(7903,79,'The Artifact room of Naris',replace('This is gloomy and dark room with only a faint light radiating from the\nwalls. A bunch of funny-looking items fill the center of the room. There are\nno furniture here what-so-ever. The only way out seems to be west, through\nthe low steel door.\n','\n',char(10)));
INSERT INTO rooms VALUES(7904,79,'The Northern end of the hall',replace('You are standing in the northern end of the huge hall. This part is under\nthe grand wooden staircase so the light seems a little less bright here,\nbut this doesn''t bother your sight at all. To the north lies the kitchen.\nTo the south lies the Southern end of the hall. To the east there is a huge\nmetal door. To the west there is a large aspenwood door.\n','\n',char(10)));
INSERT INTO rooms VALUES(7905,79,'The Sitting room of Naris',replace('You are standing in the middle of a really comfortable place. The walls are\ndecorated with paintings of smiling Kings and Queens. The most attractive\npicture is one of a Prince in shiny armour. By one of the walls there is an\nold arm-chair. The only exit is through the aspenwood door to the east.\n','\n',char(10)));
INSERT INTO rooms VALUES(7906,79,'The Kitchen of Naris',replace('This must be the place of food and drink. You can hear the faint noise of \nrats feasting on meat and bread from somewhere undeterminable. The sound\nmakes you feel the agony of HUNGER. The only visible exit is south to the\nNorthern end of the hall. To the north there is a larder, and to the east\nstands a fridge.\n','\n',char(10)));
INSERT INTO rooms VALUES(7907,79,'The Larder',replace('You can see food all over. Among the heaps of food you notice HUGE rats\nscuttering around, nibbling pieces off the heaps here and there.\n','\n',char(10)));
INSERT INTO rooms VALUES(7908,79,'The Fridge',replace('This place is LOADED with drink, water and booze.\n','\n',char(10)));
INSERT INTO rooms VALUES(7909,79,'On the stairs',replace('You can see up and down the stairway. It seems to take forever, either going\nup OR down. It''s just a seemingly insurmountable climb, either way. Up is the \nbedroom of Redferne, and Down leads to the Southern end of the hall.\n','\n',char(10)));
INSERT INTO rooms VALUES(7910,79,'The Treasure room',replace('This place is gloomy.  The only visible exit is west, through the oak door.\n','\n',char(10)));
INSERT INTO rooms VALUES(7911,79,'Redferne''s Bedroom',replace('This is a snugly set bedroom with all the necessities for a romantic evening.\nA large fireplace adorns the east wall, and sizzling away is the wood that\nis ablaze within.  The bed is enormous, covering at least HALF of this great\nroom.  This stretches at least 300 square feet, so can you imagine the BED?\nA large staircase leads down to the hall.  A couple of doors open up to a\nbroad balcony to the south. \n','\n',char(10)));
INSERT INTO rooms VALUES(7912,79,'The Balcony of Redferne''s Residence',replace('You see a splendid of the most of this world. The valleys stretch as far as\nthe eye reaches to the south from here. Down below you can see the entrance\nof this magnificent building. To the north are the doors to Redferne''s Bedroom.\n','\n',char(10)));
INSERT INTO rooms VALUES(7913,79,'The Monster Pen',replace('This looks like the cage in which a large carnivore is being kept. Judging by\nthe state the walls are in, this could very well be a large AGGRESSIVE animal. \nThis makes you pretty insecure, this stating your feeling about the place, \nquite mildly.\n','\n',char(10)));
INSERT INTO rooms VALUES(7914,79,'On the Huge Chain',replace('This place has quite a good view over Midgaard. Your possibilities of movement\nseems to extend only to up and down. Unless you want to let go of the secure\nand seemingly unmoveable chain, then those are the directions you should take\nfrom here.\n','\n',char(10)));
INSERT INTO rooms VALUES(7916,79,'On the Great Chain of Naris',replace('You are approximately on the middle of the treacherous Chain. One false step\nand death will come and collect you quickly. The chain leads upwards and down.\nNo way are you going to descend now ... you''ve only just begun your climb.\nBesides it could cost you your life.  Look down and you''ll see why.\n','\n',char(10)));
INSERT INTO rooms VALUES(7918,79,'The Mighty Chain of Naris',replace('This place offers a splendid view of the WHOLE COUNTRY SIDE!!! A magnificent\nlight shines upon you and the way up through the clouds is opened. Up there\nyou can now see the Mansion of Naris, Residence of the Greater God Redferne.\nThe chain beneath you seems to evaporate in the mustering clouds that\nsurround you by now.\n','\n',char(10)));
INSERT INTO rooms VALUES(8001,80,'Entrance to Mega-City One',replace('A road begins here in the glowing sands.  You follow it through a gate\nin a Plasteen wall onto the Megway of Mega-City One.\n','\n',char(10)));
INSERT INTO rooms VALUES(8002,80,'Mahmount Allesh Megway',replace('You are on one mile of over 13 and a half billion kilometers of\nroadway in Mega-City One.  The Megway continues north and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(8003,80,'Intersection of Junket Way and Megway',replace('The Megway intersects with Junket Way here.  Junket Way is to the east,\nthe Megway continues north and south, and the Pustule Palace Cafe is\nto the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(8004,80,'Mahmount Allesh Megway',replace('The traffic here is really congested due in part to the over 11 million\npeople driving Mo-Pads, the mobile homes which are constantly on the\nmove until their owners can find an apartment in one of the City-blocks.\nThe Megway continues north and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(8005,80,'Mahmount Allesh Megway',replace('The Megway continues north and south.  On the off-ramps here you see\nmany of the citizens of Mega-City One doing nothing.  You see of\nevery hundred citizens, it can be guaranteed that 87 of them will\nbe totally unemployed, and that a further five will not work more\nthan ten hours a week.  To the east there is a dark alley and to the\nwest is Rietzik''s Shuggy Hall.\n','\n',char(10)));
INSERT INTO rooms VALUES(8006,80,'Central Plaza',replace('You are at the Central Plaza of the downtown district.  There are a couple\nof juves Boingging (tm) in the air above you.  Max Jaffa Boulevard goes\neast, the Megway continues north and south, and Bazza''s Home for the\nTerminally Sarky is to the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(8007,80,'Corner of Ed Hilldreth Memorial Parkway and Megway',replace('Another major intersection which is being negotiated by vehicles that\nare bound to minimum speed limits.  Many Slow Driving offenses are being\nhanded out by the Judges.  The Megway goes north and south, a Parkway\ngoes east, and Nu Phisog Parlour is west.\n','\n',char(10)));
INSERT INTO rooms VALUES(8008,80,'Mahmount Allesh Megway',replace('As you travel the Megway you notice many citizens participating in their\nfavorite hobbies such as spot welding and metalwork, scratch building\nfashion Kneepads, giving blood, or just looking out the window.  The\nMegway continues north and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(8009,80,'Mahmount Allesh Megway',replace('The Megway ends here.  To the west is Ziggi Piggi''s Home for the\nSemi-Stiff, to the east and south are construction areas, and the\nMegway goes north.\n','\n',char(10)));
INSERT INTO rooms VALUES(8010,80,'Junket Way',replace('Junket Way a small Skedway continues east and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(8011,80,'Davies Alley',replace('You are in a very dark and seedy alley.  This is just the right place for\na bite fight.  Bite fighting is an illegal activity where both combatants\ncan only use their sharpened teeth as weapons.\n','\n',char(10)));
INSERT INTO rooms VALUES(8012,80,'Max Jaffa Boulevard',replace('Max Jaffa Boulevard continues east and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(8013,80,'Ed Hilldreth Memorial Parkway ',replace('The Parkway goes east and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(8014,80,'Construction site of the Harold Finkelbaum Block.',replace('A Mega-City One City Block is being constructed at this site.  A\ntypical block is from 100 to 1000 stories high with hundreds of\nthousands inhabitants.\n','\n',char(10)));
INSERT INTO rooms VALUES(8015,80,'Corner of Junket Way and Threep Lane',replace('There is a second-hand kneepad stall is doing a brisk business with a\ngroup of juves on their way to school.  Junket Way goes west and Threep\nLane travels south.\n','\n',char(10)));
INSERT INTO rooms VALUES(8016,80,'Threep Lane',replace('Threep Lane continues north and south.  There is a building to the east\nwith a sign next to the door.\n','\n',char(10)));
INSERT INTO rooms VALUES(8017,80,'Threep Lane',replace('Threep Lane continues north and south.  There is a dark alley to the west.\n','\n',char(10)));
INSERT INTO rooms VALUES(8018,80,'Corner of Max Jaffa Blvd and Threep Way',replace('A proprietor of Uncle Sumpty''s Ugly Emporium meanders by.  Threep Lane\ncontinues north and south while Max Jaffa Boulevard goes west.\n','\n',char(10)));
INSERT INTO rooms VALUES(8019,80,'Corner of Ed Hilldreth Mem. Prkwy and Threep Lane',replace('Threep Lane goes north from here while Ed Hilldreth Memorial Parkway goes\nwest.\n','\n',char(10)));
INSERT INTO rooms VALUES(8020,80,'Construction Site for the Brit-Cit One tunnel.',replace('Construction is under way for the Black Atlantic Tunnel to connect\nMega-City One and Brit-Cit One.\n','\n',char(10)));
INSERT INTO rooms VALUES(8021,80,'Pustule Palace Cafe',replace('A scabrous hole.  Run by Ernie Ramirez, an ex-perp, it is a meeting place\nfor the low-life in the area.\n','\n',char(10)));
INSERT INTO rooms VALUES(8022,80,'Rietzik''s Shuggy Hall',replace('A sleazy dive and the meeting place of a lot of perps.  Shuggy is a\ntwenty-second Century version of pool, played on a hilly table, usually\nwith large side bets.\n','\n',char(10)));
INSERT INTO rooms VALUES(8023,80,'Bazza''s Home for the Terminally Sarky',replace('This is an experimental psychiatric home.  Named after a 20th Century\nvid-critic, the home attempts, by various methods, to readjust the\nsocially unacceptable attitudes of the inmates.\n','\n',char(10)));
INSERT INTO rooms VALUES(8024,80,'Nu Phisog Parlour',replace('Opened as a direct rival to the New You Face Parlour chain to offer quick\nand cheap face-changing facilities to the general public.  However,\nsince the closure of Sump''s Ugly clinics, the craze for face-changing has\ndied down.\n','\n',char(10)));
INSERT INTO rooms VALUES(8025,80,'Ziggi Piggi''s Home for the Semi-Stiff',replace('The only suspended animation parlour in the area.  It has a high turnover\nrate.  It is rumored that the patrons are being used in body sharking and\norgan legging activities.\n','\n',char(10)));
INSERT INTO rooms VALUES(8026,80,'Throt & Gleep''s Megger Store',replace('This place promises to provide everything that the citizens don''t need,\nwith the utmost discourtesy.  Of course, something as crazy as this was\nbound to succeed.  There is a door to the north with a slot next to it.\nThere is also a sign next to the slot.\n','\n',char(10)));
INSERT INTO rooms VALUES(8027,80,'Stockroom of Throt & Gleep''s Megger Store',replace('Many useless items stock the shelves of this stockroom.  A door leads\nsouth and large vault door is to the north.\n','\n',char(10)));
INSERT INTO rooms VALUES(8028,80,'Throt & Gleep''s Vault',replace('The vault is musty with a slight smell of ozone in the air.\n','\n',char(10)));
INSERT INTO rooms VALUES(8301,83,'Muddy Path',replace('This section of the path is slowly being drowned by the nearby swamp to the\nsouth, which is creeping slowly inland.  Several caved-in buildings sprawl\nhere, torn apart both by battle and the elements.\n','\n',char(10)));
INSERT INTO rooms VALUES(8302,83,'Swamp''s Edge',replace('Briars and marsh plants stick to your boots and clothes, and clouds cover the\nskies above the murky marsh, leaving the path before you dark and sinister.\nYou see some disturbances in the marsh, but after a few strangled screams,\nthe sounds stop.\n','\n',char(10)));
INSERT INTO rooms VALUES(8303,83,'Marshy Forest',replace('This area is by no means a forest, but for those who dwell in these sparse\ntrees it is one.  Occasionally you see a whole humanoid form floating face down\nin the water, but mostly you only find pieces.  You hear a loud bellow in the\ndistance.  And feel fear creep into your heart.\n','\n',char(10)));
INSERT INTO rooms VALUES(8304,83,'On a hill.',replace('You stand atop a hill on the northwestern side of the evil swamp. Dark\nclouds whip around you and the wind raises its voice and assails you.\n','\n',char(10)));
INSERT INTO rooms VALUES(8305,83,'An Oozing Bog',replace('You stand in an oozing quagmire.  A creaking beat fills the air, \naccompanied by groans and soughing of the air.  Several large winged\nbeasts flap over you and send chilling glares your way.  You feel out\nof place, and feel that the occupants of this realm will soon \nhave you for a feast.\n','\n',char(10)));
INSERT INTO rooms VALUES(8306,83,'An Oozing Bog',replace('The ground here is soft and oozing.  You feel slimy water seeping into your\nboots.  Better stop and check for leeches when you get out of here.\n','\n',char(10)));
INSERT INTO rooms VALUES(8307,83,'Swamp Thing''s Lair',replace('A horrible swamp thing resides here.  Mutilated corpses suffuse the air with\nthe overwhelming stench of putrid flesh.\n','\n',char(10)));
INSERT INTO rooms VALUES(8308,83,'Pool of Quick Sand',replace('You stand by a large oozing pool of quick sand.  Luckily only a complete\nklutz could not avoid it.  Dancing lights fly about you and one seems to\nbe taunting you towards the pool.\n','\n',char(10)));
INSERT INTO rooms VALUES(8309,83,'A Dark Pool.',replace('You stand beside a large dark pond.  The water boils not with heat, but with\nmotion, as if it is alive.  A creaking beat pulses through the air, leaving\nyou with a cold sweat and fear in your heart.\n','\n',char(10)));
INSERT INTO rooms VALUES(8310,83,'Gloomy Path Through the Marsh.',replace('To the north lies a hill, shrouded in dark clouds, and to the south lies\na huge patch of vegetation.  You sense an evil presence and notice \na beast flying overhead to the south east, towards what looks to be a \nhuge fortress, half buried in the marsh.\n','\n',char(10)));
INSERT INTO rooms VALUES(8311,83,'Cloud of Darkness.',replace('As you travel through this cloud of darkness, a fear such as you have never\nknown before assails you.\n','\n',char(10)));
INSERT INTO rooms VALUES(8312,83,'Near Vegetation from Hell.',replace('You stand near some of the strangest plant life you have ever seen, a mixture\nof tumescent vegetables, evil-smelling fruit trees, and malignant ferns.\n','\n',char(10)));
INSERT INTO rooms VALUES(8313,83,'By the Monolith.',replace('You are standing near a monolith which protrudes some 20 feet from the\nmarsh into the air.  Its black obsidian surface shines darkly in the \nstrange, almost unearthly light that enters through the clouds above.\n','\n',char(10)));
INSERT INTO rooms VALUES(8314,83,'Murky Bog.',replace('A murky bog surrounds you.  To the east a black monolith juts forth from the\nground.  Far to the north lies a huge pool of quicksand.  Snarls can be heard\nechoing as if from a great distance.\n','\n',char(10)));
INSERT INTO rooms VALUES(8315,83,'Northern Lake Side.',replace('Floating on this boiling lake is not what you would consider an enjoyable \nexperience.  Many a creature bumps the bottom of your boat, and glares \nat you through unblinking eyes from the waters below.  The southern \nportion of the lake looks calm and serene compared to this wild place.\n','\n',char(10)));
INSERT INTO rooms VALUES(8316,83,'Southern Lake Side.',replace('You are floating on a calm section of blue crystal water.  You feel much more\nat ease then you were before in this area.  Then a wave of fear passes over\nyou.  You are not alone.\n','\n',char(10)));
INSERT INTO rooms VALUES(8317,83,'Beach',replace('You are on a sandy shore.  Marsh life creeps across the surface.  To the west\nlies an evil fortress.  You see figures walking along the battlements.\n','\n',char(10)));
INSERT INTO rooms VALUES(8318,83,'Before the Great Gates.',replace('You stand before the gates of a huge fortress.  The drawbridge is up, the\ngates closed, and the portcullis down.  This place looks very dangerous,\nand you decide not to continue onward.\n','\n',char(10)));
INSERT INTO rooms VALUES(8600,86,'The Void',replace('You are suspended in cool electric space above a translucent plain.  You feel\nsynesthesia invading your nerves and reshuffling your senses.  The sky is the\nsame obsidian color as the ground and you can''t find a horizon.\n','\n',char(10)));
INSERT INTO rooms VALUES(8601,86,'The Void',replace('You are suspended in cool electric space above a translucent plain.  You feel\nsynesthesia invading your nerves and reshuffling your senses.  The sky is the\nsame obsidian color as the ground and you can''t find a horizon.\n','\n',char(10)));
