INSERT INTO rooms VALUES(8628,86,'The Void',replace('You are suspended in cool electric space above a translucent plain.  You feel\nsynesthesia invading your nerves and reshuffling your senses.  The sky is the\nsame obsidian color as the ground and you can''t find a horizon.\n','\n',char(10)));
INSERT INTO rooms VALUES(8630,86,'Road to Newfane',replace('You are on a gently curving north-south road.  On your east side a youthful\nriver sparkles blue and rushes in the sunlight.  On the west, green leaves and\ngreen ferns burst against the rich brown earth.  You feel the heat of your\nhealthy muscles as you travel swiftly down the well-paved road.\nYou may recall now if you like.\n','\n',char(10)));
INSERT INTO rooms VALUES(8631,86,'Newfane Village Square',replace('You are on the lawn of the village square of Newfane, resting against an oak\nafter your vigorous journey.  The late spring breeze feels warm and sensuous\non your body.  An Ale is in progress: you spy more than a dozen fiddlers and\nhundreds of Morris Dancers dressed in white cotton and wearing colorful hats\nand bells.\n','\n',char(10)));
INSERT INTO rooms VALUES(8632,86,'A Large Dance Hall',replace('You are inside a large dance hall with a very polished, very slippery wooden\nfloor.  You see three long lines of dancers, alternating men and women, in\nsome sort of progressive country dance.  Two fiddlers, a flautist, and a\nharpsichord player provide the music.  You hear scattered screams of joy\nfrom the dancers.\nYou may recall now if you like.\n','\n',char(10)));
INSERT INTO rooms VALUES(8634,86,'A Small Hall',replace('You are inside a small hall with a rough wooden floor.  You see dozens of\npeople in the hall chasing one poor man who is yelling at the top of\nhis lungs.  Wait a minute.  These people are all holding hands and smiling!\nThe man in front is leading them in a spiral!  They''re DANCING!  And you\nthought people didn''t dance like this any more!\nYou may recall now if you like.\n','\n',char(10)));
INSERT INTO rooms VALUES(8636,86,'Road by a Pond',replace('You are passing by a large pond, almost a small lake.  You notice a small\nwooden shack by the side of the road.\nYou may recall now if you like.\n','\n',char(10)));
INSERT INTO rooms VALUES(8637,86,'An Old Wooden Church',replace('As you enter the hall, you see the largest crowd of people you''ve ever seen in\nyour life.  They''re also the noisiest crowd you''ve ever heard, and as they\npress around you, the SWEATIEST crowd you''ve ever felt!  At the front of the\nhall, a group of musicians are playing ''Chorus Jig''.\n','\n',char(10)));
INSERT INTO rooms VALUES(8638,86,'Mountain Road',replace('You are following a road at the top of a mountain ridge with sky all around\nyou.  Distant valleys are spread out below you on both sides.  There are\nmany horsemen and horsewomen on this road, riding hell-for-leather out of\nsheer exhilaration.  You wish you had a horse!\nYou may recall now if you like.\n','\n',char(10)));
INSERT INTO rooms VALUES(8639,86,'Yule Tree Farm',replace('This is the Yule Tree Farm at the top of Mountain Road.  All around you,\nyoung Yule Trees saturate your senses with dark green needles and pine\nessence.\n','\n',char(10)));
INSERT INTO rooms VALUES(8699,86,'The Void',replace('You are suspended in cool electric space above a translucent plain.  You feel\nsynesthesia invading your nerves and reshuffling your senses.  The sky is the\nsame obsidian color as the ground and you can''t find a horizon.\n','\n',char(10)));
INSERT INTO rooms VALUES(8901,89,'The holy grove',replace('You are standing amidst the ancient oaks and poplars in the holy grove. You\ncan feel a strange sensation of contentedness and relief seeping through You,\nas if great burdens have been lifted from Your shoulders. From here, friendly-\nlooking paths lead east and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(8902,89,'The holy grove',replace('You are standing amidst the ancient oaks and poplars in the holy grove. You\nfeel unusually happy here, as if great burdens have been lifted from Your\nshoulders. From here, pleasant-looking paths lead east, west and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(8903,89,'A clearing in the woods',replace('You are standing in a clearing in the light woods. Somehow, this place\nseems powerfully DIFFERENT from the rest of the forest, as if something is\nseverely strained in the fabric of reality here.  There is a small tablet \non one of the trees.\n','\n',char(10)));
INSERT INTO rooms VALUES(8904,89,'The holy grove',replace('You are standing amidst the ancient oaks and poplars in the holy grove. You\nfeel calm and relaxed here, as if great burdens have been lifted from Your\nshoulders. From here, pleasant-looking paths lead east, north and south. To\nthe west, through the trees, You can see the road to Midgaard.\n','\n',char(10)));
INSERT INTO rooms VALUES(8905,89,'The sacred glade',replace('You are standing in the middle of the sacred glades, where the citizens of\nMidgaard come to celebrate the spring, where farmers give thanks for bountiful\nharvest in the fall, and where lovers stroll in summer. You feel seasons of\nremembered happiness and joy taking Your sorrows and worries away from You,\nleaving You calm and invigorated, ready for the world. Paths lead into the\nholy grove to the east, north and west, while to the south a wide, sunny field\nslopes down to a sparkling lake.\n','\n',char(10)));
INSERT INTO rooms VALUES(8906,89,'The holy grove',replace('You are standing amidst the ancient oaks and poplars in the holy grove. You\ncan feel a strange sensation of joy and calm seeping through You, as if great\nburdens have been lifted from Your shoulders. To the south, You glimpse an open\narea through the trees, while paths lead away north and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(8907,89,'The holy grove',replace('You are standing amidst the tall, majestic trees in the southern end of the\nholy grove. Paths lead north and east. To the east, You can see a wide, open\nfield, sloping gently down towards a bright, glittering lake. Somehow, here\nyou feel an inexplicable happiness, as if the world''s troubles no longer\nreally matter to you.\n','\n',char(10)));
INSERT INTO rooms VALUES(8908,89,'The sunny field',replace('You are standing in the middle of a wide, summery, sunlit field. There is a\nfragrance of spring in the air, a sound of summer and a feeling of eternal\nSaturday afternoon. To the south is a clear, sparkling lake, and to the north\nand west is the holy grove. In the wood''s edge, to the east, is a stately man-\nsion, shimmering softly through the colors of the rainbow. You feel as if You\ncould spend the rest of your life here, lying on your back and looking at the\npatterns of the clouds as they gently drift across the sky.\n','\n',char(10)));
INSERT INTO rooms VALUES(8909,89,'The croquet lawn',replace('You are standing on a immaculately manicured green lawn, the kind you only\nget after 200 years of meticulous work. There is a winding stone path leading\nfrom the wood''s edge to the north, to the softly shimmering, rainbow-colored\nmansion to the south. This place enjoys a perpetual cool, sunny summers after-\nnoon.\n','\n',char(10)));
INSERT INTO rooms VALUES(8910,89,'The foyer',replace('You are standing in the foyer of Dragon''s mansion. The wide double door to\nthe croquet lawn is to the north, flanked by large windows. The walls are\npanelled in oak and hung with strange paintings.  There is door in the south\nwall.\n','\n',char(10)));
INSERT INTO rooms VALUES(8911,89,'The hallway',replace('You are in the north end of a connecting hallway, tastefully decorated with\noak paneling and the coat-of-arms of various famous nobles hung on the walls.\nThe hallway leads south, and there is a door in the eastern wall.\n','\n',char(10)));
INSERT INTO rooms VALUES(8912,89,'The blue room',replace('You are in the blue room, one of the guest rooms in Dragon''s mansion. The\nwalls are (surprise!) blue, and the rest of the room is decorated in similar\nshades, producing a very nice, cool effect. There is a large bed and a\nmatching set of sofas, easy-chairs and a coffee table. Through the venetian\nblinds in front of the large east window you can see the edge of the grove.\n','\n',char(10)));
INSERT INTO rooms VALUES(8913,89,'The hallway',replace('You are standing in the south end of the hallway. There are doors in the\nelegant oak-panelled walls to the south, east and west. Many different\ncoat-of-arms adorn the walls here.\n','\n',char(10)));
INSERT INTO rooms VALUES(8914,89,'The red room',replace('You are in the red room, one of the guest rooms in Dragon''s mansion. The\nwalls are wallpapered a deep warm red, and dark mahogany panelling nicely com-\nplements them. There is a large, warm waterbed and a sofa group in dark wood\nwith leather upholstery, including a coffee table. Heavy brown curtains are\npulled away from the wide windows, to reveal a nice view towards the grove.\n','\n',char(10)));
INSERT INTO rooms VALUES(8915,89,'The kitchen',replace('You are standing in the middle of Dragon''s kitchen. Contrary to popular\nbelief, He *doesn''t* eat virgins, which is amply demonstrated by the large\nvariety of foodstuffs found here on the shelves. There are numerous cans of\ntomatoes, peas, corn etc., vines of garlic, a *Huge* array of small spice jars\nalong several shelves and a large combo refrigerator/freezer. A big oven and\nstove is lurking in a corner. There is some proof here that Dragon is a less\nthan meticulous housekeeper... There are doors to the north and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(8916,89,'The ballroom',replace('You are standing in the middle of a vast palisander floor. This is where\nDragon entertains large number of guests, but the cloth-covered chairs\nstanding forlornly in a corner suggests that this does not happen often.\nThere are doors in the south and west walls, while to the east there is a\nshort corridor to the greenhouse.\n','\n',char(10)));
INSERT INTO rooms VALUES(8917,89,'The greenhouse',replace('This is Dragons'' greenhouse. Green light filters in slantwise through the\nplants, giving the room a subtropical ambience. It is not really hot in here,\nthough, rather a pleasantly warm temperature. The walls are all windows, except \nthe eastern one joining the greenhouse to the main building, but it is hard to \nsee out for all the greenery here. There is a set of easy-chairs and a glass\ncoffee table. To the south, there is a wide double door out to a sunlit \nterrace.\n','\n',char(10)));
INSERT INTO rooms VALUES(8918,89,'The dining hall',replace('This is Dragons'' dining hall. There is a large long solid oak table,\nseating at least 24, with heavy, wooden chairs to match. The oak panel walls\nare filled with paintings. There are doors to the north and east, and to the\nwest there is a wide double door opening out onto the sunlit terrace.\n','\n',char(10)));
INSERT INTO rooms VALUES(8919,89,'The terrace',replace('You are standing on a sunlit terrace in front of Dragon''s mansion. To the\nwest, there is a splendid view over the field down over the lake. To the north\nis the greenhouse, its large windowpanes shimmering with weird and wonderful\ncolors, while a double door leads into the house proper to the east. It is\nwarm and calm here. There is a white-painted table with a parasol here,\ntogether with a matched set of chairs.\n','\n',char(10)));
INSERT INTO rooms VALUES(8999,89,'The fog',replace('You are in a grey fog, falling, screaming in pain as you realize\nthat you are being torn to nothing, atom by atom, falling and falling \nand falling ...\n...\n.\n','\n',char(10)));
INSERT INTO rooms VALUES(9101,91,'A fluffy white cloud.',replace('You find yourself standing on a small cloud.  The cloud feels kind\nof spongy beneath your feet.  You find it hard to see anything in\nthe distance as wisps of cloud blow over your face.\n\nA floating sign says:\n\n"Scubdu''s Area--Tread carefully! Only high levels should attempt\nthis place. Leave messages on the board if you have problems."\n','\n',char(10)));
INSERT INTO rooms VALUES(9102,91,'A fluffy white cloud.',replace('You find yourself standing on a small cloud.  The cloud feels kind\nof spongy beneath your feet.  You find it hard to see anything in\nthe distance as wisps of cloud blow over your face.\n','\n',char(10)));
INSERT INTO rooms VALUES(9103,91,'A fluffy white cloud.',replace('You find yourself standing on a small cloud.  The cloud feels kind\nof spongy beneath your feet.  You find it hard to see anything in\nthe distance as wisps of cloud blow over your face.\n','\n',char(10)));
INSERT INTO rooms VALUES(9104,91,'A fluffy white cloud.',replace('You find yourself standing on a small cloud.  The cloud feels kind\nof spongy beneath your feet.  You find it hard to see anything in\nthe distance as wisps of cloud blow over your face.\n','\n',char(10)));
INSERT INTO rooms VALUES(9105,91,'A fluffy white cloud.',replace('You find yourself standing on a small cloud.  The cloud feels kind\nof spongy beneath your feet.  You find it hard to see anything in\nthe distance as wisps of cloud blow over your face.\n','\n',char(10)));
INSERT INTO rooms VALUES(9106,91,'A fluffy white cloud.',replace('You find yourself standing on a small cloud.  The cloud feels kind\nof spongy beneath your feet.  You find it hard to see anything in\nthe distance as wisps of cloud blow over your face.\n','\n',char(10)));
INSERT INTO rooms VALUES(9107,91,'A fluffy white cloud.',replace('You find yourself standing on a small cloud.  The cloud feels kind\nof spongy beneath your feet.  You find it hard to see anything in\nthe distance as wisps of cloud blow over your face.\n','\n',char(10)));
INSERT INTO rooms VALUES(9108,91,'A fluffy white cloud.',replace('You find yourself standing on a small cloud.  The cloud feels kind\nof spongy beneath your feet.  You find it hard to see anything in\nthe distance as wisps of cloud blow over your face.\n','\n',char(10)));
INSERT INTO rooms VALUES(9109,91,'A fluffy white cloud.',replace('You find yourself standing on a small cloud.  The cloud feels kind\nof spongy beneath your feet.  You find it hard to see anything in\nthe distance as wisps of cloud blow over your face.\n','\n',char(10)));
INSERT INTO rooms VALUES(9110,91,'An ominous storm cloud.',replace('You find yourself in a storm.  Lightning flashes and thunder\ncrashes, making you wish you were dry and warm.\n','\n',char(10)));
INSERT INTO rooms VALUES(9111,91,'High and perilous cliff',replace('You are on a high and rocky cliff.  To the west you see a huge\nominous storm cloud moving this way.  You might want to take cover\nbefore the storm hits.  You think that there is a narrow trail\nleading to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(9112,91,'Narrow rocky trail.',replace('A narrow trail leads down towards the mountain and north toward the\ncliff.  It seems to fade in and out as it winds up the hill.\nObviously, it has not been maintained in years.\n','\n',char(10)));
INSERT INTO rooms VALUES(9113,91,'Small valley.',replace('You are in a lush valley full of trees and other vegetation and the\nodd carcass or two.  The trail leads south and it leads up.\n','\n',char(10)));
INSERT INTO rooms VALUES(9114,91,'Small valley.',replace('You are in a lush valley full of trees and other vegetation and the\nodd carcass or three.  The trail leads north and it leads down into\na crevasse.\n','\n',char(10)));
INSERT INTO rooms VALUES(9115,91,'Deep, slippery crevice.',replace('The crevice is deep and a little dim and it is hard to make your\nway around.  A mist makes everything a little damp and slippery.\nBetter take your time climbing through here.\n','\n',char(10)));
INSERT INTO rooms VALUES(9116,91,'Incredibly slippery crevice.',replace('The crevice is getting more and more slippery.  You are getting\nincredibly nervous and want to turn back.  To the east is the\ncrevice and trail you were following.  Below, you can just see the\nedge of a cliff through the mist.  There is no trail leading there,\njust a smooth, flat, dew-covered rock that almost resembles a\nslide ...\n','\n',char(10)));
INSERT INTO rooms VALUES(9117,91,'Steep mountainside.',replace('From here, you can see forever.  Clouds, birds, the forest.\nMidgaard is far, far to the west.  What a postcard perfect view!\n','\n',char(10)));
INSERT INTO rooms VALUES(9118,91,'Steep mountainside.',replace('From here, you can see forever.  Clouds, birds, the forest.\nMidgaard is far, far to the west.  What a postcard perfect view!\n','\n',char(10)));
INSERT INTO rooms VALUES(9119,91,'Treacherous Cliff.',replace('The cliff is rocky and difficult to negotiate.  One wrong slip and\nyou could fall and break a leg or impale yourself or something else\nnasty.\n','\n',char(10)));
INSERT INTO rooms VALUES(9120,91,'Cliff Face.',replace('You are more than a little nervous climbing on this almost vertical\ncliff face.  You miraculously find places to grab onto and little\nledges to rest on.  You see a small cave here.\n','\n',char(10)));
INSERT INTO rooms VALUES(9121,91,'Dank, dark, smelly hole.',replace('This hole must have been used as a lair or nest.  There are\nfeathers and bones everywhere and the floor is covered with\nsomething disgusting.\n','\n',char(10)));
INSERT INTO rooms VALUES(9122,91,'Large, sturdy ledge.',replace('You are on a ledge above a steep cliff face.  You can climb down\nif you want, but be careful!  After viewing the scenery, you notice\ntwo small caves here, one north and one west.\n','\n',char(10)));
INSERT INTO rooms VALUES(9123,91,'Absolutely disgusting lair.',replace('The stench in here is quite foul.  There are feathers, bones and\nrotting carcasses everywhere.  This place is absolutely gross and\nyou have to strain yourself not to lose your lunch.\n','\n',char(10)));
INSERT INTO rooms VALUES(9124,91,'Absolutely disgusting lair.',replace('The stench in here is quite foul.  There are feathers, bones and\nrotting carcasses everywhere.  This place is absolutely gross and\nyou have to strain yourself not to lose your lunch.\n','\n',char(10)));
INSERT INTO rooms VALUES(9125,91,'A fluffy white cloud.',replace('You find yourself standing on a small cloud.  The cloud feels kind\nof spongy beneath your feet.  You find it hard to see anything in\nthe distance as wisps of cloud blow over your face.\n','\n',char(10)));
INSERT INTO rooms VALUES(9126,91,'A fluffy white cloud.',replace('You find yourself standing on a small cloud.  The cloud feels kind\nof spongy beneath your feet.  You find it hard to see anything in\nthe distance as wisps of cloud blow over your face.\n','\n',char(10)));
INSERT INTO rooms VALUES(9127,91,'A fluffy white cloud.',replace('You find yourself standing on a small cloud.  The cloud feels kind\nof spongy beneath your feet.  You find it hard to see anything in\nthe distance as wisps of cloud blow over your face.\n','\n',char(10)));
INSERT INTO rooms VALUES(9128,91,'A fluffy white cloud.',replace('You find yourself standing on a small cloud.  The cloud feels kind\nof spongy beneath your feet.  You find it hard to see anything in\nthe distance as wisps of cloud blow over your face.\n','\n',char(10)));
INSERT INTO rooms VALUES(9129,91,'Sleepy little cloud.',replace('This cloud is peacefully snoozing away, enjoying himself.  There\nis grumpy cloud to the east and a rather shy cloud north of here.\n','\n',char(10)));
INSERT INTO rooms VALUES(9130,91,'Grumpy little cloud.',replace('This cloud mutters and grumbles at you.  You have to jump quickly\nto avoid a lightning bolt that passes by your toe.  Your aren''t\nsure but you think you hear the cloud snicker.\n','\n',char(10)));
INSERT INTO rooms VALUES(9131,91,'Happy little cloud.',replace('You hear the cloud humming a little song to itself, but you can''t\nfigure out the song.\n','\n',char(10)));
INSERT INTO rooms VALUES(9132,91,'Bashful little cloud.',replace('This cloud blushes and tries to avoid your glance as you look at\nyour surroundings.  You decide that overall it is a peaceful little\ncloud.\n','\n',char(10)));
INSERT INTO rooms VALUES(9133,91,'Sneezing little cloud.',replace('The cloud is wracked with sneezes.  At first you thought you were\nin an earthquake before you realize where you are!\n','\n',char(10)));
INSERT INTO rooms VALUES(9134,91,'Dopey little cloud.',replace('This cloud is too busy daydreaming to watch where its going.  It\ndoesn''t even notice you landing on it.  It looks like it couldn''t\nfigure its way out of an open box.\n','\n',char(10)));
INSERT INTO rooms VALUES(9135,91,'Doc-like little cloud.',replace('The cloud looks at you through its Lennon like specs and examines\nyou quite scientifically.\n','\n',char(10)));
INSERT INTO rooms VALUES(9136,91,'Snowy, white cloud.',replace('You shiver as you stand here.  This beautiful, fluffy, pure white\ncloud is snowing.  The snow is pure and sweet as it melts in your\nmouth.  What a nifty cloud to be on.\n','\n',char(10)));
INSERT INTO rooms VALUES(9137,91,'Cold, damp cloud.',replace('Your mood grows grumpy as you find yourself cold and wet from this\ndismal cloud.  You notice a rock outcropping above you.\n','\n',char(10)));
INSERT INTO rooms VALUES(9138,91,'Mysterious rock outcropping.',replace('This rock outcropping just seems to hang in midair.  To the north\nyou see a house and if you ease yourself down, you can land on a\nrather damp, dismal cloud.  The door to the house is closed.\n','\n',char(10)));
INSERT INTO rooms VALUES(9139,91,'Foyer.',replace('Shadows play tricks on your eyes.  Everytime you think you see\nsomething in a corner and turn to get a better look, nothing is\nthere.  The place is very dark.  Even with a torch, you have\ntrouble making out the room to the east.\n','\n',char(10)));
INSERT INTO rooms VALUES(9140,91,'Tower.',replace('You are in a musty old tower.  The smell of mold and mildew is\nalmost overpowering.  You hear strange creaks and groans ... is it\nthe wind or did someone (something?) make that noise.  To the west\nis the house and there is a stairway leading up into the tower.\n','\n',char(10)));
INSERT INTO rooms VALUES(9141,91,'Witches Tower',replace('Here you see strange things of arcane value.  There is a cauldron in the\ncorner bubbling madly, belching a foul brew that must have come from hell.\nOn shelves lie jars of strange creatures you have never seen before, or\nhope to again.  A picture of a familiar temple hangs on the east wall.\n','\n',char(10)));
INSERT INTO rooms VALUES(9142,91,'Suspicious little raincloud.',replace('On second glance, this cloud doesn''t seem much like a raincloud.\nA balloon sticks out of the top and you think you hear it humming\nsomething like, ''Tut, tut!  It looks like rain!''\n','\n',char(10)));
INSERT INTO rooms VALUES(9143,91,'Cirrus maximus cloud.',replace('This cloud looks like it is of the cirrus maximus genre of clouds.\n','\n',char(10)));
INSERT INTO rooms VALUES(9144,91,'Raging hurricane.',replace('You are buffeted and knocked about by the almost godlike strength\nof the raging hurricane.  It is hard to see and hear anything.\nYour only thought is to seek refuge from the storm.\n','\n',char(10)));
INSERT INTO rooms VALUES(9145,91,'Raging hurricane.',replace('You are buffeted and knocked about by the almost godlike strength\nof the raging hurricane.  It is hard to see and hear anything.\nYour only thought is to seek refuge from the storm.\n','\n',char(10)));
INSERT INTO rooms VALUES(9146,91,'Raging hurricane.',replace('You are buffeted and knocked about by the almost godlike strength\nof the raging hurricane.  It is hard to see and hear anything.\nYour only thought is to seek refuge from the storm.\n','\n',char(10)));
INSERT INTO rooms VALUES(9147,91,'Raging hurricane.',replace('You are buffeted and knocked about by the almost godlike strength\nof the raging hurricane.  It is hard to see and hear anything.\nYour only thought is to seek refuge from the storm.\n','\n',char(10)));
INSERT INTO rooms VALUES(9148,91,'Raging hurricane.',replace('You are buffeted and knocked about by the almost godlike strength\nof the raging hurricane.  It is hard to see and hear anything.\nYour only thought is to seek refuge from the storm.\n','\n',char(10)));
INSERT INTO rooms VALUES(9149,91,'Raging hurricane.',replace('You are buffeted and knocked about by the almost godlike strength\nof the raging hurricane.  It is hard to see and hear anything.\nYour only thought is to seek refuge from the storm.\n','\n',char(10)));
INSERT INTO rooms VALUES(9150,91,'Raging hurricane.',replace('You are buffeted and knocked about by the almost godlike strength\nof the raging hurricane.  It is hard to see and hear anything.\nYour only thought is to seek refuge from the storm.\n','\n',char(10)));
INSERT INTO rooms VALUES(9151,91,'Raging hurricane.',replace('You are buffeted and knocked about by the almost godlike strength\nof the raging hurricane.  It is hard to see and hear anything.\nYour only thought is to seek refuge from the storm.\n','\n',char(10)));
INSERT INTO rooms VALUES(9152,91,'Raging hurricane.',replace('You are buffeted and knocked about by the almost godlike strength\nof the raging hurricane.  It is hard to see and hear anything.\nYour only thought is to seek refuge from the storm.\n','\n',char(10)));
INSERT INTO rooms VALUES(9153,91,'Calm cloud.',replace('This cloud is just outside the hurricane.  It looks like it might\nget sucked in, but you feel safe for the moment.\n','\n',char(10)));
INSERT INTO rooms VALUES(9154,91,'Mountainside.',replace('You find yourself on the side of a huge granite mountain.  The air\nis quite thin so you know you are at a very high altitude.  There\nis no plant life beyond moss and lichen in this lonely, barren\nplace.\n','\n',char(10)));
INSERT INTO rooms VALUES(9155,91,'Mountainside.',replace('You find yourself on the side of a huge granite mountain.  The air\nis quite thin so you know you are at a very high altitude.  There\nis no plant life beyond moss and lichen in this lonely, barren\nplace.\n','\n',char(10)));
INSERT INTO rooms VALUES(9156,91,'Roc''s Nest.',replace('You are standing in a nest.  It is huge, at least two spear-lengths\nwide.  You see three eggs in the center.  They are knee high, brown\nand look almost leathery.  Better hope mom isn''t around!\n','\n',char(10)));
INSERT INTO rooms VALUES(9157,91,'Cumulative nimbus cloud.',replace('This cloud looks like it belongs to the phylum of cumulative nimbus clouds.\n','\n',char(10)));
INSERT INTO rooms VALUES(9158,91,'Dark hidden cloud.',replace('This cloud looks like the perfect place to hide.\n','\n',char(10)));
INSERT INTO rooms VALUES(9159,91,'Yet another cloud',replace('You find yourself in yet another cloud.  Will the madness never\nend?  There is a rope ladder leading up.\n','\n',char(10)));
INSERT INTO rooms VALUES(9160,91,'Front gate',replace('There is a gate here.  It is huge, towering over you.  It creaks\nas it sways in the breeze.  To the south you see a huge lawn.\nThere is a rope ladder leading down.\n','\n',char(10)));
INSERT INTO rooms VALUES(9161,91,'Lawn',replace('The lawn seems to stretch and stretch to the south and to the west.\nNorth of you is a gate.  The grass is emerald green and luscious,\nobviously well cared for.\n','\n',char(10)));
INSERT INTO rooms VALUES(9162,91,'Croquet game',replace('A croquet game has been set up and carelessly left out.  Who ever\nwas playing blue was in the lead before they quit.  Benches have\nbeen set up for spectators and players to enjoy themselves.\n','\n',char(10)));
INSERT INTO rooms VALUES(9163,91,'Huge, gorgeous fountain.',replace('An enormous golden fountain is here.  You see swans, angels,\ngryphons and a host of other creatures in the fountain.  The\nfountain empties into a huge pool that looks quite inviting.\n','\n',char(10)));
INSERT INTO rooms VALUES(9164,91,'Patio.',replace('A huge patio overlooks the lawn area.  There are enough tables and\nchairs for a party of 100.  The tables and chairs are ornate and\nexpensive, tasteful and elegant.  Stairs lead up to the main\nhouse.\n','\n',char(10)));
INSERT INTO rooms VALUES(9165,91,'Long stairway.',replace('This stairway is suspended on clouds.  It leads from the house to\nthe front lawn.  The banisters are made of ornate gold and silver\ninlays.\n','\n',char(10)));
INSERT INTO rooms VALUES(9166,91,'Front door',replace('You stand at the front door of an immense, sprawling mansion made\nof granite and marble.  The door is at least 10 feet high and is\nmade of oak.\n','\n',char(10)));
INSERT INTO rooms VALUES(9167,91,'Lawn northwest of house.',replace('You stand just outside the northwest corner of the house.  You try\nto peek in a window, but it is a little too high to see anything.\n','\n',char(10)));
INSERT INTO rooms VALUES(9168,91,'Lawn west of house.',replace('You stand just outside the west corner of the house.  You try to\npeek in a window, but it is a little too high to see anything.\n','\n',char(10)));
INSERT INTO rooms VALUES(9169,91,'Lawn southwest of house.',replace('You stand just outside the southwest corner of the house.  You try\nto peek in a window, but it is a little too high to see anything.\n','\n',char(10)));
INSERT INTO rooms VALUES(9170,91,'Lawn south of house.',replace('You stand just outside the south corner of the house.  You try to\npeek in a window, but it is a little too high to see anything.\n','\n',char(10)));
INSERT INTO rooms VALUES(9171,91,'Lawn southeast of house.',replace('You stand just outside the southeast corner of the house.  You try\nto peek in a window, but it is a little too high to see anything.\n','\n',char(10)));
INSERT INTO rooms VALUES(9172,91,'Lawn east of house.',replace('You stand just outside the east corner of the house.  You try to\npeek in a window, but it is a little too high to see anything.\n','\n',char(10)));
INSERT INTO rooms VALUES(9173,91,'Lawn northeast of house.',replace('You stand just outside the northeast corner of the house.  You try\nto peek in a window, but it is a little too high to see anything.\n','\n',char(10)));
INSERT INTO rooms VALUES(9174,91,'Dirty, dusty tunnel.',replace('This dirty dusty tunnel must lead somewhere.\n','\n',char(10)));
INSERT INTO rooms VALUES(9175,91,'Basement.',replace('This seems like your average basement.  Old Christmas decorations,\nsuitcases, bicycles litter your way.  You hear the squeaking of\nrats in the corners.\n','\n',char(10)));
INSERT INTO rooms VALUES(9176,91,'Bottom of the stairs.',replace('You stand at the bottom of a long staircase leading up to the main\nhouse.  To the south you can barely make out the accumulated\nclutter gathered throughout the years.\n','\n',char(10)));
INSERT INTO rooms VALUES(9177,91,'Foyer.',replace('"Magnificent" does not even begin to describe the foyer.  Lavishly\ndecorated, yet elegant, it gives an impression of indescribable\nwealth.  Paintings and tapestries line the walls depicting scenes\nfrom throughout history.  Antiques furnitures and oriental rugs are\ntastefully placed in ideal spots.  The door is at least 10 feet\nhigh and is made of oak.\n','\n',char(10)));
INSERT INTO rooms VALUES(9178,91,'Elegant hallway.',replace('You are in a long, sprawling hallway connecting the eastern and\nwestern wings of the house.  There are several chairs and sofas in\nthe hallway and some gorgeous, handwoven drapes.\n','\n',char(10)));
INSERT INTO rooms VALUES(9179,91,'Library',replace('You are overwhelmed by the sheer volumes of books here.  The\nshelves stretch all the way to the ceiling and are on every wall,\neven above the doorway.  There are chairs for sitting and reading\nand a desk for more intense studies.\n','\n',char(10)));
INSERT INTO rooms VALUES(9180,91,'Arboretum.',replace('A small indoor garden so that the residents don''t have to go\noutside to enjoy plants and commune with nature.  There are several\ntrees, a small pond and flowers of every kind.\n','\n',char(10)));
INSERT INTO rooms VALUES(9181,91,'Western tower.',replace('You are in the bottom part of a tower.  A draft brings a chill to\nyour spine and causes creaks and groans.  Curtains flutter in the\nwind, causing quite a distraction.  When you go to shut the window,\nyou see that the window is closed.  An old, wooden staircase leads\nup into darkness.\n','\n',char(10)));
INSERT INTO rooms VALUES(9182,91,'Western tower.',replace('The tower creaks and groans, almost as if it were muttering to\nitself.  There are windows displaying a full moon, reigning over\nthe night sky.  The room is dark and there is almost a musty odor\nto it.  You are surprised that you can''t detect any dust or dirt,\nalthough there are a couple of cobwebs in the corner.\n','\n',char(10)));
INSERT INTO rooms VALUES(9183,91,'Elegant hallway.',replace('You are in a long, sprawling hallway connecting the eastern and\nwestern wings of the house.  There are several chairs and sofas in\nthe hallway and some gorgeous, handwoven drapes.\n','\n',char(10)));
INSERT INTO rooms VALUES(9184,91,'Conservatory',replace('Here was the rehearsal and recital room for the residents of the\nestate.  There is a Steinway piano in the corner and various gilded\ninstruments are on display in a glass cabinet.\n','\n',char(10)));
INSERT INTO rooms VALUES(9185,91,'Office',replace('You find yourself in a lavish office.  The desk is absolutely huge,\nat least ten feet by five feet and made of ebony and inlaid with\nmother of pearl.  A grandfather clock towers over the room,\nmechanically ticking and tocking the hours away.\n','\n',char(10)));
INSERT INTO rooms VALUES(9186,91,'Eastern tower.',replace('You are in the bottom part of a tower.  A draft brings a chill to\nyour spine and causes creaks and groans.  Curtains flutter in the\nwind, causing quite a distraction.  When you go to shut the window,\nyou see that the window is closed.  An old, wooden staircase leads\nup into darkness.\n','\n',char(10)));
INSERT INTO rooms VALUES(9187,91,'Eastern tower.',replace('The tower creaks and groans, almost as if it were muttering to\nitself.  There are windows displaying a full moon, reigning over\nthe night sky.  The room is dark and there is almost a musty odor\nto it.  You are surprised that you can''t detect any dust or dirt,\nalthough there are a couple of cobwebs in the corner.\n','\n',char(10)));
INSERT INTO rooms VALUES(9199,91,'Mid-Air.',replace('You slide down the moisture covered rock, gaining speed as you\napproach the cliff.  Realizing your foolish error, you madly claw\nat the rock, vainly trying to get a precious hold and save your\nworthless hide.  Next time, heed your conscience.\n\nYou''ve fallen, and you can''t get up!!!\n','\n',char(10)));
INSERT INTO rooms VALUES(9201,92,'A Mountain Path',replace('You are on a mountain path which ascends a steep mountainside.  The trail\ncurves around the mountain so that you cannot really see what lies ahead.\nYou do sense great power though coming from the area behind the mountain.\n','\n',char(10)));
INSERT INTO rooms VALUES(9202,92,'A Mountain Path',replace('You are on a rocky mountain path leading up and around a steep mountainside.\nYou sense a glow from the area beyond the mountain, which you cannot see yet.\n','\n',char(10)));
INSERT INTO rooms VALUES(9203,92,'Mountainside Tombs',replace('There are a few stone heaps here and there, the tombs of those who did not\nlast the arduous journey up the mountain.  Curiously you notice a few\nuncovered bodies which don''t seem to have died of exhaustion.  The path curves\neast around the mountain.\n','\n',char(10)));
INSERT INTO rooms VALUES(9204,92,'A Blind Curve on the Mountain Path.',replace('This looks like a normal mountain path, but it is NOT!  This section of the\npath is habitated by a huge (and of course, man-eating) Cyclops.  The path\nmakes its final ascent to an overlook.\n','\n',char(10)));
INSERT INTO rooms VALUES(9205,92,'Vista',replace('This is a stunning vista overlooking a canyon.  There is a sign here that says:\n\n	BEHOLD -- ELEMENTAL CANYON\n\nFire leaps up from firepits in the western part of the canyon.  The sky looks\nfunny, and the air seems hazy to the northwest.  Electricity sparks\nintermittently in the northeast.  To the east you see a strong, magic-looking\nriver flowing through the canyon.  Also to the east you spy a cave entrance\nleading into the canyon wall.  The path descends to the north to another\noverlook.\n','\n',char(10)));
INSERT INTO rooms VALUES(9206,92,'The Overlook',replace('You see various elemental servants wandering around the canyon.  The noise of\nhumming coming from the canyon gets louder.  The path makes a steep descent\ninto the canyon here.\n','\n',char(10)));
INSERT INTO rooms VALUES(9207,92,'Entrance to Elemental Canyon',replace('You are awed by the sounds and sights of great powers at works here.\nElemental servants bustle back and forth doing the biddings of the elemental\nrulers.  You see a sort of cross roads to the north, and you can climb up to\nthe overlook here.\n','\n',char(10)));
INSERT INTO rooms VALUES(9208,92,'The Floor of the Canyon',replace('Various elemental forms wander the floor of the canyon.  Some seem to be\ngoing about their business, while others seem to have no business at all.\nIn general, it is calm, yet there is always a incessant buzz of things\ngoing on about.  The canyon continues north and east.\n','\n',char(10)));
INSERT INTO rooms VALUES(9209,92,'Elemental Gateway',replace('To the west a path dips and winds among some flowing firepits.  To the\nnortheast a path goes toward the river.  Beyond toward the northeast and\nnorthwest are outcrops which rise up from the canyon floor. To the east there\nis a cave mouth which leads into the canyon wall.  And to the south the path\nleads up, away, and out of the canyon.  Various pure and cross-breeds of\nelemental forms wander the canyon floor, which extends in a wide swath\nnorthwards.\n','\n',char(10)));
INSERT INTO rooms VALUES(9210,92,'The Floor of the Canyon',replace('Various elemental forms wander the floor of the canyon.  Some seem to be\ngoing about their business, while others seem to have no business at\nall.  In general, it is calm, yet there is always a incessant buzz of\nthings going on about.  The canyon floor extends north and west.  There is a\ncave mouth set into the canyon wall to the east.\n','\n',char(10)));
INSERT INTO rooms VALUES(9211,92,'The Floor of the Canyon',replace('Various elemental forms wander the floor of the canyon.  Some seem to be\ngoing about their business, while others seem to have no business at\nall.  In general, it is calm, yet there is always an incessant buzz of\nthings going on about.  The canyon floor extends off to the north, east,\nand south.\n','\n',char(10)));
INSERT INTO rooms VALUES(9212,92,'The Floor of the Canyon',replace('Various elemental forms wander the floor of the canyon.  Some seem to be\ngoing about their business, while others seem to have no business at\nall.  In general, it is calm, yet there is always an incessant buzz of\nthings going on about.  The canyon floor extends in all directions.\n','\n',char(10)));
INSERT INTO rooms VALUES(9213,92,'The Floor of the Canyon',replace('Various elemental forms wander the floor of the canyon.  Some seem to be\ngoing about their business, while others seem to have no business at\nall.  In general, it is calm, yet there is always an incessant buzz of\nthings going on about.  The canyon floor extends north, south, and west.\nA path follows a stream to the east.\n','\n',char(10)));
INSERT INTO rooms VALUES(9214,92,'The Floor of the Canyon',replace('Various elemental forms wander the floor of the canyon.  Some seem to be\ngoing about their business, while others seem to have no business at\nall.  In general, it is calm, yet there is always an incessant buzz of\nthings going on about. The canyon floor extends north, east, and south.\nTo the west a garden is on fire.\n','\n',char(10)));
INSERT INTO rooms VALUES(9215,92,'The Floor of the Canyon',replace('Various elemental forms wander the floor of the canyon.  Some seem to be\ngoing about their business, while others seem to have no business at\nall.  In general, it is calm, yet there is always an incessant buzz of\nthings going on about.  The canyon floor extends in all directions.\n','\n',char(10)));
INSERT INTO rooms VALUES(9216,92,'The Floor of the Canyon',replace('Various elemental forms wander the floor of the canyon.  Some seem to be\ngoing about their business, while others seem to have no business at\nall.  In general, it is calm, yet there is always an incessant buzz of\nthings going on about.  The Canyon floor extends north, south and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(9217,92,'The Floor of the Canyon',replace('Various elemental forms wander the floor of the canyon.  Some seem to be\ngoing about their business, while others seem to have no business at\nall.  In general, it is calm, yet there is always an incessant buzz of\nthings going on about. The canyon floor extends east and south.  You can\nclimb a rise in the canyon floor to the north.\n','\n',char(10)));
INSERT INTO rooms VALUES(9218,92,'The Floor of the Canyon',replace('Various elemental forms wander the floor of the canyon.  Some seem to be\ngoing about their business, while others seem to have no business at\nall.  In general, it is calm, yet there is always an incessant buzz of\nthings going on about.  The canyon floor extends east, south, and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(9219,92,'The Floor of the Canyon',replace('Various elemental forms wander the floor of the canyon.  Some seem to be\ngoing about their business, while others seem to have no business at\nall.  In general, it is calm, yet there is always an incessant buzz of\nthings going on about.  The canyon floor extends south and west.  You can\nclimb a rise in the canyon floor to the north.\n','\n',char(10)));
INSERT INTO rooms VALUES(9220,92,'Dark Cave',replace('You notice a path winding east among some huge boulders.  You feel a powerful\nsource of energy from that direction.\n','\n',char(10)));
INSERT INTO rooms VALUES(9221,92,'Darker Caves',replace('You can barely see your way even with a light source.  The rocks of the cave\nare even darker than the darkness.  You hear a powerful humming all around\nyou.  Cave paths go south and east roughly, its hard to tell exactly when you\ncan''t see where you are going.\n','\n',char(10)));
INSERT INTO rooms VALUES(9222,92,'Darker Caves',replace('You can barely see your way even with a light source.  The rocks of the cave\nare even darker than the darkness.  You hear a powerful humming all around\nyou.  Cave paths go south and west roughly; it''s hard to tell exactly when you\ncan''t see where you are going.\n','\n',char(10)));
INSERT INTO rooms VALUES(9223,92,'Darker Caves',replace('You can barely see your way even with a light source.  The rocks of the cave\nare even darker than the darkness.  You hear a powerful humming all around you.\nCave paths go north, south and east roughly; it''s hard to tell exactly when\nyou can''t see where you are going.\n','\n',char(10)));
INSERT INTO rooms VALUES(9224,92,'Darker Caves',replace('You can barely see your way even with a light source.  The rocks of the cave\nare even darker than the darkness.  You hear a powerful humming all around you.\nCave paths go north, south and west roughly, it''s hard to tell exactly when you\ncan''t see where you are going.\n','\n',char(10)));
INSERT INTO rooms VALUES(9225,92,'Darkest Caves',replace('Your light doesn''t even seem to work here.  Even magical light sources seem\nonly to illuminate about a foot ahead of you.  You suddenly realize that the\npath has descended quite a bit but you didn''t notice before because of the\ndarkness.  You sense a great presence off to the east aways.\n','\n',char(10)));
INSERT INTO rooms VALUES(9226,92,'Darkest Caves',replace('Your light doesn''t even seem to work here.  Even magical light sources seem\nonly to illuminate about a foot ahead of you.  You suddenly realize that the\npath has descended quite a bit but you didn''t notice before because of the\ndarkness.  You sense a great presence directly to the east.\n','\n',char(10)));
INSERT INTO rooms VALUES(9227,92,'Earth Chamber',replace('This is the abode of the Earth Ruler.  He decides about earthquakes,\nlandslides, and avalanches.  The Earth Ruler sits upon a huge marble throne\ncarved into the wall.\n','\n',char(10)));
INSERT INTO rooms VALUES(9228,92,'By the River',replace('The water in the river seems to bubble and froth with magic.  Though it\nsplashes playfully on you, it does not seem wet.  The path leads north closer\nto the water. To the west you see a T-intersection.\n','\n',char(10)));
INSERT INTO rooms VALUES(9229,92,'In the River',replace('To continue you had to walk right in the river.  Though you walk along in\nwater up to your knees, you do not seem to get wet.  A bay stretches out to\nthe north and the river goes south.\n','\n',char(10)));
INSERT INTO rooms VALUES(9230,92,'Elemental Bay',replace('The water is crystal clear here and you can see the bottom of the bay 30 feet\nbelow you.  Then you realize you are walking on the water itself.  Truly\nmagical water indeed.  Though you splash through the bay you do not get wet.\n','\n',char(10)));
INSERT INTO rooms VALUES(9231,92,'Elemental Bay',replace('The water is crystal clear here and you can see the bottom of the bay 30 feet\nbelow you.  Then you realize you are walking on the water itself.  Truly\nmagical water indeed.  Though you splash through the bay you do not get wet.\n','\n',char(10)));
INSERT INTO rooms VALUES(9232,92,'Elemental Bay',replace('The water is crystal clear here and you can see the bottom of the bay 30 feet\nbelow you.  Then you realize you are walking on the water itself.  Truly\nmagical water indeed.  Though you splash through the bay you do not get wet.\n','\n',char(10)));
INSERT INTO rooms VALUES(9233,92,'Elemental Bay',replace('The water is crystal clear here and you can see the bottom of the bay 30 feet\nbelow you.  Then you realize you are walking on the water itself.  Truly\nmagical water indeed.  Though you splash through the bay you do not get wet.\n','\n',char(10)));
INSERT INTO rooms VALUES(9234,92,'Elemental Bay',replace('The water is crystal clear here and you can see the bottom of the bay 30 feet\nbelow you.  Then you realize you are walking on the water itself.  Truly\nmagical water indeed.  Though you splash through the bay you do not get wet.\n','\n',char(10)));
INSERT INTO rooms VALUES(9235,92,'Elemental Bay',replace('The water is crystal clear here and you can see the bottom of the bay 30 feet\nbelow you.  Then you realize you are walking on the water itself.  Truly\nmagical water indeed.  Though you splash through the bay you do not get wet.\n','\n',char(10)));
INSERT INTO rooms VALUES(9236,92,'Water Chamber',replace('This chamber was magically created here on the floor of the bay.  It looks\nlike it''s been here for a long, long time.  Though you are ''under water'' there\nis no difficulty breathing normally, and oddly you do not feel the pressure of\nthe water above you.\n','\n',char(10)));
INSERT INTO rooms VALUES(9237,92,'A Fiery Pathway',replace('You tread carefully along a path which dips and turns among geysers of fire.\nMiniature volcanoes spew lava in rivers.  The fire is hot but not altogether\ndangerous.  The path extends east and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(9238,92,'A Fiery Pathway',replace('You tread carefully along a path which dips and turns among pits of fire and\nbeds of coals.  A garden to the west glows with an everlasting fire.\n','\n',char(10)));
INSERT INTO rooms VALUES(9242,92,'The Burning Gardens',replace('Everywhere around you the landscape is afire; the rocks, the shrubs and even\nthe air seems to be aflame.  Curiously, the magical fire does not seem to\nconsume its hosts.  A path leads east among some fire pits.\n','\n',char(10)));
INSERT INTO rooms VALUES(9245,92,'The Fire Chamber',replace('The fire ruler sits upon a throne made of blue flame.  Little flickers of\nflame dance to and fro for the entertainment of the ruler.\n','\n',char(10)));
INSERT INTO rooms VALUES(9246,92,'Electric Pathway',replace('The pathway glows and hums because of the electricity pulsing through it.\nIt seems almost soothing to your weary feet.  To the north there is a\nsunken-in area.  A path leads east also.\n','\n',char(10)));
INSERT INTO rooms VALUES(9247,92,'The Electric Playground',replace('Though there is a seemingly carefree atmosphere here, you sense that\nsomething much more important takes place near by.  The electric playground\nextends north and east.\n','\n',char(10)));
INSERT INTO rooms VALUES(9248,92,'The Electric Playground',replace('Though there is a seemingly carefree atmosphere here, you sense that\nsomething much more important takes place near by.  There is an electric\npath heading away south.  The playground extends north and west.\n','\n',char(10)));
INSERT INTO rooms VALUES(9249,92,'The Electric Playground',replace('Though there is a seemingly carefree atmosphere here, you sense that\nsomething much more important takes place near by.  The playground continues\nsouth and east.\n','\n',char(10)));
INSERT INTO rooms VALUES(9250,92,'The Electric Playground',replace('Though there is a seemingly carefree atmosphere here, you sense that\nsomething much more important takes place near by.  The playground is\nsouth and west.  Something more important catches your eye to the east.\n','\n',char(10)));
INSERT INTO rooms VALUES(9251,92,'Lightning Causeway',replace('Up a set of stairs carved into the hill you see intermittent flashes of\nlightning.  A continuous hum also comes form that direction.  To the west\nis the electric playground.\n','\n',char(10)));
INSERT INTO rooms VALUES(9252,92,'Lightning Chamber',replace('There is some sort of control panel here. Apparently the Lightning Ruler\nobserves and controls electric forces from here.  A set of steps carved into\nthe hill lead down to a causeway.\n','\n',char(10)));
INSERT INTO rooms VALUES(9253,92,'Mesa West',replace('An electric path starts to the west.  The mesa continues to the east.\nOr you can climb down to the canyon floor to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(9254,92,'Mesa East',replace('A path starts to the north.  The mesa continues to the west.\nOr you can climb down to the canyon floor to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(9255,92,'Floating in Air',replace('Last you knew, you were walking on the mesa.  Abruptly the path dropped\nfrom beneath your feet much to quick for you to recover.  Instead of\nplunging to your death, you seemingly miss the ground and begin walking\non air.  The space to the north and east seems just thin air, but you can\nwalk there.  The pathway you came from is to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(9256,92,'Floating in Air',replace('You look down and see the ground 100 feet below you.  The wind whispering\nin your ear seems to reassure you that this is fine.  To the north aways\nyou spy a portal of sorts.  To the west is more thin air.\n','\n',char(10)));
INSERT INTO rooms VALUES(9257,92,'Floating in Air',replace('You look down and see the ground 100 feet below you.  The wind whispering\nin your ear seems to reassure you that this is fine.  To the east aways\nyou spy a portal of sorts.  To the south is more thin air.\n','\n',char(10)));
INSERT INTO rooms VALUES(9258,92,'Floating in Air',replace('You look down and see the ground 100 feet below you.  The wind whispering\nin your ear seems to reassure you that this is fine. There is a portal\nhanging in midair here. It is to the east.  You can float south or west\nif you''d like.\n','\n',char(10)));
INSERT INTO rooms VALUES(9259,92,'Windy Tunnel',replace('A tunnel leads east.  To the west you can enter a portal. The wind in\nthis tunnel is quite fierce, it seems as if it''s forced.  \n','\n',char(10)));
INSERT INTO rooms VALUES(9260,92,'Air Chamber',replace('Tiny tornadoes come and go and dance along the ground here.  At the back\nof the chamber you notice a huge throne made of swirling clouds.\nA tunnel leads west.\n','\n',char(10)));
INSERT INTO rooms VALUES(9301,93,'Inside a Tavern',replace('You are inside a dimly-lit room.  The atmosphere makes you feel uncomfortable.\nIn front of you stands a mysterious gypsy.  She whispers ''Your fate and\ndestiny lie beyond this world.''  You are still wondering what she means when\nyou suddenly notice the crystal ball ... it glows fiercely and displays the\nUniverse!\n','\n',char(10)));
INSERT INTO rooms VALUES(9302,93,'Inside the Crystal Ball',replace('You have touched the crystal ball and find that you have gone inside it:\na world of stars and wonders!  As you look back you figure out there is no\nchoice but to go forward.\n','\n',char(10)));
INSERT INTO rooms VALUES(9303,93,'Inside the Galaxy',replace('You are now inside the galaxy, around you you see stars and nebulae smiling\nat your presence, and comets and meteors wandering around you.  You realize\nthat this world may not be the true galaxy after all, but just another\nfantasy zone.  Exits lie virtually in all directions.\n','\n',char(10)));
INSERT INTO rooms VALUES(9304,93,'On an InterGalactic Walkway',replace('You are on a well-paved path which seems that it was made deliberately for\nvisitors like you.  The walkway continues north and a small exit lies west.\n','\n',char(10)));
INSERT INTO rooms VALUES(9305,93,'End of the InterGalactic Walkway',replace('You notice the walkway has come to an abrupt end and you wonder why. You see\nthat there is still a small path which leads north and one to the west.\nTo the east lies a bridge.\n','\n',char(10)));
INSERT INTO rooms VALUES(9306,93,'At the Undeveloped Part of the Galaxy',replace('This place looks deserted, covered with space debris.  Not a sign of life\nis around.\n','\n',char(10)));
INSERT INTO rooms VALUES(9308,93,'On the Bridge of Stars',replace('This bridge has been made by the stars to honour their ancestors.  The\nbridge itself shines brightly and makes you feel that you are walking on\na path of light.  An entrance to an ancient building lies north and to\nthe east lies the Milky Way.\n','\n',char(10)));
INSERT INTO rooms VALUES(9309,93,'On the Bridge of Nebulae',replace('This bridge, like the other, was made as a memorial.  The nebulae had to\nmake one just to show that they are as capable as the stars.  North lies\na throne room.\n','\n',char(10)));
INSERT INTO rooms VALUES(9310,93,'The Throne Room of the Nebula King',replace('You can only faintly make out that it is a throne room as it is too\ndark in here.  In the middle is an empty throne.  You wonder where\nthe King has gone, maybe he is hiding from you?\n','\n',char(10)));
INSERT INTO rooms VALUES(9312,93,'At the Start of the Milky Way',replace('It is here that the famous old Milky Way starts flowing.  You are surrounded\nby streams of mist the moment you tread on it.  You can''t see well in\nhere ... luckily you haven''t fallen yet!\n','\n',char(10)));
INSERT INTO rooms VALUES(9313,93,'Along the Milky Way',replace('You are still travelling inside this path of mist.  You notice a small\nopening to the east.\n','\n',char(10)));
INSERT INTO rooms VALUES(9314,93,'At the End of the Milky Way',replace('Just as you started enjoying this journey inside the mist, you have come to\nthe end of it.  West leads to a bridge and east leads to somewhere else.\n','\n',char(10)));
INSERT INTO rooms VALUES(9317,93,'A Small Clearing',replace('You are inside a small clearing.  You can see that there are signs of a\nliving creature nearby.\n','\n',char(10)));
INSERT INTO rooms VALUES(9318,93,'An Edge of the Galaxy',replace('You are on the very edge of the galaxy.  Nothing is here except that there\nis a path which leads down.\n','\n',char(10)));
INSERT INTO rooms VALUES(9319,93,'Very Near to a Gigantic Star',replace('You are very near to a gigantic red star.  While you are still fascinated\nby its beauty, the star keeps on growing ... suddenly you realize that you''d\nbetter leave.\n','\n',char(10)));
INSERT INTO rooms VALUES(9320,93,'Too Bright to Tell',replace('Indeed it is too bright to tell.  Because what you are witnessing is the\nrare event of a Supernova, how a star explodes itself into galactic dust.\nYou may find yourself lucky to witness this rare event but even luckier,\nyou have finally got out of this galaxy as your body turns into dust.\nThat really HURTS!  \n','\n',char(10)));
INSERT INTO rooms VALUES(9321,93,'The Star Cluster',replace('You are inside the home of the stars.  All you can see around you are stars\nand nothing else.  You eyes become pretty hurt as you look at them.\n','\n',char(10)));
INSERT INTO rooms VALUES(9322,93,'Another Edge of the Galaxy',replace('This is another uninhabited place.  Exits lie north, east and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(9323,93,'Corner of the Galaxy',replace('You wonder why the galaxy is limited.  All you have done in Astronomy\ncourses now prove worthless.  Well who told you to take one at the start?  \n','\n',char(10)));
INSERT INTO rooms VALUES(9324,93,'Lost in Space',replace('You are now lost in space.  Compasses don''t work here, sorry.  What''s more\nyou can sense darkness engulfing you.  You''d better get out quick.\n','\n',char(10)));
INSERT INTO rooms VALUES(9325,93,'Black Hole',replace('Well you have chosen the wrong path, sorry.  Nothing can escape from this\nmonster, not even light.\nPANIC!  You can''t escape!\n','\n',char(10)));
INSERT INTO rooms VALUES(9326,93,'The Homes of the Pleiades',replace('This is where the famous Seven Sisters live.  You''d better not disturb them.\n','\n',char(10)));
INSERT INTO rooms VALUES(9327,93,'Western Side of the Temple',replace('You are still wandering around this temple.  You notice exits lie in all\ndirections except west.\n','\n',char(10)));
INSERT INTO rooms VALUES(9328,93,'Orion''s Hunting Lodge',replace('This is dedicated to the Great Hunter of all time -- Orion.\nScattered on the floor is the famous hunting equipment used by him.\n','\n',char(10)));
INSERT INTO rooms VALUES(9329,93,'Northern Side of the Temple',replace('You are still wandering around this temple.  You notice exits lie in all\ndirections except north.\n','\n',char(10)));
INSERT INTO rooms VALUES(9330,93,'The Offering Chamber',replace('This is the sacred offering chamber in which sacrifices are made.  You see a\nyoung girl here, chained to the wall, as if she is waiting for execution.\nYou look up and realize the chains are sent down directly from above.\nBelow you recognize the temple of Thalos.\n','\n',char(10)));
INSERT INTO rooms VALUES(9331,93,'The Entrance of the Ancient Temple',replace('You have entered into this old temple, which was built originally for the gods\nin Mount Olympia, but it is now deserted as someone took over this part of the\nUniverse.\n','\n',char(10)));
INSERT INTO rooms VALUES(9332,93,'Hercules'' Mighty Throne',replace('You stand before the throne of a long-forgotten hero.  It is full of bounty\nthat he got from the Ten Labours. \n','\n',char(10)));
INSERT INTO rooms VALUES(9333,93,'Eastern Side of the Temple',replace('You are still wandering around this temple.  You notice exits lie in all\ndirections except east.\n','\n',char(10)));
INSERT INTO rooms VALUES(9334,93,'Perseus'' Chamber',replace('It is the chamber of the prince, Perseus.  However, he seems not to be here.\nMaybe he has gone to get Pegasus to save Andromeda?\n','\n',char(10)));
INSERT INTO rooms VALUES(9339,93,'On the Mystic Chains',replace('You are dangling on the chains.  You notice exits lie in all directions.\nUp above you see the chains continue upwards.  But a forcefield prevents\nyou from going further upwards.\n','\n',char(10)));
INSERT INTO rooms VALUES(9342,93,'On a Hill',replace('Suddenly you find yourself on a hillside.  As you look around, you notice\nthat Spring has descended upon you.\n','\n',char(10)));
INSERT INTO rooms VALUES(9343,93,'Inside a Spanish Bull-Ring',replace('You are inside what used to be a ground for bull fighting.  But you notice\nthere are no Matadors around.  Maybe they are all dead?\n','\n',char(10)));
INSERT INTO rooms VALUES(9344,93,'Inside a study',replace('This is a strange study. Besides the desks and chairs you also see a large\nmirror in the middle.  So, you wonder, is this how you make a Gemini into\ntwo Gemini?\n','\n',char(10)));
INSERT INTO rooms VALUES(9345,93,'Along the seashore',replace('You start to feel the heat of Summer.  Amongst the rocky beach you notice\nhidden forms which could be camouflaged crabs. \n','\n',char(10)));
INSERT INTO rooms VALUES(9346,93,'Within the Deep Jungle',replace('Nearby you can hear the roar of an animal.  Peering through the dense\novergrowth you think you glimpse a pair of menacing eyes.\n','\n',char(10)));
INSERT INTO rooms VALUES(9347,93,'Inside a Luxurious Bedroom',replace('A peaceful feeling overtakes you.  You see a magnificent four-poster bed.\nIt''s a double bed and there is only room for one more!  Well, what now ... ?\n','\n',char(10)));
INSERT INTO rooms VALUES(9348,93,'The Supreme Court',replace('You are standing inside the dock of a court.  You feel an overwhelming\nsense of guilt and you want to protest your innocence!  You fear retribution\nand feel yourself exposed, just like the trees in Autumn.\n','\n',char(10)));
INSERT INTO rooms VALUES(9349,93,'In the Dry Desert',replace('You are confused by the shifting sands around you.  Through the shimmering\nheat you see the hazy outline of a giant scorpion ... is this a mirage?\n','\n',char(10)));
INSERT INTO rooms VALUES(9350,93,'In the Woods',replace('You find yourself in the center of a Centaurion hunting party.  You''d better\nhide yourself before you become the ''center attraction''!\n','\n',char(10)));
INSERT INTO rooms VALUES(9351,93,'On a Mountain Peak',replace('You are on the highest peak of the Universe.  You look around and notice\nclouds below you.  One of the clouds resembles a goat-like form.\n','\n',char(10)));
INSERT INTO rooms VALUES(9352,93,'Inside a Waterfall',replace('The noise is deafening.  You are about to take a drink when you realize\nthat the water is being poured out of a vessel of mind-boggling proportions!\n','\n',char(10)));
INSERT INTO rooms VALUES(9353,93,'Inside a Gigantic Clam',replace('You feel uneasy here as if some evil magic is being cast on you.\nYou suspect something fishy is going on in here.\n','\n',char(10)));
INSERT INTO rooms VALUES(9354,93,'End of the Mystic Chains',replace('You have reached the end of the mystic chains.  Looking up, you notice a\nsmall landing on which you can climb.  However, there seems to be another\nforcefield blocking your way.  \n','\n',char(10)));
INSERT INTO rooms VALUES(9355,93,'On the Draco',replace('You realize you are standing on scaly ground.  As you wonder what the ground\nis made of, you feel the ground move.\n','\n',char(10)));
INSERT INTO rooms VALUES(9356,93,'Tail of the Draco',replace('At last you realize that you are on a giant snake-like dragon called the\nDraco, the guardian of the inner galaxy.  You realize that the Draco is\nactually flying now! \n','\n',char(10)));
INSERT INTO rooms VALUES(9357,93,'Path of the Draco',replace('As you struggle along this scaly creature you realize that the only way\nyou can reach to the inner galaxy is by going all the way to the head.\n','\n',char(10)));
INSERT INTO rooms VALUES(9358,93,'Near the Legs of Draco',replace('You are approaching the leg part of this creature.  You look around and see\nthat the surrounding is all dark except for some faint lights from the\ndistant stars.\n','\n',char(10)));
INSERT INTO rooms VALUES(9359,93,'On the Back of Draco',replace('At last you are half way through this long, weary journey. You can see\nthe wings are to the east but it seems that another forcefield is in the way.\n','\n',char(10)));
INSERT INTO rooms VALUES(9360,93,'Between the Wings of Draco',replace('You hear some giant flapping sounds nearby.  You desperately try to get hold\nof something as the forceful gusts sweep you away.\n','\n',char(10)));
INSERT INTO rooms VALUES(9361,93,'Near the Arms of Draco',replace('From above you can faintly make out the gigantic arms which extend far\nbeyond into the darkness.\n','\n',char(10)));
INSERT INTO rooms VALUES(9362,93,'On the Neck of Draco',replace('Your journey is now approaching the end.  However, this neck seems to be\nendless.\n','\n',char(10)));
INSERT INTO rooms VALUES(9363,93,'Approaching the Head of Draco',replace('You have come to the end of Draco, but you can''t find the head!\nYou see a forcefield to the south, some distance away, beyond reach.\nIf only the head were here ...\n','\n',char(10)));
INSERT INTO rooms VALUES(9364,93,'At the Entrance of the Great Dipper',replace('Now you are in the innermost part of the galaxy.  What you are walking on now\nis the path of the Great Dipper or the Plough.  You notice that there are\nseven rooms in this zone, representing the seven stars of the Dipper.\n','\n',char(10)));
INSERT INTO rooms VALUES(9365,93,'Cassiopeia''s Throne',replace('This is the Throne room of the Queen of the Universe.  From here you can see\nevery star and constellation in the Universe. \n','\n',char(10)));
INSERT INTO rooms VALUES(9366,93,'Along the Path of the Dipper',replace('You see stars around you but nothing of special interest.\n','\n',char(10)));
INSERT INTO rooms VALUES(9367,93,'Cepheus'' Throne',replace('This is the Throne room of the King of the Universe.  From here you can see\nevery star and constellation in the Universe. \n','\n',char(10)));
INSERT INTO rooms VALUES(9368,93,'Along the path of the Dipper',replace('You see stars around you but nothing of special interest.\n','\n',char(10)));
INSERT INTO rooms VALUES(9369,93,'Along the path of the Dipper',replace('You see stars around you but nothing of special interest.\n','\n',char(10)));
INSERT INTO rooms VALUES(9370,93,'End of the Dipper',replace('You have finished the path of the Dipper.  Here, the most prominent feature\nis a set of claw-marks.  You also notice a room to the south; it looks as\nif Polaris could lie here. \n','\n',char(10)));
INSERT INTO rooms VALUES(9371,93,'The Polar Star',replace('You have entered the private chamber of Polaris.  This is a room of great\nsignificance.  You can see a powerful telescope pointing down towards the\nUniverse (SNOOPING!).  It is from here that Polaris commands the Universe.\nYou feel you have come to end of your search in this galaxy ...\n','\n',char(10)));
INSERT INTO rooms VALUES(9400,94,'Entrance to the Mob Factory',replace('You find that you have entered a strange factory. This factory doesn''t\nmake cars or computers or something - it makes mobs! The sound of\nmachinery can be heard in the background; the grinding gears drive you\ncrazy! To the north you see the storage area, to the south the\nforeman''s office, to the east the entrance hallway, and to the west the\neastern end of alley.\n','\n',char(10)));
INSERT INTO rooms VALUES(9401,94,'Mob Factory Storage Area',replace('This is where the raw materials from which mobs are manufactured are\nstored. You see sacks of sawdust, cans of pink paint, a large box\ncontaining wigs and a bottle mysteriously labelled "solution x". Exits\nare more of storage to the east and north, and entrance to the mob\nfactory to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(9402,94,'Mob Factory Storage Area',replace('This is where the raw materials from which mobs are manufactured are\nstored. You see sacks of sawdust, cans of pink paint, a large box\ncontaining wigs and a bottle mysteriously labelled "solution X". Exits\nare more of storage to the east and south.\n','\n',char(10)));
INSERT INTO rooms VALUES(9403,94,'Foreman''s Office',replace('This is the ofice of the mob factory foreman. The room is sparsely\nfurnished with a metal desk, a couple of chairs, a shelf with helmets\nof various sizes and a Sports Illustrated Swimsuit calendar on the west\nwall. Exits lead north to the mob factory entrance and south to the\nforeman''s bathroom.\n','\n',char(10)));
INSERT INTO rooms VALUES(9404,94,'Foreman''s Bathroom',replace('This is the place where the foreman makes frequent visits. The smell\nhere is very strong and reminds you of bovine excrement! There is a\nshower to the back, and a urinal to the left. On the floor you can\nsee stains of a very suspicious nature. The only exit leads north to\nthe foreman''s office.\n','\n',char(10)));
INSERT INTO rooms VALUES(9405,94,'Mob Factory Storage Area',replace('This is where the raw materials from which mobs are manufactured are\nstored. You see sacks of sawdust, cans of pink paint, a large box\ncontaining wigs and a bottle mysteriously labelled "solution X". Exits\nare more of storage to the west and south, and an inspection room to\nthe east.\n','\n',char(10)));
INSERT INTO rooms VALUES(9406,94,'Mob Factory Storage Area',replace('This is where the raw materials from which mobs are manufactured are\nstored. You see sacks of sawdust, cans of pink paint, a large box\ncontaining wigs and a bottle mysteriously labelled "solution X". Exits\nare more of storage to the west and north, an inspection room to the\neast and the entrance hallway to the south.\n','\n',char(10)));
INSERT INTO rooms VALUES(9407,94,'Entrance Hallway to Mob Factoy',replace('You are standing in the entrance hallway of the mob factory. The sound\nof machinery gets louder now, and you can hear people shouting in the\ndistance. Every once in a while you get creepy feeling that a pair of\neyes is observing you...... Exits are north to the storage area, east\nto the entrance hallway, south to the cafeteria and west to the mob\nfactory entrance.\n','\n',char(10)));
INSERT INTO rooms VALUES(9408,94,'Mob Factory Cafeteria',replace('You find that you have entered the cafeteria of the mob factory. There\nare many workers eating at the numerous tables placed around the room.\nThe food doesn''t look too appetising, but the factory workers don''t\nseem to care. There are many places where food and drink have been\nspilled on the ground. Exits are north to the entrance hallway and\nsouth to the mob factory cafeteria.\n','\n',char(10)));
INSERT INTO rooms VALUES(9409,94,'Mob Factory Cafeteria',replace('You find that you have entered the cafeteria of the mob factory. There\nare many workers eating at the numerous tables placed around the room.\nThe food doesn''t look too appetising, but the factory workers don''t\nseem to care. There are many places where food and drink have been\nspilled on the ground. The only exit is north to the mob factory\ncafeteria.\n','\n',char(10)));
INSERT INTO rooms VALUES(9410,94,'Mob Factory Inspection Room',replace('You have entered the mob factory inspections room. This is where the\nmobs manufactured on the assembly lines are inspected for defects. A\nwhole team of inspectors from the Midgaard Inspections Bureau is\nstanding around, trying to look busy. Exits are south to the mob\nfactory inspection room, east to the primary assembly line and west to\nthe storage area.\n','\n',char(10)));
INSERT INTO rooms VALUES(9411,94,'Mob Factory Inspection Room',replace('You have entered the mob factory inspections room. This is where the\nmobs manufactured on the assembly lines are inspected for defects. A\nwhole team of inspectors from the Midgaard Inspections Bureau is\nstanding around, trying to look busy. Exits are south to the mob\nfactory inspection room, east to the primary assembly line and west to\nthe storage area.\n','\n',char(10)));
INSERT INTO rooms VALUES(9412,94,'Entrance Hallway to Mob Factoy',replace('You are standing in the entrance hallway of the mob factory. The sound\nof machinery gets louder now, and you can hear people shouting in the\ndistance. Every once in a while you get creepy feeling that a pair of\neyes is observing you...... Exits are north to the inspection room,\neast to the primary assembly line, south to the reject room and west\nto the entrance hallway.\n','\n',char(10)));
INSERT INTO rooms VALUES(9413,94,'Mob Factory Reject Room',replace('This is the factory reject room. All the mobs that are manufactured\nincorrectly or have some defect are placed here before subsequent\ndestruction. You shudder at the many deformed and grotesque shapes\npresent before you. Exits are south to the reject room and north to\nthe entrance hallway.\n','\n',char(10)));
INSERT INTO rooms VALUES(9414,94,'Mob Factory Reject Room',replace('This is the factory reject room. All the mobs that are manufactured\nincorrectly or have some defect are placed here before subsequent\ndestruction. You shudder at the many deformed and grotesque shapes\npresent before you. The only exit is north to the reject room.\n','\n',char(10)));
INSERT INTO rooms VALUES(9415,94,'Primary Assembly Line',replace('This is the primary assembly line of the mob factory. Here, all the\nmobs seen roaming around the city of Midgaard are manufactured from\nraw materials. There is a big conveyor belt present which makes a lot\nof noise! It seems that the workers are making drunks today. Exits are\neast to the secondary assembly line, south to the primary assembly\nline and west to the inspection room.\n','\n',char(10)));
INSERT INTO rooms VALUES(9416,94,'Primary Assembly Line',replace('This is the primary assembly line of the mob factory. Here, all the\nmobs seen roaming around the city of Midgaard are manufactured from\nraw materials. There is a big conveyor belt present which makes a lot\nof noise! It seems that the workers are making drunks today. Exits are\neast to the secondary assembly line, north and south to the primary\nassembly line and west to the inspection room.\n','\n',char(10)));
INSERT INTO rooms VALUES(9417,94,'Primary Assembly Line',replace('This is the primary assembly line of the mob factory. Here, all the\nmobs seen roaming around the city of Midgaard are manufactured from\nraw materials. There is a big conveyor belt present which makes a lot\nof noise! It seems that the workers are making drunks today. Exits are\neast to the secondary assembly line, north and south to the primary\nassembly line and west to the entrance hallway.\n','\n',char(10)));
INSERT INTO rooms VALUES(9418,94,'Primary Assembly Line',replace('This is the primary assembly line of the mob factory. Here, all the\nmobs seen roaming around the city of Midgaard are manufactured from\nraw materials. There is a big conveyor belt present which makes a lot\nof noise! It seems that the workers are making drunks today. Exits are\neast to the secondary assembly line, north and south to the primary\nassembly line.\n','\n',char(10)));
INSERT INTO rooms VALUES(9419,94,'Primary Assembly Line',replace('This is the primary assembly line of the mob factory. Here, all the\nmobs seen roaming around the city of Midgaard are manufactured from\nraw materials. There is a big conveyor belt present which makes a lot\nof noise! It seems that the workers are making drunks today. Exits are\neast to the secondary assembly line and north to the primary\nassembly line.\n','\n',char(10)));
INSERT INTO rooms VALUES(9420,94,'Secondary Assembly Line',replace('This is the secondary asembly line of the mob factory. You are\nsurprised to see cityguard heads come floating on the conveyor belt!\nThe very sight is sickening, but the workers seem to be quite\ncheerful about their work. Exits are south to the secondary assembly\nline and west to the primary assembly line.\n','\n',char(10)));
INSERT INTO rooms VALUES(9421,94,'Secondary Assembly Line',replace('This is the secondary asembly line of the mob factory. You are\nsurprised to see cityguard heads come floating on the conveyor belt!\nThe very sight is sickening, but the workers seem to be quite\ncheerful about their work. Exits are north and south to the secondary\nassembly line and west to the primary assembly line.\n','\n',char(10)));
INSERT INTO rooms VALUES(9422,94,'Secondary Assembly Line',replace('This is the secondary asembly line of the mob factory. You are\nsurprised to see cityguard heads come floating on the conveyor belt!\nThe very sight is sickening, but the workers seem to be quite\ncheerful about their work. Exits are north and south to the secondary\nassembly line and west to the primary assembly line.\n','\n',char(10)));
