INSERT INTO exits VALUES(7005,7006,'s',replace('South. There is even more mud in that direction than where you are now. \nIncredible.\n','\n',char(10)));
INSERT INTO exits VALUES(7006,7012,'e',replace('The pipe leads into a bend that goes south. Interesting, there''s mud on the\nfloor there.\n','\n',char(10)));
INSERT INTO exits VALUES(7006,7005,'n',replace('The muddy sewer pipe leads into a bend that goes east.\n','\n',char(10)));
INSERT INTO exits VALUES(7007,7002,'w',replace('The pipe (still filled with mud) leads into a intersection that goes north \nand south. Interesting.\n','\n',char(10)));
INSERT INTO exits VALUES(7007,7008,'s',replace('The pipe leads into a intersection that goes south and east. The floor here \nis still covered in mud.\n','\n',char(10)));
INSERT INTO exits VALUES(7008,7007,'n',replace('North. The pipe goes into a bend with a load of mud all the way up the walls.\nThe bend leads west.\n','\n',char(10)));
INSERT INTO exits VALUES(7008,7014,'e',replace('East. This way like a place for the annual mud festival, although the stench\nwouldn''t allow any happiness at all. The pipe leads into a bend that leads \nnorth.\n','\n',char(10)));
INSERT INTO exits VALUES(7008,7009,'s',replace('South. There''s less mud in that direction. *smile*. Your light doesn''t \ncover enough space for you to see much more than that it leads into some\nsort of junction.\n','\n',char(10)));
INSERT INTO exits VALUES(7009,7008,'n',replace('North. Mud is the floor basis in that direction. Yummy.\n','\n',char(10)));
INSERT INTO exits VALUES(7009,7017,'e',replace('YYEEUUCH! BOOH! THAT looks like a nice place for creepy crawlies.\n','\n',char(10)));
INSERT INTO exits VALUES(7009,7010,'s',replace('North. This direction looks quite nice actually. The pipe leads into \na bend that goes east.\n','\n',char(10)));
INSERT INTO exits VALUES(7009,7004,'w',replace('A few yards ahead - away from this junction - there is a pit leading down,\nbut the smell from there...>PHEWW<.\n','\n',char(10)));
INSERT INTO exits VALUES(7010,7009,'n',replace('North. You are staring into a huge junction with exits in all directions.\n','\n',char(10)));
INSERT INTO exits VALUES(7010,7018,'e',replace('East. The Pipe leads into utter darkness that way.\n','\n',char(10)));
INSERT INTO exits VALUES(7011,7005,'w',replace('West. The mud reaches that way too, all the way up the walls.\n','\n',char(10)));
INSERT INTO exits VALUES(7011,7024,'e',replace('East. There''s less mud in that direction, or that''s your impression.\n','\n',char(10)));
INSERT INTO exits VALUES(7011,7021,'s',replace('That way is lost in darkness, though you sense less mud in that direction,\nperhaps even a complete end to this sludge that surrounds you.\n','\n',char(10)));
INSERT INTO exits VALUES(7012,7006,'w',replace('West. All you can see, is that the pipe leads into a bend that goes\nnorth. But there''s less mud in that direction, however odd that sounds.\n','\n',char(10)));
INSERT INTO exits VALUES(7012,7013,'s',replace('South. There''s even more mud that way, incredible! Although it looks\nlike an intersection in the sewer system that leads east and south.\n','\n',char(10)));
INSERT INTO exits VALUES(7013,7012,'n',replace('North. Sludge and sediment fills this corridor of the sewer that leads\ninto a bend going west.\n','\n',char(10)));
INSERT INTO exits VALUES(7013,7026,'e',replace('East. You can see absolutely nothing of interest in that direction (Maybe\nthat''s why it''s so damn interesting.??) There''s no mud in that direction\neither, GREAT!\n','\n',char(10)));
INSERT INTO exits VALUES(7013,7014,'s',replace('South. All you can see is more mud! Although the pipe goes into a bend\nleading west.\n','\n',char(10)));
INSERT INTO exits VALUES(7014,7013,'n',replace('North. Filled with mud, that place looks like an impassable intersection\nwith pipes leading north and east.\n','\n',char(10)));
INSERT INTO exits VALUES(7014,7008,'w',replace('West. There''s less mud that way, maybe you''re on your way out of this foul\nplace.\n','\n',char(10)));
INSERT INTO exits VALUES(7015,7028,'e',replace('East. You see, because of the utter darkness that surround you, absolutely\nnothing. Your light isn''t of much use for that kind of distance.\n','\n',char(10)));
